/**
 * 星环OPC 线上门户 — 单页应用 (SPA)
 * 设计系统: UI/UX Pro Max — Swiss Modernism + Flat Design
 * 配色: SaaS General Light (#2563EB primary, #F8FAFC bg, #1E293B text)
 * 字体: Inter + Noto Sans SC
 * 菜单: 1:1 复刻桌面端管理后台
 */
import { readFileSync, existsSync } from "node:fs";
import { resolve } from "node:path";
import type { IncomingMessage, ServerResponse } from "node:http";

// 声明浏览器端全局变量（由服务端注入到 HTML head）
declare const window: Window & { LOCAL_MODE?: boolean; xhopc?: any; __OPPORTUNITY_MAP__?: any };

const EMPTY_PNG = "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=";

function toDataUri(relativePath: string): string {
  try {
    const url = new URL(relativePath, import.meta.url);
    if (!existsSync(url)) return EMPTY_PNG;
    const buffer = readFileSync(url);
    return `data:image/png;base64,${buffer.toString("base64")}`;
  } catch { return EMPTY_PNG; }
}

const PORTAL_LOGO_DARK = toDataUri("../img/galaxy.png");
const PORTAL_LOGO_LIGHT = toDataUri("../img/galaxy_black.png");
const PORTAL_LOGO = toDataUri("../img/logo.png");

function loadChinaCitiesJson(): string {
  try {
    const url = new URL("../../ChinaCitys.json", import.meta.url);
    if (existsSync(url)) return readFileSync(url, "utf-8");
    const cwdPath = resolve(process.cwd(), "ChinaCitys.json");
    if (existsSync(cwdPath)) return readFileSync(cwdPath, "utf-8");
    const projectRootPath = resolve(process.cwd(), "opc-server", "ChinaCitys.json");
    if (existsSync(projectRootPath)) return readFileSync(projectRootPath, "utf-8");
    return "[]";
  } catch { return "[]"; }
}
const CHINA_CITIES_JSON = loadChinaCitiesJson();

function escapeInlineJson(raw: string): string {
  return String(raw || "")
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");
}

function loadOpportunityMapJson(): string {
  try {
    const southwestUrl = new URL("../../research/southwest-opportunity-map.json", import.meta.url);
    if (existsSync(southwestUrl)) return readFileSync(southwestUrl, "utf-8");
    const yunnanUrl = new URL("../../research/yunnan-opportunity-map.json", import.meta.url);
    if (existsSync(yunnanUrl)) return readFileSync(yunnanUrl, "utf-8");
    const provinceUrl = new URL("../../research/sichuan-opportunity-map.json", import.meta.url);
    if (existsSync(provinceUrl)) return readFileSync(provinceUrl, "utf-8");
    const countyUrl = new URL("../../research/dazhu-opportunity-map.json", import.meta.url);
    if (existsSync(countyUrl)) return readFileSync(countyUrl, "utf-8");
    const cwdCandidates = [
      resolve(process.cwd(), "research", "southwest-opportunity-map.json"),
      resolve(process.cwd(), "research", "yunnan-opportunity-map.json"),
      resolve(process.cwd(), "research", "sichuan-opportunity-map.json"),
      resolve(process.cwd(), "research", "dazhu-opportunity-map.json"),
      resolve(process.cwd(), "opc-server", "research", "southwest-opportunity-map.json"),
      resolve(process.cwd(), "opc-server", "research", "yunnan-opportunity-map.json"),
      resolve(process.cwd(), "opc-server", "research", "sichuan-opportunity-map.json"),
      resolve(process.cwd(), "opc-server", "research", "dazhu-opportunity-map.json"),
    ];
    for (const filePath of cwdCandidates) {
      if (existsSync(filePath)) return readFileSync(filePath, "utf-8");
    }
    return '{"meta":{},"industries":[],"opportunities":[]}';
  } catch {
    return '{"meta":{},"industries":[],"opportunities":[]}';
  }
}
const SAFE_CHINA_CITIES_JSON = escapeInlineJson(CHINA_CITIES_JSON);
const OPPORTUNITY_MAP_JSON = loadOpportunityMapJson();
const SAFE_OPPORTUNITY_MAP_JSON = escapeInlineJson(OPPORTUNITY_MAP_JSON);

export function servePortalPage(_req: IncomingMessage, res: ServerResponse): void {
  res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
  res.end(buildPortalHtml());
}

export interface TenantOverrides {
  company_name: string;
  logo_url: string;
  logo_url_light: string;
  slug: string;
  accent_color: string;
  accent_color_2: string;
  bg_color: string;
  panel_color: string;
  text_color: string;
  secondary_text_color: string;
  border_color: string;
  font_family: string;
  topbar_title: string;
  topbar_subtitle: string;
  login_badge: string;
  login_slogan: string;
  login_tag1: string;
  login_tag2: string;
  login_tag3: string;
  custom_css: string;
  theme_style: string;
}

export function serveTenantPortalPage(_req: IncomingMessage, res: ServerResponse, tenant: TenantOverrides): void {
  res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
  res.end(buildPortalHtml(tenant));
}

const IS_LOCAL = process.env.LOCAL_MODE === "true"
  || process.env.OPC_LOCAL_MODE === "1" || process.env.OPC_LOCAL_MODE === "true"
  || process.env.DB_TYPE === "sqlite";
const AMAP_KEY = process.env.AMAP_KEY || "";
const CLOUD_URL_FOR_CLIENT = (process.env.OPC_CLOUD_API_URL || "").trim().replace(/\/+$/, "").replace(/\/api\/?$/, "");

function extractGoogleFontParam(fontFamily: string): string {
  const first = fontFamily.split(",")[0]?.replace(/['"]/g, "").trim() || "";
  if (!first || /system-ui|sans-serif|serif|monospace|SF Pro|apple-system|Futura|Gotham|Söhne|Optimistic|Lyon|Berkeley/i.test(first)) return "";
  return encodeURIComponent(first).replace(/%20/g, "+") + ":wght@300;400;500;600;700";
}

function buildPortalHtml(tenant?: TenantOverrides): string {
  const title = tenant ? `${tenant.company_name} — OPC 运营平台` : '星环OPC — 一人公司孵化平台';
  const favicon = tenant?.logo_url || PORTAL_LOGO;
  const isDarkTenant = tenant?.theme_style?.startsWith('dark');

  const tenantCssOverride = tenant ? `
<style>
:root {
  --accent: ${tenant.accent_color};
  --accent-2: ${tenant.accent_color_2};
  --accent-soft: ${hexToRgba(tenant.accent_color, 0.12)};
  --orange: ${tenant.accent_color};
  ${tenant.font_family ? `--font: ${tenant.font_family};` : ''}
}
[data-theme="dark"] {
  --accent: ${ensureContrastOnDark(tenant.accent_color)};
  --accent-2: ${ensureContrastOnDark(tenant.accent_color_2)};
  --orange: ${ensureContrastOnDark(tenant.accent_color)};
  --bg: ${tenant.bg_color};
  --bg-soft: ${tenant.panel_color};
  --card: ${hexToRgba(tenant.panel_color, 0.92)};
  --card-strong: ${tenant.panel_color};
  --tx: ${tenant.text_color};
  --tx2: ${tenant.secondary_text_color};
  --bd: ${tenant.border_color};
  --body-bg: radial-gradient(circle at top left, ${hexToRgba(tenant.accent_color, 0.06)}, transparent 28%),
    radial-gradient(circle at top right, ${hexToRgba(tenant.accent_color_2, 0.04)}, transparent 24%),
    linear-gradient(180deg, ${tenant.bg_color} 0%, ${tenant.panel_color} 42%, ${tenant.bg_color} 100%);
  --topbar-bg: ${tenant.bg_color};
}
[data-theme="light"] {
  --accent: ${ensureContrastOnWhite(tenant.accent_color)};
  --accent-2: ${ensureContrastOnWhite(tenant.accent_color_2)};
  --accent-soft: ${hexToRgba(ensureContrastOnWhite(tenant.accent_color), 0.08)};
  --orange: ${ensureContrastOnWhite(tenant.accent_color)};
}
.sidebar-nav a:hover { background: ${hexToRgba(tenant.accent_color, 0.08)} !important; }
.sidebar-nav a.active { background: ${hexToRgba(tenant.accent_color, 0.12)} !important; color: var(--accent) !important; box-shadow: inset 0 0 0 1px ${hexToRgba(tenant.accent_color, 0.18)} !important; }
${tenant.custom_css || ''}
</style>` : '';

  const tenantScript = tenant ? `window.__TENANT__=${JSON.stringify({
    company_name: tenant.company_name,
    logo_url: tenant.logo_url,
    logo_url_light: tenant.logo_url_light || '',
    slug: tenant.slug,
    topbar_title: tenant.topbar_title || tenant.company_name,
    topbar_subtitle: tenant.topbar_subtitle || '',
    login_badge: tenant.login_badge || '',
    login_slogan: tenant.login_slogan || '',
    login_tag1: tenant.login_tag1 || '',
    login_tag2: tenant.login_tag2 || '',
    login_tag3: tenant.login_tag3 || '',
    theme_style: tenant.theme_style,
    accent_color: tenant.accent_color,
    accent_color_2: tenant.accent_color_2,
    bg_color: tenant.bg_color,
  })};` : '';

  return `<!DOCTYPE html>
<html lang="zh-CN" data-theme="${tenant && isDarkTenant ? 'dark' : 'dark'}">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>${title}</title>
<script>window.LOCAL_MODE = ${IS_LOCAL};window.OPC_CLOUD_URL="${CLOUD_URL_FOR_CLIENT}";window.__CHINA_CITIES__=${SAFE_CHINA_CITIES_JSON};window.__OPPORTUNITY_MAP__=${SAFE_OPPORTUNITY_MAP_JSON};${tenantScript}</script>
<link rel="icon" type="image/png" href="${favicon}" />
<link rel="preload" as="style" href="https://fonts.font.im/css2?family=Inter:wght@300;400;500;600;700&family=Noto+Sans+SC:wght@400;500;600;700${tenant?.font_family ? `&family=${extractGoogleFontParam(tenant.font_family)}` : ''}&display=swap" onload="this.onload=null;this.rel='stylesheet'" />
<noscript><link href="https://fonts.font.im/css2?family=Inter:wght@300;400;500;600;700&family=Noto+Sans+SC:wght@400;500;600;700${tenant?.font_family ? `&family=${extractGoogleFontParam(tenant.font_family)}` : ''}&display=swap" rel="stylesheet" /></noscript>
${AMAP_KEY ? `<script src="https://webapi.amap.com/maps?v=2.0&key=${AMAP_KEY}"></script>` : '<!-- AMap: AMAP_KEY not configured in .env -->'}
<style>${getPortalCss()}</style>${tenantCssOverride}
<script>
(function(){var t=localStorage.getItem('easyopc-theme');if(t==='light'||t==='dark'){document.documentElement.setAttribute('data-theme',t)}})();
</script>
</head>
<body>
<div id="app"></div>
<script>${getPortalJs()}</script>
</body>
</html>`;
}

function hexToRgba(hex: string, alpha: number): string {
  if (!hex || hex.startsWith('rgba') || hex.startsWith('rgb')) return hex;
  const h = hex.replace('#', '');
  const r = parseInt(h.substring(0, 2), 16) || 0;
  const g = parseInt(h.substring(2, 4), 16) || 0;
  const b = parseInt(h.substring(4, 6), 16) || 0;
  return `rgba(${r},${g},${b},${alpha})`;
}

function hexLuminance(hex: string): number {
  const h = (hex || '#000000').replace('#', '');
  const r = parseInt(h.substring(0, 2), 16) / 255;
  const g = parseInt(h.substring(2, 4), 16) / 255;
  const b = parseInt(h.substring(4, 6), 16) / 255;
  const toL = (c: number) => c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4);
  return 0.2126 * toL(r) + 0.7152 * toL(g) + 0.0722 * toL(b);
}

function contrastRatio(l1: number, l2: number): number {
  const lighter = Math.max(l1, l2);
  const darker = Math.min(l1, l2);
  return (lighter + 0.05) / (darker + 0.05);
}

function darkenHex(hex: string, factor: number): string {
  const h = hex.replace('#', '');
  const r = Math.round(parseInt(h.substring(0, 2), 16) * factor);
  const g = Math.round(parseInt(h.substring(2, 4), 16) * factor);
  const b = Math.round(parseInt(h.substring(4, 6), 16) * factor);
  return '#' + [r, g, b].map(c => Math.min(255, c).toString(16).padStart(2, '0')).join('');
}

function lightenHex(hex: string, factor: number): string {
  const h = hex.replace('#', '');
  const r = parseInt(h.substring(0, 2), 16);
  const g = parseInt(h.substring(2, 4), 16);
  const b = parseInt(h.substring(4, 6), 16);
  const lr = Math.round(r + (255 - r) * factor);
  const lg = Math.round(g + (255 - g) * factor);
  const lb = Math.round(b + (255 - b) * factor);
  return '#' + [lr, lg, lb].map(c => Math.min(255, c).toString(16).padStart(2, '0')).join('');
}

function ensureContrastOnWhite(hex: string): string {
  const WHITE_LUM = 1.0;
  const accentLum = hexLuminance(hex);
  const ratio = contrastRatio(accentLum, WHITE_LUM);
  if (ratio >= 3.0) return hex;
  let color = hex;
  for (let i = 1; i <= 10; i++) {
    color = darkenHex(hex, 1 - i * 0.1);
    if (contrastRatio(hexLuminance(color), WHITE_LUM) >= 3.0) return color;
  }
  return '#333333';
}

function ensureContrastOnDark(hex: string): string {
  const DARK_LUM = hexLuminance('#111111');
  const accentLum = hexLuminance(hex);
  const ratio = contrastRatio(accentLum, DARK_LUM);
  if (ratio >= 3.0) return hex;
  let color = hex;
  for (let i = 1; i <= 10; i++) {
    color = lightenHex(hex, i * 0.1);
    if (contrastRatio(hexLuminance(color), DARK_LUM) >= 3.0) return color;
  }
  return '#cccccc';
}

