function hexToRgbArr(hex) {
  hex = hex.replace('#', '');
  if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
  return [parseInt(hex.substring(0,2),16), parseInt(hex.substring(2,4),16), parseInt(hex.substring(4,6),16)];
}
function darkenRgb(rgb, factor) { return [Math.round(rgb[0]*factor), Math.round(rgb[1]*factor), Math.round(rgb[2]*factor)]; }

function initAuth3dBg() {
  var canvas = document.getElementById('auth-grain-bg');
  if (!canvas || !canvas.getContext) return;
  var ctx = canvas.getContext('2d');
  if (!ctx) return;

  var T = window.__TENANT__;
  var c1 = T && T.accent_color ? hexToRgbArr(T.accent_color) : [230,115,35];
  var c2 = T && T.accent_color_2 ? hexToRgbArr(T.accent_color_2) : [195,80,12];
  var baseBg = T && T.bg_color ? T.bg_color : '#050403';

  var c1mid = darkenRgb(c1, 0.75);
  var c1edge = darkenRgb(c1, 0.5);
  var c2mid = darkenRgb(c2, 0.72);
  var c2edge = darkenRgb(c2, 0.45);

  var w = 0, h = 0;

  var grainCanvas = document.createElement('canvas');
  var grainCtx = grainCanvas.getContext('2d');

  function buildGrain() {
    var gw = w, gh = h;
    if (gw < 1 || gh < 1) return;
    grainCanvas.width = gw; grainCanvas.height = gh;
    var img = grainCtx.createImageData(gw, gh);
    var d = img.data;
    for (var i = 0; i < d.length; i += 4) {
      var v = Math.random() * 255 | 0;
      d[i] = v; d[i+1] = v; d[i+2] = v; d[i+3] = 160;
    }
    grainCtx.putImageData(img, 0, 0);
  }

  function resize() {
    if (!canvas.parentElement) return;
    var dpr = Math.min(window.devicePixelRatio || 1, 2);
    w = Math.round(canvas.parentElement.offsetWidth * dpr);
    h = Math.round(canvas.parentElement.offsetHeight * dpr);
    canvas.width = w; canvas.height = h;
    canvas.style.width = canvas.parentElement.offsetWidth + 'px';
    canvas.style.height = canvas.parentElement.offsetHeight + 'px';
    buildGrain();
  }

  var t0 = performance.now();

  function draw() {
    if (!document.getElementById('auth-grain-bg')) return;
    requestAnimationFrame(draw);
    var t = (performance.now() - t0) * 0.001;

    ctx.globalAlpha = 1;
    ctx.globalCompositeOperation = 'source-over';
    ctx.fillStyle = baseBg;
    ctx.fillRect(0, 0, w, h);

    var raw1 = Math.sin(t * 1.3);
    var raw2 = Math.sin(t * 1.05 + 2.1);
    var b1 = 0.5 + 0.5 * raw1;
    var b2 = 0.5 + 0.5 * raw2;

    ctx.globalCompositeOperation = 'lighter';

    var a1c = (0.45 + b1 * 0.55).toFixed(2);
    var a1m = (0.20 + b1 * 0.40).toFixed(2);
    var a1e = (0.04 + b1 * 0.18).toFixed(2);
    var r1 = Math.max(w, h) * (0.60 + b1 * 0.22);
    var x1 = w * 0.90, y1 = h * (-0.05);
    var grad1 = ctx.createRadialGradient(x1, y1, 0, x1, y1, r1);
    grad1.addColorStop(0,    'rgba(' + c1[0] + ',' + c1[1] + ',' + c1[2] + ',' + a1c + ')');
    grad1.addColorStop(0.28, 'rgba(' + c1mid[0] + ',' + c1mid[1] + ',' + c1mid[2] + ',' + a1m + ')');
    grad1.addColorStop(0.60, 'rgba(' + c1edge[0] + ',' + c1edge[1] + ',' + c1edge[2] + ',' + a1e + ')');
    grad1.addColorStop(1,    'rgba(0,0,0,0)');
    ctx.fillStyle = grad1;
    ctx.fillRect(0, 0, w, h);

    var a2c = (0.40 + b2 * 0.50).toFixed(2);
    var a2m = (0.18 + b2 * 0.35).toFixed(2);
    var a2e = (0.04 + b2 * 0.14).toFixed(2);
    var r2 = Math.max(w, h) * (0.55 + b2 * 0.20);
    var x2 = w * 0.06, y2 = h * 1.05;
    var grad2 = ctx.createRadialGradient(x2, y2, 0, x2, y2, r2);
    grad2.addColorStop(0,    'rgba(' + c2[0] + ',' + c2[1] + ',' + c2[2] + ',' + a2c + ')');
    grad2.addColorStop(0.32, 'rgba(' + c2mid[0] + ',' + c2mid[1] + ',' + c2mid[2] + ',' + a2m + ')');
    grad2.addColorStop(0.62, 'rgba(' + c2edge[0] + ',' + c2edge[1] + ',' + c2edge[2] + ',' + a2e + ')');
    grad2.addColorStop(1,    'rgba(0,0,0,0)');
    ctx.fillStyle = grad2;
    ctx.fillRect(0, 0, w, h);

    ctx.globalCompositeOperation = 'screen';
    ctx.globalAlpha = 0.15;
    ctx.drawImage(grainCanvas, 0, 0, w, h);
    ctx.globalAlpha = 1;

    ctx.globalCompositeOperation = 'source-over';
    var vig = ctx.createRadialGradient(w*0.5, h*0.5, h*0.2, w*0.5, h*0.5, h*0.9);
    vig.addColorStop(0, 'rgba(0,0,0,0)');
    vig.addColorStop(1, 'rgba(0,0,0,0.72)');
    ctx.fillStyle = vig;
    ctx.fillRect(0, 0, w, h);
  }

  resize();
  window.addEventListener('resize', resize);

  canvas.style.opacity = '0';
  requestAnimationFrame(function() {
    canvas.style.transition = 'opacity 1.2s ease';
    canvas.style.opacity = '1';
    draw();
  });
}

async function handleLogin() {
  var btn = document.getElementById('login-btn');
  var isCodeMode = document.querySelector('.login-mode-tab.active')?.dataset.mode === 'code';
  var body;
  if (isCodeMode) {
    var email = document.getElementById('login-email-code')?.value.trim() || '';
    var code = document.getElementById('login-code')?.value.trim() || '';
    if (!email || !code) { showAuthError('请输入邮箱和验证码'); return; }
    body = { email: email, code: code, login_type: 'code' };
  } else {
    var account = document.getElementById('login-phone').value.trim();
    var password = document.getElementById('login-password').value;
    if (!account || !password) { showAuthError('请输入邮箱/用户名和密码'); return; }
    body = { account: account, password: password };
  }
  btn.disabled = true; btn.textContent = '登录中...';
  try {
    var data = await api('/auth/login', { method: 'POST', body: body });
    saveAuth(data.token, data.user); toast('登录成功', 'success'); navigate('dashboard');
  } catch(e) { showAuthError(e.message); }
  finally { btn.disabled = false; btn.textContent = '登录'; }
}

var _codeCooldown = 0;
var _loginCodeCooldown = 0;

async function handleLoginSendCode() {
  var emailEl = document.getElementById('login-email-code');
  var email = emailEl ? emailEl.value.trim() : '';
  var btn = document.getElementById('login-send-code-btn');
  if (!email) { showAuthError('请先输入邮箱地址'); return; }
  btn.disabled = true;
  try {
    await api('/auth/send-code', { method: 'POST', body: { email: email } });
    toast('验证码已发送', 'success');
    _loginCodeCooldown = 60;
    btn.textContent = _loginCodeCooldown + 's';
    var timer = setInterval(function() {
      _loginCodeCooldown--;
      if (_loginCodeCooldown <= 0) { clearInterval(timer); btn.disabled = false; btn.textContent = '发送验证码'; }
      else { btn.textContent = _loginCodeCooldown + 's'; }
    }, 1000);
  } catch(e) { showAuthError(e.message); btn.disabled = false; }
}
async function handleSendCode() {
  var emailEl = document.getElementById('reg-email');
  var email = emailEl ? emailEl.value.trim() : '';
  var btn = document.getElementById('send-code-btn');
  if (!email) { showAuthError('\u8BF7\u5148\u8F93\u5165\u90AE\u7BB1\u5730\u5740'); return; }
  btn.disabled = true;
  try {
    await api('/auth/send-code', { method: 'POST', body: { email: email } });
    toast('\u9A8C\u8BC1\u7801\u5DF2\u53D1\u9001', 'success');
    _codeCooldown = 60;
    btn.textContent = _codeCooldown + 's';
    var timer = setInterval(function() {
      _codeCooldown--;
      if (_codeCooldown <= 0) { clearInterval(timer); btn.disabled = false; btn.textContent = '\u53D1\u9001\u9A8C\u8BC1\u7801'; }
      else { btn.textContent = _codeCooldown + 's'; }
    }, 1000);
  } catch(e) { showAuthError(e.message); btn.disabled = false; }
}

async function handleRegister() {
  var name = document.getElementById('reg-name').value.trim();
  var password = document.getElementById('reg-password').value;
  var confirm = document.getElementById('reg-confirm').value;
  var btn = document.getElementById('reg-btn');
  if (!name || !password) { showAuthError('请填写姓名和密码'); return; }
  if (password !== confirm) { showAuthError('两次密码不一致'); return; }
  if (password.length < 6) { showAuthError('密码至少6位'); return; }
  var inviteEl = document.getElementById('reg-invite');
  var inviteCode = inviteEl ? inviteEl.value.trim() : '';
  var emailEl = document.getElementById('reg-email');
  var codeEl = document.getElementById('reg-code');
  var termsEl = document.getElementById('reg-terms');
  var email = emailEl ? emailEl.value.trim() : '';
  var code = codeEl ? codeEl.value.trim() : '';
  if (!email || !code) { showAuthError('请填写邮箱和验证码'); return; }
  if (termsEl && !termsEl.checked) { showAuthError('请先阅读并同意用户协议'); return; }
  var body = { name: name, password: password, invite_code: inviteCode, email: email, code: code };
  btn.disabled = true; btn.textContent = '\u6CE8\u518C\u4E2D...';
  try {
    var data = await api('/auth/register', { method: 'POST', body: body });
    saveAuth(data.token, data.user); toast('\u6CE8\u518C\u6210\u529F', 'success'); navigate('dashboard');
  } catch(e) { showAuthError(e.message); }
  finally { btn.disabled = false; btn.textContent = '\u6CE8\u518C'; }
}

function showAuthError(msg) { const el = document.getElementById('auth-error'); el.textContent = msg; el.className = 'auth-error show'; }

async function loadGuide() {
  renderGuide();
}

