function updateMobileTabbar(route) {
  var p = route.page;
  if (p === 'login') {
    var old = document.getElementById('mobile-tabbar');
    if (old) old.remove();
    return;
  }
  function tab(href, label, svgPath, active) {
    return '<a href="#' + href + '" class="' + (active ? 'active' : '') + '"><svg viewBox="0 0 24 24">' + svgPath + '</svg>' + label + '</a>';
  }
  var html =
    tab('chat', 'AI\u5BF9\u8BDD', '<path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/>', p === 'chat') +
    tab('dashboard', '\u4EEA\u8868\u76D8', '<rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="4" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/><rect x="14" y="11" width="7" height="10" rx="1"/>', p === 'dashboard') +
    tab('feedback', '\u53CD\u9988', '<path d="M21 11.5a8.38 8.38 0 01-.9 3.8 8.5 8.5 0 01-7.6 4.7 8.38 8.38 0 01-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 01-.9-3.8 8.5 8.5 0 014.7-7.6 8.38 8.38 0 013.8-.9h.5a8.48 8.48 0 018 8v.5z"/>', p === 'feedback') +
    tab('invite', '\u63A8\u5E7F', '<path d="M16 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="8.5" cy="7" r="4"/><line x1="20" y1="8" x2="20" y2="14"/><line x1="23" y1="11" x2="17" y2="11"/>', p === 'invite') +
    tab('profile', '\u6211\u7684', '<circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/>', p === 'profile');
  var el = document.getElementById('mobile-tabbar');
  if (!el) {
    el = document.createElement('nav');
    el.id = 'mobile-tabbar';
    el.className = 'mobile-tabbar';
    document.body.appendChild(el);
  }
  el.innerHTML = html;
}

