async function loadSidebarQuota() {
  if (window.LOCAL_MODE) return;
  try {
    var data = await api('/user/quota');
    if (!data) return;
    state._quota = data;

    // 更新侧边栏额度条
    var el = document.getElementById('sidebar-quota');
    if (el) {
      var pct = data.plan === 'ultra' ? 100 : Math.min(100, Math.round(((data.quota_total - data.quota_used) / data.quota_total) * 100));
      var barColor = pct > 50 ? 'var(--green)' : pct > 20 ? 'var(--accent)' : 'var(--red)';
      var bonus = data.bonus_points || 0;
      var totalRem = data.plan === 'ultra' ? '无限算力' :
        ((data.quota_remaining + bonus) + ' / ' + data.quota_total + ' 算力点' +
         (bonus > 0 ? ' <span style="color:var(--green);font-size:10px;">(+' + bonus + ' 赠)</span>' : ''));
      el.innerHTML = '<div class="quota-plan-badge">' + (data.plan_name || '内测体验') + '</div>' +
        '<div class="quota-bar-wrap"><div class="quota-bar" style="width:' + pct + '%;background:' + barColor + ';"></div></div>' +
        '<div class="quota-text">' + totalRem + '</div>' +
        '<button class="btn btn-sm quota-upgrade-btn" onclick="navigate(&quot;plan&quot;)">套餐详情</button>';
    }

    // 更新顶栏额度 pill（始终执行，不依赖 sidebar 元素是否存在）
    var pill = document.getElementById('topbar-quota-pill');
    var pillText = document.getElementById('topbar-quota-text');
    if (pill && pillText) {
      if (data.plan === 'ultra') {
        pill.className = 'topbar-quota-pill ultra';
        pillText.textContent = '无限算力';
      } else {
        var rem = (data.quota_remaining || 0) + (data.bonus_points || 0);
        var total = data.quota_total || 1;
        var remPct = Math.round(rem / total * 100);
        pill.className = 'topbar-quota-pill' + (remPct <= 20 ? ' low' : remPct <= 50 ? ' medium' : '');
        pillText.textContent = rem + ' 点剩余';
      }
    }
  } catch {}
}

// ─── 城市选择器 ──────────────────────────────────────────────────────

async function loadCitySelector() {
  try {
    var data = await api('/cities', { silent: true });
    state.cities = data.cities || [];
  } catch(e) { state.cities = []; }
  updateCitySelectorName();
}

function updateCitySelectorName() {
  var el = document.getElementById('city-selector-name');
  if (!el) return;
  if (state.selectedCityId) {
    var city = state.cities.find(function(c) { return c.id === state.selectedCityId; });
    el.textContent = city ? city.name : '\u5168\u90E8\u57CE\u5E02';
  } else if (state._selectedRegion) {
    el.textContent = state._selectedRegion;
  } else {
    el.textContent = '\u5168\u90E8\u57CE\u5E02';
  }
}

var _csTab = 'park';
var _csProvince = '';
var _csCity = '';

function toggleCitySelector() {
  var existing = document.getElementById('city-dropdown');
  if (existing) { document.body.removeChild(existing); return; }

  var btn = document.getElementById('city-selector-btn');
  if (!btn) return;
  var br = btn.getBoundingClientRect();

  var dd = document.createElement('div');
  dd.id = 'city-dropdown';
  dd.style.cssText = 'position:fixed;top:' + (br.bottom + 4) + 'px;right:' + (window.innerWidth - br.right) + 'px;min-width:380px;max-height:520px;overflow-y:auto;background:var(--bg);border:1px solid var(--bd);border-radius:12px;box-shadow:0 12px 40px rgba(0,0,0,0.15);z-index:10000;padding:0;';
  document.body.appendChild(dd);

  renderCityDropdown();

  setTimeout(function() {
    function closeDD(e) {
      var ddEl = document.getElementById('city-dropdown');
      if (!ddEl) { document.removeEventListener('mousedown', closeDD); return; }
      var rect = ddEl.getBoundingClientRect();
      var inDD = e.clientX >= rect.left && e.clientX <= rect.right && e.clientY >= rect.top && e.clientY <= rect.bottom;
      if (inDD) return;
      var btnEl = document.getElementById('city-selector-btn');
      if (btnEl) {
        var br2 = btnEl.getBoundingClientRect();
        if (e.clientX >= br2.left && e.clientX <= br2.right && e.clientY >= br2.top && e.clientY <= br2.bottom) return;
      }
      if (ddEl.parentNode) ddEl.parentNode.removeChild(ddEl);
      document.removeEventListener('mousedown', closeDD);
    }
    document.addEventListener('mousedown', closeDD);
  }, 0);
}

var _csComposing = false;

function renderCityDropdown(searchKey, contentOnly) {
  var dd = document.getElementById('city-dropdown');
  if (!dd) return;
  var selId = state.selectedCityId;
  var parks = state.cities || [];
  var chinaCities = window.__CHINA_CITIES__ || [];
  var q = (searchKey || '').trim().toLowerCase();

  if (!contentOnly) {
    var h = '<div style="padding:12px 14px 6px;">';

    h += '<div style="position:relative;margin-bottom:10px;">' +
      '<input id="cs-search" type="text" placeholder="\u641C\u7D22\u57CE\u5E02\u6216\u56ED\u533A..." style="width:100%;padding:8px 12px 8px 32px;border:1px solid var(--bd);border-radius:8px;font-size:12px;outline:none;background:var(--bg-soft);color:var(--tx);box-sizing:border-box;" />' +
      '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="var(--tx3)" stroke-width="2" style="position:absolute;left:10px;top:50%;transform:translateY(-50%);pointer-events:none;"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg></div>';

    var selPark = parks.find(function(c) { return c.id === selId; });
    var selLabel = selPark ? selPark.name : (state._selectedRegion || '\u5168\u90E8\u57CE\u5E02');
    var hasFilter = !!(selId || state._selectedRegion);
    h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">' +
      '<div style="display:flex;align-items:center;gap:6px;font-size:12px;color:var(--tx2);"><span style="color:var(--tx3);">\u5F53\u524D:</span><strong style="color:var(--accent);">' + esc(selLabel) + '</strong></div>' +
      (hasFilter ? '<div onclick="clearCityFilter()" style="font-size:11px;color:#ef4444;cursor:pointer;font-weight:500;display:flex;align-items:center;gap:3px;"><svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="#ef4444" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>\u6E05\u9664\u7B5B\u9009</div>' : '<div onclick="selectCity(&quot;&quot;)" style="font-size:11px;color:var(--accent);cursor:pointer;font-weight:500;">\u67E5\u770B\u5168\u90E8</div>') +
      '</div>';

    h += '<div style="display:flex;border-bottom:2px solid var(--bd);margin-bottom:10px;">' +
      '<div onclick="switchCsTab(&quot;park&quot;)" style="flex:1;text-align:center;padding:6px 0;font-size:12px;font-weight:600;cursor:pointer;border-bottom:2px solid ' + (_csTab === 'park' ? 'var(--accent)' : 'transparent') + ';color:' + (_csTab === 'park' ? 'var(--accent)' : 'var(--tx3)') + ';margin-bottom:-2px;">\u6309\u56ED\u533A</div>' +
      '<div onclick="switchCsTab(&quot;region&quot;)" style="flex:1;text-align:center;padding:6px 0;font-size:12px;font-weight:600;cursor:pointer;border-bottom:2px solid ' + (_csTab === 'region' ? 'var(--accent)' : 'transparent') + ';color:' + (_csTab === 'region' ? 'var(--accent)' : 'var(--tx3)') + ';margin-bottom:-2px;">\u6309\u57CE\u5E02</div></div>';

    h += '<div id="cs-content"></div></div>';
    dd.innerHTML = h;

    var inp = document.getElementById('cs-search');
    if (inp) {
      inp.addEventListener('compositionstart', function() { _csComposing = true; });
      inp.addEventListener('compositionend', function(e) { _csComposing = false; onCsSearch(e.target.value); });
      inp.addEventListener('input', function(e) { if (!_csComposing) onCsSearch(e.target.value); });
      inp.focus();
    }
  }

  var content = document.getElementById('cs-content');
  if (!content) return;
  var ch = '';

  if (_csTab === 'park') {
    // park list
    var filtered = parks;
    if (q) {
      filtered = parks.filter(function(p) {
        return (p.name || '').toLowerCase().indexOf(q) >= 0 ||
          (p.city_name || '').toLowerCase().indexOf(q) >= 0 ||
          (p.region || '').toLowerCase().indexOf(q) >= 0 ||
          (p.address || '').toLowerCase().indexOf(q) >= 0;
      });
    }
    if (filtered.length === 0) {
      ch += '<div style="padding:20px;text-align:center;color:var(--tx3);font-size:12px;">' + (q ? '\u672A\u627E\u5230\u5339\u914D\u7684\u56ED\u533A' : '\u6682\u65E0\u56ED\u533A') + '</div>';
    } else {
      ch += '<div style="display:flex;flex-direction:column;gap:4px;max-height:280px;overflow-y:auto;">';
      filtered.forEach(function(p) {
        var isSel = p.id === selId;
        ch += '<div onclick="selectCity(&quot;' + p.id + '&quot;)" style="display:flex;align-items:center;gap:10px;padding:8px 10px;border-radius:8px;cursor:pointer;transition:all .15s;' + (isSel ? 'background:rgba(249,115,22,0.08);border:1px solid var(--accent);' : 'border:1px solid transparent;') + '" onmouseover="if(!' + isSel + ')this.style.background=&quot;var(--bg-soft)&quot;" onmouseout="if(!' + isSel + ')this.style.background=&quot;transparent&quot;">' +
          '<div style="width:28px;height:28px;border-radius:6px;background:' + (isSel ? 'var(--accent)' : '#F97316') + ';display:flex;align-items:center;justify-content:center;flex-shrink:0;"><svg viewBox="0 0 24 24" width="12" height="12" fill="#fff" stroke="none"><path d="M12 7V3H2v18h20V7H12zM6 19H4v-2h2v2zm0-4H4v-2h2v2zm0-4H4V9h2v2zm0-4H4V5h2v2zm4 12H8v-2h2v2zm0-4H8v-2h2v2zm0-4H8V9h2v2zm0-4H8V5h2v2zm10 12h-8v-2h2v-2h-2v-2h2v-2h-2V9h8v10zm-2-8h-2v2h2v-2zm0 4h-2v2h2v-2z"/></svg></div>' +
          '<div style="flex:1;min-width:0;"><div style="font-size:12px;font-weight:' + (isSel ? '700' : '500') + ';color:' + (isSel ? 'var(--accent)' : 'var(--tx)') + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + esc(p.name) + '</div>' +
          '<div style="font-size:10px;color:var(--tx3);">' + esc(p.city_name || p.region || '') + '</div></div>' +
          '<div style="font-size:11px;color:var(--tx3);flex-shrink:0;">' + (p.used_seats || 0) + '\u4EBA</div>' +
          (isSel ? '<svg viewBox="0 0 24 24" width="14" height="14" fill="var(--accent)" stroke="none" style="flex-shrink:0;"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41L9 16.17z"/></svg>' : '') +
          '</div>';
      });
      ch += '</div>';
    }
  } else {
    if (!_csProvince) {
      var provinces = chinaCities;
      if (q) {
        provinces = chinaCities.filter(function(prov) {
          if (prov.province.toLowerCase().indexOf(q) >= 0) return true;
          return prov.citys.some(function(ct) {
            if (ct.city.toLowerCase().indexOf(q) >= 0) return true;
            return ct.areas.some(function(a) { return a.area.toLowerCase().indexOf(q) >= 0; });
          });
        });
      }
      ch += '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:4px;max-height:300px;overflow-y:auto;">';
      provinces.forEach(function(prov) {
        var isActive = state._selectedRegion && state._selectedRegion.indexOf(prov.province) === 0;
        ch += '<div onclick="csSelectProvince(&quot;' + esc(prov.province) + '&quot;)" style="padding:7px 4px;text-align:center;border-radius:6px;font-size:11px;cursor:pointer;border:1px solid ' + (isActive ? 'var(--accent)' : 'var(--bd)') + ';color:' + (isActive ? 'var(--accent)' : 'var(--tx)') + ';background:' + (isActive ? 'rgba(249,115,22,0.06)' : 'var(--bg)') + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap;transition:all .15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;' + (isActive ? 'var(--accent)' : 'var(--bd)') + '&quot;">' + esc(prov.province.replace(/\u7701$/, '').replace(/\u81EA\u6CBB\u533A$/, '').replace(/\u7279\u522B\u884C\u653F\u533A$/, '').replace(/\u5E02$/, '')) + '</div>';
      });
      ch += '</div>';
    } else if (!_csCity) {
      var prov = chinaCities.find(function(p) { return p.province === _csProvince; });
      ch += '<div style="margin-bottom:8px;display:flex;align-items:center;gap:6px;">' +
        '<div onclick="csBack(&quot;province&quot;)" style="cursor:pointer;display:flex;align-items:center;gap:4px;font-size:11px;color:var(--accent);font-weight:600;"><svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2"><polyline points="15 18 9 12 15 6"/></svg>\u8FD4\u56DE</div>' +
        '<span style="font-size:12px;font-weight:600;color:var(--tx);">' + esc(_csProvince) + '</span>' +
        '<div onclick="selectRegion(&quot;' + esc(_csProvince) + '&quot;)" style="margin-left:auto;font-size:10px;color:var(--accent);cursor:pointer;padding:2px 8px;border:1px solid var(--accent);border-radius:4px;">\u7B5B\u9009\u8BE5\u7701</div></div>';
      if (prov) {
        var cityList = prov.citys || [];
        if (q) cityList = cityList.filter(function(ct) { return ct.city.toLowerCase().indexOf(q) >= 0 || ct.areas.some(function(a) { return a.area.toLowerCase().indexOf(q) >= 0; }); });
        ch += '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:4px;max-height:280px;overflow-y:auto;">';
        cityList.forEach(function(ct) {
          ch += '<div onclick="csSelectCity2(&quot;' + esc(ct.city) + '&quot;)" style="padding:7px 4px;text-align:center;border-radius:6px;font-size:11px;cursor:pointer;border:1px solid var(--bd);color:var(--tx);background:var(--bg);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;transition:all .15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">' + esc(ct.city.replace(/\u5E02$/, '')) + '</div>';
        });
        ch += '</div>';
      }
    } else {
      var prov2 = chinaCities.find(function(p) { return p.province === _csProvince; });
      var city2 = prov2 ? prov2.citys.find(function(ct) { return ct.city === _csCity; }) : null;
      ch += '<div style="margin-bottom:8px;display:flex;align-items:center;gap:6px;flex-wrap:wrap;">' +
        '<div onclick="csBack(&quot;province&quot;)" style="cursor:pointer;font-size:11px;color:var(--accent);font-weight:500;">' + esc(_csProvince.replace(/\u7701$/, '').replace(/\u81EA\u6CBB\u533A$/, '').replace(/\u5E02$/, '')) + '</div>' +
        '<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="var(--tx3)" stroke-width="2"><polyline points="9 6 15 12 9 18"/></svg>' +
        '<div onclick="csBack(&quot;city&quot;)" style="cursor:pointer;font-size:11px;color:var(--accent);font-weight:500;">' + esc(_csCity.replace(/\u5E02$/, '')) + '</div>' +
        '<div onclick="selectRegion(&quot;' + esc(_csProvince + _csCity) + '&quot;)" style="margin-left:auto;font-size:10px;color:var(--accent);cursor:pointer;padding:2px 8px;border:1px solid var(--accent);border-radius:4px;">\u7B5B\u9009\u8BE5\u5E02</div></div>';
      if (city2) {
        var areas = city2.areas || [];
        if (q) areas = areas.filter(function(a) { return a.area.toLowerCase().indexOf(q) >= 0; });
        ch += '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:4px;max-height:280px;overflow-y:auto;">';
        areas.forEach(function(a) {
          ch += '<div onclick="selectRegion(&quot;' + esc(_csProvince + _csCity + a.area) + '&quot;)" style="padding:7px 4px;text-align:center;border-radius:6px;font-size:11px;cursor:pointer;border:1px solid var(--bd);color:var(--tx);background:var(--bg);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;transition:all .15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">' + esc(a.area) + '</div>';
        });
        ch += '</div>';
      }
    }
  }

  content.innerHTML = ch;
}

function switchCsTab(tab) { _csTab = tab; _csProvince = ''; _csCity = ''; renderCityDropdown(''); }
function onCsSearch(val) { renderCityDropdown(val, true); }
function csSelectProvince(prov) { _csProvince = prov; _csCity = ''; renderCityDropdown('', true); }
function csSelectCity2(city) { _csCity = city; renderCityDropdown('', true); }
function csBack(level) {
  if (level === 'province') { _csProvince = ''; _csCity = ''; }
  else if (level === 'city') { _csCity = ''; }
  renderCityDropdown('', true);
}

function clearCityFilter() {
  state.selectedCityId = '';
  state._selectedRegion = '';
  _csProvince = ''; _csCity = '';
  localStorage.setItem(_storagePrefix + 'selectedCity', '');
  localStorage.setItem(_storagePrefix + 'selectedRegion', '');
  updateCitySelectorName();
  var dd = document.getElementById('city-dropdown');
  if (dd && dd.parentNode) dd.parentNode.removeChild(dd);
  toast('\u5DF2\u6E05\u9664\u7B5B\u9009', 'info');
  if (_mapInstance) {
    try { _mapInstance.setZoomAndCenter(5, [104.07, 30.67]); } catch(e) {}
  }
  var route = getRoute();
  if (route.page === 'dashboard') loadDashboard();
  else if (route.page === 'companies') loadCompanies();
  else if (route.page === 'cities') loadCities();
  else loadDashboard();
}

function zoomMapToRegion(regionName) {
  if (!_mapInstance) return;
  var parts = regionName.replace(/\u7701|\u81EA\u6CBB\u533A|\u7279\u522B\u884C\u653F\u533A/g, '').length;
  var isProvince = regionName.match(/\u7701$|\u81EA\u6CBB\u533A$|\u7279\u522B\u884C\u653F\u533A$/);
  var hasDistrict = regionName.replace(/^.*?\u5E02/, '').length > 0 && !isProvince;

  api('/geocode?address=' + encodeURIComponent(regionName), { silent: true }).then(function(data) {
    if (data.longitude && data.latitude) {
      var zoom = 8;
      if (isProvince) zoom = 7;
      else if (hasDistrict) zoom = 12;
      else zoom = 10;
      _mapInstance.setZoomAndCenter(zoom, [data.longitude, data.latitude]);
    }
  }).catch(function() {});
}

function selectRegion(regionStr) {
  state.selectedCityId = '';
  state._selectedRegion = regionStr;
  localStorage.setItem(_storagePrefix + 'selectedCity', '');
  localStorage.setItem(_storagePrefix + 'selectedRegion', regionStr);
  updateCitySelectorName();
  var dd = document.getElementById('city-dropdown');
  if (dd && dd.parentNode) dd.parentNode.removeChild(dd);
  toast('\u5DF2\u7B5B\u9009\uFF1A' + regionStr, 'info');
  zoomMapToRegion(regionStr);
  var route = getRoute();
  if (route.page === 'dashboard') loadDashboard();
  else if (route.page === 'companies') loadCompanies();
  else if (route.page === 'cities') loadCities();
  else loadDashboard();
}

function selectCity(cityId) {
  state.selectedCityId = cityId;
  state._selectedRegion = '';
  localStorage.setItem(_storagePrefix + 'selectedCity', cityId);
  localStorage.setItem(_storagePrefix + 'selectedRegion', '');
  updateCitySelectorName();
  var dd = document.getElementById('city-dropdown');
  if (dd && dd.parentNode) dd.parentNode.removeChild(dd);

  var cityName = '\u5168\u90E8\u57CE\u5E02';
  if (cityId) {
    var c = (state.cities || []).find(function(x) { return x.id === cityId; });
    if (c) {
      cityName = c.name;
      if (c.lat && c.lng && _mapInstance) {
        try { _mapInstance.setZoomAndCenter(14, [c.lng, c.lat]); } catch(e) {}
      }
    }
  } else {
    if (_mapInstance) {
      try { _mapInstance.setZoomAndCenter(5, [104.07, 30.67]); } catch(e) {}
    }
  }
  toast('\u5DF2\u5207\u6362\u5230\uFF1A' + cityName, 'info');

  var route = getRoute();
  if (route.page === 'dashboard') loadDashboard();
  else if (route.page === 'companies') loadCompanies();
  else if (route.page === 'cities') loadCities();
  else loadDashboard();
}

// ─── 仪表盘 ──────────────────────────────────────────────────────────

async function loadDashboard() {
  var cityParam = state.selectedCityId ? '?city_id=' + encodeURIComponent(state.selectedCityId) : '';
  var data = await api('/dashboard' + cityParam);
  state.dashboard = data; state.companies = data.companies || [];
  var mc = document.getElementById('mc');
  if (!mc) return;
  var s = data.summary;
  var h = '<div class="page-inner"><div class="page-header"><h1>\u4EEA\u8868\u76D8</h1><p>\u5E73\u53F0\u6574\u4F53\u8FD0\u8425\u6570\u636E\u6982\u89C8</p></div>';

  // AI config banner
  if (!data.aiConfigured) {
    h += '<div onclick="navigate(window.LOCAL_MODE ? &quot;model-config&quot; : &quot;plan&quot;)" style="margin-bottom:20px;padding:20px 24px;border-radius:12px;background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.2);cursor:pointer;transition:all .2s;">';
    h += '<div style="display:flex;align-items:flex-start;gap:16px;">';
    h += '<div style="width:48px;height:48px;background:linear-gradient(135deg,#F97316,#EA580C);border-radius:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:24px;">🔑</div>';
    h += '<div style="flex:1;"><div style="font-size:16px;font-weight:700;color:var(--tx);margin-bottom:6px;">\u5F00\u59CB\u4F7F\u7528\uFF1A\u914D\u7F6E AI \u6A21\u578B</div>';
    h += '<div style="font-size:13px;color:var(--tx2);line-height:1.5;margin-bottom:12px;">\u60A8\u9700\u8981\u914D\u7F6E AI \u63D0\u4F9B\u5546\u7684 API Key \u624D\u80FD\u4F7F\u7528\u667A\u80FD\u529F\u80FD\u3002\u63A8\u8350\u4F7F\u7528\u300C\u901A\u4E49\u5343\u95EE Coding Plan\u300D\uFF0C\u514D\u8D39\u5373\u53EF\u4F53\u9A8C\u3002</div>';
    h += '<div style="display:inline-flex;align-items:center;gap:6px;background:#F97316;color:#fff;padding:8px 18px;border-radius:8px;font-size:13px;font-weight:600;">\u524D\u5F80\u6A21\u578B\u914D\u7F6E \u2192</div>';
    h += '</div></div></div>';
  }

  // 3-step onboarding guide (show when no companies yet)
  if (data.companies.length === 0) {
    h += '<div style="margin-bottom:24px;padding:24px;border-radius:12px;background:var(--bg-soft);border:1px solid var(--bd);">';
    h += '<div style="font-size:15px;font-weight:700;margin-bottom:10px;display:flex;align-items:center;gap:8px;">🚀 从建公司到拿第一单</div>';
    h += '<div style="font-size:13px;color:var(--tx2);line-height:1.8;margin-bottom:16px;">星环 OPC 不该只是让你建一个公司壳子，而是要带你从“想做什么”走到“第一单怎么落地”。如果你准备真实注册公司，AI 也会给你线下办理清单。</div>';
    h += '<div class="onboard-steps" style="display:flex;gap:12px;flex-wrap:wrap;">';
    h += '<div style="flex:1;min-width:180px;padding:16px;border-radius:10px;background:rgba(22,163,74,0.06);border:1px solid rgba(22,163,74,0.15);">';
    h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;"><span style="width:28px;height:28px;border-radius:50%;background:#16a34a;color:#fff;display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0;">\u2713</span>';
    h += '<span style="font-size:13px;font-weight:600;color:#16a34a;">\u7B2C 1 \u6B65\uFF1A\u6CE8\u518C\u8D26\u53F7</span></div>';
    h += '<div style="font-size:12px;color:var(--tx3);margin-left:38px;">\u5DF2\u5B8C\u6210</div></div>';
    h += '<div style="flex:1;min-width:180px;padding:16px;border-radius:10px;background:rgba(249,115,22,0.08);border:2px solid rgba(249,115,22,0.4);">';
    h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;"><span style="width:28px;height:28px;border-radius:50%;background:#F97316;color:#fff;display:flex;align-items:center;justify-content:center;font-size:13px;flex-shrink:0;font-weight:700;">2</span>';
    h += '<span style="font-size:13px;font-weight:600;color:#F97316;">\u7B2C 2 \u6B65\uFF1A\u5148\u5B9A\u65B9\u5411</span></div>';
    h += '<button class="btn btn-primary btn-sm" style="margin-left:38px;" onclick="openChatWithPrompt(&quot;我还没创建公司。请先像创业顾问一样，帮我判断适合做什么业务，并给我一个起步方案。&quot;)">\u8BA9 AI \u5E2E\u6211\u8D77\u76D8 \u2192</button>';
    h += '</div>';
    h += '<div style="flex:1;min-width:180px;padding:16px;border-radius:10px;background:var(--bg);border:1px solid var(--bd);">';
    h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;"><span style="width:28px;height:28px;border-radius:50%;background:var(--bd);color:var(--tx3);display:flex;align-items:center;justify-content:center;font-size:13px;flex-shrink:0;font-weight:700;">3</span>';
    h += '<span style="font-size:13px;font-weight:600;color:var(--tx2);">\u7B2C 3 \u6B65\uFF1A\u518D\u51B3\u5B9A\u662F\u5426\u5EFA\u516C\u53F8</span></div>';
    h += '<div style="font-size:12px;color:var(--tx3);margin-left:38px;">\u5148\u6A21\u62DF\u8FD0\u8425\uFF0C\u6216\u8005\u8D70\u771F\u5B9E\u6CE8\u518C\u6D41\u7A0B</div></div>';
    h += '</div>';
    h += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin-top:16px;">';
    h += '<div class="card" style="padding:16px;background:linear-gradient(180deg,rgba(37,99,235,.06),transparent);border:1px solid rgba(37,99,235,.14);box-shadow:none;">';
    h += '<div style="font-size:14px;font-weight:800;color:#2563eb;margin-bottom:8px;">1. 先定业务方向</div>';
    h += '<div style="font-size:12px;color:var(--tx2);line-height:1.8;margin-bottom:12px;">不知道开什么公司没关系，先让 AI 帮你定：卖什么、卖给谁、第一阶段提供什么服务。</div>';
    h += '<button class="btn btn-sm" onclick="openChatWithPrompt(&quot;我还没创建公司。请像创业顾问一样，先帮我判断适合做什么业务，并给我一个从 0 开始的起步方案。&quot;)" style="width:100%;">让 AI 帮我定方向</button>';
    h += '</div>';
    h += '<div class="card" style="padding:16px;background:linear-gradient(180deg,rgba(249,115,22,.08),transparent);border:1px solid rgba(249,115,22,.16);box-shadow:none;">';
    h += '<div style="font-size:14px;font-weight:800;color:var(--accent);margin-bottom:8px;">2. 真实注册怎么跑</div>';
    h += '<div style="font-size:12px;color:var(--tx2);line-height:1.8;margin-bottom:12px;">如果你准备线下真实注册公司，不只是点创建，还需要名称、地址、股东、开户、税务这些实操清单。</div>';
    h += '<button class="btn btn-sm" onclick="openChatWithPrompt(&quot;我准备真实注册公司。请根据中国线下办理流程，给我一份详细的注册清单、办理顺序、准备材料、常见坑，以及我现在该先做什么。&quot;)" style="width:100%;">获取线下办理清单</button>';
    h += '</div>';
    h += '<div class="card" style="padding:16px;background:linear-gradient(180deg,rgba(22,163,74,.08),transparent);border:1px solid rgba(22,163,74,.16);box-shadow:none;">';
    h += '<div style="font-size:14px;font-weight:800;color:#16a34a;margin-bottom:8px;">3. 第一单怎么落地</div>';
    h += '<div style="font-size:12px;color:var(--tx2);line-height:1.8;margin-bottom:12px;">真正难的是开张。让 AI 帮你拆第一单：目标客户、报价方式、获客动作、第一周执行清单。</div>';
    h += '<button class="btn btn-sm" onclick="openChatWithPrompt(&quot;请把我当成刚起步的一人公司老板，帮我设计第一单业务落地方案。我要知道卖什么、卖给谁、怎么报价、怎么找客户、第一周每天做什么。&quot;)" style="width:100%;">生成第一单行动方案</button>';
    h += '</div>';
    h += '</div></div>';
  }

  // Alert banners
  if (data.alerts && data.alerts.length) {
    data.alerts.slice(0, 3).forEach(function(a) {
      var sev = a.severity || 'info';
      var bgc = sev === 'critical' ? 'rgba(239,68,68,0.08)' : sev === 'warning' ? 'rgba(217,119,6,0.08)' : 'rgba(249,115,22,0.08)';
      var bdc = sev === 'critical' ? 'rgba(239,68,68,0.2)' : sev === 'warning' ? 'rgba(217,119,6,0.2)' : 'rgba(249,115,22,0.2)';
      var txc = sev === 'critical' ? '#ef4444' : sev === 'warning' ? '#f59e0b' : '#F97316';
      h += '<div style="padding:10px 16px;background:' + bgc + ';border:1px solid ' + bdc + ';border-radius:8px;margin-bottom:8px;font-size:12px;color:' + txc + ';">';
      h += '<strong>' + esc(a.company_name || '') + '</strong> ' + esc(a.title || '') + ': ' + esc(a.message || '') + '</div>';
    });
  }

  // Stat cards with trend arrows
  h += '<div class="stats-grid">';
  function trendArrow(cur, prev) { if (!prev || prev === 0) return ''; var pct = ((cur - prev) / prev * 100).toFixed(1); if (cur > prev) return ' <span style="color:#16a34a;font-size:11px;">\u2191' + pct + '%</span>'; if (cur < prev) return ' <span style="color:#dc2626;font-size:11px;">\u2193' + Math.abs(parseFloat(pct)).toFixed(1) + '%</span>'; return ''; }
  h += statCard('\u516C\u53F8\u603B\u6570', s.company_count, '\u5BB6');
  h += statCard('\u8FD0\u8425\u4E2D', s.active_companies, '\u5BB6');
  h += statCardEx('\u603B\u6536\u5165', formatMoney(s.total_income), '\u5143', trendArrow(data.mom.curIncome, data.mom.prevIncome));
  h += statCardEx('\u603B\u652F\u51FA', formatMoney(s.total_expense), '\u5143', trendArrow(data.mom.curExpense, data.mom.prevExpense));
  h += statCard('\u4EA4\u6613\u7B14\u6570', s.total_transactions || 0, '\u7B14');
  h += statCard('\u5BA2\u6237\u6570', s.total_contacts, '\u4EBA');
  h += '</div>';

  // Charts row
  h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px;">';
  // Bar chart - Monthly trends
  h += '<div class="card"><h3 style="font-size:15px;font-weight:600;margin-bottom:12px;">\u6536\u652F\u8D8B\u52BF\uFF08\u8FD1 6 \u4E2A\u6708\uFF09</h3>';
  if (data.trends && data.trends.length) {
    var maxT = 1; data.trends.forEach(function(t) { maxT = Math.max(maxT, t.income, t.expense); });
    h += '<div style="display:flex;align-items:flex-end;gap:8px;height:180px;padding-bottom:24px;position:relative;">';
    data.trends.forEach(function(t) {
      var hI = Math.max(4, t.income / maxT * 150);
      var hE = Math.max(4, t.expense / maxT * 150);
      h += '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px;">';
      h += '<div style="display:flex;gap:3px;align-items:flex-end;height:150px;">';
      h += '<div style="width:12px;height:' + hI + 'px;background:linear-gradient(180deg,var(--accent),rgba(249,115,22,0.4));border-radius:4px 4px 0 0;" title="\u6536\u5165: ' + formatMoney(t.income) + '"></div>';
      h += '<div style="width:12px;height:' + hE + 'px;background:linear-gradient(180deg,rgba(120,113,108,0.7),rgba(120,113,108,0.25));border-radius:4px 4px 0 0;" title="\u652F\u51FA: ' + formatMoney(t.expense) + '"></div>';
      h += '</div>';
      h += '<span style="font-size:10px;color:var(--tx3);margin-top:4px;">' + esc(t.month) + '</span></div>';
    });
    h += '</div>';
    h += '<div style="display:flex;gap:16px;font-size:11px;color:var(--tx3);"><span><span style="display:inline-block;width:8px;height:8px;background:var(--accent);border-radius:2px;margin-right:4px;"></span>\u6536\u5165</span><span><span style="display:inline-block;width:8px;height:8px;background:rgba(120,113,108,0.6);border-radius:2px;margin-right:4px;"></span>\u652F\u51FA</span></div>';
  } else { h += '<div style="text-align:center;padding:40px;color:var(--tx3);font-size:13px;">\u6682\u65E0\u6570\u636E</div>'; }
  h += '</div>';
  // Donut chart - expense by category
  h += '<div class="card"><h3 style="font-size:15px;font-weight:600;margin-bottom:12px;">\u652F\u51FA\u5206\u7C7B</h3>';
  if (data.expenseByCategory && data.expenseByCategory.length) {
    var totalExp = 0; data.expenseByCategory.forEach(function(e) { totalExp += e.total; });
    var dColors = ['#f97316','#fb923c','#fdba74','#7c3aed','#a78bfa','#34d399'];
    h += '<div style="text-align:center;margin-bottom:12px;"><span style="font-size:24px;font-weight:700;">' + formatMoney(totalExp) + '</span><br/><span style="font-size:11px;color:var(--tx3);">\u603B\u652F\u51FA (\u5143)</span></div>';
    h += '<div style="display:flex;flex-direction:column;gap:6px;">';
    data.expenseByCategory.slice(0, 6).forEach(function(e, i) {
      var pct = totalExp > 0 ? (e.total / totalExp * 100).toFixed(1) : '0';
      h += '<div style="display:flex;align-items:center;gap:8px;font-size:12px;">';
      h += '<span style="width:8px;height:8px;border-radius:2px;background:' + dColors[i % dColors.length] + ';flex-shrink:0;"></span>';
      h += '<span style="flex:1;color:var(--tx2);">' + esc(e.category || '\u672A\u5206\u7C7B') + '</span>';
      h += '<span style="font-weight:600;">' + formatMoney(e.total) + '</span>';
      h += '<span style="color:var(--tx3);width:40px;text-align:right;">' + pct + '%</span></div>';
    });
    h += '</div>';
  } else { h += '<div style="text-align:center;padding:40px;color:var(--tx3);font-size:13px;">\u6682\u65E0\u6570\u636E</div>'; }
  h += '</div></div>';

  // Recent transactions table
  h += '<div class="card" style="margin-bottom:16px;"><h3 style="font-size:15px;font-weight:600;margin-bottom:12px;">\u8FD1\u671F\u4EA4\u6613</h3>';
  if (data.recentTransactions && data.recentTransactions.length) {
    h += '<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;font-size:12px;"><thead><tr style="border-bottom:1px solid var(--bd);">';
    h += '<th style="text-align:left;padding:8px;color:var(--tx3);font-weight:600;">\u516C\u53F8</th>';
    h += '<th style="text-align:left;padding:8px;color:var(--tx3);font-weight:600;">\u7C7B\u578B</th>';
    h += '<th style="text-align:left;padding:8px;color:var(--tx3);font-weight:600;">\u5206\u7C7B</th>';
    h += '<th style="text-align:right;padding:8px;color:var(--tx3);font-weight:600;">\u91D1\u989D</th>';
    h += '<th style="text-align:left;padding:8px;color:var(--tx3);font-weight:600;">\u5BF9\u65B9</th>';
    h += '<th style="text-align:left;padding:8px;color:var(--tx3);font-weight:600;">\u65E5\u671F</th>';
    h += '</tr></thead><tbody>';
    data.recentTransactions.forEach(function(tx) {
      var isIncome = tx.type === 'income';
      h += '<tr style="border-bottom:1px solid var(--bg);">';
      h += '<td style="padding:8px;">' + esc(tx.company_name || '') + '</td>';
      h += '<td style="padding:8px;"><span style="padding:2px 8px;border-radius:4px;font-size:11px;' + (isIncome ? 'background:#dcfce7;color:#16a34a;' : 'background:#fee2e2;color:#dc2626;') + '">' + (isIncome ? '\u6536\u5165' : '\u652F\u51FA') + '</span></td>';
      h += '<td style="padding:8px;color:var(--tx2);">' + esc(tx.category || '') + '</td>';
      h += '<td style="padding:8px;text-align:right;font-weight:600;">' + (isIncome ? '+' : '-') + formatMoney(tx.amount) + '</td>';
      h += '<td style="padding:8px;color:var(--tx2);">' + esc(tx.counterparty || '') + '</td>';
      h += '<td style="padding:8px;color:var(--tx3);">' + esc((tx.transaction_date || '').toString().slice(0,10)) + '</td>';
      h += '</tr>';
    });
    h += '</tbody></table></div>';
  } else { h += '<div style="text-align:center;padding:40px;color:var(--tx3);font-size:13px;">\u6682\u65E0\u4EA4\u6613\u8BB0\u5F55</div>'; }
  h += '</div>';

  // My companies
  h += '<div class="card" style="flex:1;"><h3 style="font-size:15px;font-weight:600;margin-bottom:16px;display:flex;align-items:center;justify-content:space-between;">\u6211\u7684\u516C\u53F8 <button class="btn btn-primary btn-sm" onclick="showCreateCompanyModal()">+ \u65B0\u5EFA\u7ECF\u8425\u76D8</button></h3>';
  if (data.companies.length === 0) {
    h += '<div class="empty-state"><h3>\u4ECE\u60F3\u6CD5\u5230\u7B2C\u4E00\u5355</h3><p>\u5148\u8BA9 AI \u5E2E\u4F60\u5B9A\u65B9\u5411\uff0c\u518D\u65B0\u5EFA\u6A21\u62DF\u8FD0\u8425\u76D8\u6216\u771F\u5B9E\u6CE8\u518C\u516C\u53F8\uff0c\u628A\u83B7\u5BA2\u3001\u6210\u4EA4\u3001\u4EA4\u4ED8\u3001\u56DE\u6B3E\u4E32\u8D77\u6765\u3002</p><div style="display:flex;gap:8px;justify-content:center;flex-wrap:wrap;"><button class="btn" onclick="openChatWithPrompt(&quot;我还没创建公司。请先像创业顾问一样，帮我判断适合做什么业务，并给我一个起步方案。&quot;)">\u5148\u5B9A\u65B9\u5411</button><button class="btn btn-primary" onclick="showCreateCompanyModal()">+ \u65B0\u5EFA\u7ECF\u8425\u76D8</button></div></div>';
  } else {
    h += '<div class="companies-grid">';
    data.companies.forEach(function(c) {
      h += '<div class="company-card" onclick="navigate(&quot;company/' + c.id + '&quot;)">';
      h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:4px;"><h4>' + esc(c.name) + '</h4><span class="company-status status-' + c.status + '">' + statusText(c.status) + '</span></div>';
      h += '<div style="color:var(--tx3);font-size:12px;">' + (esc(c.industry) || '\u672A\u8BBE\u7F6E\u884C\u4E1A') + (c.owner_name ? ' \u00B7 ' + esc(c.owner_name) : '') + '</div>';
      h += '</div>';
    });
    h += '</div>';
  }
  h += '</div>';  // card
  h += '</div>';  // page-inner

  mc.innerHTML = h;
}

async function loadCheckinCard() {
  var body = document.getElementById('checkin-body');
  if (!body) return;
  try {
    var data = await api('/checkin');
    renderCheckinCard(body, data);
  } catch(e) {
    body.innerHTML = '<div style="color:var(--tx3);font-size:13px;padding:10px;">\u7B7E\u5230\u52A0\u8F7D\u5931\u8D25</div>';
  }
}

function renderCheckinCard(container, data) {
  var checked = data.checked_today;
  var streak = data.current_streak || 0;
  var dates = data.checkin_dates || [];
  var totalCheckins = data.total_checkins || 0;
  var nextBonus = data.streak_days - (streak % data.streak_days);
  if (checked) nextBonus = data.streak_days - ((streak) % data.streak_days);
  if (nextBonus === data.streak_days && streak > 0 && streak % data.streak_days === 0 && checked) nextBonus = data.streak_days;

  var datesSet = {};
  dates.forEach(function(d) { datesSet[d] = true; });

  var today = new Date();
  var todayStr = today.getFullYear() + '-' + String(today.getMonth()+1).padStart(2,'0') + '-' + String(today.getDate()).padStart(2,'0');
  var dow = today.getDay();
  var mondayOffset = dow === 0 ? -6 : 1 - dow;
  var monday = new Date(today.getFullYear(), today.getMonth(), today.getDate() + mondayOffset);
  var weekDays = [];
  var dayLabels = ['\u4E00','\u4E8C','\u4E09','\u56DB','\u4E94','\u516D','\u65E5'];
  for (var i = 0; i < 7; i++) {
    var d = new Date(monday.getFullYear(), monday.getMonth(), monday.getDate() + i);
    var ds = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
    weekDays.push({ date: ds, day: d.getDate(), weekDay: dayLabels[i], checked: !!datesSet[ds], isToday: ds === todayStr });
  }

  var h = '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;">' +
    '<div style="display:flex;align-items:center;gap:10px;">' +
    '<div style="font-size:28px;">🔥</div>' +
    '<div style="text-align:left;">' +
    '<div style="font-size:16px;font-weight:700;">\u6BCF\u65E5\u7B7E\u5230</div>' +
    '<div style="font-size:12px;color:var(--tx3);">\u6BCF\u5929\u7B7E\u5230\u9001 ' + data.daily_reward + ' \u7B97\u529B\uFF0C\u8FDE\u7EED' + data.streak_days + '\u5929\u989D\u5916\u9001 ' + data.streak_bonus + '</div>' +
    '</div></div>' +
    '<div style="display:flex;align-items:center;gap:16px;">' +
    '<div style="text-align:center;"><div style="font-size:22px;font-weight:800;color:#F97316;">' + streak + '</div><div style="font-size:11px;color:var(--tx3);">\u8FDE\u7EED\u5929\u6570</div></div>' +
    '<div style="text-align:center;"><div style="font-size:22px;font-weight:800;color:#8b5cf6;">' + totalCheckins + '</div><div style="font-size:11px;color:var(--tx3);">\u7D2F\u8BA1\u7B7E\u5230</div></div>' +
    '</div></div>';

  // 7天日历
  h += '<div style="display:flex;gap:8px;justify-content:center;margin-bottom:16px;">';
  weekDays.forEach(function(w) {
    var bg = w.checked ? 'linear-gradient(135deg,#F97316,#EA580C)' : 'var(--bg-soft)';
    var color = w.checked ? '#fff' : 'var(--tx3)';
    var border = w.isToday && !w.checked ? '2px solid #F97316' : w.checked ? 'none' : '1px solid var(--bd)';
    h += '<div style="flex:1;text-align:center;padding:10px 4px;border-radius:10px;background:' + bg + ';color:' + color + ';border:' + border + ';min-width:0;">' +
      '<div style="font-size:10px;opacity:.7;">\u5468' + w.weekDay + '</div>' +
      '<div style="font-size:16px;font-weight:700;margin:4px 0;">' + w.day + '</div>' +
      (w.checked ? '<div style="font-size:10px;">✓</div>' : '<div style="font-size:10px;opacity:.4;">·</div>') +
      '</div>';
  });
  h += '</div>';

  // 进度条（连续天数进度）
  var progressPct = Math.round((streak % data.streak_days) / data.streak_days * 100);
  if (streak > 0 && streak % data.streak_days === 0 && checked) progressPct = 100;
  h += '<div style="margin-bottom:14px;">' +
    '<div style="display:flex;justify-content:space-between;font-size:11px;color:var(--tx3);margin-bottom:4px;">' +
    '<span>\u8FDE\u7EED\u7B7E\u5230\u8FDB\u5EA6</span><span>' + (streak % data.streak_days) + ' / ' + data.streak_days + ' \u5929</span></div>' +
    '<div style="height:6px;background:var(--bd);border-radius:3px;overflow:hidden;">' +
    '<div style="height:100%;background:linear-gradient(90deg,#F97316,#EA580C);border-radius:3px;width:' + progressPct + '%;transition:width .3s;"></div></div>' +
    (nextBonus <= data.streak_days && nextBonus > 0 && !checked ? '<div style="font-size:11px;color:#d97706;margin-top:4px;">\u518D\u7B7E ' + nextBonus + ' \u5929\u53EF\u83B7\u5F97\u989D\u5916 ' + data.streak_bonus + ' \u7B97\u529B\u5956\u52B1 🎁</div>' : '') +
    '</div>';

  // 签到按钮
  if (checked) {
    h += '<button class="btn" disabled style="width:100%;opacity:.6;cursor:not-allowed;padding:12px;font-size:14px;font-weight:600;">\u2705 \u4ECA\u65E5\u5DF2\u7B7E\u5230\uFF0C\u660E\u5929\u518D\u6765</button>';
  } else {
    h += '<button class="btn btn-primary" onclick="doCheckin()" id="checkin-btn" style="width:100%;padding:12px;font-size:14px;font-weight:600;background:linear-gradient(135deg,#F97316,#EA580C);border:none;border-radius:10px;">\uD83D\uDD25 \u7ACB\u5373\u7B7E\u5230\uFF0C\u9886\u53D6 ' + data.daily_reward + ' \u7B97\u529B</button>';
  }

  container.innerHTML = h;
}

async function doCheckin() {
  var btn = document.getElementById('checkin-btn');
  if (btn) { btn.disabled = true; btn.innerHTML = '\u7B7E\u5230\u4E2D...'; }
  try {
    var result = await api('/checkin', { method: 'POST' });
    toast(result.message || '\u7B7E\u5230\u6210\u529F\uFF01', 'success', 4000);
    loadCheckinCard();
    loadSidebarQuota();
  } catch(e) {
    toast(e.message || '\u7B7E\u5230\u5931\u8D25', 'error');
    if (btn) { btn.disabled = false; btn.innerHTML = '\uD83D\uDD25 \u7ACB\u5373\u7B7E\u5230'; }
  }
}

function statCard(label, value, unit) {
  return '<div class="stat-card">' +
    '<div class="stat-label">' + label + '</div>' +
    '<div class="stat-value">' + value + '<small class="stat-unit">' + unit + '</small></div>' +
  '</div>';
}

function statCardEx(label, value, unit, trend) {
  return '<div class="stat-card">' +
    '<div class="stat-label">' + label + '</div>' +
    '<div class="stat-value">' + value + '<small class="stat-unit">' + unit + '</small></div>' +
    (trend ? '<div class="stat-trend">' + trend + ' 较上月</div>' : '') +
  '</div>';
}

// ─── 公司管理 ──────────────────────────────────────────────────────

var _companyFilter = { search: '', status: '', page: 1 };

async function loadCompanies() {
  var cityParam = state.selectedCityId ? '?city_id=' + encodeURIComponent(state.selectedCityId) : '';
  var data = await api('/dashboard' + cityParam);
  state.companies = data.companies || [];
  var mc = document.getElementById('mc');
  if (!mc) return;
  renderCompaniesPage();
}

function renderCompaniesPage() {
  var mc = document.getElementById('mc');
  if (!mc) return;
  var all = state.companies || [];
  var filtered = all;
  if (_companyFilter.search) {
    var q = _companyFilter.search.toLowerCase();
    filtered = filtered.filter(function(c) { return (c.name||'').toLowerCase().indexOf(q) >= 0 || (c.industry||'').toLowerCase().indexOf(q) >= 0 || (c.owner_name||'').toLowerCase().indexOf(q) >= 0; });
  }
  if (_companyFilter.status) {
    if (_companyFilter.status === 'other') {
      filtered = filtered.filter(function(c) { return c.status !== 'active' && c.status !== 'pending'; });
    } else {
      filtered = filtered.filter(function(c) { return c.status === _companyFilter.status; });
    }
  }

  var statusCounts = { all: all.length, active: 0, pending: 0, other: 0 };
  all.forEach(function(c) { if (c.status === 'active') statusCounts.active++; else if (c.status === 'pending') statusCounts.pending++; else statusCounts.other++; });

  var pageSize = 10;
  var totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  if (_companyFilter.page > totalPages) _companyFilter.page = totalPages;
  var start = (_companyFilter.page - 1) * pageSize;
  var pageItems = filtered.slice(start, start + pageSize);

  var h = '<div class="page-inner">';
  h += '<div class="page-header" style="display:flex;justify-content:space-between;align-items:flex-start;"><div><h1>\u516C\u53F8\u7BA1\u7406</h1><p>\u7BA1\u7406\u4F60\u7684\u6A21\u62DF\u8FD0\u8425\u76D8\u548C\u771F\u5B9E\u6CE8\u518C\u516C\u53F8</p></div>';
  h += '<button class="btn btn-primary" onclick="showCreateCompanyModal()">+ \u65B0\u5EFA\u7ECF\u8425\u76D8</button></div>';

  // Search bar
  h += '<div style="display:flex;gap:8px;margin-bottom:16px;align-items:center;">';
  h += '<input id="company-search" placeholder="\u641C\u7D22\u516C\u53F8\u540D\u79F0\u3001\u884C\u4E1A\u3001\u8D1F\u8D23\u4EBA..." value="' + esc(_companyFilter.search) + '" onkeyup="if(event.key===&quot;Enter&quot;)doCompanySearch()" style="flex:1;padding:8px 12px;border:1px solid var(--bd);border-radius:8px;font-size:13px;background:var(--bg-soft);color:var(--tx);" />';
  h += '<button class="btn" onclick="doCompanySearch()" style="font-size:12px;">\u641C\u7D22</button></div>';

  // Status tabs
  h += '<div style="display:flex;gap:4px;margin-bottom:16px;">';
  var tabs = [{k:'', l:'\u5168\u90E8', c:statusCounts.all}, {k:'active', l:'\u8FD0\u8425\u4E2D', c:statusCounts.active}, {k:'pending', l:'\u5F85\u6CE8\u518C', c:statusCounts.pending}, {k:'other', l:'\u5176\u4ED6', c:statusCounts.other}];
  tabs.forEach(function(t) {
    var isActive = _companyFilter.status === t.k || (!_companyFilter.status && t.k === '');
    h += '<button onclick="filterCompanyStatus(&quot;' + t.k + '&quot;)" style="padding:6px 14px;border-radius:6px;font-size:12px;cursor:pointer;border:1px solid ' + (isActive ? 'var(--accent)' : 'var(--bd)') + ';background:' + (isActive ? 'var(--accent)' : 'transparent') + ';color:' + (isActive ? '#fff' : 'var(--tx2)') + ';">' + t.l + ' (' + t.c + ')</button>';
  });
  h += '</div>';

  // Table
  h += '<div class="card" style="flex:1;display:flex;flex-direction:column;">';
  if (pageItems.length === 0) {
    h += '<div style="flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:60px 20px;color:var(--tx3);"><div style="font-size:48px;margin-bottom:16px;">🏢</div><div style="font-size:16px;font-weight:600;margin-bottom:8px;">\u8FD8\u6CA1\u6709\u7ECF\u8425\u76D8</div><div style="font-size:13px;line-height:1.8;max-width:420px;text-align:center;">\u53EF\u4EE5\u5148\u8BA9 AI \u5E2E\u4F60\u5B9A\u65B9\u5411\uff0c\u518D\u5EFA\u4E00\u4E2A\u300C\u5148\u6A21\u62DF\u8FD0\u8425\u300D\u6216\u300C\u51C6\u5907\u771F\u5B9E\u6CE8\u518C\u300D\u7684\u516C\u53F8\u76D8\u5B50\u3002</div></div>';
  } else {
    h += '<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;font-size:13px;"><thead><tr style="border-bottom:2px solid var(--bd);">';
    h += '<th style="text-align:left;padding:10px 8px;font-weight:600;color:var(--tx3);">\u540D\u79F0</th>';
    h += '<th style="text-align:left;padding:10px 8px;font-weight:600;color:var(--tx3);">\u884C\u4E1A</th>';
    h += '<th style="text-align:left;padding:10px 8px;font-weight:600;color:var(--tx3);">\u8D1F\u8D23\u4EBA</th>';
    h += '<th style="text-align:right;padding:10px 8px;font-weight:600;color:var(--tx3);">\u6CE8\u518C\u8D44\u672C</th>';
    h += '<th style="text-align:center;padding:10px 8px;font-weight:600;color:var(--tx3);">\u72B6\u6001</th>';
    h += '<th style="text-align:left;padding:10px 8px;font-weight:600;color:var(--tx3);">\u521B\u5EFA\u65F6\u95F4</th>';
    h += '<th style="text-align:center;padding:10px 8px;font-weight:600;color:var(--tx3);">\u64CD\u4F5C</th>';
    h += '</tr></thead><tbody>';
    pageItems.forEach(function(c) {
      var companyName = cleanDirtyPlaceholderText(c.name, '未命名公司');
      var companyIndustry = cleanDirtyPlaceholderText(c.industry || '', '');
      var companyOwner = cleanDirtyPlaceholderText(c.owner_name || '', '');
      h += '<tr style="border-bottom:1px solid var(--bg);cursor:pointer;" onmouseover="this.style.background=&quot;var(--bg)&quot;" onmouseout="this.style.background=&quot;&quot;">';
      h += '<td style="padding:10px 8px;"><div style="display:flex;align-items:center;gap:6px;"><strong>' + esc(companyName) + '</strong>';
      if (c.my_role && c.my_role !== 'owner') h += '<span style="display:inline-block;padding:1px 6px;border-radius:5px;font-size:10px;font-weight:600;' + teamRoleColor(c.my_role) + '">' + teamRoleLabel(c.my_role) + '</span>';
      h += '</div></td>';
      h += '<td style="padding:10px 8px;color:var(--tx2);">' + esc(companyIndustry || '-') + '</td>';
      h += '<td style="padding:10px 8px;color:var(--tx2);">' + esc(companyOwner || '-') + '</td>';
      h += '<td style="padding:10px 8px;text-align:right;">' + (c.registered_capital ? formatMoney(c.registered_capital) + ' \u5143' : '-') + '</td>';
      h += '<td style="padding:10px 8px;text-align:center;"><span class="company-status status-' + c.status + '">' + statusText(c.status) + '</span></td>';
      h += '<td style="padding:10px 8px;color:var(--tx3);font-size:12px;">' + esc((c.created_at || '').toString().slice(0,10)) + '</td>';
      h += '<td style="padding:10px 8px;text-align:center;white-space:nowrap;">';
      h += '<button class="btn btn-sm" onclick="event.stopPropagation();navigate(&quot;company/' + c.id + '&quot;)" style="font-size:11px;margin-right:4px;">\u8BE6\u60C5</button>';
      h += '<button class="btn btn-sm" onclick="event.stopPropagation();startChatWithCompany(&quot;' + c.id + '&quot;)" style="font-size:11px;margin-right:4px;">公司管家</button>';
      if (c.my_role === 'owner') h += '<button class="btn btn-sm" onclick="event.stopPropagation();deleteCompany(&quot;' + c.id + '&quot;,&quot;' + esc(companyName) + '&quot;)" style="font-size:11px;color:var(--red);">\u5220\u9664</button>';
      else h += '<button class="btn btn-sm" onclick="event.stopPropagation();leaveCompanyUI(&quot;' + c.id + '&quot;,&quot;' + esc(companyName) + '&quot;)" style="font-size:11px;color:var(--tx3);">退出</button>';
      h += '</td></tr>';
    });
    h += '</tbody></table></div>';
  }

  // Pagination
  if (totalPages > 1) {
    h += '<div style="display:flex;justify-content:center;gap:4px;margin-top:16px;">';
    for (var p = 1; p <= totalPages; p++) {
      h += '<button onclick="goCompanyPage(' + p + ')" style="width:32px;height:32px;border-radius:6px;border:1px solid ' + (_companyFilter.page === p ? 'var(--accent)' : 'var(--bd)') + ';background:' + (_companyFilter.page === p ? 'var(--accent)' : 'transparent') + ';color:' + (_companyFilter.page === p ? '#fff' : 'var(--tx2)') + ';font-size:12px;cursor:pointer;">' + p + '</button>';
    }
    h += '</div>';
  }
  h += '</div>';
  h += '</div>'; // page-inner

  mc.innerHTML = h;
}

function doCompanySearch() {
  _companyFilter.search = (document.getElementById('company-search') || {}).value || '';
  _companyFilter.page = 1;
  renderCompaniesPage();
}

function filterCompanyStatus(status) {
  _companyFilter.status = status;
  _companyFilter.page = 1;
  renderCompaniesPage();
}

function goCompanyPage(p) {
  _companyFilter.page = p;
  renderCompaniesPage();
}

async function deleteCompany(id, name) {
  var ok = await confirmModal({
    title: '\u5220\u9664\u516C\u53F8',
    message: '\u786E\u5B9A\u8981\u5220\u9664\u300C' + name + '\u300D\u5417\uFF1F\u6B64\u64CD\u4F5C\u4E0D\u53EF\u6062\u590D\u3002',
    confirmText: '\u5220\u9664',
    confirmType: 'danger',
  });
  if (!ok) return;
  try {
    await api('/companies/' + id, { method: 'DELETE' });
    toast('\u5DF2\u5220\u9664 ' + name);
    state.companies = state.companies.filter(function(c) { return c.id !== id; });
    renderCompaniesPage();
  } catch(e) { toast(e.message, 'error'); }
}

async function leaveCompanyUI(cid, name) {
  var ok = await modalConfirm('确定退出「' + name + '」？退出后将无法访问该公司数据。');
  if (!ok) return;
  try {
    await fetch('/api/companies/' + cid + '/members/leave', {
      method: 'POST', headers: authH()
    }).then(function(r) { return r.json(); }).then(function(d) {
      if (d.error) throw new Error(d.error);
    });
    toast('已退出 ' + name);
    state.companies = state.companies.filter(function(c) { return c.id !== cid; });
    renderCompaniesPage();
  } catch(e) { toast(e.message || '操作失败', 'error'); }
}

function startChatWithCompany(companyId) {
  state.chatCompanyId = companyId;
  state.chatCompanySnapshot = state.currentCompany && state.currentCompany.id === companyId && state.companyDetail
    ? { company: state.currentCompany, dashboard: state.companyDetail.dashboard, stats: state.companyDetail.stats }
    : null;
  state.currentConvId = '';
  state.messages = [];
  sessionStorage.removeItem('opc-conv-id');
  navigate('chat');
}

// ─── 公司详情 ──────────────────────────────────────────────────────

var _detailTab = 'overview';

async function loadCompanyDetail(id) {
  var data = await api('/companies/' + id);
  state.currentCompany = data.company; state.companyDetail = data;
  if (state.chatCompanyId && state.chatCompanyId === id) {
    state.chatCompanySnapshot = { company: data.company, dashboard: data.dashboard, stats: data.stats };
  }
  _detailTab = 'overview';
  renderCompanyDetailPage();
}

var DETAIL_TABS = [
  {k:'overview', l:'\u6982\u89C8'},
  {k:'finance', l:'\u8D22\u52A1'},
  {k:'contacts', l:'\u5BA2\u6237'},
  {k:'opportunities', l:'\u673A\u4F1A'},
  {k:'delivery', l:'\u4EA4\u4ED8'},
  {k:'team', l:'\u56E2\u961F'},
  {k:'projects', l:'\u9879\u76EE'},
  {k:'contracts', l:'\u5408\u540C'},
  {k:'staff', l:'AI\u5458\u5DE5'},
  {k:'timeline', l:'\u65F6\u95F4\u7EBF'}
];

function renderCompanyDetailPage() {
  var mc = document.getElementById('mc'); if (!mc) return;
  var c = state.currentCompany;
  var companyName = cleanDirtyPlaceholderText(c.name, '未命名公司');
  var companyIndustry = cleanDirtyPlaceholderText(c.industry || '', '');
  var companyOwner = cleanDirtyPlaceholderText(c.owner_name || '', '');

  // Header + Tabs 外壳，content 区域单独渲染
  var h = '<div class="page-inner">';

  // Back + Title
  h += '<div style="margin-bottom:16px;">';
  h += '<button class="btn btn-sm" onclick="navigate(&quot;companies&quot;)" style="margin-bottom:10px;font-size:12px;">← 返回列表</button>';
  h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px;">';
  h += '<div style="min-width:0;flex:1;"><h2 style="margin:0 0 4px;font-size:20px;word-break:break-word;">' + esc(companyName) + ' <span class="company-status status-' + c.status + '" style="font-size:12px;">' + statusText(c.status) + '</span></h2>';
  h += '<div style="color:var(--tx3);font-size:13px;">' + (esc(companyIndustry) || '') + (companyOwner ? ' · ' + esc(companyOwner) : '') + '</div></div>';
  h += '<div style="display:flex;gap:6px;flex-shrink:0;">';
  h += '<button class="btn btn-sm" onclick="editCompanyModal(&quot;' + c.id + '&quot;)" style="font-size:12px;">✎ 编辑</button>';
  h += '<button class="btn btn-primary btn-sm" onclick="startChatWithCompany(&quot;' + c.id + '&quot;)" style="font-size:12px;">公司管家</button>';
  h += '</div></div></div>';

  // Tab bar
  h += renderDetailTabBar();

  // Tab content
  h += '<div id="detail-content" style="flex:1;min-height:0;overflow-y:auto;padding-top:16px;">' + renderDetailTabContent() + '</div>';

  h += '</div>';
  mc.innerHTML = h;
}

function renderDetailTabBar() {
  var h = '<div id="detail-tab-bar" style="display:flex;gap:0;border-bottom:2px solid var(--bd);overflow-x:auto;" class="hide-scrollbar">';
  DETAIL_TABS.forEach(function(t) {
    var isActive = _detailTab === t.k;
    h += '<button onclick="switchDetailTab(&quot;' + t.k + '&quot;)" style="padding:9px 16px;font-size:13px;font-weight:' + (isActive ? '700' : '500') + ';color:' + (isActive ? 'var(--accent)' : 'var(--tx3)') + ';border:none;border-bottom:2px solid ' + (isActive ? 'var(--accent)' : 'transparent') + ';background:none;cursor:pointer;white-space:nowrap;margin-bottom:-2px;transition:all 0.15s;">' + t.l + '</button>';
  });
  h += '</div>';
  return h;
}

function switchDetailTab(tab) {
  _detailTab = tab;
  var tabBarEl = document.getElementById('detail-tab-bar');
  if (tabBarEl) tabBarEl.outerHTML = renderDetailTabBar();
  var el = document.getElementById('detail-content');
  if (el) el.innerHTML = renderDetailTabContent();
}

function renderDetailTabContent() {
  var c = state.currentCompany;
  var st = state.companyDetail.stats;
  if (!st) return renderLoading();

  switch(_detailTab) {
    case 'overview': return renderOverviewTab(c, st);
    case 'finance': return renderFinanceTab(st);
    case 'contacts': return renderContactsTab(st);
    case 'opportunities': return renderOpportunitiesTab(st);
    case 'delivery': return renderDeliveryTab(st);
    case 'team': return renderTeamTab(st);
    case 'projects': return renderProjectsTab(st);
    case 'contracts': return renderContractsTab(st);
    case 'staff': return renderStaffTab(c, st);
    case 'timeline': return renderTimelineTab(st);
    default: return renderOverviewTab(c, st);
  }
}

function companyLifecycleText(type, value) {
  var maps = {
    registration_mode: { virtual: '先模拟运营', real: '准备真实注册', hybrid: '边跑业务边注册' },
    registration_stage: { not_started: '待判断', simulated: '模拟经营', preparing: '准备材料', filing: '办理中', registered: '已拿执照' },
    startup_stage: { idea: '待起盘', setup: '定位/搭班子', offer_ready: '服务包成型', acquiring: '开始获客', delivering: '已在交付' },
    first_order_stage: { not_started: '还没开始', prospecting: '找线索', quoting: '报价沟通', negotiating: '推动成交', won: '已成交' },
  };
  return (maps[type] && maps[type][value]) || value || '-';
}

function renderCompanyLifecyclePanel(c, st) {
  var registrationMode = c.registration_mode || 'virtual';
  var registrationStage = c.registration_stage || (registrationMode === 'virtual' ? 'simulated' : 'preparing');
  if (registrationStage === 'not_started') registrationStage = registrationMode === 'virtual' ? 'simulated' : 'preparing';
  var startupStage = c.startup_stage || 'setup';
  if (startupStage === 'idea') startupStage = 'setup';
  var firstOrderStage = c.first_order_stage || 'not_started';
  var contractCount = Number(st.contract_count) || 0;
  var projectCount = Number(st.project_count) || 0;
  var income = Number(st.total_income) || 0;
  var todos = st.todos || [];
  var pendingTodos = todos.filter(function(t) { return !t.completed; });
  var documents = st.documents || [];
  var collectionStage = income > 0 ? '回款已发生' : (contractCount > 0 ? '待收款设计' : '待签单后规划');
  var nextAction = registrationMode === 'virtual'
    ? '继续把服务包、报价和首批客户名单做出来。'
    : (registrationStage === 'registered' ? '执照已到位，重点把获客和成交动作跑起来。' : '先把线下注册清单跑顺，再并行推进获客。');

  function stageCard(index, title, status, desc, color) {
    return '<div style="flex:1;min-width:180px;padding:14px 15px;border-radius:16px;border:1px solid ' + color + ';background:linear-gradient(180deg,' + color + '14,transparent);">' +
      '<div style="display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:8px;"><div style="font-size:12px;font-weight:800;color:' + color + ';">阶段 ' + index + '</div><span style="font-size:11px;color:var(--tx3);">' + esc(status) + '</span></div>' +
      '<div style="font-size:14px;font-weight:700;color:var(--tx);margin-bottom:6px;">' + esc(title) + '</div>' +
      '<div style="font-size:12px;color:var(--tx2);line-height:1.8;">' + esc(desc) + '</div>' +
      '</div>';
  }

  var h = '<div class="card" style="margin-bottom:16px;padding:18px 18px 16px;background:linear-gradient(135deg,rgba(249,115,22,.08),transparent 45%,transparent);border:1px solid rgba(249,115,22,.14);">';
  h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:14px;">';
  h += '<div><div style="font-size:16px;font-weight:800;color:var(--tx);margin-bottom:6px;">一人公司生命流程</div><div style="font-size:12px;color:var(--tx2);line-height:1.8;max-width:760px;">把“是否注册、怎么起盘、第一单怎么拿、成交后怎么交付回款”串成一个经营闭环。这一块不是展示页，是你的实际经营推进面板。</div></div>';
  h += '<div style="font-size:12px;color:var(--tx3);padding:7px 10px;border-radius:999px;background:rgba(249,115,22,.10);border:1px solid rgba(249,115,22,.14);">当前建议：' + esc(nextAction) + '</div>';
  h += '</div>';
  h += '<div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:14px;">';
  h += stageCard('1', '经营模式', companyLifecycleText('registration_mode', registrationMode), registrationMode === 'virtual' ? '适合先验证市场，先卖服务和拿第一单。' : '适合边做业务边补足线下注册、开户、税务等动作。', '#2563eb');
  h += stageCard('2', '注册推进', companyLifecycleText('registration_stage', registrationStage), registrationMode === 'virtual' ? '当前以模拟经营为主，不强制推进真实注册。' : '把名称、地址、刻章、开户、税务这些线下事项按顺序推进。', '#f97316');
  h += stageCard('3', '起盘进度', companyLifecycleText('startup_stage', startupStage), '先把服务包、目标客户、报价方式、交付范围打磨清楚，再持续获客。', '#8b5cf6');
  h += stageCard('4', '第一单推进', companyLifecycleText('first_order_stage', firstOrderStage), contractCount > 0 ? '已经有合同沉淀，重点转向交付和回款。' : '这是现阶段最关键的一步，要把线索、报价、决策链和成交动作做实。', '#16a34a');
  h += '</div>';
  h += '<div style="display:grid;grid-template-columns:1.2fr 1fr;gap:14px;">';
  h += '<div style="padding:14px;border-radius:16px;background:var(--bg);border:1px solid var(--bd);">';
  h += '<div style="font-size:13px;font-weight:700;color:var(--tx);margin-bottom:10px;">经营状态直接更新</div>';
  h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">';
  h += '<div><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">经营模式</div><select class="input-field" onchange="updateCompanyLifecycle(&quot;' + c.id + '&quot;,&quot;registration_mode&quot;,this.value)" style="font-size:12px;"><option value="virtual"' + (registrationMode === 'virtual' ? ' selected' : '') + '>先模拟运营</option><option value="real"' + (registrationMode === 'real' ? ' selected' : '') + '>准备真实注册</option><option value="hybrid"' + (registrationMode === 'hybrid' ? ' selected' : '') + '>边跑业务边注册</option></select></div>';
  h += '<div><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">注册阶段</div><select class="input-field" onchange="updateCompanyLifecycle(&quot;' + c.id + '&quot;,&quot;registration_stage&quot;,this.value)" style="font-size:12px;"><option value="simulated"' + (registrationStage === 'simulated' ? ' selected' : '') + '>模拟经营</option><option value="preparing"' + (registrationStage === 'preparing' ? ' selected' : '') + '>准备材料</option><option value="filing"' + (registrationStage === 'filing' ? ' selected' : '') + '>办理中</option><option value="registered"' + (registrationStage === 'registered' ? ' selected' : '') + '>已拿执照</option></select></div>';
  h += '<div><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">起盘阶段</div><select class="input-field" onchange="updateCompanyLifecycle(&quot;' + c.id + '&quot;,&quot;startup_stage&quot;,this.value)" style="font-size:12px;"><option value="setup"' + (startupStage === 'setup' ? ' selected' : '') + '>定位/搭班子</option><option value="offer_ready"' + (startupStage === 'offer_ready' ? ' selected' : '') + '>服务包成型</option><option value="acquiring"' + (startupStage === 'acquiring' ? ' selected' : '') + '>开始获客</option><option value="delivering"' + (startupStage === 'delivering' ? ' selected' : '') + '>已在交付</option></select></div>';
  h += '<div><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">第一单阶段</div><select class="input-field" onchange="updateCompanyLifecycle(&quot;' + c.id + '&quot;,&quot;first_order_stage&quot;,this.value)" style="font-size:12px;"><option value="not_started"' + (firstOrderStage === 'not_started' ? ' selected' : '') + '>还没开始</option><option value="prospecting"' + (firstOrderStage === 'prospecting' ? ' selected' : '') + '>找线索</option><option value="quoting"' + (firstOrderStage === 'quoting' ? ' selected' : '') + '>报价沟通</option><option value="negotiating"' + (firstOrderStage === 'negotiating' ? ' selected' : '') + '>推动成交</option><option value="won"' + (firstOrderStage === 'won' ? ' selected' : '') + '>已成交</option></select></div>';
  h += '</div>';
  h += '</div>';
  h += '<div style="padding:14px;border-radius:16px;background:var(--bg);border:1px solid var(--bd);">';
  h += '<div style="font-size:13px;font-weight:700;color:var(--tx);margin-bottom:10px;">下一步怎么干</div>';
  h += '<div style="display:flex;flex-direction:column;gap:8px;">';
  h += '<button class="btn btn-sm" onclick="openCompanyLifecyclePrompt(&quot;register&quot;)" style="justify-content:flex-start;">生成线下注册清单</button>';
  h += '<button class="btn btn-sm" onclick="openCompanyLifecyclePrompt(&quot;first_order&quot;)" style="justify-content:flex-start;">生成第一单行动方案</button>';
  h += '<button class="btn btn-sm" onclick="openCompanyLifecyclePrompt(&quot;delivery&quot;)" style="justify-content:flex-start;">生成交付启动方案</button>';
  h += '<button class="btn btn-sm" onclick="openCompanyLifecyclePrompt(&quot;collection&quot;)" style="justify-content:flex-start;">生成回款设计方案</button>';
  h += '</div>';
  h += '<div style="margin-top:12px;padding:12px;border-radius:12px;background:rgba(139,92,246,.08);border:1px solid rgba(139,92,246,.16);">';
  h += '<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap;"><div><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">经营待办状态</div><div style="font-size:14px;font-weight:800;color:#7c3aed;">待完成 ' + esc(String(pendingTodos.length)) + ' 项</div></div><div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-sm" onclick="createCompanyLifecycleTodoPack(&quot;' + c.id + '&quot;)">一键生成经营待办包</button><button class="btn btn-sm" onclick="switchDetailTab(&quot;timeline&quot;)">打开时间线</button></div></div>';
  if (pendingTodos.length) {
    h += '<div style="margin-top:10px;font-size:12px;color:var(--tx2);line-height:1.8;">当前优先待办：' + esc(pendingTodos.slice(0, 2).map(function(t) { return t.title; }).join('；')) + (pendingTodos.length > 2 ? ' 等' : '') + '</div>';
  } else {
    h += '<div style="margin-top:10px;font-size:12px;color:var(--tx2);line-height:1.8;">当前还没有经营待办，建议先生成一套与当前阶段匹配的执行清单。</div>';
  }
  h += '</div>';
  h += '<div style="margin-top:12px;padding:12px;border-radius:12px;background:rgba(37,99,235,.08);border:1px solid rgba(37,99,235,.16);">';
  h += '<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap;"><div><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">经营文档资产</div><div style="font-size:14px;font-weight:800;color:#2563eb;">已沉淀 ' + esc(String(documents.length)) + ' 份</div></div><div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-sm" onclick="createCompanyLifecycleDocPack(&quot;' + c.id + '&quot;)">一键生成经营文档包</button>' + (documents.length ? '<button class="btn btn-sm" onclick="viewCompanyDocument(&quot;' + documents[0].id + '&quot;)">查看最新文档</button>' : '') + '</div></div>';
  if (documents.length) {
    h += '<div style="margin-top:10px;font-size:12px;color:var(--tx2);line-height:1.8;">当前已沉淀：' + esc(documents.slice(0, 3).map(function(doc) { return doc.title; }).join('；')) + (documents.length > 3 ? ' 等' : '') + '</div>';
  } else {
    h += '<div style="margin-top:10px;font-size:12px;color:var(--tx2);line-height:1.8;">建议先把注册清单、第一单方案、交付方案、回款方案沉淀成公司文档，避免下次重新组织。</div>';
  }
  h += '</div>';
  h += '<div style="margin-top:12px;font-size:12px;color:var(--tx2);line-height:1.8;">当前经营信号：客户 ' + esc(String(st.contact_count || 0)) + ' 人，项目 ' + esc(String(projectCount)) + ' 个，合同 ' + esc(String(contractCount)) + ' 份，累计收入 ' + esc(formatMoney(income)) + ' 元，回款状态 ' + esc(collectionStage) + '。</div>';
  h += '<div style="margin-top:8px;font-size:11px;color:var(--tx3);line-height:1.8;">当公司进入已成交、已交付或已回款状态时，系统会把带“来源机会”标记的机会自动同步到地图作战台。</div>';
  h += '</div>';
  h += '</div>';
  return h + '</div>';
}

function renderCompanySalesFunnel(c, st) {
  var contacts = st.contacts || [];
  var projects = st.projects || [];
  var contracts = st.contracts || [];
  var income = Number(st.total_income) || 0;

  var hotContacts = contacts.filter(function(item) {
    var stage = String(item.pipeline_stage || '').toLowerCase();
    return /lead|contacted|proposal|quoted|negotiating|follow/.test(stage);
  }).length || contacts.length;
  var activeProjects = projects.filter(function(item) {
    return item.status === 'active' || item.status === 'planning';
  }).length;
  var activeContracts = contracts.filter(function(item) {
    return item.status === 'active' || item.status === 'pending' || item.status === 'draft';
  }).length;
  var returnedCash = income > 0 ? 1 : 0;

  function node(title, value, desc, color, tab) {
    return '<button class="card" onclick="switchDetailTab(&quot;' + tab + '&quot;)" style="text-align:left;padding:16px;border:1px solid ' + color + ';background:linear-gradient(180deg,' + color + '14,transparent);box-shadow:none;cursor:pointer;">' +
      '<div style="font-size:11px;font-weight:800;color:' + color + ';margin-bottom:6px;">' + esc(title) + '</div>' +
      '<div style="font-size:30px;line-height:1;font-weight:900;color:var(--tx);margin-bottom:8px;">' + esc(String(value)) + '</div>' +
      '<div style="font-size:12px;color:var(--tx2);line-height:1.8;">' + esc(desc) + '</div>' +
      '</button>';
  }

  var bottleneck = '当前最弱的一环是回款设计，签单后要尽快补收款节点和开票节奏。';
  if (hotContacts === 0) bottleneck = '当前最弱的一环是线索池，先把可触达客户名单补起来。';
  else if (activeProjects === 0) bottleneck = '已有客户但缺少明确项目载体，建议把机会先转成项目盘。';
  else if (activeContracts === 0) bottleneck = '项目在推进但合同沉淀不足，重点补报价、方案边界和合同前置。';
  else if (income > 0) bottleneck = '已经形成回款，下一步重点是复购、转介绍和标准化交付。';

  var h = '<div class="card" style="margin-bottom:16px;padding:18px 18px 16px;">';
  h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:14px;">';
  h += '<div><div style="font-size:16px;font-weight:800;color:var(--tx);margin-bottom:6px;">第一单成交漏斗</div><div style="font-size:12px;color:var(--tx2);line-height:1.8;max-width:760px;">把联系人、项目、合同、回款串成一条经营转化链。哪个环节薄弱，就优先补哪个，不要平均用力。</div></div>';
  h += '<button class="btn btn-sm" onclick="openCompanyLifecyclePrompt(&quot;first_order&quot;)">让 AI 重做成交方案</button>';
  h += '</div>';
  h += '<div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-bottom:14px;">';
  h += node('线索池', hotContacts, '当前可推进的联系人/客户线索数量。', '#2563eb', 'contacts');
  h += node('项目推进', activeProjects, '已经落到项目盘并进入推进的机会。', '#8b5cf6', 'projects');
  h += node('合同沉淀', activeContracts, '已经进入合同、审批或签约阶段的项目。', '#16a34a', 'contracts');
  h += node('回款发生', income > 0 ? '是' : '否', income > 0 ? ('累计收入 ' + formatMoney(income) + ' 元') : '尚未形成真实回款。', '#f97316', 'finance');
  h += '</div>';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);font-size:12px;color:var(--tx2);line-height:1.9;">';
  h += '<strong style="color:var(--tx);">当前瓶颈：</strong>' + esc(bottleneck);
  h += '<div style="margin-top:8px;display:flex;gap:8px;flex-wrap:wrap;">';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;contacts&quot;)">看联系人</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;projects&quot;)">看项目</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;contracts&quot;)">看合同</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;finance&quot;)">看回款</button>';
  h += '</div></div>';
  h += '</div>';
  return h;
}

function collectCompanyOpportunityLinks(st) {
  var markerMap = {};
  function addMarkers(rawText) {
    var raw = String(rawText || '');
    if (!raw) return;
    var prefix = '[机会ID:';
    var pos = 0;
    while (pos < raw.length) {
      var start = raw.indexOf(prefix, pos);
      if (start < 0) break;
      var end = raw.indexOf(']', start + prefix.length);
      if (end < 0) break;
      var id = raw.slice(start + prefix.length, end).trim();
      if (id) markerMap[id] = true;
      pos = end + 1;
    }
  }
  (st.documents || []).forEach(function(item) { addMarkers(item.content); });
  (st.projects || []).forEach(function(item) { addMarkers(item.document); addMarkers(item.description); });
  (st.todos || []).forEach(function(item) { addMarkers(item.description); });
  (st.contacts || []).forEach(function(item) { addMarkers(item.notes); });
  (st.contracts || []).forEach(function(item) { addMarkers(item.title); addMarkers(item.terms); addMarkers(item.counterparty); });
  (st.invoices || []).forEach(function(item) { addMarkers(item.notes); });
  (st.transactions || []).forEach(function(item) { addMarkers(item.description); addMarkers(item.counterparty); });
  return Object.keys(markerMap).map(function(id) {
    var source = findOpportunityByMarker(id) || {};
    var battle = getOpportunityBattleState(id);
    return {
      id: id,
      title: source.title || source.name || id,
      followStatus: battle.followStatus || '',
      monetizationStage: battle.monetizationStage || '',
      quoteAmount: battle.quoteAmount || '',
      ownerCompanyId: battle.ownerCompanyId || ''
    };
  });
}

function renderCompanyOpportunityClosurePanel(c, st) {
  var links = collectCompanyOpportunityLinks(st).filter(function(item) {
    return !item.ownerCompanyId || item.ownerCompanyId === c.id;
  });
  if (!links.length) return '';
  var wonCount = links.filter(function(item) { return item.followStatus === 'won'; }).length;
  var dealCount = links.filter(function(item) { return item.monetizationStage === 'deal'; }).length;
  var totalQuote = links.reduce(function(sum, item) {
    return sum + parseOpportunityMoney(item.quoteAmount || 0);
  }, 0);
  var rows = links.slice(0, 5).map(function(item) {
    var follow = getOpportunityFollowDefs().find(function(v) { return v.key === item.followStatus; });
    var monetization = getOpportunityMonetizationDefs().find(function(v) { return v.key === item.monetizationStage; });
    return '<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;padding:10px 12px;border-radius:12px;background:var(--bg);border:1px solid var(--bd);">' +
      '<div style="min-width:0;"><div style="font-size:13px;font-weight:700;color:var(--tx);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(item.title) + '</div><div style="font-size:11px;color:var(--tx3);margin-top:4px;">' +
      esc((follow && follow.label) || '待推进') + ' · ' + esc((monetization && monetization.label) || '待变现') + '</div></div>' +
      '<div style="text-align:right;flex:0 0 auto;"><div style="font-size:12px;font-weight:800;color:var(--accent);">' + esc(item.quoteAmount || '未回写') + '</div><button class="btn btn-sm" onclick="openOpportunityMapFocus(&quot;' + item.id + '&quot;)" style="margin-top:6px;padding:3px 8px;">查看机会</button></div>' +
      '</div>';
  }).join('');
  var h = '<div class="card" style="margin-bottom:16px;padding:18px;">';
  h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:12px;"><div><div style="font-size:16px;font-weight:800;color:var(--tx);">商机闭环看板</div><div style="font-size:12px;color:var(--tx2);line-height:1.8;max-width:760px;">这里展示当前公司已绑定的机会、系统回写的报价金额，以及是否已经进入成交/变现阶段。</div></div><div style="display:flex;gap:8px;flex-wrap:wrap;"><span style="padding:7px 10px;border-radius:999px;background:rgba(59,130,246,.10);border:1px solid rgba(59,130,246,.16);font-size:12px;color:#2563eb;">关联 ' + esc(String(links.length)) + ' 个</span><span style="padding:7px 10px;border-radius:999px;background:rgba(22,163,74,.10);border:1px solid rgba(22,163,74,.16);font-size:12px;color:#16a34a;">成交 ' + esc(String(wonCount)) + ' 个</span><span style="padding:7px 10px;border-radius:999px;background:rgba(249,115,22,.10);border:1px solid rgba(249,115,22,.16);font-size:12px;color:#f97316;">金额 ' + esc(formatMoney(totalQuote)) + '</span></div></div>';
  h += '<div style="display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px;margin-bottom:12px;">';
  h += '<div style="padding:12px 14px;border-radius:14px;background:var(--bg);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">已关联机会</div><div style="font-size:20px;font-weight:800;color:var(--tx);">' + esc(String(links.length)) + '</div></div>';
  h += '<div style="padding:12px 14px;border-radius:14px;background:var(--bg);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">进入 deal</div><div style="font-size:20px;font-weight:800;color:#16a34a;">' + esc(String(dealCount)) + '</div></div>';
  h += '<div style="padding:12px 14px;border-radius:14px;background:var(--bg);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">累计回写金额</div><div style="font-size:20px;font-weight:800;color:var(--accent);">' + esc(formatMoney(totalQuote)) + '</div></div>';
  h += '</div>';
  h += '<div style="display:grid;gap:10px;">' + rows + '</div>';
  h += '</div>';
  return h;
}

