  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">交付方式</div><div style="font-size:13px;color:var(--tx);line-height:1.8;">' + esc(cleanDirtyPlaceholderText(productStrategy.delivery_model || '', '建议明确标准交付物、周期和边界。')) + '</div></div>';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">盈利方式</div><div style="font-size:13px;color:var(--tx);line-height:1.8;">' + esc(cleanDirtyPlaceholderText(productStrategy.revenue_strategy || '', '建议明确按项目、顾问费、订阅还是佣金收费。')) + '</div></div>';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">月营收目标</div><div style="font-size:22px;font-weight:900;color:var(--accent);line-height:1;">' + esc(formatMoney(productStrategy.monthly_revenue_target || 0)) + '<span style="font-size:12px;color:var(--tx3);font-weight:600;margin-left:4px;">元</span></div><div style="font-size:12px;color:var(--tx2);line-height:1.8;margin-top:8px;">给销售推进、报价判断和现金计划一个明确目标。</div></div>';
  h += '</div></div>';

  h += '<div style="display:grid;grid-template-columns:1.05fr .95fr;gap:16px;margin-bottom:16px;">';
  h += '<div class="card" style="padding:18px;">';
  h += '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;margin-bottom:12px;"><div><div style="font-size:16px;font-weight:800;color:var(--tx);">经营闭环看板</div><div style="font-size:12px;color:var(--tx2);line-height:1.8;">让你明确自己卡在产品、机会、成交还是交付回款。</div></div><button class="btn btn-sm" onclick="switchDetailTab(&quot;overview&quot;)">刷新判断</button></div>';
  h += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;">';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">线索池</div><div style="font-size:26px;font-weight:900;color:#2563eb;">' + esc(String(pipeline.lead_pool || 0)) + '</div><div style="font-size:12px;color:var(--tx2);margin-top:8px;">值得继续判断的线索数</div></div>';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">在推进机会</div><div style="font-size:26px;font-weight:900;color:#7c3aed;">' + esc(String(pipeline.active_opportunities || 0)) + '</div><div style="font-size:12px;color:var(--tx2);margin-top:8px;">有明确下一动作的销售机会</div></div>';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">合同/报价</div><div style="font-size:26px;font-weight:900;color:#16a34a;">' + esc(String(pipeline.active_contracts || 0)) + '</div><div style="font-size:12px;color:var(--tx2);margin-top:8px;">在手合同或报价节点</div></div>';
  h += '<div style="padding:14px;border-radius:14px;background:var(--bg-soft);border:1px solid var(--bd);"><div style="font-size:11px;color:var(--tx3);margin-bottom:6px;">发票/回款风险</div><div style="font-size:26px;font-weight:900;color:#f97316;">' + esc(String(pipeline.overdue_invoices || 0)) + '</div><div style="font-size:12px;color:var(--tx2);margin-top:8px;">待收款/已开票待推进</div></div>';
  h += '</div>';
  h += '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:12px;">';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;contacts&quot;)">看客户池</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;opportunities&quot;)">看机会推进</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;projects&quot;)">看项目推进</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;delivery&quot;)">看交付回款</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;contracts&quot;)">看合同状态</button>';
  h += '<button class="btn btn-sm" onclick="switchDetailTab(&quot;finance&quot;)">看财务回款</button>';
  h += '</div>';
  h += '</div>';

  h += '<div class="card" style="padding:18px;">';
