  html += '</div></div>';

  html += '<div style="padding:20px 28px;">';

  html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:20px;">';
  html += '<div class="card" style="padding:16px;text-align:center;"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">\u5408\u540C\u91D1\u989D</div><div style="font-size:22px;font-weight:700;color:var(--accent);">\u00A5' + Number(ct.value||0).toLocaleString('zh-CN',{minimumFractionDigits:2}) + '</div></div>';
  html += '<div class="card" style="padding:16px;text-align:center;"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">\u5408\u540C\u7C7B\u578B</div><div style="font-size:16px;font-weight:600;">' + esc(ct.type||'service') + '</div></div>';
  html += '</div>';

  html += '<div class="card" style="padding:16px;margin-bottom:16px;"><h4 style="margin:0 0 12px;font-size:14px;font-weight:600;">\u57FA\u672C\u4FE1\u606F</h4>';
