  html += infoItem('\u4E59\u65B9', ct.counterparty || '');
  html += infoItem('\u7C7B\u578B', ct.type || 'service');
  html += infoItem('\u5F00\u59CB\u65E5\u671F', (ct.start_date||'').toString().slice(0,10));
  html += infoItem('\u7ED3\u675F\u65E5\u671F', (ct.end_date||'').toString().slice(0,10));
  html += infoItem('\u98CE\u9669\u7B49\u7EA7', ct.risk_level === 'high' ? '🔴 \u9AD8' : ct.risk_level === 'medium' ? '🟡 \u4E2D' : '🟢 \u4F4E');
  html += infoItem('\u521B\u5EFA\u65F6\u95F4', (ct.created_at||'').toString().slice(0,10));
  html += '</div></div>';

  if (ct.terms) {
    html += '<div class="card" style="padding:16px;margin-bottom:16px;"><h4 style="margin:0 0 8px;font-size:14px;font-weight:600;">\u5173\u952E\u6761\u6B3E</h4>';
    html += '<div style="font-size:13px;line-height:1.7;color:var(--tx);white-space:pre-wrap;">' + esc(ct.terms) + '</div></div>';
  }

