async function loadUsers() {
  const [statsData, usersData] = await Promise.all([api('/admin/stats'), api('/admin/users')]);
  const mc = document.getElementById('mc'); if (!mc) return;
  mc.innerHTML = '<div class="page-inner"><div class="page-header"><h1>用户管理</h1><p>注册用户 ' + statsData.users + ' 人，今日新增 ' + statsData.today_users + ' 人</p></div>' +
    '<div class="card" style="flex:1"><div class="table-wrap"><table><thead><tr><th>姓名</th><th>手机号</th><th>角色</th><th>公司数</th><th>状态</th><th>操作</th></tr></thead><tbody>' +
    usersData.users.map(u => {
      var isSelf = state.user && state.user.id === u.id;
      var actions = u.status==='active'
        ? '<button class="btn btn-sm btn-danger" onclick="adminToggleUser(&quot;'+u.id+'&quot;,&quot;disabled&quot;)">\u7981\u7528</button>'
        : '<button class="btn btn-sm btn-secondary" onclick="adminToggleUser(&quot;'+u.id+'&quot;,&quot;active&quot;)">\u542f\u7528</button>';
      if (!isSelf) {
        actions += ' <button class="btn btn-sm" style="color:var(--red);border-color:var(--red);" onclick="adminDeleteUser(&quot;'+u.id+'&quot;,&quot;'+esc(u.name)+'&quot;)">\u5220\u9664</button>';
      }
      return '<tr><td style="font-weight:500">' + esc(u.name) + '</td><td>' + esc(u.phone) + '</td><td>' + (u.role==='admin'?'<span style="color:var(--blue)">\u7ba1\u7406\u5458</span>':'\u7528\u6237') + '</td><td>' + u.company_count + '</td><td>' + (u.status==='active'?'<span style="color:var(--green)">\u6b63\u5e38</span>':'<span style="color:var(--red)">\u7981\u7528</span>') + '</td><td><div style="display:flex;gap:6px;">' + actions + '</div></td></tr>';
    }).join('') + '</tbody></table></div></div></div>';
}

