function getFeaturedCenterIds() {
  return getFeaturedOpcCenters().map(function(center) { return center.id; });
}

function findCityDisplayNode(parkId) {
  return ((state._cityDisplayNodes || []).find(function(c) { return c.id === parkId; })) ||
    ((state.cities || []).find(function(c) { return c.id === parkId; })) ||
    null;
}

function currentUserCanManagePark(park) {
  return !!(state.user && park && (state.user.role === 'admin' || park.creator_id === state.user.id));
}

function getManagedParkNode(parkId) {
  return ((state._managedParkNodes || []).find(function(c) { return c.id === parkId; })) ||
    findCityDisplayNode(parkId) ||
    null;
}

function getAdminManageableParks() {
  var parkMap = {};
  getFeaturedOpcCenters().concat(state.cities || [], state._managedParkNodes || []).forEach(function(park) {
    if (!park || !park.id) return;
    if (!currentUserCanManagePark(park)) return;
    parkMap[park.id] = Object.assign({}, parkMap[park.id] || {}, park);
  });
  return Object.keys(parkMap).map(function(id) { return parkMap[id]; });
}

async function fetchPendingParkApplicationsSummary() {
  var parks = getAdminManageableParks();
  if (!parks.length) return [];
  var settled = await Promise.all(parks.map(async function(park) {
    try {
      var data = await api('/parks/' + park.id + '/applications', { silent: true });
      var pending = (data.applications || []).filter(function(app) { return app.status === 'pending'; });
      return pending.map(function(app) {
        return { park: park, application: app };
      });
    } catch (e) {
      return [];
    }
  }));
  return settled.flat();
}

function openParkVisualOverridesDb() {
  return new Promise(function(resolve, reject) {
    if (!window.indexedDB) { reject(new Error('当前浏览器不支持图片存储')); return; }
    var request = window.indexedDB.open(_storagePrefix + 'parkVisualDb', 1);
    request.onerror = function() { reject(request.error || new Error('图片存储打开失败')); };
    request.onupgradeneeded = function(event) {
      var db = event.target.result;
      if (!db.objectStoreNames.contains('kv')) db.createObjectStore('kv');
    };
    request.onsuccess = function() { resolve(request.result); };
  });
}

async function loadParkVisualOverrides() {
  if (state._parkVisualOverridesLoaded) return state._parkVisualOverrides || {};
  var legacy = {};
  try {
    legacy = JSON.parse(localStorage.getItem(_storagePrefix + 'parkVisualOverrides') || '{}') || {};
  } catch(e) { legacy = {}; }
  try {
    var db = await openParkVisualOverridesDb();
    var result = await new Promise(function(resolve, reject) {
      var tx = db.transaction('kv', 'readonly');
      var store = tx.objectStore('kv');
      var req = store.get('parkVisualOverrides');
      req.onerror = function() { reject(req.error || new Error('图片存储读取失败')); };
      req.onsuccess = function() { resolve(req.result || null); };
    });
    state._parkVisualOverrides = result || legacy || {};
    state._parkVisualOverridesLoaded = true;
    if (Object.keys(legacy || {}).length) {
      try { localStorage.removeItem(_storagePrefix + 'parkVisualOverrides'); } catch(e) {}
      await saveParkVisualOverrides(state._parkVisualOverrides);
    }
    return state._parkVisualOverrides;
  } catch(e) {
    state._parkVisualOverrides = legacy || {};
    state._parkVisualOverridesLoaded = true;
    return state._parkVisualOverrides;
  }
}

