function focusOpportunityOnMap(itemId) {
  if (!itemId) return;
  var item = ((OPPORTUNITY_MAP_DATA.opportunities || []).concat(OPPORTUNITY_MAP_DATA.industries || [])).find(function(v) { return v.id === itemId; }) || null;
  if (!item) return;
  _pendingOpportunityFocusId = '';
  _opportunityMapSelected = item;
  renderOpportunitySidePanel(item);
  if (_opportunityMap && item.longitude && item.latitude) {
    try { _opportunityMap.setZoomAndCenter(11, [Number(item.longitude), Number(item.latitude)]); } catch(e) {}
  }
}

function openOpportunityMapFocus(itemId) {
  _pendingOpportunityFocusId = itemId || '';
  navigate('opportunity-map');
}

function setOpportunityQuickPreset(kind) {
  if (kind === 'strong_orders') {
    _opportunityMapStrength = '强';
    _opportunityMapOpportunityKind = '招采订单';
    _opportunityMapDataset = 'all';
  } else if (kind === '招商项目') {
    _opportunityMapStrength = '中';
    _opportunityMapOpportunityKind = '招商项目';
    _opportunityMapDataset = 'all';
  } else if (kind === '政策窗口') {
    _opportunityMapStrength = '中';
    _opportunityMapOpportunityKind = '政策窗口';
    _opportunityMapDataset = 'all';
  } else {
    _opportunityMapStrength = 'all';
    _opportunityMapOpportunityKind = 'all';
  }
  loadOpportunityMap().catch(function() {});
}

