function parseOpportunityMoney(value) {
  var text = String(value || '').replace(/,/g, '').trim();
  if (!text) return 0;
  var match = text.match(/(\d+(?:\.\d+)?)/);
  if (!match) return 0;
  var amount = Number(match[1] || 0);
  if (!isFinite(amount)) return 0;
  if (/亿/.test(text)) return amount * 100000000;
  if (/千万/.test(text)) return amount * 10000000;
  if (/百万/.test(text)) return amount * 1000000;
  if (/万/.test(text)) return amount * 10000;
  if (/千/.test(text)) return amount * 1000;
  return amount;
}

function formatOpportunityMoney(value) {
  var amount = Number(value || 0);
  if (!amount) return '¥0';
  if (amount >= 100000000) return '¥' + (amount / 100000000).toFixed(amount >= 1000000000 ? 0 : 1).replace(/\.0$/, '') + '亿';
  if (amount >= 10000) return '¥' + (amount / 10000).toFixed(amount >= 1000000 ? 0 : 1).replace(/\.0$/, '') + '万';
  return '¥' + Math.round(amount);
}

function summarizeOpportunityBusinessMetrics(items) {
  var summary = {
    totalBudget: 0,
    quotedGmv: 0,
    wonGmv: 0,
    assignedCount: 0,
    quotedCount: 0,
    wonCount: 0,
    dealCount: 0
  };
  (items || []).forEach(function(item) {
    var battle = getOpportunityBattleState(item.id);
    var baseAmount = parseOpportunityMoney(battle.quoteAmount || item.budget || item.money);
    summary.totalBudget += parseOpportunityMoney(item.budget || item.money);
    if (battle.ownerCompanyId || battle.ownerCompanyName || battle.ownerPerson) summary.assignedCount += 1;
    if (battle.followStatus === 'quoted') {
      summary.quotedCount += 1;
      summary.quotedGmv += baseAmount;
    }
    if (battle.followStatus === 'won') {
      summary.wonCount += 1;
      summary.wonGmv += baseAmount;
    }
    if (battle.monetizationStage === 'deal') summary.dealCount += 1;
  });
  return summary;
}

function getOpportunityActiveCompanyProfile() {
  var company = state.currentCompany || (state.companies && state.companies[0]) || null;
  var text = company ? [company.name, company.industry, company.description, company.track].filter(Boolean).join(' ') : '';
  return {
    company: company,
    name: company ? (company.name || '我的公司') : '我的公司',
    industry: company ? (company.industry || '') : '',
    description: company ? (company.description || '') : '',
    track: company ? (company.track || '') : '',
    text: String(text || '').toLowerCase()
  };
}

function scoreOpportunityForActiveCompany(item) {
  var profile = getOpportunityActiveCompanyProfile();
  var score = scoreOpportunityMarker(item);
  var reasons = [];
  var region = [item.province, item.city, item.county].filter(Boolean).join(' ');
  var itemText = String([
    item.title,
    item.summary,
    item.entryFocus,
    item.category,
    item.type,
    item.opportunityKind,
    (item.services || []).join(' '),
    (item.fitProfiles || []).join(' ')
  ].join(' ') || '').toLowerCase();

  if (profile.text) {
    var tokens = profile.text.split(/[\s,，、/]+/).filter(function(v) { return v && v.length >= 2; }).slice(0, 10);
    var matched = tokens.filter(function(token) { return itemText.indexOf(token) >= 0; });
    if (matched.length) {
      score += matched.length * 180;
      reasons.push('和你当前公司的行业/服务方向更接近');
    }
  }
  if (item.commercialStrength === '强') {
    score += 240;
    reasons.push('属于强机会，成交窗口更近');
  } else if (item.commercialStrength === '中') {
    score += 120;
  }
  if (/招采订单|采购|招标/.test(String(item.opportunityKind || item.type || item.category || ''))) {
    score += 160;
    reasons.push('更接近直接可跟的订单型资源');
  }
  if (item.services && item.services.length) {
    score += Math.min(120, item.services.length * 30);
    reasons.push('已经带有可卖服务切口');
  }
  if (item.targetOrg) {
    score += 80;
    reasons.push('甲方主体相对明确，方便直接推进');
  }
  if (item.businessStage || item.stageTag) {
    score += 60;
  }
  if (!reasons.length) {
    reasons.push('当前属于可继续判断和切入的资源入口');
  }
  return { score: score, reasons: reasons.slice(0, 3), region: region || '待补充地区' };
}

function buildOpportunityBuyerFitSummary(item) {
  var scored = scoreOpportunityForActiveCompany(item);
  var narrative = buildOpportunityNarrative(item);
  var service = (item.services && item.services.length) ? item.services.slice(0, 3).join('、') : (item.entryFocus || '先判断切入服务');
  return {
    score: scored.score,
    region: scored.region,
    why: scored.reasons.join('；'),
    service: service,
    firstStep: (narrative.action && narrative.action[0]) || '先核验甲方主体、项目节点和预算口径。'
  };
}

