async function updateCompanyLifecycle(companyId, field, value) {
  var body = {};
  body[field] = value;
  if (field === 'registration_mode') {
    if (value === 'virtual') body.registration_stage = 'simulated';
    if (value === 'real') body.registration_stage = 'preparing';
    if (value === 'hybrid' && !(state.currentCompany || {}).registration_stage) body.registration_stage = 'preparing';
  }
  if (field === 'first_order_stage' && value === 'won') {
    body.startup_stage = 'delivering';
  }
  try {
    await api('/companies/' + companyId, { method: 'PUT', body: body });
    var d = await api('/companies/' + companyId);
    state.currentCompany = d.company;
    state.companyDetail = d;
    renderCompanyDetailPage();
    toast('经营阶段已更新', 'success');
  } catch(e) {
    toast(e.message || '更新失败', 'error');
  }
}

