function generateQrCode(text, canvasId) {
  var canvas = document.getElementById(canvasId);
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  if (!ctx) return;

  var qrData = simpleQrEncode(text);
  var size = qrData.length;
  var cellSize = Math.floor(200 / (size + 8));
  var offset = Math.floor((200 - size * cellSize) / 2);

  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, 200, 200);
  ctx.fillStyle = '#000000';

  for (var y = 0; y < size; y++) {
    for (var x = 0; x < size; x++) {
      if (qrData[y][x]) {
        ctx.fillRect(offset + x * cellSize, offset + y * cellSize, cellSize, cellSize);
      }
    }
  }
}

function simpleQrEncode(text) {
  var size = 33;
  var grid = [];
  for (var i = 0; i < size; i++) { grid[i] = []; for (var j = 0; j < size; j++) grid[i][j] = 0; }
  function setFinder(row, col) {
    for (var r = -1; r <= 7; r++) for (var c = -1; c <= 7; c++) {
      var rr = row + r, cc = col + c;
      if (rr < 0 || rr >= size || cc < 0 || cc >= size) continue;
      grid[rr][cc] = (r >= 0 && r <= 6 && (c === 0 || c === 6)) || (c >= 0 && c <= 6 && (r === 0 || r === 6)) || (r >= 2 && r <= 4 && c >= 2 && c <= 4) ? 1 : 0;
    }
  }
  setFinder(0, 0); setFinder(0, size - 7); setFinder(size - 7, 0);
  for (var k = 8; k < size - 8; k++) { grid[6][k] = k % 2 === 0 ? 1 : 0; grid[k][6] = k % 2 === 0 ? 1 : 0; }
  var bytes = [];
  for (var b = 0; b < text.length; b++) bytes.push(text.charCodeAt(b));
  var idx = 0;
  for (var col = size - 1; col > 0; col -= 2) {
    if (col === 6) col = 5;
    for (var row = 0; row < size; row++) {
      for (var dc = 0; dc < 2; dc++) {
        var cc = col - dc;
        if (grid[row][cc] === 0) {
          grid[row][cc] = (idx < bytes.length * 8) ? ((bytes[Math.floor(idx / 8)] >> (7 - idx % 8)) & 1) : ((row + cc) % 2 === 0 ? 1 : 0);
          idx++;
        }
      }
    }
  }
  return grid;
}

