function startPayPoll(tradeNo, container) {
  if (_payPollTimer) clearInterval(_payPollTimer);
  var attempts = 0;
  _payPollTimer = setInterval(async function() {
    attempts++;
    if (attempts > 120) {
      clearInterval(_payPollTimer); _payPollTimer = null;
      var st = document.getElementById('pay-poll-status');
      if (st) st.innerHTML = '<span style="color:#f59e0b;">支付超时，请刷新页面重试</span>';
      return;
    }
    try {
      var res = await api('/subscription/status?trade_no=' + encodeURIComponent(tradeNo), { silent: true });
      if (res.paid && res.secret_key) {
        clearInterval(_payPollTimer); _payPollTimer = null;
        if (container) container.innerHTML = '<div style="text-align:center;padding:30px 0;"><div class="loading-spinner"></div><div style="margin-top:10px;font-size:13px;color:var(--tx3);">支付成功，正在激活套餐...</div></div>';
        try {
          await api('/subscription/activate', { method: 'POST', body: { secret_key: res.secret_key } });
          if (container) container.innerHTML = renderPaySuccess(res.plan || '');
          toast('套餐已激活', 'success');
        } catch(ae) {
          if (container) container.innerHTML = renderSubStep3(res.secret_key);
        }
      }
    } catch(e) { /* ignore poll errors */ }
  }, 3000);
}

