async function activateXinghuanKey() {
  var keyEl = document.getElementById('xh-activate-key');
  var statusEl = document.getElementById('xh-activate-status');
  if (!keyEl) return;
  var key = keyEl.value.trim();
  if (!key) { toast('请输入套餐密钥', 'info'); return; }

  if (statusEl) { statusEl.style.display = 'block'; statusEl.innerHTML = '<div style="padding:10px 14px;border-radius:8px;background:rgba(249,115,22,0.08);color:var(--accent);font-size:13px;">验证中...</div>'; }

  try {
    var res = await api('/subscription/activate', { method: 'POST', body: { secret_key: key } });
    await api('/ai-config', {
      method: 'POST',
      body: {
        ai_provider: 'xinghuan-cloud',
        ai_model: 'auto',
        ai_api_key: key,
        ai_base_url: '',
      }
    });
    if (statusEl) { statusEl.innerHTML = '<div style="padding:10px 14px;border-radius:8px;background:rgba(34,197,94,0.08);border:1px solid rgba(34,197,94,0.2);color:#22c55e;font-size:13px;font-weight:600;">✓ ' + esc(res.message || '套餐激活成功') + '</div>'; }
    toast('星环套餐已激活', 'success');
  } catch(e) {
    if (statusEl) { statusEl.innerHTML = '<div style="padding:10px 14px;border-radius:8px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.2);color:#ef4444;font-size:13px;">激活失败: ' + esc(e.message || '未知错误') + '</div>'; }
  }
}

function onProviderChange() {
  var sel = document.getElementById('ai-provider');
  var prov = AI_PROVIDERS.find(function(p) { return p.id === (sel && sel.value); });
  var mSel = document.getElementById('ai-model-select');
  var urlInput = document.getElementById('ai-baseurl');
  if (!mSel) return;
  mSel.innerHTML = '<option value="">选择模型或输入自定义</option>';
  if (prov) {
    if (prov.baseUrl && urlInput) urlInput.value = prov.baseUrl;
    var mi = document.getElementById('ai-model');
    prov.models.forEach(function(m) {
      var o = document.createElement('option');
      o.value = m; o.textContent = m;
      if (mi && m === mi.value) o.selected = true;
      mSel.appendChild(o);
    });
    if (mi && !mi.value && prov.models.length > 0) {
      mi.value = prov.models[0];
      mSel.value = prov.models[0];
    }
  }
}

function onModelSelect() {
  var v = document.getElementById('ai-model-select').value;
  if (v) { var el = document.getElementById('ai-model'); if (el) el.value = v; }
}

function toggleKeyVis() {
  var inp = document.getElementById('ai-key');
  if (inp) inp.type = inp.type === 'password' ? 'text' : 'password';
}

async function saveAiConfig() {
  var provider = (document.getElementById('ai-provider') || {}).value || '';
  var key = ((document.getElementById('ai-key') || {}).value || '').trim();
  var model = ((document.getElementById('ai-model') || {}).value || '').trim();
  var baseUrl = ((document.getElementById('ai-baseurl') || {}).value || '').trim();
  if (!key || key.includes('****')) { toast('请输入完整的 API Key', 'error'); return; }
  if (!model) { toast('请选择或输入模型', 'error'); return; }
  try {
    await api('/ai-config', { method: 'POST', body: { ai_provider: provider, ai_api_key: key, ai_model: model, ai_base_url: baseUrl, ai_mode: 'local' } });
    toast('配置已保存，AI 对话将使用您的自配模型');
    var badge = document.getElementById('ai-status');
    if (badge) { badge.style.background = 'rgba(34,197,94,0.12)'; badge.style.color = '#22c55e'; badge.textContent = '✓ 已配置'; }
    if (window.LOCAL_MODE && model) {
      var chatModelName = document.getElementById('chat-model-name');
      if (chatModelName) chatModelName.textContent = model;
    }
  } catch(e) { toast(e.message, 'error'); }
}

async function testAiConfig() {
  var key = ((document.getElementById('ai-key') || {}).value || '').trim();
  var model = ((document.getElementById('ai-model') || {}).value || '').trim();
  var baseUrl = ((document.getElementById('ai-baseurl') || {}).value || '').trim();
  if (!key) { toast('请先输入 API Key', 'error'); return; }
  if (!baseUrl) { toast('请填写 Base URL', 'error'); return; }
  var useStored = key.includes('****');
  toast('正在测试连接...', 'info');
  try {
    var body = { ai_model: model, ai_base_url: baseUrl };
    if (useStored) { body.use_stored_key = true; } else { body.ai_api_key = key; }
    var result = await api('/ai-config/test', { method: 'POST', body: body });
    if (result.ok) toast('✓ 连接成功！' + (result.message ? (' ' + result.message) : ''), 'success');
    else { var msg = result.error || '未知错误'; if (result.status) msg = result.status + ' - ' + msg; toast('连接失败: ' + msg, 'error'); }
  } catch(e) { toast('连接失败: ' + e.message, 'error'); }
}

