// ─── 删除空间 ──────────────────────────────────────
window.deleteIotSpace = async function(id) {
  var ok = await confirmModal('确定删除该空间？相关房间和设备数据将一并删除。', {title:'删除空间'}); if (!ok) return;
  try {
    await api('/iot/spaces/' + id, { method: 'DELETE' });
    toast('空间已删除');
    await loadIotPlatform();
  } catch(e) { toast(e.message || '删除失败', 'error'); }
};

