window.previewIotImage = function(input) {
  var file = input.files[0];
  if (!file) return;
  if (file.size > 5 * 1024 * 1024) { toast('图片不能超过 5MB', 'error'); input.value = ''; return; }
  window._iotWizardImageFile = file;
  var reader = new FileReader();
  reader.onload = function(e) {
    window._iotWizardImageSrc = e.target.result;
    var preview = document.getElementById('iot-image-preview');
    if (preview) preview.innerHTML = '<img src="' + e.target.result + '" style="width:100%;height:100%;object-fit:cover">';
  };
  reader.readAsDataURL(file);
};

window.doIotAiGenerate = async function() {
  var areaInput = document.getElementById('iot-total-area');
  var descInput = document.getElementById('iot-description');
  var nameInput = document.getElementById('iot-space-name');
  var floorsInput = document.getElementById('iot-floors');
  var roomCountInput = document.getElementById('iot-room-count');

  var totalArea = parseFloat(areaInput.value) || 0;
  var description = descInput.value.trim();

  if (!totalArea && !description) {
    toast('请至少填写总面积或空间描述', 'error');
    if (areaInput) areaInput.focus();
    return;
  }

  var progress = document.getElementById('iot-ai-progress');
  var footer = document.getElementById('iot-wizard-footer');
  var genBtn = document.getElementById('iot-generate-btn');
  if (progress) progress.style.display = 'block';
  if (genBtn) { genBtn.disabled = true; genBtn.textContent = '⏳ 生成中...'; }

  var bodyPayload = {
    total_area: totalArea || undefined,
    description: description || undefined,
    space_name: nameInput.value.trim() || undefined,
    floors: parseInt(floorsInput.value) || 1,
    room_count: parseInt(roomCountInput.value) || undefined,
  };

  if (window._iotWizardImageSrc) {
    bodyPayload.image_base64 = window._iotWizardImageSrc.split(',')[1] || '';
  }

  try {
    var statusEl = document.getElementById('iot-ai-status');
    var steps = ['AI 正在分析空间需求...', 'AI 正在规划房间布局...', 'AI 正在分配设备...', '即将完成...'];
    var stepIdx = 0;
    var stepTimer = setInterval(function() {
      stepIdx++;
      if (statusEl && stepIdx < steps.length) statusEl.textContent = steps[stepIdx];
    }, 5000);

    var result = await api('/iot/ai-generate', { method: 'POST', body: bodyPayload });
    clearInterval(stepTimer);

    closeModal('iot-create-modal');
    window._iotWizardImageFile = null;
    window._iotWizardImageSrc = null;

    toast('空间「' + (result.space_name || 'AI 空间') + '」创建成功！共 ' + (result.rooms || []).length + ' 个房间', 'success');

    await loadIotPlatform();

    setTimeout(function() {
      if (result.space_id) {
        confirmModal('空间已生成，是否立即打开 3D 视图查看效果？', {title:'生成完成', confirmText:'打开 3D 视图', cancelText:'稍后查看', danger:false}).then(function(ok){
          if(ok) window.open('/iot?space=' + result.space_id, '_blank');
        });
      }
    }, 500);
  } catch(e) {
    clearInterval(stepTimer);
    if (progress) progress.style.display = 'none';
    if (genBtn) { genBtn.disabled = false; genBtn.textContent = '🤖 AI 生成空间'; }
    toast(e.message || 'AI 生成失败', 'error');
  }
};

async function loadMemoryCenter() {
  var mc = document.getElementById('mc');
  if (!mc) return;
  mc.innerHTML = renderLoading();

  var data = { stats: {}, memories: [], reflections: [], skills: [], recent_skill_usage: [] };
  try { data = await api('/user/memory-center'); } catch(e) { mc.innerHTML = renderPlaceholder('记忆与成长', e.message || '加载失败'); return; }

  var stats = data.stats || {};
  var memories = Array.isArray(data.memories) ? data.memories : [];
  var reflections = Array.isArray(data.reflections) ? data.reflections : [];
  var skills = Array.isArray(data.skills) ? data.skills : [];
  var recentRuns = Array.isArray(data.recent_skill_usage) ? data.recent_skill_usage : [];
  window.__memoryCenterMemories = memories;
  window.__memoryCenterReflections = reflections;
  window.__memoryCenterSkills = skills;
  window.__memoryCenterRecentRuns = recentRuns;
  var filtered = filterMemoryCenterData(memories, reflections, skills, recentRuns);
  var visibleMemories = filtered.memories;
  var visibleReflections = filtered.reflections;
  var visibleSkills = filtered.skills;
  var visibleRuns = filtered.recentRuns;

  var h = '<div class="page-inner memory-page">';
  h += '<div class="page-header"><div><h1>记忆与成长</h1><p>管理 AI 为你沉淀的长期记忆、复盘经验与技能资产</p></div>';
  h += '<div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-secondary" onclick="loadMemoryCenter()">刷新</button><button class="btn btn-primary" onclick="navigate(&quot;skills&quot;)">去管理 Skills</button></div></div>';
  h += '<div class="card" style="margin-bottom:16px;padding:14px 16px;">';
  h += '<div style="display:grid;grid-template-columns:minmax(0,1.2fr) 180px 180px;gap:12px;align-items:end;">';
  h += '<div class="input-group" style="margin:0;"><label>搜索</label><input id="memory-search-input" class="input-field" placeholder="搜记忆内容、复盘摘要、技能名、调用任务" value="' + esc(_memorySearchQuery) + '" oninput="applyMemoryCenterFilters()" /></div>';
  h += '<div class="input-group" style="margin:0;"><label>状态</label><select id="memory-status-filter" class="input-field" onchange="applyMemoryCenterFilters()"><option value="all"' + (_memoryStatusFilter === 'all' ? ' selected' : '') + '>全部</option><option value="active"' + (_memoryStatusFilter === 'active' ? ' selected' : '') + '>只看启用中</option><option value="inactive"' + (_memoryStatusFilter === 'inactive' ? ' selected' : '') + '>只看停用/未启用</option></select></div>';
  h += '<div class="input-group" style="margin:0;"><label>模块</label><select id="memory-type-filter" class="input-field" onchange="applyMemoryCenterFilters()"><option value="all"' + (_memoryTypeFilter === 'all' ? ' selected' : '') + '>全部模块</option><option value="memories"' + (_memoryTypeFilter === 'memories' ? ' selected' : '') + '>长期记忆</option><option value="reflections"' + (_memoryTypeFilter === 'reflections' ? ' selected' : '') + '>复盘经验</option><option value="skills"' + (_memoryTypeFilter === 'skills' ? ' selected' : '') + '>技能资产</option><option value="runs"' + (_memoryTypeFilter === 'runs' ? ' selected' : '') + '>技能调用</option></select></div>';
  h += '</div>';
  h += '<div style="display:flex;justify-content:space-between;gap:12px;align-items:center;margin-top:10px;font-size:12px;color:var(--tx2);"><span>当前筛选结果：记忆 ' + visibleMemories.length + ' / ' + memories.length + '，复盘 ' + visibleReflections.length + ' / ' + reflections.length + '，技能 ' + visibleSkills.length + ' / ' + skills.length + '</span><button class="btn btn-sm btn-secondary" onclick="resetMemoryCenterFilters()">清空筛选</button></div>';
  h += '</div>';

  h += '<div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-bottom:16px;">';
  h += renderMemoryStatCard('激活记忆', stats.active_memories || 0, '当前会参与 prompt 召回');
  h += renderMemoryStatCard('激活复盘', stats.active_reflections || 0, '保留已验证的做法');
  h += renderMemoryStatCard('技能资产', stats.installed_skills || 0, '已安装或自动沉淀的技能');
  h += renderMemoryStatCard('最近技能调用', recentRuns.length || 0, '最近 30 次执行轨迹');
  h += '</div>';

  h += '<div class="card" style="margin-bottom:16px;">';
  h += '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:14px;"><div><div style="font-size:16px;font-weight:700;">长期记忆</div><div style="font-size:12px;color:var(--tx2);margin-top:4px;">这些内容会按当前问题相关性注入 prompt。对无效或错误记忆，可以直接停用。</div></div><div style="font-size:12px;color:var(--tx3);">共 ' + visibleMemories.length + ' 条</div></div>';
  if (!visibleMemories.length) {
    h += '<div class="empty-state" style="padding:28px 18px;"><h3>还没有长期记忆</h3><p>继续对话后，系统会自动提炼偏好、目标和关键信息。</p></div>';
  } else {
    h += '<div style="display:flex;flex-direction:column;gap:10px;">';
    visibleMemories.slice(0, 80).forEach(function(item) { h += renderMemoryItem(item); });
    h += '</div>';
  }
  h += '</div>';

  h += '<div class="card" style="margin-bottom:16px;">';
  h += '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:14px;"><div><div style="font-size:16px;font-weight:700;">复盘经验</div><div style="font-size:12px;color:var(--tx2);margin-top:4px;">每轮对话后提炼出来的稳定工作方式。启用的经验会进入后续 prompt。</div></div><div style="font-size:12px;color:var(--tx3);">共 ' + visibleReflections.length + ' 条</div></div>';
  if (!visibleReflections.length) {
    h += '<div class="empty-state" style="padding:28px 18px;"><h3>还没有复盘经验</h3><p>当对话里形成稳定工作流时，这里会自动积累。</p></div>';
  } else {
    h += '<div style="display:flex;flex-direction:column;gap:10px;">';
    visibleReflections.slice(0, 40).forEach(function(item) { h += renderReflectionItem(item); });
    h += '</div>';
  }
  h += '</div>';

  h += '<div style="display:grid;grid-template-columns:1.3fr .7fr;gap:16px;">';
  h += '<div class="card">';
  h += '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:14px;"><div><div style="font-size:16px;font-weight:700;">技能资产</div><div style="font-size:12px;color:var(--tx2);margin-top:4px;">这里能看到哪些技能真正被用起来了，方便保留高价值技能。</div></div><div style="font-size:12px;color:var(--tx3);">共 ' + visibleSkills.length + ' 个</div></div>';
  if (!visibleSkills.length) {
    h += '<div class="empty-state" style="padding:28px 18px;"><h3>还没有技能</h3><p>你可以手动安装，也可以让系统在复盘中自动沉淀。</p></div>';
  } else {
    h += '<div style="display:flex;flex-direction:column;gap:10px;">';
    visibleSkills.slice(0, 20).forEach(function(item) { h += renderMemorySkillItem(item); });
    h += '</div>';
  }
  h += '</div>';

  h += '<div class="card">';
  h += '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:14px;"><div><div style="font-size:16px;font-weight:700;">最近技能调用</div><div style="font-size:12px;color:var(--tx2);margin-top:4px;">看 AI 最近在什么场景下调用了哪些技能。</div></div></div>';
  if (!visibleRuns.length) {
    h += '<div class="empty-state" style="padding:28px 18px;"><h3>暂无调用记录</h3><p>当 AI 调用技能后，这里会显示最近的执行轨迹。</p></div>';
  } else {
    h += '<div style="display:flex;flex-direction:column;gap:10px;">';
    visibleRuns.slice(0, 16).forEach(function(item) { h += renderSkillRunItem(item); });
    h += '</div>';
  }
  h += '</div>';
  h += '</div>';

  h += '</div>';
  mc.innerHTML = h;
}

function renderMemoryStatCard(title, value, hint) {
  return '<div class="card" style="padding:16px 18px;"><div style="font-size:12px;color:var(--tx3);margin-bottom:6px;">' + esc(title) + '</div><div style="font-size:26px;font-weight:800;line-height:1;">' + esc(String(value || 0)) + '</div><div style="font-size:12px;color:var(--tx2);margin-top:8px;line-height:1.6;">' + esc(hint || '') + '</div></div>';
}

var _memorySearchQuery = '';
var _memoryStatusFilter = 'all';
var _memoryTypeFilter = 'all';
var MEMORY_SKILL_CATEGORY_OPTIONS = [
  { id: 'business', name: '商业' },
  { id: 'content', name: '内容' },
  { id: 'finance', name: '财务' },
  { id: 'legal', name: '法务' },
  { id: 'product', name: '产品/技术' },
  { id: 'marketing', name: '营销' },
  { id: 'efficiency', name: '效率' },
  { id: 'custom', name: '自定义' }
];

function applyMemoryCenterFilters() {
  _memorySearchQuery = ((document.getElementById('memory-search-input') || {}).value || '').trim();
  _memoryStatusFilter = ((document.getElementById('memory-status-filter') || {}).value || 'all');
  _memoryTypeFilter = ((document.getElementById('memory-type-filter') || {}).value || 'all');
  loadMemoryCenter();
}

function resetMemoryCenterFilters() {
  _memorySearchQuery = '';
  _memoryStatusFilter = 'all';
  _memoryTypeFilter = 'all';
  loadMemoryCenter();
}

function filterMemoryCenterData(memories, reflections, skills, recentRuns) {
  var q = (_memorySearchQuery || '').toLowerCase();
  function activePass(item, activeValue) {
    if (_memoryStatusFilter === 'active') return activeValue;
    if (_memoryStatusFilter === 'inactive') return !activeValue;
    return true;
  }
  function queryPass(text) {
    if (!q) return true;
    return String(text || '').toLowerCase().indexOf(q) >= 0;
  }
  var filteredMemories = memories.filter(function(item) {
    if (_memoryTypeFilter !== 'all' && _memoryTypeFilter !== 'memories') return false;
    if (!activePass(item, item.is_active === true || item.is_active === 1)) return false;
    return queryPass([item.content, item.category, item.source_conv_id].join(' '));
  });
  var filteredReflections = reflections.filter(function(item) {
    if (_memoryTypeFilter !== 'all' && _memoryTypeFilter !== 'reflections') return false;
    if (!activePass(item, item.is_active === true || item.is_active === 1)) return false;
    return queryPass([item.summary, (item.lessons || []).join(' '), (item.style_adjustments || []).join(' '), (item.tools || []).join(' '), item.source_conv_id].join(' '));
  });
  var filteredSkills = skills.filter(function(item) {
    if (_memoryTypeFilter !== 'all' && _memoryTypeFilter !== 'skills') return false;
    if (!activePass(item, item.enabled === true || item.enabled === 1)) return false;
    return queryPass([item.name, item.description, item.category].join(' '));
  });
  var filteredRuns = recentRuns.filter(function(item) {
    if (_memoryTypeFilter !== 'all' && _memoryTypeFilter !== 'runs') return false;
    if (_memoryStatusFilter === 'active' && item.status !== 'success') return false;
    if (_memoryStatusFilter === 'inactive' && item.status === 'success') return false;
    return queryPass([item.skill_name, item.task, item.output_preview, item.category, item.status].join(' '));
  });
  return {
    memories: filteredMemories,
    reflections: filteredReflections,
    skills: filteredSkills,
    recentRuns: filteredRuns
  };
}

function memoryCategoryLabel(category) {
  var map = { preference: '偏好', decision: '决策', fact: '事实', personality: '特质', goal: '目标' };
  return map[category] || (category || '未分类');
}

function renderMemoryItem(item) {
  var enabled = item.is_active === true || item.is_active === 1;
  var badgeBg = enabled ? 'rgba(34,197,94,.12)' : 'rgba(120,113,108,.12)';
  var badgeColor = enabled ? '#16a34a' : 'var(--tx3)';
  return '<div style="border:1px solid var(--bd);border-radius:14px;padding:14px 16px;background:var(--card);">' +
    '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:8px;">' +
      '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">' +
        '<span style="font-size:11px;padding:4px 8px;border-radius:999px;background:var(--accent-soft);color:var(--accent);font-weight:700;">' + esc(memoryCategoryLabel(item.category)) + '</span>' +
        '<span style="font-size:11px;padding:4px 8px;border-radius:999px;background:' + badgeBg + ';color:' + badgeColor + ';font-weight:700;">' + (enabled ? '启用中' : '已停用') + '</span>' +
        '<span style="font-size:11px;color:var(--tx3);">重要度 ' + esc(String(item.importance || 0)) + '/10</span>' +
      '</div>' +
      '<div style="display:flex;gap:8px;align-items:center;flex-shrink:0;"><button class="btn btn-sm btn-secondary" onclick="openMemoryEditModal(&quot;' + esc(item.id) + '&quot;)">编辑</button><button class="btn btn-sm btn-secondary" onclick="toggleMemoryActive(&quot;' + esc(item.id) + '&quot;,' + (!enabled ? 'true' : 'false') + ')">' + (enabled ? '停用' : '启用') + '</button></div>' +
    '</div>' +
    '<div style="font-size:14px;color:var(--tx);line-height:1.75;">' + esc(item.content || '') + '</div>' +
    '<div style="display:flex;justify-content:space-between;gap:12px;margin-top:10px;font-size:11px;color:var(--tx3);">' +
      '<span>更新于 ' + esc(formatDateTime(item.updated_at)) + '</span>' +
      '<span>' + (item.source_conv_id ? '<button class="btn btn-sm btn-secondary" style="padding:4px 10px;font-size:11px;" onclick="jumpToConversation(&quot;' + esc(item.source_conv_id) + '&quot;)">查看来源对话</button>' : '系统提炼') + '</span>' +
    '</div>' +
  '</div>';
}

function renderReflectionItem(item) {
  var enabled = item.is_active === true || item.is_active === 1;
  var lessons = Array.isArray(item.lessons) ? item.lessons : [];
  var adjustments = Array.isArray(item.style_adjustments) ? item.style_adjustments : [];
  var tools = Array.isArray(item.tools) ? item.tools : [];
  return '<div style="border:1px solid var(--bd);border-radius:14px;padding:14px 16px;background:var(--card);">' +
    '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:8px;">' +
      '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">' +
        '<span style="font-size:11px;padding:4px 8px;border-radius:999px;background:rgba(59,130,246,.12);color:#2563eb;font-weight:700;">复盘</span>' +
        '<span style="font-size:11px;padding:4px 8px;border-radius:999px;background:' + (enabled ? 'rgba(34,197,94,.12)' : 'rgba(120,113,108,.12)') + ';color:' + (enabled ? '#16a34a' : 'var(--tx3)') + ';font-weight:700;">' + (enabled ? '启用中' : '已停用') + '</span>' +
      '</div>' +
      '<div style="display:flex;gap:8px;align-items:center;flex-shrink:0;flex-wrap:wrap;"><button class="btn btn-sm btn-secondary" onclick="openReflectionEditModal(&quot;' + esc(item.id) + '&quot;)">编辑</button><button class="btn btn-sm btn-secondary" onclick="promoteReflectionToSkill(&quot;' + esc(item.id) + '&quot;)">沉淀为 Skill</button><button class="btn btn-sm btn-secondary" onclick="toggleReflectionActive(&quot;' + esc(item.id) + '&quot;,' + (!enabled ? 'true' : 'false') + ')">' + (enabled ? '停用' : '启用') + '</button></div>' +
    '</div>' +
    '<div style="font-size:15px;font-weight:700;line-height:1.6;margin-bottom:8px;">' + esc(item.summary || '未命名复盘') + '</div>' +
    (lessons.length ? '<div style="font-size:12px;color:var(--tx2);line-height:1.7;margin-bottom:8px;">' + lessons.map(function(v){ return '• ' + esc(v); }).join('<br/>') + '</div>' : '') +
    (adjustments.length ? '<div style="font-size:12px;color:var(--tx3);line-height:1.7;margin-bottom:8px;">风格调整：' + adjustments.map(esc).join('；') + '</div>' : '') +
    '<div style="display:flex;justify-content:space-between;gap:12px;margin-top:10px;font-size:11px;color:var(--tx3);">' +
      '<span>工具链：' + esc(tools.length ? tools.join(' / ') : '无') + '</span>' +
      '<span style="display:flex;align-items:center;gap:8px;justify-content:flex-end;">' + (item.source_conv_id ? '<button class="btn btn-sm btn-secondary" style="padding:4px 10px;font-size:11px;" onclick="jumpToConversation(&quot;' + esc(item.source_conv_id) + '&quot;)">查看来源对话</button>' : '') + esc(formatDateTime(item.updated_at)) + '</span>' +
    '</div>' +
  '</div>';
}

function renderMemorySkillItem(item) {
  var enabled = item.enabled === true || item.enabled === 1;
  return '<div style="border:1px solid var(--bd);border-radius:14px;padding:14px 16px;background:var(--card);">' +
    '<div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;">' +
      '<div style="min-width:0;">' +
        '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:6px;">' +
          '<div style="font-size:15px;font-weight:700;">' + esc(item.name || '未命名技能') + '</div>' +
          '<span style="font-size:11px;padding:4px 8px;border-radius:999px;background:' + (enabled ? 'rgba(34,197,94,.12)' : 'rgba(120,113,108,.12)') + ';color:' + (enabled ? '#16a34a' : 'var(--tx3)') + ';font-weight:700;">' + (enabled ? '已启用' : '已停用') + '</span>' +
        '</div>' +
        '<div style="font-size:12px;color:var(--tx2);line-height:1.7;">' + esc(item.description || '暂无描述') + '</div>' +
      '</div>' +
      '<div style="text-align:right;flex-shrink:0;">' +
        '<div style="font-size:22px;font-weight:800;line-height:1;">' + esc(String(item.usage_count || 0)) + '</div>' +
        '<div style="font-size:11px;color:var(--tx3);margin-top:4px;">使用次数</div>' +
      '</div>' +
    '</div>' +
    '<div style="display:flex;justify-content:space-between;gap:12px;margin-top:10px;font-size:11px;color:var(--tx3);"><span>' + esc(item.category || 'custom') + '</span><span>' + esc(item.last_used_at ? formatDateTime(item.last_used_at) : '尚未使用') + '</span></div>' +
  '</div>';
}

function renderSkillRunItem(item) {
  var ok = item.status === 'success';
  return '<div style="border:1px solid var(--bd);border-radius:14px;padding:12px 14px;background:var(--card);">' +
    '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:6px;">' +
      '<div style="font-size:14px;font-weight:700;">' + esc(item.skill_name || '未命名技能') + '</div>' +
      '<span style="font-size:11px;padding:4px 8px;border-radius:999px;background:' + (ok ? 'rgba(34,197,94,.12)' : 'rgba(239,68,68,.12)') + ';color:' + (ok ? '#16a34a' : '#dc2626') + ';font-weight:700;">' + (ok ? '成功' : '失败') + '</span>' +
    '</div>' +
    '<div style="font-size:12px;color:var(--tx2);line-height:1.7;margin-bottom:6px;">' + esc(item.task || '') + '</div>' +
    '<div style="font-size:11px;color:var(--tx3);line-height:1.6;background:rgba(249,115,22,.04);border:1px solid var(--bd);border-radius:10px;padding:8px 10px;">' + esc(String(item.output_preview || '').slice(0, 160) || '无输出摘要') + '</div>' +
    '<div style="display:flex;justify-content:space-between;gap:12px;margin-top:8px;font-size:11px;color:var(--tx3);"><span>' + esc(item.category || 'custom') + '</span><span>' + esc(formatDateTime(item.created_at)) + '</span></div>' +
  '</div>';
}

async function toggleMemoryActive(id, enabled) {
  try {
    await api('/user/memories/' + encodeURIComponent(id), { method: 'PATCH', body: { is_active: !!enabled } });
    toast(enabled ? '记忆已启用' : '记忆已停用', 'success');
    loadMemoryCenter();
  } catch(e) { toast(e.message || '操作失败', 'error'); }
}

async function toggleReflectionActive(id, enabled) {
  try {
    await api('/user/reflections/' + encodeURIComponent(id), { method: 'PATCH', body: { is_active: !!enabled } });
    toast(enabled ? '复盘已启用' : '复盘已停用', 'success');
    loadMemoryCenter();
  } catch(e) { toast(e.message || '操作失败', 'error'); }
}

function formatDateTime(value) {
  if (!value) return '-';
  try {
    var d = new Date(value);
    if (isNaN(d.getTime())) return String(value);
    var y = d.getFullYear();
    var m = String(d.getMonth() + 1).padStart(2, '0');
    var day = String(d.getDate()).padStart(2, '0');
    var hh = String(d.getHours()).padStart(2, '0');
    var mm = String(d.getMinutes()).padStart(2, '0');
    return y + '-' + m + '-' + day + ' ' + hh + ':' + mm;
  } catch(e) { return String(value); }
}

function openMemoryEditModal(id) {
  var list = window.__memoryCenterMemories || [];
  var item = list.find(function(v) { return v.id === id; });
  if (!item) { toast('未找到这条记忆', 'error'); return; }
  var h = '<div class="modal-header"><h3>编辑长期记忆</h3><button class="modal-close" onclick="closeModal()">×</button></div>';
  h += '<div class="modal-body">';
  h += '<div class="input-group" style="margin:0;"><label>类别</label><select id="memory-edit-category" class="input-field">' +
    '<option value="preference"' + (item.category === 'preference' ? ' selected' : '') + '>偏好</option>' +
    '<option value="decision"' + (item.category === 'decision' ? ' selected' : '') + '>决策</option>' +
    '<option value="fact"' + (item.category === 'fact' ? ' selected' : '') + '>事实</option>' +
    '<option value="personality"' + (item.category === 'personality' ? ' selected' : '') + '>特质</option>' +
    '<option value="goal"' + (item.category === 'goal' ? ' selected' : '') + '>目标</option>' +
  '</select></div>';
  h += '<div class="input-group" style="margin:0;"><label>重要度</label><input id="memory-edit-importance" class="input-field" type="number" min="1" max="10" value="' + esc(String(item.importance || 5)) + '" /></div>';
  h += '<div class="input-group" style="margin:0;"><label>内容</label><textarea id="memory-edit-content" class="input-field" style="min-height:120px;">' + esc(item.content || '') + '</textarea></div>';
  h += '<label style="display:flex;align-items:center;gap:8px;font-size:13px;color:var(--tx2);"><input id="memory-edit-active" type="checkbox"' + ((item.is_active === true || item.is_active === 1) ? ' checked' : '') + ' /> 启用这条记忆</label>';
  h += '</div>';
  h += '<div class="modal-footer"><button class="btn" onclick="closeModal()">取消</button><button class="btn btn-primary" onclick="saveMemoryEdit(&quot;' + esc(item.id) + '&quot;)">保存</button></div>';
  showModal(h.replace('<div class="modal-header">', '<div class="modal-header">'), '760px');
}

async function saveMemoryEdit(id) {
  var category = (document.getElementById('memory-edit-category') || {}).value || 'fact';
  var importance = Number((document.getElementById('memory-edit-importance') || {}).value || 5);
  var content = ((document.getElementById('memory-edit-content') || {}).value || '').trim();
  var isActive = !!((document.getElementById('memory-edit-active') || {}).checked);
  if (!content) { toast('记忆内容不能为空', 'error'); return; }
  try {
    await api('/user/memories/' + encodeURIComponent(id), {
      method: 'PATCH',
      body: { category: category, importance: importance, content: content, is_active: isActive }
    });
    toast('记忆已更新', 'success');
    closeModal();
    loadMemoryCenter();
  } catch(e) { toast(e.message || '保存失败', 'error'); }
}

function openReflectionEditModal(id) {
  var list = window.__memoryCenterReflections || [];
  var item = list.find(function(v) { return v.id === id; });
  if (!item) { toast('未找到这条复盘', 'error'); return; }
  var lessons = Array.isArray(item.lessons) ? item.lessons.join('\\n') : '';
  var adjustments = Array.isArray(item.style_adjustments) ? item.style_adjustments.join('\\n') : '';
  var h = '<div class="modal-header"><h3>编辑复盘经验</h3><button class="modal-close" onclick="closeModal()">×</button></div>';
  h += '<div class="modal-body">';
  h += '<div class="input-group" style="margin:0;"><label>复盘摘要</label><textarea id="reflection-edit-summary" class="input-field" style="min-height:96px;">' + esc(item.summary || '') + '</textarea></div>';
  h += '<div class="input-group" style="margin:0;"><label>经验原则（每行一条）</label><textarea id="reflection-edit-lessons" class="input-field" style="min-height:120px;">' + esc(lessons) + '</textarea></div>';
  h += '<div class="input-group" style="margin:0;"><label>风格调整（每行一条）</label><textarea id="reflection-edit-adjustments" class="input-field" style="min-height:100px;">' + esc(adjustments) + '</textarea></div>';
  h += '<label style="display:flex;align-items:center;gap:8px;font-size:13px;color:var(--tx2);"><input id="reflection-edit-active" type="checkbox"' + ((item.is_active === true || item.is_active === 1) ? ' checked' : '') + ' /> 启用这条复盘</label>';
  h += '</div>';
  h += '<div class="modal-footer"><button class="btn" onclick="closeModal()">取消</button><button class="btn btn-primary" onclick="saveReflectionEdit(&quot;' + esc(item.id) + '&quot;)">保存</button></div>';
  showModal(h, '760px');
}

async function saveReflectionEdit(id) {
  var summary = ((document.getElementById('reflection-edit-summary') || {}).value || '').trim();
  var lessonsRaw = ((document.getElementById('reflection-edit-lessons') || {}).value || '').trim();
  var adjustmentsRaw = ((document.getElementById('reflection-edit-adjustments') || {}).value || '').trim();
  var isActive = !!((document.getElementById('reflection-edit-active') || {}).checked);
  var lessons = lessonsRaw ? lessonsRaw.split(/\\r?\\n/).map(function(v){ return v.trim(); }).filter(Boolean) : [];
  var styleAdjustments = adjustmentsRaw ? adjustmentsRaw.split(/\\r?\\n/).map(function(v){ return v.trim(); }).filter(Boolean) : [];
  if (!summary) { toast('复盘摘要不能为空', 'error'); return; }
  try {
    await api('/user/reflections/' + encodeURIComponent(id), {
      method: 'PATCH',
      body: { summary: summary, lessons: lessons, style_adjustments: styleAdjustments, is_active: isActive }
    });
    toast('复盘已更新', 'success');
    closeModal();
    loadMemoryCenter();
  } catch(e) { toast(e.message || '保存失败', 'error'); }
}

async function promoteReflectionToSkill(id) {
  var list = window.__memoryCenterReflections || [];
  var item = list.find(function(v) { return v.id === id; });
  if (!item) { toast('未找到这条复盘', 'error'); return; }
  var defaultName = String(item.summary || '复盘技能').slice(0, 24);
  var defaultDesc = String(item.summary || '从复盘经验沉淀出的可复用工作流').slice(0, 120);
  var catOptions = MEMORY_SKILL_CATEGORY_OPTIONS.map(function(c) {
    return '<option value="' + c.id + '"' + (c.id === 'efficiency' ? ' selected' : '') + '>' + c.name + '</option>';
  }).join('');
  var h = '<div class="modal-header"><h3>沉淀为 Skill</h3><button class="modal-close" onclick="closeModal()">×</button></div>';
  h += '<div class="modal-body">';
  h += '<div style="font-size:12px;color:var(--tx2);line-height:1.8;">把这条复盘经验整理成一个可反复调用的 Skill。若同名 Skill 已存在，将直接更新。</div>';
  h += '<div class="input-group" style="margin:0;"><label>Skill 名称</label><input id="promote-skill-name" class="input-field" maxlength="24" value="' + esc(defaultName) + '" /></div>';
  h += '<div class="input-group" style="margin:0;"><label>分类</label><select id="promote-skill-category" class="input-field">' + catOptions + '</select></div>';
  h += '<div class="input-group" style="margin:0;"><label>描述</label><textarea id="promote-skill-desc" class="input-field" style="min-height:100px;">' + esc(defaultDesc) + '</textarea></div>';
  h += '</div>';
  h += '<div class="modal-footer"><button class="btn" onclick="closeModal()">取消</button><button class="btn btn-primary" onclick="submitPromoteReflectionToSkill(&quot;' + esc(id) + '&quot;)">确认沉淀</button></div>';
  showModal(h, '680px');
}

async function submitPromoteReflectionToSkill(id) {
  var name = ((document.getElementById('promote-skill-name') || {}).value || '').trim();
  var description = ((document.getElementById('promote-skill-desc') || {}).value || '').trim();
  var category = ((document.getElementById('promote-skill-category') || {}).value || 'efficiency').trim();
  if (!name) { toast('Skill 名称不能为空', 'error'); return; }
  try {
    var result = await api('/user/reflections/' + encodeURIComponent(id) + '/promote-skill', { method: 'POST', body: { name: name, description: description, category: category } });
    toast((result && result.message) || '已沉淀为 Skill', 'success');
    closeModal();
    loadMemoryCenter();
  } catch(e) { toast(e.message || '沉淀失败', 'error'); }
}

async function jumpToConversation(id) {
  if (!id) { toast('没有可跳转的来源对话', 'info'); return; }
  state.currentConvId = id;
  sessionStorage.setItem('opc-conv-id', id);
  navigate('chat');
  setTimeout(function() {
    loadConversations().then(function() {
      return selectConversation(id);
    }).catch(function(e) {
      toast((e && e.message) || '打开来源对话失败', 'error');
    });
  }, 80);
}

function buildProvinceOptions(sel) {
  var cc = window.__CHINA_CITIES__ || [];
  return cc.map(function(p) { return '<option value="' + esc(p.province) + '"' + (p.province === sel ? ' selected' : '') + '>' + esc(p.province) + '</option>'; }).join('');
}
function buildCityOptions(prov, sel) {
  var cc = window.__CHINA_CITIES__ || [];
  var p = cc.find(function(x) { return x.province === prov; });
  if (!p) return '';
  return p.citys.map(function(c) { return '<option value="' + esc(c.city) + '"' + (c.city === sel ? ' selected' : '') + '>' + esc(c.city) + '</option>'; }).join('');
}
function buildDistrictOptions(prov, city, sel) {
  var cc = window.__CHINA_CITIES__ || [];
  var p = cc.find(function(x) { return x.province === prov; });
  if (!p) return '';
  var c = p.citys.find(function(x) { return x.city === city; });
  if (!c) return '';
  return c.areas.map(function(a) { return '<option value="' + esc(a.area) + '"' + (a.area === sel ? ' selected' : '') + '>' + esc(a.area) + '</option>'; }).join('');
}

function onProfileProvinceChange() {
  var prov = (document.getElementById('profile-province') || {}).value || '';
  var cityEl = document.getElementById('profile-pcity');
  var distEl = document.getElementById('profile-district');
  if (cityEl) cityEl.innerHTML = '<option value="">\u8BF7\u9009\u62E9</option>' + buildCityOptions(prov, '');
  if (distEl) distEl.innerHTML = '<option value="">\u8BF7\u9009\u62E9</option>';
}
function onProfileCityChange() {
  var prov = (document.getElementById('profile-province') || {}).value || '';
  var city = (document.getElementById('profile-pcity') || {}).value || '';
  var distEl = document.getElementById('profile-district');
  if (distEl) distEl.innerHTML = '<option value="">\u8BF7\u9009\u62E9</option>' + buildDistrictOptions(prov, city, '');
}

async function saveProfileLocation() {
  var province = (document.getElementById('profile-province') || {}).value || '';
  var city = (document.getElementById('profile-pcity') || {}).value || '';
  var district = (document.getElementById('profile-district') || {}).value || '';
  if (!province || !city) { toast('\u8BF7\u9009\u62E9\u7701\u4EFD\u548C\u57CE\u5E02', 'error'); return; }
  try {
    await api('/user/location', { method: 'POST', body: { user_province: province, user_city: city, user_district: district } });
    toast('\u4F4D\u7F6E\u5DF2\u4FDD\u5B58', 'success');
  } catch(e) { toast(e.message, 'error'); }
}

async function saveProfileInfo() {
  var nameEl = document.getElementById('profile-name');
  var name = nameEl ? nameEl.value.trim() : '';
  if (!name) { toast('昵称不能为空', 'error'); return; }
  try {
    await api('/user/profile', { method: 'PUT', body: { name: name } });
    if (state.user) { state.user.name = name; }
    toast('资料已保存', 'success');
    loadSidebarQuota();
  } catch(e) { toast((e && e.message) || '保存失败', 'error'); }
}

var _profileCodeTimer = null;
async function sendProfileCode() {
  var emailEl = document.getElementById('profile-email');
  var email = emailEl ? emailEl.value.trim() : '';
  if (!email) { toast('请先填写邮箱', 'error'); return; }
  var btn = document.getElementById('pwd-send-code-btn');
  if (btn) { btn.disabled = true; }
  try {
    await api('/auth/send-code', { method: 'POST', body: { email: email, type: 'change_password' } });
    toast('验证码已发送至 ' + email, 'success');
    var sec = 60;
    if (_profileCodeTimer) clearInterval(_profileCodeTimer);
    _profileCodeTimer = setInterval(function() {
      sec--;
      if (btn) btn.textContent = sec + 's 后重发';
      if (sec <= 0) {
        clearInterval(_profileCodeTimer); _profileCodeTimer = null;
        if (btn) { btn.disabled = false; btn.textContent = '发送验证码'; }
      }
    }, 1000);
  } catch(e) {
    if (btn) { btn.disabled = false; btn.textContent = '发送验证码'; }
    toast((e && e.message) || '发送失败', 'error');
  }
}

async function saveNewPassword() {
  var newPwd = document.getElementById('pwd-new') ? document.getElementById('pwd-new').value : '';
  var confirmPwd = document.getElementById('pwd-confirm') ? document.getElementById('pwd-confirm').value : '';
  var code = document.getElementById('pwd-code') ? document.getElementById('pwd-code').value.trim() : '';
  var emailEl = document.getElementById('profile-email');
  var email = emailEl ? emailEl.value.trim() : '';
  if (!newPwd || newPwd.length < 8) { toast('密码至少8位', 'error'); return; }
  if (newPwd !== confirmPwd) { toast('两次密码不一致', 'error'); return; }
  if (!code) { toast('请输入邮箱验证码', 'error'); return; }
  if (!email) { toast('请填写邮箱', 'error'); return; }
  try {
    await api('/user/password', { method: 'PUT', body: { new_password: newPwd, email: email, code: code } });
    toast('密码已修改，请重新登录', 'success');
    setTimeout(function() { clearAuth(); navigate('login'); }, 1500);
  } catch(e) { toast((e && e.message) || '修改失败', 'error'); }
}

// ─── 套餐与用量 (Plan) ─────────────────────────────────────────────────

async function loadPlan() {
  var mc = document.getElementById('mc');
  if (!mc) return;
  mc.innerHTML = renderLoading();

  var q = {};
  try { q = await api('/user/quota'); state._quota = q; } catch(e) {}

  var plan = q.plan || 'free';
  var planName = q.plan_name || '内测体验';
  var quotaTotal = q.quota_total || 500;
  var quotaUsed = q.quota_used || 0;
  var quotaRem = q.quota_remaining || 0;
  var bonus = q.bonus_points || 0;
  var totalRem = plan === 'ultra' ? 50000 : quotaRem + bonus;
  var stats = q.usage_stats || {};

  // 从后端获取真实套餐定义（保证前后端一致）
  var remotePlans = [];
  try { var pr = await api('/subscription/plans'); remotePlans = pr.plans || []; } catch(e) {}

  var plans = [
    {
      id: 'free', name: '免费体验', price: 0, quota: 500,
      desc: '注册即享，每月 500 算力点',
      features: [
        '500 算力点/月',
        '约 10-15 次 AI 对话',
        '搜索工具 +2 点/次',
        '模型：qwen3.6-plus',
        '1 个定时任务',
        '基础 AI 工具集',
      ]
    }
  ];
  remotePlans.forEach(function(rp) {
    var quota = rp.quota || 0;
    var quotaStr = quota >= 1000 ? quota.toLocaleString() : String(quota);
    var ft = (rp.features && rp.features.length > 0) ? rp.features.slice() : [quotaStr + ' 算力点/月', '搜索工具 +2 点/次', '全部 AI 工具集'];
    if (ft.length > 0 && ft[0].indexOf('算力点') < 0) ft.unshift(quotaStr + ' 算力点/月');
    plans.push({ id: rp.id, name: rp.name, price: Number(rp.price), quota: quota, desc: rp.desc || rp.name, features: ft });
  });

  var pct = Math.min(100, Math.round(quotaUsed / (quotaTotal || 1) * 100));
  var barColor = pct < 70 ? 'var(--green)' : pct < 90 ? 'var(--accent)' : 'var(--red)';
  var resetDate = q.quota_reset_at ? new Date(q.quota_reset_at).toLocaleDateString('zh-CN') : '每月1日';

  var planCards = plans.map(function(p) {
    var isCurrent = p.id === plan;
    var isPopular = p.id === 'pro';
    // 免费套餐不显示选中效果，付费套餐才高亮
    var border = (isCurrent && p.price > 0) ? '2px solid var(--accent)' : (isPopular ? '2px solid var(--accent)' : '1px solid var(--bd)');
    var bg = (isCurrent && p.price > 0) ? 'background:linear-gradient(160deg,rgba(249,115,22,0.1),rgba(249,115,22,0.03));' : (isPopular ? 'background:linear-gradient(160deg,rgba(249,115,22,0.07),rgba(249,115,22,0.02));' : '');
    var featureList = p.features.map(function(f, i) {
      var isHighlight = i === 0;
      return '<div style="display:flex;align-items:flex-start;gap:8px;font-size:12px;padding:4px 0;color:' + (isHighlight ? 'var(--accent)' : 'var(--tx2)') + ';font-weight:' + (isHighlight ? '700' : '400') + ';">' +
        '<span style="color:var(--green);flex-shrink:0;margin-top:1px;font-weight:700;">✓</span><span>' + esc(f) + '</span>' +
      '</div>';
    }).join('');
    var btnHtml = (isCurrent && p.price > 0) ?
      '<button disabled style="margin-top:18px;width:100%;padding:9px 0;border-radius:8px;border:1px solid var(--bd);background:transparent;color:var(--tx3);font-size:13px;cursor:default;">当前套餐</button>' :
      (p.price > 0 ?
        '<button onclick="openSubscribeModal(&quot;' + p.id + '&quot;,&quot;' + p.name + '&quot;,' + p.price + ')" style="margin-top:18px;width:100%;padding:9px 0;border-radius:8px;border:1px solid var(--accent);background:' + (isPopular ? 'var(--accent)' : 'transparent') + ';color:' + (isPopular ? '#fff' : 'var(--accent)') + ';font-size:13px;font-weight:600;cursor:pointer;transition:all .2s;" onmouseover="this.style.opacity=&quot;.82&quot;" onmouseout="this.style.opacity=&quot;1&quot;">立即升级</button>' :
        '');
    return '<div style="border:' + border + ';border-radius:16px;padding:20px 18px 18px;' + bg + 'display:flex;flex-direction:column;position:relative;">' +
      (isPopular ? '<div style="position:absolute;top:12px;right:12px;font-size:10px;font-weight:700;color:var(--accent);background:rgba(249,115,22,0.12);padding:2px 9px;border-radius:20px;letter-spacing:.04em;">推荐</div>' : '') +
      '<div style="font-size:11px;font-weight:700;color:var(--tx3);text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px;">' + esc(p.name) + '</div>' +
      '<div style="margin-bottom:6px;">' +
        (p.price > 0 ?
          '<span style="font-size:28px;font-weight:800;color:var(--tx);line-height:1;">¥' + p.price + '</span><span style="font-size:12px;color:var(--tx3);margin-left:3px;">/月</span>' :
          '<span style="font-size:28px;font-weight:800;color:var(--green);line-height:1;">免费</span>') +
      '</div>' +
      '<div style="font-size:11px;color:var(--tx3);margin-bottom:14px;line-height:1.5;">' + esc(p.desc) + '</div>' +
      '<div style="border-top:1px solid var(--bd);padding-top:12px;flex:1;">' + featureList + '</div>' +
      btnHtml +
    '</div>';
  }).join('');

  mc.innerHTML =
    '<div class="page-inner"><div class="page-header"><h1>套餐与用量</h1><p>查看您的算力消耗和套餐信息</p></div>' +
    // 当前用量卡片
    '<div class="card" style="margin-bottom:16px;">' +
      '<div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:16px;">' +
        '<div style="flex:1;min-width:220px;">' +
          '<div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;">' +
            '<span style="font-size:12px;padding:3px 12px;border-radius:20px;font-weight:700;letter-spacing:.04em;' + (plan === 'free' ? 'background:rgba(120,113,108,0.18);color:var(--tx2);' : plan === 'basic' ? 'background:rgba(59,130,246,0.15);color:#60a5fa;' : plan === 'pro' ? 'background:rgba(249,115,22,0.15);color:var(--accent);' : 'background:rgba(168,85,247,0.15);color:#c084fc;') + '">' + (plan === 'free' ? 'FREE' : plan.toUpperCase()) + '</span>' +
            (bonus > 0 ? '<span style="font-size:11px;color:var(--green);">+' + bonus + ' 赠点</span>' : '') +
          '</div>' +
          (plan !== 'ultimate' ?
            '<div style="font-size:13px;color:var(--tx2);margin-bottom:8px;">本月用量 <span style="color:var(--fg);font-weight:600;">' + quotaUsed + '</span> / ' + quotaTotal + ' 算力点</div>' +
            '<div class="quota-bar-wrap" style="height:8px;margin-bottom:6px;"><div class="quota-bar" style="width:' + pct + '%;background:' + barColor + ';"></div></div>' +
            '<div style="font-size:11px;color:var(--tx3);">剩余 ' + totalRem + ' 点（含赠点）· 下次重置：' + resetDate + '</div>'
            :
            '<div style="font-size:13px;color:var(--tx2);margin-bottom:8px;">本月用量 <span style="color:var(--fg);font-weight:600;">' + quotaUsed + '</span> / 30,000 算力点</div>' +
            '<div class="quota-bar-wrap" style="height:8px;margin-bottom:6px;"><div class="quota-bar" style="width:' + Math.min(100,Math.round(quotaUsed/300)) + '%;background:var(--green);"></div></div>' +
            '<div style="font-size:11px;color:var(--tx3);">旗舰版 · 超大算力包 · 下次重置：' + resetDate + '</div>') +
        '</div>' +
        '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;min-width:280px;">' +
          '<div style="text-align:center;padding:12px;background:var(--bg-soft);border-radius:10px;">' +
            '<div style="font-size:20px;font-weight:700;color:var(--accent);">' + Math.round(Number(stats.today_cost_points) || 0) + '</div>' +
            '<div style="font-size:11px;color:var(--tx3);margin-top:2px;">今日消耗</div>' +
          '</div>' +
          '<div style="text-align:center;padding:12px;background:var(--bg-soft);border-radius:10px;">' +
            '<div style="font-size:20px;font-weight:700;color:var(--fg);">' + quotaUsed + '</div>' +
            '<div style="font-size:11px;color:var(--tx3);margin-top:2px;">本月消耗</div>' +
          '</div>' +
          '<div style="text-align:center;padding:12px;background:var(--bg-soft);border-radius:10px;">' +
            '<div style="font-size:20px;font-weight:700;color:var(--fg);">' + Math.round(Number(stats.total_requests) || 0) + '</div>' +
            '<div style="font-size:11px;color:var(--tx3);margin-top:2px;">累计对话</div>' +
          '</div>' +
        '</div>' +
      '</div>' +
    '</div>' +
    // 套餐对比
    '<div style="margin-bottom:16px;"><h3 style="font-size:15px;font-weight:700;margin:0 0 14px;">套餐对比</h3>' +
    '<div style="display:grid;grid-template-columns:repeat(' + plans.length + ',1fr);gap:12px;align-items:stretch;">' + planCards + '</div></div>' +
    // 使用详情
    '<div style="margin-bottom:16px;"><h3 style="font-size:15px;font-weight:700;margin:0 0 14px;">使用详情</h3>' +
    '<div id="usage-log-list">' + renderLoading() + '</div></div>' +
    // 我的订单
    '<div style="margin-bottom:16px;"><div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;"><h3 style="font-size:15px;font-weight:700;margin:0;">我的订单</h3></div>' +
    '<div id="my-orders-list">' + renderLoading() + '</div></div>' +
    // 用户用量表（管理员移至独立页面）
    '</div>';
  // 加载使用详情（表格，分页，日期筛选）
  window._planLogState = { page: 1, dateFrom: '', dateTo: '' };
  loadPlanUsageLogs(1);
  // 加载我的订单
  loadMyOrders();
}

// ─── 我的订单 & 管理员订单 ────────────────────────────────────────────

var ORDER_STATUS_MAP = {
  'pending': { label: '待付款', color: 'var(--orange)' },
  'paid':    { label: '已生效', color: 'var(--green)' },
  'expired': { label: '已过期', color: 'var(--tx3)' },
  'cancelled': { label: '已取消', color: 'var(--tx3)' },
};
var PLAN_NAME_MAP = { basic: '基础版', pro: '专业版', ultimate: '旗舰版' };

async function loadMyOrders() {
  var el = document.getElementById('my-orders-list');
  if (!el) return;
  try {
    var d = await api('/orders');
    var orders = d.orders || [];
    if (orders.length === 0) {
      el.innerHTML = '<p style="color:var(--tx3);font-size:13px;text-align:center;padding:20px 0;">暂无订单记录</p>';
      return;
    }
    var rows = orders.map(function(o) {
      var st = ORDER_STATUS_MAP[o.status] || { label: o.status, color: 'var(--tx3)' };
      var planLabel = PLAN_NAME_MAP[o.plan_id] || o.plan_id || '-';
      var actionBtn = o.status === 'pending'
        ? '<button onclick="cancelMyOrder(&quot;' + o.id + '&quot;,this)" class="btn btn-sm" style="font-size:11px;padding:3px 10px;color:var(--orange);border-color:rgba(249,115,22,.35);">取消订单</button>'
        : '<button onclick="deleteMyOrder(&quot;' + o.id + '&quot;,this)" class="btn btn-sm" style="font-size:11px;padding:3px 10px;color:var(--red);border-color:rgba(239,68,68,.35);">删除</button>';
      return '<tr>' +
        '<td style="font-family:monospace;font-size:12px;color:var(--tx3);">' + esc((o.id || '').slice(0,8).toUpperCase()) + '</td>' +
        '<td>' + esc(planLabel) + '</td>' +
        '<td style="font-weight:600;color:var(--accent);">¥' + ((o.amount_fen || 0) / 100).toFixed(2) + '</td>' +
        '<td><span style="font-size:11px;padding:2px 9px;border-radius:10px;background:rgba(0,0,0,.2);color:' + st.color + ';font-weight:700;">' + st.label + '</span></td>' +
        '<td style="font-size:12px;color:var(--tx3);">' + (o.created_at ? new Date(o.created_at).toLocaleString('zh-CN') : '-') + '</td>' +
        '<td style="font-size:12px;color:var(--tx3);">' + (o.paid_at ? new Date(o.paid_at).toLocaleString('zh-CN') : '-') + '</td>' +
        '<td>' + actionBtn + '</td>' +
      '</tr>';
    }).join('');
    el.innerHTML = '<div class="table-wrap"><table><thead><tr><th>订单号</th><th>套餐</th><th>金额</th><th>状态</th><th>创建时间</th><th>生效时间</th><th>操作</th></tr></thead><tbody>' + rows + '</tbody></table></div>';
  } catch(e) {
    el.innerHTML = '<p style="color:var(--red);font-size:13px;">加载失败</p>';
  }
}

async function loadAdminOrders() {
  var el = document.getElementById('admin-orders-list');
  if (!el) return;
  try {
    var d = await api('/admin/orders');
    var orders = d.orders || [];
    if (orders.length === 0) {
      el.innerHTML = '<p style="color:var(--tx3);font-size:13px;text-align:center;padding:20px 0;">暂无订单</p>';
      return;
    }
    var rows = orders.map(function(o) {
      var st = ORDER_STATUS_MAP[o.status] || { label: o.status, color: 'var(--tx3)' };
      var planLabel = PLAN_NAME_MAP[o.plan_id] || o.plan_id || '-';
      var confirmBtn = o.status === 'pending' ?
        '<button onclick="adminConfirmOrder(&quot;' + o.id + '&quot;,this)" class="btn btn-sm btn-primary" style="font-size:11px;padding:3px 10px;">确认付款</button>' : '';
      return '<tr>' +
        '<td style="font-family:monospace;font-size:12px;color:var(--tx3);">' + esc((o.id || '').slice(0,8).toUpperCase()) + '</td>' +
        '<td style="font-size:12px;">' + esc(o.user_phone || o.user_id || '-') + '</td>' +
        '<td>' + esc(planLabel) + '</td>' +
        '<td style="font-weight:600;color:var(--accent);">¥' + ((o.amount_fen || 0) / 100).toFixed(2) + '</td>' +
        '<td><span style="font-size:11px;padding:2px 9px;border-radius:10px;background:rgba(0,0,0,.2);color:' + st.color + ';font-weight:700;">' + st.label + '</span></td>' +
        '<td style="font-size:12px;color:var(--tx3);">' + (o.created_at ? new Date(o.created_at).toLocaleString('zh-CN') : '-') + '</td>' +
        '<td>' + confirmBtn + '</td>' +
      '</tr>';
    }).join('');
    el.innerHTML = '<div class="table-wrap"><table><thead><tr><th>订单号</th><th>用户</th><th>套餐</th><th>金额</th><th>状态</th><th>创建时间</th><th>操作</th></tr></thead><tbody>' + rows + '</tbody></table></div>';
  } catch(e) {
    el.innerHTML = '<p style="color:var(--red);font-size:13px;">加载失败</p>';
  }
}

async function cancelMyOrder(orderId, btn) {
  if (!orderId) return;
  if (btn) { btn.disabled = true; btn.textContent = '取消中...'; }
  try {
    await api('/orders/' + orderId + '/cancel', { method: 'POST' });
    loadMyOrders();
  } catch(e) {
    if (btn) { btn.disabled = false; btn.textContent = '取消订单'; }
    toast('取消失败：' + ((e && e.message) || '未知错误'));
  }
}

async function deleteMyOrder(orderId, btn) {
  if (!orderId) return;
  if (btn) { btn.disabled = true; btn.textContent = '删除中...'; }
  try {
    await api('/orders/' + orderId, { method: 'DELETE' });
    loadMyOrders();
  } catch(e) {
    if (btn) { btn.disabled = false; btn.textContent = '删除'; }
    toast('删除失败：' + ((e && e.message) || '未知错误'));
  }
}

