var _aiVideoScriptJson = '';

async function aiVideoGenerate() {
  var topic = document.getElementById('av-topic').value.trim();
  if (!topic) { toast('\u8BF7\u8F93\u5165\u89C6\u9891\u4E3B\u9898', 'error'); return; }
  var scenesCount = document.getElementById('av-scenes').value;
  var btn = document.getElementById('av-gen-btn');
  btn.disabled = true; btn.textContent = 'AI \u751F\u6210\u4E2D...';

  var nl = String.fromCharCode(10);
  var schemaHint = '{ "productName": "\u4EA7\u54C1\u540D", "tagline": "\u4E00\u53E5\u8BDD\u5B9A\u4F4D", "accentColor": "#f97316", "scenes": [{ "icon": "emoji", "title": "\u6807\u9898", "subtitle": "\u526F\u6807\u9898", "color": "#\u989C\u8272", "body": "\u6B63\u6587\u8BF4\u660E(50-80\u5B57)", "subs": [{ "text": "\u5B57\u5E55", "start": 0, "end": 80 }, { "text": "\u7B2C\u4E8C\u6761", "start": 80, "end": 210 }] }] }';
  var prompt = '\u4F60\u662F\u4E00\u4F4D\u4E13\u4E1A\u89C6\u9891\u811A\u672C\u7B56\u5212\u5E08\u3002\u8BF7\u4E3A\u4E3B\u9898\u300C' + topic + '\u300D\u5236\u4F5C\u4E00\u4E2A\u5305\u542B ' + scenesCount + ' \u4E2A\u573A\u666F\u7684\u77ED\u89C6\u9891\u811A\u672C\u3002' + nl + '\u8FD4\u56DE\u683C\u5F0F\u5982\u4E0B\uFF08\u53EA\u8FD4\u56DE JSON\uFF0C\u4E0D\u8981\u52A0\u5176\u4ED6\u6587\u5B57\uFF09\uFF1A' + nl + schemaHint + nl + '\u8981\u6C42\uFF1Ascenes \u6570\u91CF\u4E3A ' + scenesCount + '\uFF0Csubs \u7684 end \u503C\u4E0D\u8981\u8D85\u8FC7 210\u3002';

  try {
    var result = await api('/chat/simple', { method: 'POST', body: { message: prompt } });
    var raw = (result.content || '').trim();
    var bt = String.fromCharCode(96); var fence = bt+bt+bt;
    if (raw.indexOf(fence+'json') === 0) raw = raw.slice(7);
    else if (raw.indexOf(fence) === 0) raw = raw.slice(3);
    if (raw.slice(-3) === fence) raw = raw.slice(0,-3);
    raw = raw.trim();

    var parsed = JSON.parse(raw);
    _aiVideoScriptJson = JSON.stringify(parsed, null, 2);

    var preview = document.getElementById('av-script-preview');
    var box = document.getElementById('av-script-box');
    preview.innerHTML =
      '<div style="margin-bottom:8px;"><strong>' + esc(parsed.productName || '') + '</strong> &nbsp; <span style="color:var(--tx3);">' + esc(parsed.tagline || '') + '</span></div>' +
      (parsed.scenes || []).map(function(s, i) {
        return '<div style="display:flex;align-items:flex-start;gap:10px;padding:8px 0;border-top:1px solid var(--bd);">' +
          '<span style="font-size:20px;">' + (s.icon || '') + '</span>' +
          '<div><div style="font-weight:600;">' + esc(s.title||'') + '</div><div style="color:var(--tx3);font-size:12px;">' + esc(s.subtitle||'') + '</div><div style="font-size:12px;margin-top:4px;">' + esc(s.body||'') + '</div></div>' +
          '</div>';
      }).join('');
    box.style.display = '';
    document.getElementById('av-render-btn').disabled = false;
    toast('\u811A\u672C\u751F\u6210\u6210\u529F\uFF0C\u53EF\u4EE5\u5F00\u59CB\u6E32\u67D3', 'success');
  } catch(e) {
    toast('AI \u751F\u6210\u5931\u8D25: ' + e.message, 'error');
  }
  btn.disabled = false; btn.textContent = '\u2728 AI \u91CD\u65B0\u751F\u6210';
}

function aiVideoEditScript() {
  var raw = document.getElementById('av-script-raw');
  var preview = document.getElementById('av-script-preview');
  if (raw.style.display === 'none') {
    raw.value = _aiVideoScriptJson;
    raw.style.display = '';
    preview.style.display = 'none';
  } else {
    try {
      _aiVideoScriptJson = JSON.stringify(JSON.parse(raw.value), null, 2);
      preview.style.display = '';
      raw.style.display = 'none';
      toast('\u5185\u5BB9\u5DF2\u66F4\u65B0', 'success');
    } catch(e) { toast('JSON \u683C\u5F0F\u9519\u8BEF\uFF0C\u8BF7\u68C0\u67E5', 'error'); }
  }
}

async function aiVideoRender() {
  if (!_aiVideoScriptJson) { toast('\u8BF7\u5148\u751F\u6210\u811A\u672C', 'error'); return; }
  var topic = document.getElementById('av-topic').value.trim() || 'AI\u89C6\u9891';
  var btn = document.getElementById('av-render-btn');
  btn.disabled = true; btn.textContent = '\u63D0\u4EA4\u6E32\u67D3\u4E2D...';
  try {
    var result = await api('/video/render', { method: 'POST', body: { title: topic, script_json: _aiVideoScriptJson } });
    if (result.video_id) {
      toast('\u5DF2\u52A0\u5165\u6E32\u67D3\u961F\u5217\uFF0C\u8BF7\u7B49\u5F852-5\u5206\u949F', 'info');
      aiVideoLoadJobs();
      // 每 8 秒自动轮询进度
      var _avPollTimer = setInterval(async function() {
        try {
          var jobsRes = await api('/video/jobs').catch(function() { return { videos: [] }; });
          var filesRes = await api('/video/files').catch(function() { return { files: [] }; });
          aiVideoRenderJobsList(jobsRes.videos || [], filesRes.files || []);
          var allDone = (jobsRes.videos || []).every(function(j) {
            return j.status === 'completed' || j.status === 'failed';
          });
          if (allDone) clearInterval(_avPollTimer);
        } catch(e) { clearInterval(_avPollTimer); }
      }, 8000);
    } else {
      toast(result.error || '\u63D0\u4EA4\u5931\u8D25', 'error');
    }
  } catch(e) { toast('\u6E32\u67D3\u5931\u8D25: ' + e.message, 'error'); }
  btn.disabled = false; btn.textContent = '\u25B6 \u5F00\u59CB\u6E32\u67D3';
}

async function aiVideoLoadJobs() {
  try {
    // 同时拉取任务队列 + 磁盘文件
    var jobsResult = await api('/video/jobs').catch(function() { return { videos: [] }; });
    var filesResult = await api('/video/files').catch(function() { return { files: [] }; });
    aiVideoRenderJobsList(jobsResult.videos || [], filesResult.files || []);
  } catch(e) {}
}

function aiVideoRenderJobsList(videos, diskFiles) {
  var el = document.getElementById('av-jobs-list');
  if (!el) return;

  // 任务队列
  var h = '';
  if (videos && videos.length) {
    h += '<div style="font-size:12px;font-weight:700;color:var(--tx);margin-bottom:8px;">渲染队列</div>';
    videos.slice().reverse().forEach(function(v) {
      var statusColor = v.status === 'completed' ? '#22c55e' : v.status === 'failed' ? '#ef4444' : '#f97316';
      var statusText = { queued: '排队中', rendering: '渲染中...', completed: '完成', failed: '失败' }[v.status] || v.status;
      h += '<div style="border:1px solid var(--bd);border-radius:8px;padding:12px;margin-bottom:10px;">';
      h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">';
      h += '<div><div style="font-weight:600;font-size:14px;">' + esc(v.title) + '</div>';
      h += '<div style="font-size:11px;color:var(--tx3);">' + new Date(v.created_at).toLocaleString('zh-CN') + '</div></div>';
      h += '<span style="font-size:12px;color:' + statusColor + ';font-weight:600;">' + statusText + '</span>';
      h += '</div>';
      if (v.error) h += '<div style="font-size:12px;color:#ef4444;margin-bottom:6px;">' + esc(v.error.slice(0, 120)) + '</div>';
      if (v.output_url) {
        h += '<video src="' + v.output_url + '" controls style="width:100%;max-height:280px;border-radius:6px;background:#000;"></video>';
        h += '<div style="display:flex;gap:8px;margin-top:8px;">';
        h += '<a href="' + v.output_url + '" target="_blank" class="btn btn-sm btn-primary" style="font-size:12px;">▶ 在新标签播放</a>';
        h += '<a href="' + v.output_url + '" download class="btn btn-sm" style="font-size:12px;">⬇ 下载 MP4</a>';
        h += '</div>';
      } else if (v.status === 'rendering' || v.status === 'queued') {
        h += '<div style="font-size:12px;color:#f97316;padding:6px 0;">⏳ 正在渲染，视频较大约需 2-5 分钟...</div>';
      }
      h += '</div>';
    });
  }

  // 磁盘上的历史视频（包含工作流生成的）
  if (diskFiles && diskFiles.length) {
    h += '<div style="display:flex;align-items:center;justify-content:space-between;margin:16px 0 8px;">';
    h += '<div style="font-size:12px;font-weight:700;color:var(--tx);">全部视频文件</div>';
    h += '<button onclick="openVideoFolder()" style="display:inline-flex;align-items:center;gap:4px;background:rgba(0,0,0,0.06);color:var(--tx2);padding:4px 10px;border-radius:6px;font-size:12px;border:1px solid var(--bd);cursor:pointer;">📂 打开文件夹</button>';
    h += '</div>';
    diskFiles.forEach(function(f) {
      var sizeMb = (f.size / 1024 / 1024).toFixed(1);
      h += '<div style="border:1px solid var(--bd);border-radius:8px;padding:12px;margin-bottom:10px;">';
      h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">';
      h += '<div><div style="font-weight:500;font-size:13px;font-family:monospace;">' + esc(f.name) + '</div>';
      h += '<div style="font-size:11px;color:var(--tx3);">' + new Date(f.mtime).toLocaleString('zh-CN') + ' · ' + sizeMb + ' MB</div></div>';
      h += '<div style="display:flex;gap:6px;">';
      h += '<a href="' + f.url + '" target="_blank" class="btn btn-sm btn-primary" style="font-size:12px;">▶ 播放</a>';
      h += '<a href="' + f.url + '" download class="btn btn-sm" style="font-size:12px;">⬇ 下载</a>';
      h += '</div></div>';
      h += '<video src="' + f.url + '" controls preload="metadata" style="width:100%;max-height:240px;border-radius:6px;background:#000;"></video>';
      h += '</div>';
    });
  }

  if (!h) h = '<p style="color:var(--tx3);font-size:13px;">暂无视频，点击上方生成并渲染第一个视频</p>';
  el.innerHTML = h;
}

