async function adminWarmOpportunityEnrichments(forceRefresh) {
  var province = ((document.getElementById('admin-enrich-province') || {}).value || '').trim();
  var city = ((document.getElementById('admin-enrich-city') || {}).value || '').trim();
  var county = ((document.getElementById('admin-enrich-county') || {}).value || '').trim();
  var limit = Number(((document.getElementById('admin-enrich-limit') || {}).value || 20));
  var el = document.getElementById('admin-enrichment-result');
  if (el) el.innerHTML = '<div style="padding:12px 14px;border:1px solid var(--bd);border-radius:12px;background:var(--bg-soft);">正在预生成资源内容，请稍候…</div>';
  try {
    var data = await api('/admin/opportunity-enrichments/warmup', {
      method: 'POST',
      body: {
        province: province,
        city: city,
        county: county,
        limit: limit,
        refresh: !!forceRefresh
      }
    });
    var items = data.items || [];
    if (el) {
      el.innerHTML =
        '<div style="padding:12px 14px;border:1px solid rgba(34,197,94,.18);border-radius:12px;background:rgba(34,197,94,.06);">' +
          '本次处理 <b>' + esc(String(data.total || 0)) + '</b> 条，新增生成 <b>' + esc(String(data.generated || 0)) + '</b> 条，命中缓存 <b>' + esc(String(data.cached || 0)) + '</b> 条，回退兜底 <b>' + esc(String(data.stale || 0)) + '</b> 条。' +
        '</div>' +
        '<div style="margin-top:10px;display:grid;gap:8px;">' +
          items.slice(0, 12).map(function(item) {
            return '<div style="padding:10px 12px;border:1px solid var(--bd);border-radius:12px;background:var(--bg);">' +
              '<div style="font-size:12px;font-weight:700;color:var(--tx);">' + esc(item.title || item.id || '-') + '</div>' +
              '<div style="font-size:11px;color:var(--tx3);margin-top:4px;">强度：' + esc(item.strength || '-') + ' · 优先级：' + esc(item.priority || '-') + ' · 状态：' + esc(item.stale ? '兜底' : (item.cached ? '缓存' : '新生成')) + (item.error ? ' · ' + esc(item.error) : '') + '</div>' +
            '</div>';
          }).join('') +
        '</div>';
    }
    toast('资源内容预生成完成', 'success');
  } catch(e) {
    if (el) el.innerHTML = '<div style="padding:12px 14px;border:1px solid rgba(239,68,68,.18);border-radius:12px;background:rgba(239,68,68,.06);color:var(--red);">预生成失败：' + esc(e.message || '未知错误') + '</div>';
    toast(e.message || '预生成失败', 'error');
  }
}

async function renderCanvasContent() {
  var el = document.getElementById('canvas-content'); if (!el) return;
  var cid = getModuleCompanyId(); if (!cid) { el.innerHTML = renderNoCompanyContent('请先创建一家公司，再使用商业分析。'); return; }
  el.innerHTML = renderLoading();
  try {
    var data = await api('/companies/' + cid + '/canvas');
    var compassData = await api('/companies/' + cid + '/compass').catch(function() { return { compass: {}, models: [] }; });
    var c = data.canvas || {};
    var cp = compassData.compass || {};
    var models = compassData.models || [];
    var groups = [
      { title: '\u5BA2\u6237\u5C42', fields: [
        { key: 'target_customer', label: '\u76EE\u6807\u5BA2\u6237' },
        { key: 'pain_point', label: '\u5BA2\u6237\u75DB\u70B9' },
        { key: 'channels', label: '\u6E20\u9053\u901A\u8DEF' }
      ]},
      { title: '\u4EF7\u503C\u5C42', fields: [
        { key: 'solution', label: '\u89E3\u51B3\u65B9\u6848' },
        { key: 'unique_value', label: '\u72EC\u7279\u4EF7\u503C' },
        { key: 'revenue_model', label: '\u6536\u5165\u6A21\u5F0F' },
        { key: 'cost_structure', label: '\u6210\u672C\u7ED3\u6784' }
      ]},
      { title: '\u8FD0\u8425\u5C42', fields: [
        { key: 'key_resources', label: '\u6838\u5FC3\u8D44\u6E90' },
        { key: 'key_activities', label: '\u6838\u5FC3\u6D3B\u52A8' },
        { key: 'key_partners', label: '\u6838\u5FC3\u4F19\u4F34' },
        { key: 'metrics', label: '\u5173\u952E\u6307\u6807' }
      ]},
      { title: '\u6218\u7565\u5C42', fields: [
        { key: 'track', label: '\u8D5B\u9053\u9009\u62E9' },
        { key: 'unfair_advantage', label: '\u7ADE\u4E89\u58C1\u5792' },
        { key: 'non_compete', label: '\u975E\u7ADE\u4E89\u4F18\u52BF' },
        { key: 'scaling_strategy', label: '\u89C4\u6A21\u5316\u7B56\u7565' },
        { key: 'notes', label: '\u5907\u6CE8' }
      ]}
    ];
    var filled = 0, total = 0;
    groups.forEach(function(g) { g.fields.forEach(function(f) { total++; if (c[f.key]) filled++; }); });
    var pct = total > 0 ? Math.round(filled / total * 100) : 0;
    var html = '<div class="card" style="margin-bottom:16px;background:linear-gradient(135deg,rgba(249,115,22,.08),transparent);"><div style="display:flex;justify-content:space-between;gap:16px;align-items:flex-start;"><div><div style="font-size:15px;font-weight:700;color:var(--tx);margin-bottom:6px;">商业分析底稿</div><div style="font-size:12px;color:var(--tx2);line-height:1.8;">这一页用于沉淀商业模式、客户痛点、收入结构和增长策略。先把结构补齐，再交给 AI 做延展分析和项目推演。</div></div><div style="min-width:140px;"><div style="display:flex;justify-content:space-between;font-size:13px;margin-bottom:6px;"><span>\u5B8C\u6210\u5EA6 ' + filled + '/' + total + '</span><span>' + pct + '%</span></div><div style="height:6px;background:var(--bd);border-radius:3px;overflow:hidden;"><div style="height:100%;width:' + pct + '%;background:var(--accent);border-radius:3px;transition:width 0.3s;"></div></div></div></div></div>';
    groups.forEach(function(g) {
      html += '<div class="card" style="margin-bottom:16px;"><h3 style="font-size:14px;font-weight:700;margin-bottom:12px;color:var(--accent);">' + g.title + '</h3><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px;">';
      g.fields.forEach(function(f) {
        html += '<div class="input-group"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px;"><label style="margin-bottom:0;">' + f.label + '</label><button class="btn btn-sm" style="font-size:11px;padding:2px 8px;height:22px;line-height:1;background:linear-gradient(135deg,#f97316,#fb923c);color:#fff;border:none;border-radius:4px;cursor:pointer;white-space:nowrap;" data-k="' + f.key + '" data-l="' + f.label + '" onclick="aiCanvasFill(this.dataset.k,this.dataset.l,this)">✨ AI 填写</button></div><textarea class="input-field canvas-field" data-key="' + f.key + '" rows="3" placeholder="\u8BF7\u586B\u5199' + f.label + '">' + esc(cleanDirtyPlaceholderText(c[f.key], '')) + '</textarea></div>';
      });
      html += '</div></div>';
    });
    html += '<div style="display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;"><button class="btn btn-secondary btn-sm" onclick="aiCanvasFillAll()">\u2728 AI \u4E00\u952E\u586B\u5145\u5168\u90E8</button><div style="display:flex;gap:10px;flex-wrap:wrap;"><button class="btn btn-sm" onclick="showCanvasTutorial()">分析教程</button><button class="btn btn-primary" onclick="saveCanvas()">保存分析</button></div></div>';
    var dims = [
      { key: 'passions', label: 'Passions 激情', icon: '❤️', color: '#EF4444' },
      { key: 'positions', label: 'Positions 位置', icon: '📍', color: '#F59E0B' },
      { key: 'possessions', label: 'Possessions 资源', icon: '📦', color: '#10B981' },
      { key: 'powers', label: 'Powers 能力', icon: '⚡', color: '#3B82F6' },
      { key: 'potentials', label: 'Potentials 潜力', icon: '🌟', color: '#8B5CF6' }
    ];
    html += '<div class="card" style="margin-top:18px;"><div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;flex-wrap:wrap;margin-bottom:14px;"><div><h3 style="font-size:15px;font-weight:700;margin-bottom:6px;">5P 自我画像</h3><p style="font-size:12px;color:var(--tx2);line-height:1.8;">把创始人的激情、位置、资源、能力和潜力补齐，后续的商业方向和模式池才有判断依据。</p></div><div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-secondary btn-sm" onclick="aiCompassFillAll()">✨ AI 生成 5P</button><button class="btn btn-primary btn-sm" onclick="saveCompass()">保存 5P</button></div></div><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:12px;">';
    dims.forEach(function(d) {
      html += '<div style="border:1px solid var(--bd);border-left:3px solid ' + d.color + ';border-radius:14px;padding:12px 12px 10px;background:var(--bg);"><div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;"><span>' + d.icon + '</span><strong style="font-size:13px;color:var(--tx);">' + d.label + '</strong></div><textarea class="input-field compass-field" data-key="' + d.key + '" rows="4" placeholder="请填写...">' + esc(cp[d.key] || '') + '</textarea></div>';
    });
    html += '</div></div>';
    html += '<div class="card" style="margin-top:16px;"><div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;flex-wrap:wrap;margin-bottom:12px;"><div><h3 style="font-size:15px;font-weight:700;margin-bottom:6px;">商业模式池</h3><p style="font-size:12px;color:var(--tx2);line-height:1.8;">把商业想法沉淀成可比较的模式池，方便筛选值得先做的方向。</p></div><div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-sm" onclick="showCompassTutorial()">5P 教程</button><button class="btn btn-primary btn-sm" onclick="showAddModelModal()">添加模式</button></div></div>';
    if (!models.length) {
      html += '<div style="font-size:12px;color:var(--tx3);padding:8px 0 2px;">暂无商业模式。先补齐 5P，再添加 1-3 个可验证的生意方向。</div>';
    } else {
      html += '<div class="table-wrap"><table><thead><tr><th>模式名</th><th>目标客户</th><th>兴奋度</th><th>匹配度</th><th>状态</th><th>操作</th></tr></thead><tbody>';
      models.forEach(function(m) {
        html += '<tr><td style="font-weight:600;">' + esc(cleanDirtyPlaceholderText(m.name, '未命名模式')) + '</td><td>' + esc(cleanDirtyPlaceholderText(m.who || '', '')) + '</td><td>' + '⭐'.repeat(Math.min(5, Number(m.excitement) || 0)) + '</td><td>' + esc(String(m.fit_score || 0)) + '/5</td><td>' + esc(m.status || '') + '</td><td><button class="btn btn-sm btn-danger" onclick="deleteBizModel(&quot;' + m.id + '&quot;)">删除</button></td></tr>';
      });
      html += '</tbody></table></div>';
    }
    html += '</div>';
    el.innerHTML = '<div style="display:flex;flex-direction:column;flex:1;">' + html + '</div>';
  } catch(e) { el.innerHTML = '<p style="color:var(--red);text-align:center;">\u52A0\u8F7D\u5931\u8D25: ' + esc(e.message) + '</p>'; }
}

async function saveCanvas() {
  var cid = getModuleCompanyId(); if (!cid) return;
  var body = {};
  document.querySelectorAll('.canvas-field').forEach(function(el) { body[el.dataset.key] = el.value; });
  try { await api('/companies/' + cid + '/canvas', { method: 'PUT', body: body }); toast('\u753B\u5E03\u5DF2\u4FDD\u5B58', 'success'); } catch(e) { toast(e.message, 'error'); }
}

// 收集画布当前已填内容，作为 AI 上下文
function getCanvasContext() {
  var ctx = [];
  var labelMap = {
    target_customer: '\u76EE\u6807\u5BA2\u6237', pain_point: '\u5BA2\u6237\u75DB\u70B9', channels: '\u6E20\u9053\u901A\u8DEF',
    solution: '\u89E3\u51B3\u65B9\u6848', unique_value: '\u72EC\u7279\u4EF7\u503C', revenue_model: '\u6536\u5165\u6A21\u5F0F', cost_structure: '\u6210\u672C\u7ED3\u6784',
    key_resources: '\u6838\u5FC3\u8D44\u6E90', key_activities: '\u6838\u5FC3\u6D3B\u52A8', key_partners: '\u6838\u5FC3\u4F19\u4F34', metrics: '\u5173\u952E\u6307\u6807',
    track: '\u8D5B\u9053\u9009\u62E9', unfair_advantage: '\u7ADE\u4E89\u58C1\u5792', non_compete: '\u975E\u7ADE\u4E89\u4F18\u52BF', scaling_strategy: '\u89C4\u6A21\u5316\u7B56\u7565', notes: '\u5907\u6CE8'
  };
  document.querySelectorAll('.canvas-field').forEach(function(el) {
    if (el.value.trim()) ctx.push(labelMap[el.dataset.key] + '\uFF1A' + el.value.trim());
  });
  return ctx.join(String.fromCharCode(10));
}

async function aiCanvasFill(key, label, btn) {
  var ta = document.querySelector('.canvas-field[data-key="' + key + '"]');
  if (!ta) return;
  var origText = btn.textContent;
  btn.disabled = true; btn.textContent = '\u751F\u6210\u4E2D...';
  var ctx = getCanvasContext();
  var nl=String.fromCharCode(10); var ctxPart = ctx ? nl+nl+'\u5DF2\u586B\u5185\u5BB9\u4F9B\u53C2\u8003\uFF1A'+nl + ctx : '';
  var prompt = '\u6211\u5728\u586B\u5199\u4E00\u4EBA\u516C\u53F8\u7684 OPB \u753B\u5E03\u3002\u8BF7\u4E3A\u300C' + label + '\u300D\u6A21\u5757\u751F\u6210\u4E00\u6BB5\u7B80\u6D01\u3001\u5177\u4F53\u3001\u5B9E\u7528\u7684\u5185\u5BB9\uFF08100\u5B57\u5185\uFF09\u3002\u76F4\u63A5\u8F93\u51FA\u5185\u5BB9\u672C\u8EAB\uFF0C\u4E0D\u8981\u52A0\u6807\u9898\u548C\u89E3\u91CA\u3002' + ctxPart;
  try {
    var result = await api('/chat/simple', { method: 'POST', body: { message: prompt } });
    ta.value = result.content || '';
    ta.style.borderColor = 'var(--accent)';
    setTimeout(function() { ta.style.borderColor = ''; }, 2000);
    toast(label + ' \u5DF2\u7531 AI \u586B\u5199', 'success');
  } catch(e) { toast('AI \u751F\u6210\u5931\u8D25: ' + e.message, 'error'); }
  finally { btn.disabled = false; btn.textContent = origText; }
}
window.aiCanvasFill = aiCanvasFill;

async function aiCanvasFillAll() {
  var fields = [
    { key: 'target_customer', label: '\u76EE\u6807\u5BA2\u6237' },
    { key: 'pain_point', label: '\u5BA2\u6237\u75DB\u70B9' },
    { key: 'channels', label: '\u6E20\u9053\u901A\u8DEF' },
    { key: 'solution', label: '\u89E3\u51B3\u65B9\u6848' },
    { key: 'unique_value', label: '\u72EC\u7279\u4EF7\u503C' },
    { key: 'revenue_model', label: '\u6536\u5165\u6A21\u5F0F' },
    { key: 'cost_structure', label: '\u6210\u672C\u7ED3\u6784' },
    { key: 'key_resources', label: '\u6838\u5FC3\u8D44\u6E90' },
    { key: 'key_activities', label: '\u6838\u5FC3\u6D3B\u52A8' },
    { key: 'key_partners', label: '\u6838\u5FC3\u4F19\u4F34' },
    { key: 'metrics', label: '\u5173\u952E\u6307\u6807' },
    { key: 'track', label: '\u8D5B\u9053\u9009\u62E9' },
    { key: 'unfair_advantage', label: '\u7ADE\u4E89\u58C1\u5792' },
    { key: 'non_compete', label: '\u975E\u7ADE\u4E89\u4F18\u52BF' },
    { key: 'scaling_strategy', label: '\u89C4\u6A21\u5316\u7B56\u7565' },
  ];
  // 先收集公司名作为上下文
  var cname = '';
  var sel = document.querySelector('.module-company-select');
  if (sel) { var opt = sel.options[sel.selectedIndex]; if (opt) cname = opt.text; }
  toast('\u2728 AI \u6B63\u5728\u9010\u4E00\u586B\u5145\u753B\u5E03\uFF0C\u8BF7\u7A0D\u5019...', 'info');
  var prompt = '\u6211\u5728\u586B\u5199\u4E00\u4EBA\u516C\u53F8\u300C' + (cname || '\u6211\u7684\u516C\u53F8') + '\u300D\u7684 OPB \u753B\u5E03\u3002\u8BF7\u4E00\u6B21\u6027\u8F93\u51FA\u6240\u6709 15 \u4E2A\u6A21\u5757\u7684\u5185\u5BB9\uFF0C\u6BCF\u4E2A\u6A21\u5757 50-80 \u5B57\u3002\u4EE5 JSON \u683C\u5F0F\u8FD4\u56DE\uFF0C\u5B57\u6BB5\u540D\u5BF9\u5E94\uFF1Atarget_customer, pain_point, channels, solution, unique_value, revenue_model, cost_structure, key_resources, key_activities, key_partners, metrics, track, unfair_advantage, non_compete, scaling_strategy\u3002\u53EA\u8FD4\u56DE JSON\uFF0C\u4E0D\u8981\u52A0\u5176\u4ED6\u6587\u5B57\u3002';
  try {
    var result = await api('/chat/simple', { method: 'POST', body: { message: prompt } });
    var raw = (result.content || '').trim(); var bt = String.fromCharCode(96); var fence = bt+bt+bt; if(raw.indexOf(fence+'json') === 0) raw = raw.slice(7); else if(raw.indexOf(fence) === 0) raw = raw.slice(3); if(raw.slice(-3) === fence) raw = raw.slice(0,-3); raw = raw.trim();
    var data = JSON.parse(raw);
    fields.forEach(function(f) {
      if (data[f.key]) {
        var ta = document.querySelector('.canvas-field[data-key="' + f.key + '"]');
        if (ta) { ta.value = data[f.key]; ta.style.borderColor = 'var(--accent)'; setTimeout(function(){ ta.style.borderColor=''; }, 2000); }
      }
    });
    toast('\u2728 AI \u5DF2\u5B8C\u6210\u753B\u5E03\u586B\u5145\uFF0C\u8BF7\u68C0\u67E5\u5E76\u4FDD\u5B58', 'success');
  } catch(e) { toast('AI \u751F\u6210\u5931\u8D25: ' + e.message, 'error'); }
}
window.aiCanvasFillAll = aiCanvasFillAll;

