function tutorialSection(title, color, items) {
  var rows = items.map(function(item) {
    return '<div style="display:flex;gap:10px;padding:8px 0;border-bottom:1px solid var(--bd);">' +
      '<div style="flex-shrink:0;width:96px;font-size:12px;font-weight:600;color:' + color + ';padding-top:1px;">' + item[0] + '</div>' +
      '<div style="font-size:13px;color:var(--tx2);line-height:1.6;">' + item[1] + '</div>' +
    '</div>';
  }).join('');
  return '<div style="border:1px solid var(--bd);border-radius:10px;overflow:hidden;">' +
    '<div style="padding:10px 14px;background:var(--bg-soft);font-size:13px;font-weight:700;border-bottom:1px solid var(--bd);color:var(--tx);">' + title + '</div>' +
    '<div style="padding:4px 14px;">' + rows + '</div>' +
  '</div>';
}

