async function doAddModel() {
  var cid = getModuleCompanyId(); if (!cid) return;
  var name = document.getElementById('bm-name').value.trim(); if (!name) { toast('\u8BF7\u8F93\u5165\u540D\u79F0', 'error'); return; }
  try {
    await api('/companies/' + cid + '/biz-models', { method: 'POST', body: { name: name, who: document.getElementById('bm-who').value, problem: document.getElementById('bm-problem').value, solution: document.getElementById('bm-solution').value, revenue_method: document.getElementById('bm-revenue').value } });
    closeModal('add-model-modal'); toast('\u5DF2\u6DFB\u52A0', 'success'); await renderCompassContent();
  } catch(e) { toast(e.message, 'error'); }
}

async function deleteBizModel(id) {
  var ok = await confirmModal({ title: '\u5220\u9664\u5546\u4E1A\u6A21\u5F0F', message: '\u786E\u5B9A\u5220\u9664\u8BE5\u5546\u4E1A\u6A21\u5F0F\uFF1F', confirmText: '\u5220\u9664', confirmType: 'danger' });
  if (!ok) return;
  try { await api('/biz-models/' + id, { method: 'DELETE' }); toast('\u5DF2\u5220\u9664', 'success'); await renderCompassContent(); } catch(e) { toast(e.message, 'error'); }
}

// ─── 监控中心 ──────────────────────────────────────────────────────

async function loadMonitor() {
  var mc = document.getElementById('mc'); if (!mc) return;
  if (!state.companies.length) { var d = await api('/dashboard'); state.companies = d.companies || []; }
  var cid = state.companies.length ? state.companies[0].id : '';
  if (!cid) {
    mc.innerHTML = '<div class="page-inner"><div class="page-header"><h1>\u76D1\u63A7\u4E2D\u5FC3</h1><p>\u516C\u53F8\u8FD0\u8425\u72B6\u6001\u3001\u98CE\u9669\u9884\u8B66\u3001\u4ECA\u65E5\u5F85\u529E</p></div>' + renderNoCompanyContent('\u8BF7\u5148\u521B\u5EFA\u516C\u53F8\uFF0C\u518D\u67E5\u770B\u76D1\u63A7\u4E2D\u5FC3') + '</div>';
    return;
  }
  mc.innerHTML = '<div class="page-inner"><div class="page-header"><h1>\u76D1\u63A7\u4E2D\u5FC3</h1><p>\u516C\u53F8\u8FD0\u8425\u72B6\u6001\u3001\u98CE\u9669\u9884\u8B66\u3001\u4ECA\u65E5\u5F85\u529E</p></div>' + companySelector(cid) + '<div id="monitor-content" style="flex:1;display:flex;flex-direction:column;">' + renderLoading() + '</div></div>';
  window.moduleCompanyChanged = async function() { await renderMonitorContent(); };
  await renderMonitorContent();
}

async function renderMonitorContent() {
  var el = document.getElementById('monitor-content'); if (!el) return;
  var cid = getModuleCompanyId(); if (!cid) { el.innerHTML = renderNoCompanyContent('请先创建一家公司，再查看监控中心。'); return; }
  el.innerHTML = renderLoading();
  try {
    var data = await api('/companies/' + cid + '/monitor');
    var m = data.metrics || {};
    var html = '<div class="stats-grid" style="margin-bottom:20px;">' +
      statCard('\u672C\u6708\u6536\u5165', formatMoney(m.monthly_income), '\u5143') +
      statCard('\u672C\u6708\u652F\u51FA', formatMoney(m.monthly_expense), '\u5143') +
      statCard('\u672C\u6708\u5229\u6DA6', formatMoney(m.monthly_profit), '\u5143') +
      statCard('\u8D26\u6237\u4F59\u989D', formatMoney(m.cash_balance), '\u5143') +
      statCard('\u8D44\u91D1\u8DD1\u9053', m.runway_months, '\u4E2A\u6708') +
    '</div>';
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">';
    html += '<div class="card"><h3 style="font-size:14px;font-weight:700;margin-bottom:12px;color:var(--red);">🚨 \u98CE\u9669\u9884\u8B66</h3>';
    if (!data.alerts || data.alerts.length === 0) {
      html += '<p style="color:var(--tx3);font-size:13px;text-align:center;padding:16px;">\u6682\u65E0\u9884\u8B66\uFF0C\u8FD0\u8425\u72B6\u6001\u826F\u597D \u2705</p>';
    } else {
      data.alerts.forEach(function(a) { html += '<div style="padding:8px 0;border-bottom:1px solid var(--bd);font-size:13px;"><strong style="color:' + (a.severity==='high'?'var(--red)':'var(--orange)') + '">[' + esc(a.severity) + ']</strong> ' + esc(a.title) + '<p style="color:var(--tx3);font-size:12px;margin-top:2px;">' + esc(a.message) + '</p></div>'; });
    }
    html += '</div>';
    html += '<div class="card"><h3 style="font-size:14px;font-weight:700;margin-bottom:12px;color:var(--blue);">📋 \u5F85\u529E\u4E8B\u9879</h3>';
    if (!data.todos || data.todos.length === 0) {
      html += '<p style="color:var(--tx3);font-size:13px;text-align:center;padding:16px;">\u6682\u65E0\u5F85\u529E\u4E8B\u9879 🎉</p>';
    } else {
      data.todos.forEach(function(t) {
        var tag = renderRecordOpportunityTag(t.description || '', 'small');
        html += '<div style="padding:8px 0;border-bottom:1px solid var(--bd);font-size:13px;"><div style="display:flex;justify-content:space-between;gap:8px;"><span>' + esc(t.title) + '</span><span style="color:var(--tx3);font-size:11px;">' + esc(t.due_date) + '</span></div>' + (tag ? '<div style="margin-top:6px;">' + tag + '</div>' : '') + '</div>';
      });
    }
    html += '</div></div>';
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-top:16px;flex:1;">';
    html += '<div class="card" style="display:flex;flex-direction:column;"><h3 style="font-size:14px;font-weight:700;margin-bottom:12px;color:var(--orange);">📞 \u8DDF\u8FDB\u63D0\u9192</h3>';
    if (!data.follow_ups || data.follow_ups.length === 0) {
      html += '<p style="color:var(--tx3);font-size:13px;text-align:center;padding:16px;">\u6682\u65E0\u9700\u8DDF\u8FDB\u5BA2\u6237</p>';
    } else {
      data.follow_ups.forEach(function(f) { html += '<div style="padding:8px 0;border-bottom:1px solid var(--bd);font-size:13px;"><strong>' + esc(f.name) + '</strong> <span style="color:var(--tx3);">- ' + esc(f.company) + '</span><p style="color:var(--tx3);font-size:12px;">\u8DDF\u8FDB\u65E5\u671F: ' + esc(f.follow_up_date) + '</p></div>'; });
    }
    html += '</div>';
    html += '<div class="card"><h3 style="font-size:14px;font-weight:700;margin-bottom:12px;color:var(--green);">📂 \u6D3B\u8DC3\u9879\u76EE</h3>';
    if (!data.active_projects || data.active_projects.length === 0) {
      html += '<p style="color:var(--tx3);font-size:13px;text-align:center;padding:16px;">\u6682\u65E0\u6D3B\u8DC3\u9879\u76EE</p>';
    } else {
      data.active_projects.forEach(function(p) {
        var tag = renderRecordOpportunityTag((p.document || '') + '\\\\n' + (p.description || ''), 'small');
        html += '<div style="padding:8px 0;border-bottom:1px solid var(--bd);font-size:13px;"><div style="display:flex;justify-content:space-between;gap:8px;"><span><strong>' + esc(p.name) + '</strong></span><span style="color:var(--tx3);">' + esc(p.status) + '</span></div>' + (tag ? '<div style="margin-top:6px;">' + tag + '</div>' : '') + '</div>';
      });
    }
    html += '</div></div>';
    el.innerHTML = html;
  } catch(e) { el.innerHTML = '<p style="color:var(--red);text-align:center;">' + esc(e.message) + '</p>'; }
}

