var _toolConfig = {};
var _skillsConfigList = [];
var _toolConfigReadonly = false;

async function loadTools() {
  var mc = document.getElementById('mc'); if (!mc) return;
  mc.innerHTML = '<div class="page-inner"><div class="page-header"><div><h1>\u5DE5\u5177\u7BA1\u7406</h1><p>\u542F\u7528\u3001\u914D\u7F6E\u5404\u529F\u80FD\u6A21\u5757\uFF0C\u7EDF\u4E00\u7BA1\u7406\u5DE5\u5177\u4E0E Skills \u80FD\u529B\u5E93</p></div><div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-secondary" onclick="showSkillCatalogModal()">\ud83d\udd0e \u6D4F\u89C8\u6280\u80FD\u5E93</button><button class="btn btn-secondary" onclick="showSkillImportModal()">\u2197 \u5BFC\u5165\u7F51\u4E0A Skill</button><button class="btn btn-primary" onclick="showSkillCreateModal()">+ \u521B\u5EFA Skill</button></div></div><div id="tools-content" style="flex:1;display:flex;flex-direction:column;">' + renderLoading() + '</div></div>';
  try {
    var results = await Promise.allSettled([api('/tool-config'), api('/skills')]);
    if (results[0].status !== 'fulfilled') throw results[0].reason;
    _toolConfig = results[0].value.config || {};
    _skillsConfigList = results[1].status === 'fulfilled' && Array.isArray(results[1].value) ? results[1].value : [];
    _toolConfigReadonly = !(state.user && state.user.role === 'admin');
    renderToolCards();
  } catch(e) { document.getElementById('tools-content').innerHTML = '<p style="color:var(--red);">' + esc(e.message) + '</p>'; }
}

function renderToolCards() {
  var html = '';
  if (_toolConfigReadonly) {
    html += '<div class="card" style="margin-bottom:16px;padding:14px 16px;background:rgba(59,130,246,.08);border:1px solid rgba(59,130,246,.14);font-size:12px;color:var(--tx2);line-height:1.8;">当前账号为只读模式，可查看工具与 Skills 配置，但只有管理员可以修改工具开关和高级参数。</div>';
  }
  html += '<section style="margin-bottom:24px;">';
  html += '<div style="display:flex;justify-content:space-between;align-items:flex-end;gap:12px;flex-wrap:wrap;margin-bottom:12px;">';
  html += '<div><div style="font-size:18px;font-weight:700;">\u5DE5\u5177\u6A21\u5757</div><p style="font-size:12px;color:var(--tx2);margin-top:4px;">\u63A7\u5236 OPC \u5404\u4E2A\u529F\u80FD\u6A21\u5757\u7684\u542F\u7528\u72B6\u6001\u3001\u4F18\u5148\u7EA7\u4E0E\u9AD8\u7EA7\u63D0\u793A\u8BCD</p></div>';
  html += '<div style="font-size:12px;color:var(--tx3);">\u5171 ' + TOOL_DEFS.length + ' \u4E2A\u6A21\u5757</div></div>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:14px;">';
  TOOL_DEFS.forEach(function(t) {
    var enabled = _toolConfig[t.key] !== 'disabled';
    var priority = _toolConfig[t.key + '_priority'] || 'normal';
    var prompt = _toolConfig[t.key + '_prompt'] || '';
    var notes = _toolConfig[t.key + '_notes'] || '';
    var priLabel = priority === 'high' ? '\u9AD8' : priority === 'low' ? '\u4F4E' : '\u6B63\u5E38';
    html += '<div class="card" style="opacity:' + (enabled ? '1' : '0.6') + ';transition:opacity .2s;" id="tcard-' + t.key + '">';
    // Header
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">';
    html += '<div><div style="font-weight:700;font-size:14px;">' + t.name + '</div><code style="font-size:11px;color:var(--tx3);background:var(--bg);padding:1px 6px;border-radius:4px;">' + t.key + '</code></div>';
    html += '<label style="position:relative;display:inline-block;width:40px;height:22px;cursor:pointer;">';
    html += '<input type="checkbox"' + (enabled ? ' checked' : '') + ' onchange="toggleTool(&quot;' + t.key + '&quot;, this.checked)" style="opacity:0;width:0;height:0;">';
    html += '<span style="position:absolute;inset:0;background:' + (enabled ? '#22c55e' : 'var(--bd-strong)') + ';border-radius:22px;transition:.2s;"></span>';
    html += '<span style="position:absolute;top:2px;left:' + (enabled ? '20px' : '2px') + ';width:18px;height:18px;background:#FAFAF9;border-radius:50%;transition:.2s;box-shadow:0 1px 3px rgba(0,0,0,.3);"></span>';
    html += '</label></div>';
    // Desc
    html += '<p style="font-size:12px;color:var(--tx2);margin:8px 0 12px;">' + t.desc + '</p>';
    // Priority
    html += '<div style="margin-bottom:8px;"><label style="font-size:11px;font-weight:600;color:var(--tx3);display:block;margin-bottom:4px;">\u4F18\u5148\u7EA7</label>';
    html += '<select onchange="saveToolField(&quot;' + t.key + '_priority&quot;, this.value)" style="width:100%;padding:6px 10px;border:1px solid var(--bd);border-radius:6px;font-size:12px;background:var(--card-strong);color:var(--tx);">';
    html += '<option value="high"' + (priority==='high'?' selected':'') + '>\u9AD8 - \u4F18\u5148\u8C03\u7528</option>';
    html += '<option value="normal"' + (priority==='normal'?' selected':'') + '>\u6B63\u5E38</option>';
    html += '<option value="low"' + (priority==='low'?' selected':'') + '>\u4F4E - \u6309\u9700\u8C03\u7528</option></select></div>';
    // Advanced config toggle
    html += '<button onclick="toggleToolSettings(&quot;' + t.key + '&quot;)" style="background:none;border:1px solid var(--bd);border-radius:6px;padding:6px 12px;font-size:11px;cursor:pointer;color:var(--tx2);width:100%;text-align:center;margin-bottom:4px;">\u2699 \u9AD8\u7EA7\u914D\u7F6E</button>';
    // Expandable settings
    html += '<div id="tsettings-' + t.key + '" style="display:none;margin-top:8px;padding-top:8px;border-top:1px solid var(--bd);">';
    html += '<div style="margin-bottom:8px;"><label style="font-size:11px;font-weight:600;color:var(--tx3);display:block;margin-bottom:4px;">\u81EA\u5B9A\u4E49\u63D0\u793A\u8BCD (System Prompt)</label>';
    html += '<textarea onblur="saveToolField(&quot;' + t.key + '_prompt&quot;, this.value)" placeholder="\u8F93\u5165\u81EA\u5B9A\u4E49\u6307\u4EE4\uFF0C\u5F71\u54CD\u8BE5\u5DE5\u5177\u7684\u884C\u4E3A\u65B9\u5F0F..." style="width:100%;padding:8px 10px;border:1px solid var(--bd);border-radius:6px;font-size:12px;resize:vertical;min-height:80px;box-sizing:border-box;font-family:inherit;background:var(--bg-soft);color:var(--tx);">' + esc(prompt) + '</textarea></div>';
    html += '<div><label style="font-size:11px;font-weight:600;color:var(--tx3);display:block;margin-bottom:4px;">\u5907\u6CE8</label>';
    html += '<input type="text" value="' + esc(notes) + '" onblur="saveToolField(&quot;' + t.key + '_notes&quot;, this.value)" placeholder="\u5185\u90E8\u5907\u6CE8\uFF0C\u4EC5\u7BA1\u7406\u5458\u53EF\u89C1..." style="width:100%;padding:6px 10px;border:1px solid var(--bd);border-radius:6px;font-size:12px;box-sizing:border-box;background:var(--bg-soft);color:var(--tx);" /></div>';
    html += '</div>';
    // Footer
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-top:10px;padding-top:8px;border-top:1px solid var(--bg);">';
    html += '<span style="font-size:11px;color:var(--tx3);">\u4F18\u5148\u7EA7: ' + priLabel + '</span>';
    html += '<span style="font-size:11px;padding:2px 8px;border-radius:10px;' + (enabled ? 'background:#dcfce7;color:#16a34a;' : 'background:#f3f4f6;color:#9ca3af;') + '">' + (enabled ? '\u5DF2\u542F\u7528' : '\u5DF2\u7981\u7528') + '</span>';
    html += '</div></div>';
  });
  html += '</div></section>';
  html += renderToolsSkillsSection();
  var el = document.getElementById('tools-content');
  if (el) el.innerHTML = html;
}

function renderToolsSkillsSection() {
  var html = '';
  var enabledCount = _skillsConfigList.filter(function(sk) { return sk.enabled === 1 || sk.enabled === true; }).length;
  html += '<section>';
  html += '<div class="card" style="margin-bottom:16px;padding:18px 20px;background:linear-gradient(135deg, rgba(249,115,22,0.12), rgba(249,115,22,0.04));border-color:rgba(249,115,22,0.18);">';
  html += '<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:16px;flex-wrap:wrap;">';
  html += '<div><div style="font-size:18px;font-weight:700;margin-bottom:6px;">Skills \u80FD\u529B\u5E93</div><p style="font-size:12px;color:var(--tx2);max-width:720px;">\u8FD9\u91CC\u7EDF\u4E00\u7BA1\u7406 AI \u53EF\u8C03\u7528\u7684\u4E13\u4E1A\u6280\u80FD\u3002\u652F\u6301\u5B89\u88C5\u5185\u7F6E skill\u3001\u4ECE GitHub / SKILL.md \u5730\u5740\u5BFC\u5165\u7F51\u4E0A skill\u3001\u81EA\u5B9A\u4E49 prompt\u3001\u542F\u505C\u548C\u7F16\u8F91\u3002</p></div>';
  html += '<div style="display:flex;gap:12px;flex-wrap:wrap;">';
  html += '<div style="min-width:112px;padding:10px 12px;border:1px solid var(--bd);border-radius:12px;background:var(--card);"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">\u5DF2\u5B89\u88C5</div><div style="font-size:20px;font-weight:700;">' + _skillsConfigList.length + '</div></div>';
  html += '<div style="min-width:112px;padding:10px 12px;border:1px solid var(--bd);border-radius:12px;background:var(--card);"><div style="font-size:11px;color:var(--tx3);margin-bottom:4px;">\u5DF2\u542F\u7528</div><div style="font-size:20px;font-weight:700;">' + enabledCount + '</div></div>';
  html += '</div></div></div>';

  if (_skillsConfigList.length === 0) {
    html += '<div class="card" style="padding:24px;">';
    html += '<div style="text-align:center;padding:12px 0 4px;">';
    html += '<div style="font-size:42px;margin-bottom:12px;">\u26A1</div>';
    html += '<h3 style="font-size:18px;font-weight:700;margin-bottom:8px;">\u8FD8\u6CA1\u6709 Skill</h3>';
    html += '<p style="color:var(--tx2);font-size:13px;line-height:1.8;max-width:720px;margin:0 auto 20px;">Skill \u662F\u53EF\u4EE5\u8BA9 AI \u5728\u67D0\u7C7B\u573A\u666F\u4E0B\u66F4\u4E13\u4E1A\u7684\u63D2\u4EF6\u5316\u80FD\u529B\u3002\u4F60\u53EF\u4EE5\u4ECE\u5185\u7F6E\u6280\u80FD\u5E93\u5FEB\u901F\u5B89\u88C5\uff0c\u4E5F\u53EF\u4EE5\u76F4\u63A5\u7C98\u8D34 GitHub skill \u94FE\u63A5\u6216 SKILL.md \u5730\u5740\u5BFC\u5165\u3002</p>';
    html += '<div style="display:flex;justify-content:center;gap:10px;flex-wrap:wrap;margin-bottom:18px;"><button class="btn btn-secondary" onclick="showSkillImportModal()">\u2197 \u5BFC\u5165\u7F51\u4E0A Skill</button><button class="btn btn-primary" onclick="showSkillCatalogModal()">\ud83d\udd0e \u6D4F\u89C8\u5185\u7F6E\u6280\u80FD\u5E93</button></div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:12px;text-align:left;">';
    PRESET_SKILLS.forEach(function(ps) {
      var cat = SKILL_CATEGORIES.find(function(c){ return c.id === ps.category; });
      html += '<div onclick="installPresetSkill(&quot;' + esc(ps.name) + '&quot;)" style="padding:14px;border:1px solid var(--bd);border-radius:12px;cursor:pointer;transition:all .2s;background:var(--card);" onmouseover="this.style.borderColor=&quot;rgba(249,115,22,0.3)&quot;" onmouseout="this.style.borderColor=&quot;&quot;">';
      html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">';
      html += '<span style="font-size:18px;">' + (cat ? cat.icon : '\u2728') + '</span>';
      html += '<span style="font-weight:600;font-size:13px;">' + esc(ps.name) + '</span></div>';
      html += '<p style="font-size:11px;color:var(--tx3);line-height:1.5;">' + esc(ps.description) + '</p></div>';
    });
    html += '</div></div></div>';
  } else {
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:16px;">';
    _skillsConfigList.forEach(function(sk) {
      var cat = SKILL_CATEGORIES.find(function(c){ return c.id === sk.category; });
      var catName = cat ? cat.name : sk.category;
      var catIcon = cat ? cat.icon : '\u2728';
      var enabled = sk.enabled === 1 || sk.enabled === true;
      var skillName = cleanDirtyPlaceholderText(sk.name, '未命名技能');
      var skillDesc = cleanDirtyPlaceholderText(sk.description || '', '描述缺失，建议重新编辑或删除');
      var skillPrompt = cleanDirtyPlaceholderText(sk.prompt || '', '');
      html += '<div class="card" style="position:relative;transition:all .2s;' + (enabled ? '' : 'opacity:0.64;') + '">';
      html += '<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;gap:10px;">';
      html += '<div style="display:flex;align-items:center;gap:10px;min-width:0;">';
      html += '<span style="font-size:28px;line-height:1;">' + catIcon + '</span>';
      html += '<div style="min-width:0;"><div style="font-weight:700;font-size:15px;word-break:break-word;">' + esc(skillName) + '</div>';
      html += '<div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:4px;"><span style="font-size:11px;padding:2px 8px;border-radius:999px;background:rgba(249,115,22,0.1);color:var(--accent);">' + esc(catName) + '</span>';
      html += '<span style="font-size:11px;padding:2px 8px;border-radius:999px;' + (enabled ? 'background:rgba(34,197,94,0.14);color:#22c55e;' : 'background:rgba(120,113,108,0.14);color:var(--tx2);') + '">' + (enabled ? '\u542F\u7528\u4E2D' : '\u5DF2\u7981\u7528') + '</span></div></div></div>';
      html += '<label style="position:relative;display:inline-block;width:40px;height:22px;cursor:pointer;flex-shrink:0;">';
      html += '<input type="checkbox"' + (enabled ? ' checked' : '') + ' onchange="toggleSkill(&quot;' + sk.id + '&quot;, this.checked)" style="opacity:0;width:0;height:0;">';
      html += '<span style="position:absolute;inset:0;background:' + (enabled ? '#22c55e' : 'var(--bd-strong)') + ';border-radius:22px;transition:.2s;"></span>';
      html += '<span style="position:absolute;top:2px;left:' + (enabled ? '20px' : '2px') + ';width:18px;height:18px;background:#FAFAF9;border-radius:50%;transition:.2s;box-shadow:0 1px 3px rgba(0,0,0,.3);"></span>';
      html += '</label></div>';
      html += '<p style="font-size:12px;color:var(--tx2);line-height:1.7;margin-bottom:12px;min-height:40px;">' + esc(skillDesc) + '</p>';
      if (skillPrompt) {
        html += '<div style="font-size:11px;color:var(--tx3);background:rgba(249,115,22,0.04);border:1px solid var(--bd);border-radius:8px;padding:10px;max-height:96px;overflow-y:auto;line-height:1.5;white-space:pre-wrap;">' + esc(skillPrompt).substring(0, 220) + (skillPrompt.length > 220 ? '...' : '') + '</div>';
      }
      html += '<div style="display:flex;gap:8px;margin-top:12px;justify-content:flex-end;flex-wrap:wrap;">';
      html += '<button class="btn btn-sm btn-secondary" onclick="editSkill(&quot;' + sk.id + '&quot;)">\u7F16\u8F91</button>';
      html += '<button class="btn btn-sm" style="color:var(--red);" onclick="deleteSkill(&quot;' + sk.id + '&quot;)">\u5220\u9664</button>';
      html += '</div></div>';
    });
    html += '</div>';
  }

  html += '</section>';
  return html;
}

async function refreshSkillsPanel() {
  if (document.getElementById('tools-content')) {
    await loadTools();
    return;
  }
  await loadSkills();
}

function toggleToolSettings(key) {
  var el = document.getElementById('tsettings-' + key);
  if (el) el.style.display = el.style.display === 'none' ? 'block' : 'none';
}

async function toggleTool(key, enabled) {
  if (_toolConfigReadonly) { toast('当前账号仅可查看，不能修改工具配置', 'error'); return; }
  _toolConfig[key] = enabled ? 'enabled' : 'disabled';
  try {
    await api('/tool-config', { method: 'POST', body: { [key]: enabled ? 'enabled' : 'disabled' } });
    toast(enabled ? '\u5DF2\u542F\u7528 ' + key : '\u5DF2\u7981\u7528 ' + key);
    renderToolCards();
  } catch(e) { toast(e.message, 'error'); }
}

async function saveToolField(key, value) {
  if (_toolConfigReadonly) { toast('当前账号仅可查看，不能修改工具配置', 'error'); return; }
  _toolConfig[key] = value;
  try { await api('/tool-config', { method: 'POST', body: { [key]: value } }); toast('\u5DF2\u4FDD\u5B58'); } catch(e) { toast(e.message, 'error'); }
}

// ─── 资金闭环 ──────────────────────────────────────────────────────

async function loadClosure() {
  var mc = document.getElementById('mc'); if (!mc) return;
  if (!state.companies.length) { var d = await api('/dashboard'); state.companies = d.companies || []; }
  var cid = state.companies.length ? state.companies[0].id : '';
  if (!cid) {
    mc.innerHTML = '<div class="page-inner"><div class="page-header"><h1>\u8D44\u91D1\u95ED\u73AF</h1><p>\u6536\u5E76\u8D2D\u3001\u8D44\u4EA7\u5305\u3001\u57CE\u6295\u8F6C\u8BA9\u3001\u878D\u8D44\u670D\u52A1\u8D39\u7BA1\u7406</p></div>' + renderNoCompanyContent('\u8BF7\u5148\u521B\u5EFA\u516C\u53F8\uFF0C\u518D\u4F7F\u7528\u8D44\u91D1\u95ED\u73AF\u6A21\u5757') + '</div>';
    return;
  }
  mc.innerHTML = '<div class="page-inner"><div class="page-header"><h1>\u8D44\u91D1\u95ED\u73AF</h1><p>\u6536\u5E76\u8D2D\u3001\u8D44\u4EA7\u5305\u3001\u57CE\u6295\u8F6C\u8BA9\u3001\u878D\u8D44\u670D\u52A1\u8D39\u7BA1\u7406</p></div>' + companySelector(cid) + '<div id="closure-content" style="flex:1;display:flex;flex-direction:column;">' + renderLoading() + '</div></div>';
  window.moduleCompanyChanged = async function() { await renderClosureContent(); };
  await renderClosureContent();
}

async function renderClosureContent() {
  var el = document.getElementById('closure-content'); if (!el) return;
  var cid = getModuleCompanyId(); if (!cid) { el.innerHTML = renderNoCompanyContent('请先创建一家公司，再查看资金闭环。'); return; }
  el.innerHTML = renderLoading();
  try {
    var data = await api('/companies/' + cid + '/closures');
    var items = data.items || [];
    var sm = data.summary || {};
    var html = '<div class="card" style="margin-bottom:20px;background:linear-gradient(135deg,#1E293B,#334155);color:#fff;border:none;">' +
      '<h3 style="font-size:14px;font-weight:700;margin-bottom:16px;">🔄 \u8D44\u91D1\u95ED\u73AF\u6A21\u578B</h3>' +
      '<div style="display:flex;justify-content:space-around;text-align:center;font-size:12px;">' +
      '<div><div style="width:48px;height:48px;border-radius:50%;background:rgba(59,130,246,0.2);display:flex;align-items:center;justify-content:center;margin:0 auto 8px;font-size:18px;">💰</div>\u6295\u8D44\u53C2\u80A1</div>' +
      '<div style="color:rgba(255,255,255,0.3);font-size:20px;align-self:center;">\u2192</div>' +
      '<div><div style="width:48px;height:48px;border-radius:50%;background:rgba(16,185,129,0.2);display:flex;align-items:center;justify-content:center;margin:0 auto 8px;font-size:18px;">🛒</div>\u670D\u52A1\u91C7\u8D2D</div>' +
      '<div style="color:rgba(255,255,255,0.3);font-size:20px;align-self:center;">\u2192</div>' +
      '<div><div style="width:48px;height:48px;border-radius:50%;background:rgba(249,115,22,0.2);display:flex;align-items:center;justify-content:center;margin:0 auto 8px;font-size:18px;">💵</div>\u8D44\u91D1\u56DE\u6D41</div>' +
      '<div style="color:rgba(255,255,255,0.3);font-size:20px;align-self:center;">\u2192</div>' +
      '<div><div style="width:48px;height:48px;border-radius:50%;background:rgba(168,85,247,0.2);display:flex;align-items:center;justify-content:center;margin:0 auto 8px;font-size:18px;">🏢</div>\u8D44\u4EA7\u8F6C\u8BA9</div>' +
      '<div style="color:rgba(255,255,255,0.3);font-size:20px;align-self:center;">\u2192</div>' +
      '<div><div style="width:48px;height:48px;border-radius:50%;background:rgba(236,72,153,0.2);display:flex;align-items:center;justify-content:center;margin:0 auto 8px;font-size:18px;">📈</div>\u878D\u8D44\u670D\u52A1\u8D39</div>' +
      '</div></div>';
    html += '<div class="stats-grid" style="margin-bottom:20px;">' +
      statCard('\u6536\u5E76\u8D2D', sm.acquisitions || 0, '\u7B14') +
      statCard('\u8D44\u4EA7\u5305', sm.packages || 0, '\u4E2A') +
      statCard('\u57CE\u6295\u8F6C\u8BA9', sm.transfers || 0, '\u7B14') +
      statCard('\u603B\u91D1\u989D', formatMoney(sm.total_amount || 0), '\u5143') +
    '</div>';
    var types = [
      { key: 'acquisition', label: '\u6536\u5E76\u8D2D\u8BB0\u5F55' },
      { key: 'package', label: '\u8D44\u4EA7\u5305' },
      { key: 'transfer', label: '\u57CE\u6295\u8F6C\u8BA9' }
    ];
    types.forEach(function(tp, idx) {
      var filtered = items.filter(function(i) { return i.type === tp.key; });
      var isLast = idx === types.length - 1;
      html += '<div class="card" style="' + (isLast ? 'flex:1;' : 'margin-bottom:16px;') + '"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;"><h3 style="font-size:14px;font-weight:700;">' + tp.label + '</h3><button class="btn btn-primary btn-sm" onclick="showClosureModal(&quot;' + tp.key + '&quot;)">\u65B0\u5EFA</button></div>';
      if (filtered.length === 0) {
        html += '<p style="color:var(--tx3);text-align:center;padding:16px;font-size:13px;">\u6682\u65E0\u8BB0\u5F55</p>';
      } else {
        html += '<div class="table-wrap"><table><thead><tr><th>\u540D\u79F0</th><th>\u5BF9\u65B9</th><th>\u91D1\u989D</th><th>\u72B6\u6001</th><th>\u65E5\u671F</th><th>\u64CD\u4F5C</th></tr></thead><tbody>';
        filtered.forEach(function(i) { html += '<tr><td style="font-weight:500;">' + esc(cleanDirtyPlaceholderText(i.name, '未命名记录')) + '</td><td>' + esc(cleanDirtyPlaceholderText(i.counterparty, '')) + '</td><td style="font-weight:600;color:var(--blue);">' + formatMoney(i.amount) + '</td><td>' + esc(i.status) + '</td><td style="color:var(--tx3);">' + (i.created_at||'').slice(0,10) + '</td><td><button class="btn btn-sm" style="color:var(--red);font-size:12px;" onclick="deleteClosure(&quot;' + i.id + '&quot;)">删除</button></td></tr>'; });
        html += '</tbody></table></div>';
      }
      html += '</div>';
    });
    el.innerHTML = '<div style="display:flex;flex-direction:column;flex:1;">' + html + '</div>';
  } catch(e) { el.innerHTML = '<p style="color:var(--red);text-align:center;">' + esc(e.message) + '</p>'; }
}

function showClosureModal(type) {
  var labels = { acquisition: '\u6536\u5E76\u8D2D', package: '\u8D44\u4EA7\u5305', transfer: '\u57CE\u6295\u8F6C\u8BA9' };
  var modal = document.createElement('div'); modal.className = 'modal-overlay'; modal.id = 'closure-modal';
  modal.innerHTML = '<div class="modal"><div class="modal-header"><h3>\u65B0\u5EFA' + (labels[type]||'') + '</h3><button class="modal-close" onclick="closeModal(&quot;closure-modal&quot;)">&times;</button></div><div class="modal-body">' +
    '<div class="input-group"><label>\u540D\u79F0 *</label><input class="input-field" id="cl-name" /></div>' +
    '<div class="input-group"><label>\u5BF9\u65B9</label><input class="input-field" id="cl-counterparty" /></div>' +
    '<div class="input-group"><label>\u91D1\u989D</label><input class="input-field" id="cl-amount" type="number" /></div>' +
    '</div><div class="modal-footer"><button class="btn btn-secondary" onclick="closeModal(&quot;closure-modal&quot;)">\u53D6\u6D88</button><button class="btn btn-primary" onclick="doCreateClosure(&quot;' + type + '&quot;)">\u521B\u5EFA</button></div></div>';
  document.body.appendChild(modal);
}

async function doCreateClosure(type) {
  var cid = getModuleCompanyId(); if (!cid) return;
  var name = document.getElementById('cl-name').value.trim(); if (!name) { toast('\u8BF7\u8F93\u5165\u540D\u79F0', 'error'); return; }
  try {
    await api('/companies/' + cid + '/closures', { method: 'POST', body: { type: type, name: name, counterparty: document.getElementById('cl-counterparty').value, amount: parseFloat(document.getElementById('cl-amount').value) || 0 } });
    closeModal('closure-modal'); toast('\u5DF2\u521B\u5EFA', 'success'); await renderClosureContent();
  } catch(e) { toast(e.message, 'error'); }
}

async function deleteClosure(closureId) {
  var ok = await modalConfirm('\u786e\u8ba4\u5220\u9664\uff1f\u6b64\u64cd\u4f5c\u4e0d\u53ef\u6062\u590d');
  if (!ok) return;
  var cid = getModuleCompanyId(); if (!cid) return;
  try {
    await api('/companies/' + cid + '/closures/' + closureId, { method: 'DELETE' });
    toast('已删除', 'success'); await renderClosureContent();
  } catch(e) { toast(e.message, 'error'); }
}

