async function doCreateCompany() {
  const prefix = document.getElementById('new-company-prefix').value.trim();
  const suffix = document.getElementById('new-company-suffix').value;
  const name = suffix ? prefix + suffix : prefix;
  const industry = document.getElementById('new-company-industry').value;
  const owner_name = document.getElementById('new-company-owner').value.trim();
  const description = document.getElementById('new-company-desc').value.trim();
  const core_offer = document.getElementById('new-company-offer').value.trim();
  const target_customer_profile = document.getElementById('new-company-target-customer').value.trim();
  const customer_pain_point = document.getElementById('new-company-customer-pain').value.trim();
  const delivery_model = document.getElementById('new-company-delivery-model').value.trim();
  const revenue_strategy = document.getElementById('new-company-revenue-strategy').value.trim();
  const monthly_revenue_target = Number(document.getElementById('new-company-monthly-target').value) || 0;
  const registrationModeNode = document.querySelector('input[name="registration-mode"]:checked');
  const registration_mode = registrationModeNode ? registrationModeNode.value : 'virtual';
  var registration_stage = (document.getElementById('new-company-registration-stage') || {}).value || 'simulated';
  var startup_stage = (document.getElementById('new-company-startup-stage') || {}).value || 'setup';
  var first_order_stage = (document.getElementById('new-company-first-order-stage') || {}).value || 'not_started';
  const btn = document.getElementById('create-company-btn');
  if (!name) { toast('请输入公司名称', 'error'); return; }
  if (registration_mode === 'virtual' && registration_stage !== 'simulated') registration_stage = 'simulated';
  if ((registration_mode === 'real' || registration_mode === 'hybrid') && registration_stage === 'simulated') registration_stage = 'preparing';
  btn.disabled = true; btn.textContent = '创建中...';
  try {
    var city_id = (document.getElementById('new-company-city') || {}).value || '';
    await api('/companies', { method: 'POST', body: { name, industry, owner_name, description, city_id, registration_mode, registration_stage, startup_stage, first_order_stage, core_offer, target_customer_profile, customer_pain_point, delivery_model, revenue_strategy, monthly_revenue_target } });
    toast('公司创建成功', 'success'); closeModal('create-company-modal');
    const route = getRoute();
    if (route.page === 'companies') await loadCompanies(); else await loadDashboard();
  } catch(e) { toast(e.message, 'error'); }
  finally { btn.disabled = false; btn.textContent = '创建'; }
}

async function aiPolishCompanyDesc() {
  const prefix = document.getElementById('new-company-prefix').value.trim();
  const industry = document.getElementById('new-company-industry').value;
  const btn = document.getElementById('ai-polish-btn');
  if (!prefix) { toast('\u8BF7\u5148\u586B\u5199\u516C\u53F8\u5B57\u53F7', 'error'); return; }
  btn.disabled = true; btn.textContent = '\u751F\u6210\u4E2D...';
  try {
    const suffix = document.getElementById('new-company-suffix').value;
    const fullName = prefix + suffix;
    const prompt = '\u4E3A"' + fullName + '"(' + industry + ')\u5199\u4E00\u53E560\u5B57\u5185\u7684\u516C\u53F8\u7B80\u4ECB\uFF0C\u7B80\u6D01\u4E13\u4E1A\uFF0C\u4E0D\u542B\u8054\u7CFB\u65B9\u5F0F\uFF0C\u76F4\u63A5\u8F93\u51FA\u7B80\u4ECB\u6587\u672C\u3002';
    const result = await api('/chat/simple', { method: 'POST', body: { message: prompt } });
    document.getElementById('new-company-desc').value = result.content || '';
    toast('AI \u7B80\u4ECB\u5DF2\u751F\u6210', 'success');
  } catch(e) { toast((e.message || 'AI \u5E2E\u5199\u5931\u8D25'), 'error'); }
  finally { btn.disabled = false; btn.textContent = '\u2728 AI \u5E2E\u5199'; }
}

