    add_transaction: '\u8bb0\u8d26', list_transactions: '\u67e5\u8be2\u8d26\u76ee', finance_summary: '\u8d22\u52a1\u6982\u89c8',
    add_contact: '\u6dfb\u52a0\u5ba2\u6237', list_contacts: '\u67e5\u8be2\u5ba2\u6237', update_contact: '\u66f4\u65b0\u5ba2\u6237',
    delete_contact: '\u5220\u9664\u5ba2\u6237', dashboard: '\u4eea\u8868\u76d8', crm_pipeline: 'CRM\u6d41\u7a0b',
    follow_up_reminders: '\u8ddf\u8fdb\u63d0\u9192',
    create_invoice: '\u521b\u5efa\u53d1\u7968', list_invoices: '\u67e5\u8be2\u53d1\u7968',
