var _dgMode = false;
var _swarmRemaining = null;

function updateSwarmBtn(remaining, max, unlimited) {
  _swarmRemaining = remaining;
  var btn = document.getElementById('dg-toggle');
  if (!btn) return;
  var label;
  if (unlimited || remaining >= 999999) {
    label = '🐝 蜂群';
    btn.disabled = false;
  } else if (remaining <= 0) {
    label = '🐝 蜂群(已用完)';
    btn.disabled = true;
    btn.classList.remove('active'); _dgMode = false;
  } else {
    label = '🐝 蜂群(剩' + remaining + '/' + max + ')';
    btn.disabled = false;
  }
  if (!_dgMode) btn.textContent = label;
}

function toggleDgMode() {
  if (_swarmRemaining !== null && _swarmRemaining <= 0) { toast('蜂群次数已用完，请联系管理员', 'error'); return; }
  _dgMode = !_dgMode;
  var btn = document.getElementById('dg-toggle');
  if (btn) {
    btn.classList.toggle('active', _dgMode);
    var rem = _swarmRemaining !== null ? '(剩' + _swarmRemaining + '/' + 3 + ')' : '';
    btn.textContent = _dgMode ? ('🐝 蜂群 ON' + rem) : ('🐝 蜂群' + rem);
  }
  if (_dgMode) toast('蜂群模式已开启，多AI协作', 'success');
}

