function shouldAutoFollow(el) {
  if (!el) return false;
  var threshold = 48;
  return el.scrollTop + el.clientHeight >= el.scrollHeight - threshold;
}

function smartScrollToBottom(el, force) {
  if (!el) return;
  if (force || shouldAutoFollow(el)) {
    el.scrollTop = el.scrollHeight;
  }
}

function buildExportFilename(rawTitle, fallback) {
  var title = String(rawTitle || '').trim();
  if (!title) title = String(fallback || '导出文档');
  title = title
    .replace(/^#+\s*/, '')
    .split('**').join('')
    .split(String.fromCharCode(96)).join('')
    .replace(/【[^】]*】/g, ' ')
    .replace(/\[[^\]]*\]/g, ' ')
    .replace(/[\\/:*?"<>|]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!title) title = String(fallback || '导出文档');
  if (title.length > 36) title = title.slice(0, 36).trim();
  return title;
}

function exportDgReport(format) {
  var raw = window._dgReportRaw || '';
  if (!raw) {
    var body = document.querySelector('.dg-report-body');
    if (body) raw = body.innerText || body.textContent || '';
  }
  if (!raw) { toast('\u6CA1\u6709\u53EF\u5BFC\u51FA\u7684\u5185\u5BB9', 'error'); return; }
  var lines = raw.trim().split(String.fromCharCode(10));
  var firstLine = '';
  for (var li = 0; li < lines.length; li++) {
    var l = lines[li].trim();
    if (l) { firstLine = l.replace(/^#+\s*/, ''); break; }
  }
  var filename = buildExportFilename(firstLine, '\u9F99\u5BAB\u6C47\u603B\u5448\u62A5');
  if (format === 'md') {
    var blob = new Blob([raw], { type: 'text/markdown;charset=utf-8' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a'); a.href = url; a.download = filename + '.md'; a.click();
    URL.revokeObjectURL(url);
    toast('\u5DF2\u5BFC\u51FA MD \u6587\u4EF6', 'success');
  } else if (format === 'docx') {
    var reportBodyEl = document.querySelector('.dg-report-body');
    var htmlContent = reportBodyEl ? reportBodyEl.innerHTML : renderMd(raw);
    var docHtml = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8"><style>body{font-family:"Microsoft YaHei",sans-serif;font-size:14px;line-height:1.8;color:#333;}h1,h2,h3{color:#1a1a1a;}ul,ol{padding-left:20px;}</style></head><body>' + htmlContent + '</body></html>';
    var blob2 = new Blob([docHtml], { type: 'application/msword;charset=utf-8' });
    var url2 = URL.createObjectURL(blob2);
    var a2 = document.createElement('a'); a2.href = url2; a2.download = filename + '.doc'; a2.click();
    URL.revokeObjectURL(url2);
    toast('\u5DF2\u5BFC\u51FA Word \u6587\u4EF6', 'success');
  }
}

var _dgTimerInterval = null;
var _dgTimerStart = 0;
function startDgTimer() {
  _dgTimerStart = Date.now();
  if (_dgTimerInterval) clearInterval(_dgTimerInterval);
  _dgTimerInterval = setInterval(function() {
    var el = document.getElementById('dg-elapsed');
    if (!el) { clearInterval(_dgTimerInterval); return; }
    var sec = Math.floor((Date.now() - _dgTimerStart) / 1000);
    var min = Math.floor(sec / 60);
    var s = sec % 60;
    el.textContent = (min > 0 ? min + 'm ' : '') + s + 's';
  }, 1000);
}
function stopDgTimer() {
  if (_dgTimerInterval) { clearInterval(_dgTimerInterval); _dgTimerInterval = null; }
}

function emailDgReport() {
  var raw = window._dgReportRaw || '';
  if (!raw) { toast('\u6CA1\u6709\u53EF\u53D1\u9001\u7684\u5185\u5BB9', 'error'); return; }
  var subject = encodeURIComponent('\u9F99\u5BAB\u6C47\u603B\u5448\u62A5 - ' + new Date().toLocaleDateString());
  var body = encodeURIComponent(raw);
  var mailto = 'mailto:?subject=' + subject + '&body=' + body;
  if (mailto.length > 2000) {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(raw).then(function() {
        toast('\u62A5\u544A\u5DF2\u590D\u5236\u5230\u526A\u8D34\u677F\uFF0C\u8BF7\u6253\u5F00\u90AE\u4EF6\u5BA2\u6237\u7AEF\u7C98\u8D34\u53D1\u9001', 'success');
      }).catch(function() { toast('\u590D\u5236\u5931\u8D25', 'error'); });
    } else {
      toast('\u5185\u5BB9\u8FC7\u957F\uFF0C\u8BF7\u5148\u5BFC\u51FA MD \u6587\u4EF6\u540E\u624B\u52A8\u53D1\u9001', 'info');
    }
  } else {
    window.location.href = mailto;
  }
}

function buildDgShell(msg, userName, time) {
  return '<div class="dg-container" id="dg-live">' +
    '<div class="dg-header"><div class="dg-header-spinner" id="dg-spinner"></div><div><div class="dg-title" id="dg-title">\uD83C\uDFEF \u9F99\u5BAB \u00B7 \u4E13\u5BB6\u534F\u4F5C\u4E2D <span id="dg-elapsed" style="font-size:13px;font-weight:500;color:var(--tx2);margin-left:8px;">0s</span></div><div class="dg-sub" id="dg-sub">\u6B63\u5728\u5206\u6790\u4EFB\u52A1\uFF0C\u8C03\u5EA6\u4E13\u5BB6\u56E2\u961F</div></div></div>' +
    '<div class="dg-timeline">' +
      '<div class="dg-phase" id="dg-phase-1"><div class="dg-phase-dot done" id="dg-dot-1"></div><div class="dg-phase-label">Phase 1 \u00B7 \u53D1\u5E03\u4EFB\u52A1</div>' +
        '<div class="dg-decree"><span class="dg-decree-seal">\uD83D\uDCDC</span><div class="dg-decree-text">' + esc(msg) + '</div><div class="dg-decree-meta">' + esc(userName || '') + ' \u00B7 ' + esc(time || '') + '</div></div></div>' +
      '<div class="dg-phase" id="dg-phase-2" style="display:none;"><div class="dg-phase-dot" id="dg-dot-2"></div><div class="dg-phase-label">Phase 2 \u00B7 \u9F99\u5BAB\u8C03\u5EA6</div>' +
        '<div class="dg-dispatch" id="dg-dispatch"><div class="dg-dispatch-loader" id="dg-dispatch-loader"></div><div class="dg-dispatch-result" id="dg-dispatch-result" style="display:none;"></div></div></div>' +
      '<div class="dg-phase" id="dg-phase-3" style="display:none;"><div class="dg-phase-dot" id="dg-dot-3"></div><div class="dg-phase-label">Phase 3 \u00B7 \u4E13\u5BB6\u9886\u547D</div>' +
        '<div id="dg-experts-wrap"></div></div>' +
      '<div class="dg-phase" id="dg-phase-4" style="display:none;"><div class="dg-phase-dot" id="dg-dot-4"></div><div class="dg-phase-label">Phase 4 \u00B7 \u5BA1\u8BA1\u4E13\u5BB6</div>' +
        '<div id="dg-audit-wrap"><div class="dg-dispatch-loader" id="dg-audit-loader"></div><div id="dg-audit-cards" style="display:none;"></div></div></div>' +
      '<div class="dg-phase" id="dg-phase-5" style="display:none;"><div class="dg-phase-dot" id="dg-dot-5"></div><div class="dg-phase-label">Phase 5 \u00B7 \u6C47\u603B\u5448\u62A5</div>' +
        '<div id="dg-report-area"></div></div>' +
    '</div></div>';
}

async function sendDgMessage(msg, companyId) {
  appendMsg({role:'user', content: msg});
  var sendBtn = document.getElementById('chat-send'); if (sendBtn) sendBtn.disabled = true;
  var container = document.getElementById('chat-messages');
  var now = new Date();
  var timeStr = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');
  var userName = (state.user && state.user.nickname) || '';

  var dgDiv = document.createElement('div');
  dgDiv.className = 'message assistant';
  dgDiv.innerHTML = '<div style="width:100%;">' + buildDgShell(msg, userName, timeStr) + '</div>';
  container.appendChild(dgDiv);
  container.scrollTop = container.scrollHeight;
  startDgTimer();

  var agentOutputs = {};
  var _summaryStarted = false;

  try {
    var resp = await fetch('/api/chat/swarm', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + state.token },
      body: JSON.stringify({ message: msg, company_id: companyId, conversation_id: state.currentConvId })
    });
    var reader = resp.body.getReader();
    var decoder = new TextDecoder();
    var buffer = '';
    var evtType = '';

    while (true) {
      var chunk = await reader.read();
      if (chunk.done) break;
      buffer += decoder.decode(chunk.value, {stream: true});
      var lines = buffer.split(String.fromCharCode(10));
      buffer = lines.pop() || '';

      for (var i = 0; i < lines.length; i++) {
        var line = lines[i].replace(String.fromCharCode(13), '');
        if (line.startsWith('event: ')) { evtType = line.slice(7).trim(); continue; }
        if (line.startsWith('data: ') && evtType) {
          try {
            var evtData = JSON.parse(line.slice(6));

            if (evtType === 'meta' && evtData.conversation_id) {
              state.currentConvId = evtData.conversation_id;
            }

            if (evtType === 'swarm_planning') {
              showPhase(2); setDotState(2, 'active');
              var sub = document.getElementById('dg-sub');
              if (sub) sub.textContent = '\uD83E\uDDE0 ' + (evtData.message || '\u6B63\u5728\u5206\u6790\u4EFB\u52A1\u9700\u6C42...');
            }

            if (evtType === 'swarm_plan') {
              var loader = document.getElementById('dg-dispatch-loader');
              if (loader) loader.style.display = 'none';
              var dResult = document.getElementById('dg-dispatch-result');
              if (dResult) {
                var avatarsHtml = '';
                evtData.agents.forEach(function(a, idx) {
                  var icon = _dgAgentIcons[a.role] || '\uD83E\uDD16';
                  avatarsHtml += '<div class="dg-avatar" style="background:transparent;font-size:24px;" title="' + esc(a.role_name) + ' [' + (a.model || '') + ']">' + icon + '</div>';
                });
                dResult.innerHTML = '<div class="dg-dispatch-agents-row">' + avatarsHtml + '</div>' +
                  '<div style="margin-bottom:6px;"><span class="dg-dispatch-mode-badge ' + evtData.mode + '">' + (evtData.mode === 'parallel' ? '\u26A1 \u5E76\u884C\u6267\u884C' : '\u27A1\uFE0F \u987A\u5E8F\u6267\u884C') + '</span> <span style="font-size:12px;color:var(--tx2);margin-left:6px;">' + evtData.agents.length + ' \u4F4D\u4E13\u5BB6\u5DF2\u5C31\u4F4D</span></div>' +
                  (evtData.reasoning ? '<div class="dg-dispatch-reasoning">\uD83D\uDCCB ' + esc(evtData.reasoning) + '</div>' : '');
                dResult.style.display = '';
              }
              setDotState(2, 'done');
              showPhase(3); setDotState(3, 'active');
              var wrap = document.getElementById('dg-experts-wrap');
              if (wrap) {
                var cardsHtml = '';
                evtData.agents.forEach(function(a, idx) {
                  var c = _dgAgentColors[idx % _dgAgentColors.length];
                  var icon = _dgAgentIcons[a.role] || '\uD83E\uDD16';
                  var modelLabel = a.model || '';
                  agentOutputs[a.role] = '';
                  cardsHtml += '<div class="dg-expert-card" id="dg-card-' + a.role + '" style="border-color:' + c.border + ';background:' + c.light + ';animation-delay:' + (idx * 0.08) + 's;">' +
                    '<div class="dg-expert-header" onclick="toggleDgCard(&quot;' + a.role + '&quot;)">' +
                      '<span style="font-size:24px;flex-shrink:0;">' + icon + '</span>' +
                      '<div style="flex:1;min-width:0;"><div class="dg-expert-name">' + esc(a.role_name) + ' <span style="font-size:11px;font-weight:400;color:var(--tx2);background:var(--bg-soft);padding:1px 6px;border-radius:4px;">' + esc(modelLabel) + '</span></div></div>' +
                      '<span class="dg-expert-status" id="dg-status-' + a.role + '" style="background:var(--bg-soft);color:var(--tx2);">\u23F3 \u7B49\u5F85\u4E2D</span>' +
                      '<span id="dg-card-arrow-' + a.role + '" style="font-size:10px;color:var(--tx2);transition:transform 0.2s;margin-left:4px;">\u25BC</span>' +
                    '</div>' +
                    '<div class="dg-expert-mission">\uD83D\uDCCC ' + esc(a.task) + '</div>' +
                    '<div class="dg-expert-output" id="dg-output-' + a.role + '"></div></div>';
                });
                wrap.innerHTML = cardsHtml;
              }
              var sub2 = document.getElementById('dg-sub');
              if (sub2) sub2.textContent = '\u5DF2\u5206\u914D ' + evtData.agents.length + ' \u4F4D\u4E13\u5BB6\uFF0C' + (evtData.mode === 'parallel' ? '\u5E76\u884C\u6267\u884C\u4E2D' : '\u987A\u5E8F\u6267\u884C\u4E2D');
            }

            if (evtType === 'agent_start') {
              var s1 = document.getElementById('dg-status-' + evtData.role);
              if (s1) { s1.textContent = '\uD83D\uDD04 \u601D\u8003\u4E2D...'; s1.style.background = 'rgba(249,115,22,0.12)'; s1.style.color = 'var(--accent)'; }
              var card1 = document.getElementById('dg-card-' + evtData.role);
              if (card1) card1.classList.add('thinking');
            }

            if (evtType === 'agent_chunk') {
              agentOutputs[evtData.role] = (agentOutputs[evtData.role] || '') + evtData.delta;
              var o1 = document.getElementById('dg-output-' + evtData.role);
              var outputAutoFollow = shouldAutoFollow(o1);
              if (o1) {
                o1.innerHTML = formatMd(agentOutputs[evtData.role]);
                smartScrollToBottom(o1, outputAutoFollow);
              }
              container.scrollTop = container.scrollHeight;
            }

            if (evtType === 'agent_done') {
              var s2 = document.getElementById('dg-status-' + evtData.role);
              if (s2) { s2.textContent = '\u2705 \u5B8C\u6210'; s2.style.background = 'rgba(34,197,94,0.12)'; s2.style.color = 'var(--green)'; }
              var card2 = document.getElementById('dg-card-' + evtData.role);
              if (card2) card2.classList.remove('thinking');
            }

            if (evtType === 'review_start') {
              setDotState(3, 'done');
              showPhase(4); setDotState(4, 'active');
              var title2r = document.getElementById('dg-title');
              if (title2r) title2r.innerHTML = '\uD83C\uDFEF \u5BA1\u8BA1\u4E13\u5BB6\u5BA1\u6838\u4E2D... <span id="dg-elapsed" style="font-size:13px;font-weight:500;color:var(--tx2);margin-left:8px;">' + (document.getElementById('dg-elapsed') ? document.getElementById('dg-elapsed').textContent : '') + '</span>';
              var sub2r = document.getElementById('dg-sub');
              if (sub2r) sub2r.textContent = evtData.message || '\u5BA1\u8BA1\u4E13\u5BB6\u6B63\u5728\u5BA1\u6838\u5404\u4F4D\u4E13\u5BB6\u7684\u8F93\u51FA\u8D28\u91CF...';
              var expWrapR = document.getElementById('dg-experts-wrap');
              if (expWrapR) { var outs2 = expWrapR.querySelectorAll('.dg-expert-output'); for (var ci2 = 0; ci2 < outs2.length; ci2++) outs2[ci2].style.display = 'none'; }
            }

            if (evtType === 'agent_review') {
              var sr = document.getElementById('dg-status-' + evtData.role);
              if (sr) {
                if (evtData.score === 'revise') {
                  sr.textContent = '\uD83D\uDD04 \u9700\u4FEE\u8BA2';
                  sr.style.background = 'rgba(245,158,11,0.12)';
                  sr.style.color = '#F59E0B';
                } else {
                  sr.textContent = '\u2705 \u5BA1\u6838\u901A\u8FC7';
                  sr.style.background = 'rgba(34,197,94,0.12)';
                  sr.style.color = 'var(--green)';
                }
              }
              // Phase 4 审计卡片
              var auditLoader = document.getElementById('dg-audit-loader');
              if (auditLoader) auditLoader.style.display = 'none';
              var auditCards = document.getElementById('dg-audit-cards');
              if (auditCards) {
                auditCards.style.display = '';
                var scoreBg = evtData.score === 'pass' ? 'rgba(34,197,94,0.08)' : 'rgba(245,158,11,0.08)';
                var scoreBd = evtData.score === 'pass' ? 'rgba(34,197,94,0.25)' : 'rgba(245,158,11,0.25)';
                var scoreIcon = evtData.score === 'pass' ? '\u2705' : '\uD83D\uDD04';
                var scoreText = evtData.score === 'pass' ? '\u901A\u8FC7' : '\u9700\u4FEE\u8BA2';
                var roleName = evtData.role;
                // 查找对应的 role_name
                var expertNameEl = document.querySelector('#dg-card-' + evtData.role + ' .dg-expert-name');
                if (expertNameEl) { var nm = expertNameEl.textContent || ''; roleName = nm.split(' ')[0] || evtData.role; }
                auditCards.innerHTML += '<div style="padding:10px 14px;border-radius:10px;border:1px solid ' + scoreBd + ';background:' + scoreBg + ';margin-bottom:6px;display:flex;align-items:center;gap:10px;">' +
                  '<span style="font-size:18px;">' + scoreIcon + '</span>' +
                  '<div style="flex:1;"><div style="font-weight:600;font-size:13px;">' + esc(roleName) + '</div>' +
                  (evtData.feedback ? '<div style="font-size:12px;color:var(--tx2);margin-top:2px;">' + esc(evtData.feedback) + '</div>' : '') +
                  '</div><span style="font-size:12px;font-weight:600;color:' + (evtData.score === 'pass' ? 'var(--green)' : '#F59E0B') + ';">' + scoreText + '</span></div>';
              }
            }

            if (evtType === 'agent_revise') {
              var srev = document.getElementById('dg-status-' + evtData.role);
              if (srev) { srev.textContent = '\uD83D\uDD04 \u4FEE\u8BA2\u4E2D...'; srev.style.background = 'rgba(249,115,22,0.12)'; srev.style.color = 'var(--accent)'; }
              var cardRev = document.getElementById('dg-card-' + evtData.role);
              if (cardRev) cardRev.classList.add('thinking');
            }

            if (evtType === 'summary_chunk') {
              if (!_summaryStarted) {
                _summaryStarted = true;
                setDotState(4, 'done');
                showPhase(5); setDotState(5, 'active');
                var title2 = document.getElementById('dg-title');
                if (title2) title2.innerHTML = '\uD83C\uDFEF \u6B63\u5728\u6C47\u603B\u7ED3\u679C... <span id="dg-elapsed" style="font-size:13px;font-weight:500;color:var(--tx2);margin-left:8px;">' + (document.getElementById('dg-elapsed') ? document.getElementById('dg-elapsed').textContent : '') + '</span>';
              }
              var reportArea = document.getElementById('dg-report-area');
              if (reportArea) {
                if (!reportArea._raw) reportArea._raw = '';
                reportArea._raw += evtData.delta;
                var reportBody = reportArea.querySelector('.dg-report-body');
                var reportAutoFollow = shouldAutoFollow(reportBody);
                reportArea.innerHTML = '<div class="dg-report"><div class="dg-report-header"><span>\uD83D\uDCCA \u9F99\u5BAB\u6C47\u603B\u5448\u62A5</span><div style="display:flex;gap:4px;margin-left:auto;"><button onclick="exportDgReport(&quot;md&quot;)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\uD83D\uDCC4 MD</button><button onclick="exportDgReport(&quot;docx&quot;)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\uD83D\uDCDD Word</button><button onclick="emailDgReport()" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\uD83D\uDCE7 \u90AE\u4EF6</button></div></div><div class="dg-report-body">' + formatMd(reportArea._raw) + '</div></div>';
                smartScrollToBottom(reportArea.querySelector('.dg-report-body'), reportAutoFollow);
              }
              container.scrollTop = container.scrollHeight;
            }

            if (evtType === 'done') {
              stopDgTimer();
              setDotState(5, 'done');
              var spinner = document.getElementById('dg-spinner');
              if (spinner) { spinner.className = 'dg-header-spinner done'; spinner.innerHTML = '<span style="color:var(--green);font-size:16px;">\u2713</span>'; }
              var elapsedEl = document.getElementById('dg-elapsed');
              var elapsedText = elapsedEl ? elapsedEl.textContent : '';
              var title3 = document.getElementById('dg-title');
              if (title3) title3.innerHTML = '\uD83C\uDFEF \u9F99\u5BAB \u00B7 \u534F\u4F5C\u5B8C\u6210 <span style="font-size:13px;font-weight:500;color:var(--green);margin-left:8px;">\u2713 ' + esc(elapsedText) + '</span>';
              var sub3 = document.getElementById('dg-sub');
              if (sub3) sub3.textContent = '\u6240\u6709\u4E13\u5BB6\u5DF2\u5B8C\u6210\u5206\u6790\uFF0C\u7ED3\u679C\u5DF2\u6C47\u603B\u5448\u62A5';
              var ra = document.getElementById('dg-report-area');
              if (ra && ra._raw) window._dgReportRaw = ra._raw;
              if (!state.currentConvId && evtData.conversation_id) state.currentConvId = evtData.conversation_id;
              loadConversations();
              // 刷新蜂群剩余次数
              api('/swarm/quota').then(function(sq) { updateSwarmBtn(sq.remaining, sq.max, sq.unlimited); }).catch(function(){});
            }

            if (evtType === 'error') { toast(evtData.error, 'error'); }
          } catch(e2) {}
          evtType = '';
        }
      }
    }
    container.scrollTop = container.scrollHeight;
  } catch(e) { toast('\u9F99\u5BAB\u6A21\u5F0F\u51FA\u9519: ' + e.message, 'error'); }
  if (sendBtn) sendBtn.disabled = false;
}

function renderDgFromHistory(sd) {
  if (!sd || !sd.session) return '';
  var session = sd.session;
  var turns = sd.turns || [];
  var plan = null;
  try { plan = typeof session.plan_json === 'string' ? JSON.parse(session.plan_json) : session.plan_json; } catch(e) {}

  if ((!plan || !plan.agents || !plan.agents.length) && turns.length > 0) {
    plan = {
      mode: session.mode || 'parallel',
      reasoning: '',
      agents: turns.map(function(t) {
        return { role: t.agent_role, role_name: t.agent_role_name || t.agent_role, task: t.input_prompt || '' };
      })
    };
  }
  if (!plan || !plan.agents || !plan.agents.length) return '';

  var userMsg = '';
  if (state.messages && state.messages.length) {
    for (var mi = state.messages.length - 1; mi >= 0; mi--) {
      if (state.messages[mi].role === 'user') { userMsg = state.messages[mi].content || ''; break; }
    }
  }

  var avatarsHtml = '';
  plan.agents.forEach(function(a, idx) {
    var icon = _dgAgentIcons[a.role] || '\uD83E\uDD16';
    avatarsHtml += '<div class="dg-avatar" style="background:transparent;font-size:24px;">' + icon + '</div>';
  });

  var expertsHtml = '';
  plan.agents.forEach(function(a, idx) {
    var c = _dgAgentColors[idx % _dgAgentColors.length];
    var icon = _dgAgentIcons[a.role] || '\uD83E\uDD16';
    var modelLabel = a.model || '';
    var turn = null;
    for (var ti = 0; ti < turns.length; ti++) {
      if (turns[ti].agent_role === a.role) { turn = turns[ti]; break; }
    }
    var output = turn ? turn.output_text : '';
    var statusLabel = turn ? '\u2705 \u5B8C\u6210' : '\u2014';
    var statusBg = turn ? 'rgba(34,197,94,0.12)' : 'var(--bg-soft)';
    var statusColor = turn ? 'var(--green)' : 'var(--tx2)';
    expertsHtml += '<div class="dg-expert-card" style="border-color:' + c.border + ';background:' + c.light + ';">' +
      '<div class="dg-expert-header" style="cursor:pointer;" onclick="var o=this.parentNode.querySelector(&quot;.dg-expert-output&quot;);if(o){o.style.display=o.style.display===&quot;none&quot;?&quot;block&quot;:&quot;none&quot;}">' +
        '<span style="font-size:24px;flex-shrink:0;">' + icon + '</span>' +
        '<div style="flex:1;min-width:0;"><div class="dg-expert-name">' + esc(a.role_name || a.role) + (modelLabel ? ' <span style="font-size:11px;font-weight:400;color:var(--tx2);background:var(--bg-soft);padding:1px 6px;border-radius:4px;">' + esc(modelLabel) + '</span>' : '') + '</div></div>' +
        '<span class="dg-expert-status" style="background:' + statusBg + ';color:' + statusColor + ';">' + statusLabel + '</span>' +
      '</div>' +
      '<div class="dg-expert-mission">\uD83D\uDCCC ' + esc(a.task) + '</div>' +
      '<div class="dg-expert-output" style="display:none;">' + (output ? formatMd(output) : '') + '</div></div>';
  });

  // Phase 4 审计
  var auditHtml = '';
  var hasReview = false;
  var auditCardsContent = '';
  for (var ati = 0; ati < turns.length; ati++) {
    var t = turns[ati];
    if (t.review_score) {
      hasReview = true;
      var sBg = t.review_score === 'pass' || t.review_score === 'revised' ? 'rgba(34,197,94,0.08)' : 'rgba(245,158,11,0.08)';
      var sBd = t.review_score === 'pass' || t.review_score === 'revised' ? 'rgba(34,197,94,0.25)' : 'rgba(245,158,11,0.25)';
      var sIcon = t.review_score === 'pass' || t.review_score === 'revised' ? '\u2705' : '\uD83D\uDD04';
      var sText = t.review_score === 'pass' ? '\u901A\u8FC7' : (t.review_score === 'revised' ? '\u5DF2\u4FEE\u8BA2' : '\u9700\u4FEE\u8BA2');
      var sColor = t.review_score === 'pass' || t.review_score === 'revised' ? 'var(--green)' : '#F59E0B';
      auditCardsContent += '<div style="padding:10px 14px;border-radius:10px;border:1px solid ' + sBd + ';background:' + sBg + ';margin-bottom:6px;display:flex;align-items:center;gap:10px;">' +
        '<span style="font-size:18px;">' + sIcon + '</span>' +
        '<div style="flex:1;"><div style="font-weight:600;font-size:13px;">' + esc(t.agent_role_name || t.agent_role) + '</div>' +
        (t.review_feedback ? '<div style="font-size:12px;color:var(--tx2);margin-top:2px;">' + esc(t.review_feedback) + '</div>' : '') +
        '</div><span style="font-size:12px;font-weight:600;color:' + sColor + ';">' + sText + '</span></div>';
    }
  }
  if (hasReview) {
    auditHtml = '<div class="dg-phase"><div class="dg-phase-dot done"></div><div class="dg-phase-label">Phase 4 \u00B7 \u5BA1\u8BA1\u4E13\u5BB6</div><div>' + auditCardsContent + '</div></div>';
  }

  var summaryHtml = '';
  if (session.conductor_summary) {
    summaryHtml = '<div class="dg-phase"><div class="dg-phase-dot done"></div><div class="dg-phase-label">Phase 5 \u00B7 \u6C47\u603B\u5448\u62A5</div>' +
      '<div class="dg-report"><div class="dg-report-header"><span>\uD83D\uDCCA \u9F99\u5BAB\u6C47\u603B\u5448\u62A5</span><div style="display:flex;gap:4px;margin-left:auto;"><button onclick="exportDgReport(&quot;md&quot;)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\uD83D\uDCC4 MD</button><button onclick="exportDgReport(&quot;docx&quot;)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\uD83D\uDCDD Word</button><button onclick="emailDgReport()" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\uD83D\uDCE7 \u90AE\u4EF6</button></div></div><div class="dg-report-body">' + formatMd(session.conductor_summary) + '</div></div></div>';
  }

  return '<div class="message assistant"><div style="width:100%;"><div class="dg-container">' +
    '<div class="dg-header"><div class="dg-header-spinner done"><span style="color:var(--green);font-size:16px;">\u2713</span></div><div><div class="dg-title">\uD83C\uDFEF \u9F99\u5BAB \u00B7 \u534F\u4F5C\u5B8C\u6210</div><div class="dg-sub">\u6240\u6709\u4E13\u5BB6\u5DF2\u5B8C\u6210\u5206\u6790\uFF0C\u7ED3\u679C\u5DF2\u6C47\u603B\u5448\u62A5</div></div></div>' +
    '<div class="dg-timeline">' +
      '<div class="dg-phase"><div class="dg-phase-dot done"></div><div class="dg-phase-label">Phase 1 \u00B7 \u53D1\u5E03\u4EFB\u52A1</div>' +
        '<div class="dg-decree"><span class="dg-decree-seal">\uD83D\uDCDC</span><div class="dg-decree-text">' + esc(userMsg) + '</div></div></div>' +
      '<div class="dg-phase"><div class="dg-phase-dot done"></div><div class="dg-phase-label">Phase 2 \u00B7 \u9F99\u5BAB\u8C03\u5EA6</div>' +
        '<div class="dg-dispatch"><div class="dg-dispatch-agents-row">' + avatarsHtml + '</div>' +
          '<div style="margin-bottom:6px;"><span class="dg-dispatch-mode-badge ' + (plan.mode || 'parallel') + '">' + (plan.mode === 'sequential' ? '\u27A1\uFE0F \u987A\u5E8F\u6267\u884C' : '\u26A1 \u5E76\u884C\u6267\u884C') + '</span> <span style="font-size:12px;color:var(--tx2);margin-left:6px;">' + plan.agents.length + ' \u4F4D\u4E13\u5BB6</span></div>' +
          (plan.reasoning ? '<div class="dg-dispatch-reasoning">\uD83D\uDCCB ' + esc(plan.reasoning) + '</div>' : '') + '</div></div>' +
      '<div class="dg-phase"><div class="dg-phase-dot done"></div><div class="dg-phase-label">Phase 3 \u00B7 \u4E13\u5BB6\u9886\u547D</div><div>' + expertsHtml + '</div></div>' +
      auditHtml +
      summaryHtml +
    '</div></div></div></div>';
}

// ─── 好友页面 ────────────────────────────────────────────────────────
async function loadFriends() {
  var mc = document.getElementById('mc'); if (!mc) return;
  var data = await api('/friends');
  var reqData = await api('/friends/requests');
  var friends = data.friends || [];
  var requests = (reqData.requests || []).filter(function(r) { return r.status === 'pending'; });

  var h = '<div class="page-inner">';
  h += '<div class="page-header" style="display:flex;justify-content:space-between;align-items:flex-start;"><div><h1>\u597D\u53CB\u7F51\u7EDC</h1><p>\u6DFB\u52A0\u597D\u53CB\uFF0C\u8BA9\u4F60\u7684 AI Agent \u4EE3\u8868\u4F60\u4E0E\u597D\u53CB\u7684 Agent \u5546\u52A1\u5BF9\u63A5\u3001\u4FE1\u606F\u5BF9\u9F50</p></div></div>';

  // Stats
  h += '<div class="stats-grid" style="margin-bottom:20px;">';
  h += '<div class="card" style="display:flex;align-items:center;gap:14px;padding:18px 20px;"><div style="width:44px;height:44px;border-radius:12px;background:linear-gradient(135deg,#F97316,#EA580C);display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">👥</div><div><div style="font-size:24px;font-weight:700;line-height:1;">' + friends.length + '</div><div style="font-size:12px;color:var(--tx2);margin-top:4px;">\u597D\u53CB\u603B\u6570</div></div></div>';
  h += '<div class="card" style="display:flex;align-items:center;gap:14px;padding:18px 20px;"><div style="width:44px;height:44px;border-radius:12px;background:linear-gradient(135deg,#3B82F6,#2563EB);display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">📨</div><div><div style="font-size:24px;font-weight:700;line-height:1;">' + requests.length + '</div><div style="font-size:12px;color:var(--tx2);margin-top:4px;">\u5F85\u5904\u7406\u7533\u8BF7</div></div></div>';
  h += '</div>';

  // Search
  h += '<div class="card" style="margin-bottom:16px;"><div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;"><svg viewBox="0 0 24 24" width="18" height="18" stroke="var(--accent)" fill="none" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg><span style="font-weight:600;font-size:15px;">\u641C\u7D22\u7528\u6237</span></div>';
  h += '<div style="display:flex;gap:8px;margin-top:12px;"><input type="text" id="friend-search-input" placeholder="\u8F93\u5165\u90AE\u7BB1\u6216\u6635\u79F0\uFF0C\u6700\u5C11 2 \u4E2A\u5B57\u7B26" style="flex:1;padding:10px 14px;border:1px solid var(--bd);border-radius:10px;font-size:14px;background:var(--bg-soft);color:var(--tx);outline:none;transition:border 0.2s;" onfocus="this.style.borderColor=&quot;var(--accent)&quot;" onblur="this.style.borderColor=&quot;var(--bd)&quot;" onkeydown="if(event.key===&quot;Enter&quot;)doFriendSearch()" /><button class="btn btn-primary" onclick="doFriendSearch()" style="padding:10px 24px;border-radius:10px;">\u641C\u7D22</button></div>';
  h += '<div id="friend-search-results" style="margin-top:12px;"></div></div>';

  // Pending requests
  if (requests.length > 0) {
    h += '<div class="card" style="margin-bottom:16px;border-left:3px solid #3B82F6;">';
    h += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;"><span style="font-size:18px;">📬</span><span style="font-weight:700;font-size:15px;">\u5F85\u5904\u7406\u7684\u597D\u53CB\u7533\u8BF7</span><span style="background:#3B82F6;color:#fff;font-size:11px;padding:2px 8px;border-radius:10px;font-weight:600;">' + requests.length + '</span></div>';
    requests.forEach(function(r, idx) {
      var colors = ['#F97316','#3B82F6','#8B5CF6','#EC4899','#10B981'];
      var bgColor = colors[idx % colors.length];
      h += '<div style="display:flex;align-items:center;gap:14px;padding:14px 16px;background:var(--bg-soft);border-radius:12px;margin-bottom:8px;transition:transform 0.15s;" onmouseover="this.style.transform=&quot;translateY(-1px)&quot;" onmouseout="this.style.transform=&quot;&quot;">';
      h += '<div style="width:44px;height:44px;border-radius:50%;background:linear-gradient(135deg,' + bgColor + ',' + bgColor + 'cc);color:#fff;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:18px;flex-shrink:0;box-shadow:0 4px 12px ' + bgColor + '33;">' + esc((r.from_name || '?')[0]) + '</div>';
      h += '<div style="flex:1;min-width:0;"><div style="font-weight:600;font-size:14px;">' + esc(r.from_name || '\u672A\u77E5\u7528\u6237') + '</div>';
      h += '<div style="font-size:12px;color:var(--tx2);margin-top:2px;">' + esc(r.from_email || '') + '</div>';
      if (r.message) h += '<div style="font-size:12px;color:var(--tx2);margin-top:4px;padding:4px 8px;background:var(--bg);border-radius:6px;font-style:italic;">\u201C' + esc(r.message) + '\u201D</div>';
      h += '</div>';
      h += '<div style="display:flex;gap:6px;flex-shrink:0;"><button class="btn btn-primary btn-sm" onclick="acceptFriendReq(&quot;' + r.id + '&quot;)" style="border-radius:8px;padding:6px 16px;">\u2713 \u63A5\u53D7</button>';
      h += '<button class="btn btn-sm" onclick="rejectFriendReq(&quot;' + r.id + '&quot;)" style="border-radius:8px;padding:6px 12px;color:var(--tx2);">\u62D2\u7EDD</button></div>';
      h += '</div>';
    });
    h += '</div>';
  }

  // Friends list
  h += '<div class="card">';
  h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;"><div style="display:flex;align-items:center;gap:8px;"><span style="font-size:18px;">🤝</span><span style="font-weight:700;font-size:15px;">\u597D\u53CB\u5217\u8868</span></div></div>';
  if (friends.length === 0) {
    h += '<div style="text-align:center;padding:60px 20px;"><div style="font-size:56px;margin-bottom:16px;opacity:0.3;">👥</div>';
    h += '<div style="font-size:16px;font-weight:600;color:var(--tx);margin-bottom:8px;">\u8FD8\u6CA1\u6709\u597D\u53CB</div>';
    h += '<div style="font-size:13px;color:var(--tx2);margin-bottom:20px;">\u5728\u4E0A\u65B9\u641C\u7D22\u6846\u8F93\u5165\u90AE\u7BB1\u6216\u6635\u79F0\uFF0C\u6DFB\u52A0\u4F60\u7684\u7B2C\u4E00\u4E2A\u597D\u53CB</div>';
    h += '<button class="btn btn-primary" onclick="document.getElementById(&quot;friend-search-input&quot;).focus()" style="border-radius:10px;padding:10px 24px;">\u53BB\u641C\u7D22</button></div>';
  } else {
    h += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px;">';
    friends.forEach(function(f, idx) {
      var colors = ['#F97316','#8B5CF6','#3B82F6','#EC4899','#10B981','#F59E0B'];
      var bgColor = colors[idx % colors.length];
      h += '<div style="border:1px solid var(--bd);border-radius:14px;padding:16px;display:flex;align-items:center;gap:14px;transition:all 0.2s;cursor:default;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;;this.style.boxShadow=&quot;0 4px 16px rgba(0,0,0,0.06)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;;this.style.boxShadow=&quot;&quot;">';
      h += '<div style="width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,' + bgColor + ',' + bgColor + 'aa);color:#fff;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:20px;flex-shrink:0;box-shadow:0 4px 14px ' + bgColor + '30;">' + esc((f.name || '?')[0]) + '</div>';
      h += '<div style="flex:1;min-width:0;"><div style="font-weight:600;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(f.name) + '</div>';
      h += '<div style="font-size:12px;color:var(--tx2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(f.email) + '</div>';
      h += '<div style="display:flex;gap:6px;margin-top:10px;">';
      h += '<button class="btn btn-primary btn-sm" onclick="startAgentChat(&quot;' + f.friend_id + '&quot;)" style="border-radius:8px;font-size:11px;padding:5px 12px;">💬 Agent \u5BF9\u8BDD</button>';
      h += '<button class="btn btn-sm" onclick="deleteFriend(&quot;' + f.id + '&quot;)" style="border-radius:8px;font-size:11px;padding:5px 10px;color:var(--tx2);">\u5220\u9664</button>';
      h += '</div></div></div>';
    });
    h += '</div>';
  }
  h += '</div></div>';
  mc.innerHTML = h;
}

async function doFriendSearch() {
  var keyword = document.getElementById('friend-search-input')?.value?.trim();
  if (!keyword) return;
  var results = document.getElementById('friend-search-results');
  results.innerHTML = '<div style="padding:12px;text-align:center;color:var(--tx2);font-size:13px;">\u641C\u7D22\u4E2D...</div>';
  try {
    var data = await apiPost('/friends/search', { keyword: keyword });
    if (!data.users || data.users.length === 0) { results.innerHTML = '<div style="padding:16px;text-align:center;color:var(--tx2);font-size:13px;background:var(--bg-soft);border-radius:10px;">\u672A\u627E\u5230\u5339\u914D\u300C' + esc(keyword) + '\u300D\u7684\u7528\u6237</div>'; return; }
    var h = '<div style="font-size:12px;color:var(--tx2);margin-bottom:8px;">\u627E\u5230 ' + data.users.length + ' \u4E2A\u7528\u6237</div>';
    data.users.forEach(function(u) {
      h += '<div style="display:flex;align-items:center;gap:14px;padding:12px 16px;background:var(--bg-soft);border-radius:12px;margin-bottom:6px;transition:background 0.15s;" onmouseover="this.style.background=&quot;var(--bg)&quot;" onmouseout="this.style.background=&quot;var(--bg-soft)&quot;">';
      h += '<div style="width:40px;height:40px;border-radius:50%;background:linear-gradient(135deg,#6366F1,#8B5CF6);color:#fff;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:16px;flex-shrink:0;">' + esc((u.name || '?')[0]) + '</div>';
      h += '<div style="flex:1;min-width:0;"><div style="font-weight:600;font-size:14px;">' + esc(u.name) + '</div><div style="font-size:12px;color:var(--tx2);">' + esc(u.email) + '</div></div>';
      h += '<button class="btn btn-primary btn-sm" onclick="sendFriendRequest(&quot;' + u.id + '&quot;);this.textContent=&quot;\u2713 \u5DF2\u53D1\u9001&quot;;this.disabled=true;this.style.opacity=0.6;" style="border-radius:8px;padding:6px 16px;white-space:nowrap;">+ \u6DFB\u52A0</button>';
      h += '</div>';
    });
    results.innerHTML = h;
  } catch(e) { toast(e.message, 'error'); results.innerHTML = ''; }
}

async function sendFriendRequest(uid) {
  try { await apiPost('/friends/request', { to_user_id: uid }); toast('好友申请已发送', 'success'); } catch(e) { toast(e.message, 'error'); }
}
async function acceptFriendReq(id) {
  try { await apiPost('/friends/requests/' + id + '/accept'); toast('已接受', 'success'); loadFriends(); } catch(e) { toast(e.message, 'error'); }
}
async function rejectFriendReq(id) {
  try { await apiPost('/friends/requests/' + id + '/reject'); toast('已拒绝'); loadFriends(); } catch(e) { toast(e.message, 'error'); }
}
async function deleteFriend(id) {
  var ok = await modalConfirm('\u786e\u5b9a\u5220\u9664\u8be5\u597d\u53cb\uff1f');
  if (!ok) return;
  try { await apiDel('/friends/' + id); toast('\u5df2\u5220\u9664'); loadFriends(); } catch(e) { toast(e.message, 'error'); }
}
async function startAgentChat(friendId) {
  var companies = state.companies || [];
  var companyId = companies.length > 0 ? companies[0].id : '';
  try {
    var data = await apiPost('/agent-rooms', { type: 'dm', invite_friend_id: friendId, company_id: companyId, agent_role: 'assistant' });
    navigate('agent-room/' + data.room_id);
  } catch(e) { toast(e.message, 'error'); }
}

// ─── Agent 房间列表 ──────────────────────────────────────────────────
var _agentRoomListCache = [];
var _agentActiveRoomId = null;
var _agentInvitesCache = [];
var _agentPollTimer = null;
var _agentPendingSnapshot = '';

function stopAgentPoll() { if (_agentPollTimer) { clearInterval(_agentPollTimer); _agentPollTimer = null; } }

function startAgentPoll() {
  stopAgentPoll();
  _agentPollTimer = setInterval(async function() {
    if (!document.getElementById('agent-left-panel')) { stopAgentPoll(); return; }
    try {
      // 1. 左侧邀请卡片
      var invData = await api('/agent-rooms/invites');
      var newInvites = invData.invites || [];
      var invKey = newInvites.map(function(i){return i.room_id}).join(',');
      var oldInvKey = _agentInvitesCache.map(function(i){return i.room_id}).join(',');
      if (invKey !== oldInvKey) {
        _agentInvitesCache = newInvites;
        renderAgentInviteCards(_agentInvitesCache);
      }
      // 2. 左侧房间列表
      var data = await api('/agent-rooms');
      var newRooms = data.rooms || [];
      var oldIds = _agentRoomListCache.map(function(r){return r.id}).join(',');
      var newIds = newRooms.map(function(r){return r.id}).join(',');
      if (oldIds !== newIds) {
        _agentRoomListCache = newRooms;
        renderAgentRoomList(_agentRoomListCache);
      }
      // 3. 右侧房间详情 — pending 成员变化时刷新
      if (_agentActiveRoomId) {
        var roomData = await api('/agent-rooms/' + _agentActiveRoomId);
        var snap = (roomData.pending_members || []).map(function(m){return m.name}).join(',');
        if (snap !== _agentPendingSnapshot) {
          _agentPendingSnapshot = snap;
          loadAgentRoomDetail(_agentActiveRoomId);
        }
      }
    } catch(e) { console.warn('[AgentPoll]', e); }
  }, 5000);
}

async function loadAgentRooms() {
  var mc = document.getElementById('mc'); if (!mc) return;
  if (!state.companies || !state.companies.length) { try { var d = await api('/dashboard'); state.companies = d.companies || []; } catch(e) {} }
  var data = await api('/agent-rooms');
  _agentRoomListCache = data.rooms || [];
  try { var invData = await api('/agent-rooms/invites'); _agentInvitesCache = invData.invites || []; } catch(e) { _agentInvitesCache = []; }
  mc.innerHTML = renderAgentSplitLayout();
  renderAgentInviteCards(_agentInvitesCache);
  renderAgentRoomList(_agentRoomListCache);
  if (_agentRoomListCache.length > 0) {
    selectAgentRoom(_agentRoomListCache[0].id);
  }
  startAgentPoll();
}

function renderAgentSplitLayout() {
  var h = '<div style="display:flex;height:calc(100vh - 64px);overflow:hidden;">';
  h += '<div id="agent-left-panel" style="width:320px;min-width:320px;border-right:1px solid var(--bd);display:flex;flex-direction:column;background:var(--card);">';
  h += '<div style="padding:14px 16px;border-bottom:1px solid var(--bd);display:flex;align-items:center;justify-content:space-between;">';
  h += '<span style="font-weight:700;font-size:16px;">Agent \u5BF9\u8BDD</span>';
  h += '<button onclick="showCreateRoomModal()" style="width:32px;height:32px;border-radius:8px;border:1px solid var(--bd);background:var(--bg-soft);display:flex;align-items:center;justify-content:center;cursor:pointer;color:var(--tx);font-size:18px;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;;this.style.color=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;;this.style.color=&quot;var(--tx)&quot;" title="\u65B0\u5EFA\u5BF9\u8BDD">+</button>';
  h += '</div>';
  h += '<div id="agent-invite-cards" style=""></div>';
  h += '<div id="agent-room-list" style="flex:1;overflow-y:auto;"></div>';
  h += '</div>';
  h += '<div id="agent-right-panel" style="flex:1;display:flex;flex-direction:column;overflow:hidden;">';
  h += '<div id="agent-room-detail" style="flex:1;display:flex;flex-direction:column;overflow:hidden;"></div>';
  h += '</div></div>';
  return h;
}

function renderAgentRoomList(rooms) {
  var el = document.getElementById('agent-room-list');
  if (!el) return;
  if (rooms.length === 0) {
    el.innerHTML = '<div style="text-align:center;padding:60px 20px;"><div style="font-size:48px;opacity:0.2;margin-bottom:16px;">💬</div><div style="font-size:14px;color:var(--tx2);margin-bottom:16px;">\u8FD8\u6CA1\u6709\u5BF9\u8BDD</div><button class="btn btn-primary" onclick="showCreateRoomModal()" style="border-radius:10px;padding:8px 20px;font-size:13px;">+ \u65B0\u5EFA\u5BF9\u8BDD</button></div>';
    return;
  }
  var colors = ['#F97316','#8B5CF6','#3B82F6','#EC4899','#10B981','#F59E0B'];
  var h = '';
  rooms.forEach(function(r, idx) {
    var isDm = r.type === 'dm';
    var active = _agentActiveRoomId === r.id;
    var c = colors[idx % colors.length];
    h += '<div class="agent-room-item' + (active ? ' active' : '') + '" onclick="selectAgentRoom(&quot;' + r.id + '&quot;)" style="display:flex;align-items:center;gap:12px;padding:14px 16px;cursor:pointer;border-bottom:1px solid var(--bd);transition:background 0.15s;' + (active ? 'background:var(--accent-soft);' : '') + '" onmouseover="if(!this.classList.contains(&quot;active&quot;))this.style.background=&quot;var(--bg-soft)&quot;" onmouseout="if(!this.classList.contains(&quot;active&quot;))this.style.background=&quot;&quot;">';
    h += '<div style="width:42px;height:42px;border-radius:12px;background:' + (isDm ? 'linear-gradient(135deg,' + c + ',' + c + 'aa)' : 'linear-gradient(135deg,#3B82F6,#2563EB)') + ';color:#fff;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;">' + (isDm ? esc((r.name || '?')[0]) : '👥') + '</div>';
    h += '<div style="flex:1;min-width:0;">';
    h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px;"><span style="font-weight:600;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:160px;">' + esc(r.name) + '</span>';
    h += '<span style="font-size:10px;color:var(--tx2);flex-shrink:0;">' + (isDm ? '\u79C1\u804A' : r.member_count + '\u4EBA') + '</span></div>';
    var preview = r.last_message ? r.last_message.replace(new RegExp('[#*_~>\\\\[\\\\]]', 'g'), '').replace(new RegExp('\\s+', 'g'), ' ').trim().slice(0, 40) : '';
    h += '<div style="font-size:12px;color:var(--tx2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + (preview ? esc(preview) : '\u6682\u65E0\u6D88\u606F') + '</div>';
    h += '</div>';
    h += '<button class="room-del-btn" onclick="event.stopPropagation();confirmDeleteRoom(&quot;' + r.id + '&quot;,&quot;' + esc(r.name).replace(/"/g, '&quot;') + '&quot;)" style="display:none;width:26px;height:26px;border-radius:6px;border:1px solid transparent;background:transparent;color:var(--tx2);font-size:14px;cursor:pointer;flex-shrink:0;transition:all 0.15s;align-items:center;justify-content:center;" onmouseover="this.style.color=&quot;#DC2626&quot;;this.style.borderColor=&quot;#DC2626&quot;" onmouseout="this.style.color=&quot;var(--tx2)&quot;;this.style.borderColor=&quot;transparent&quot;" title="\u5220\u9664\u5BF9\u8BDD">\u00D7</button>';
    h += '</div>';
  });
  el.innerHTML = h;
}

function renderAgentInviteCards(invites) {
  var el = document.getElementById('agent-invite-cards');
  if (!el) return;
  if (!invites || invites.length === 0) { el.innerHTML = ''; return; }
  var h = '<div style="padding:10px 12px;border-bottom:1px solid var(--bd);background:rgba(249,115,22,0.04);">';
  h += '<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px;"><span style="font-size:13px;">\u2709\uFE0F</span><span style="font-weight:700;font-size:13px;">\u5F85\u5904\u7406\u9080\u8BF7</span><span style="background:var(--accent);color:#fff;font-size:10px;font-weight:700;padding:1px 7px;border-radius:10px;margin-left:2px;">' + invites.length + '</span></div>';
  invites.forEach(function(inv) {
    h += '<div style="border-left:3px solid var(--accent);background:var(--card);border-radius:0 10px 10px 0;padding:10px 12px;margin-bottom:6px;border:1px solid var(--bd);border-left:3px solid var(--accent);">';
    h += '<div style="font-weight:600;font-size:13px;margin-bottom:2px;">' + esc(inv.room_name) + '</div>';
    h += '<div style="font-size:11px;color:var(--tx2);margin-bottom:6px;">' + esc(inv.inviter_name) + (inv.inviter_company_name ? ' \u00B7 ' + esc(inv.inviter_company_name) : '') + '</div>';
    h += '<div style="display:flex;gap:6px;">';
    h += '<button onclick="showAcceptInviteModal(&quot;' + inv.room_id + '&quot;,&quot;' + esc(inv.room_name).replace(/"/g, '&quot;') + '&quot;)" style="flex:1;padding:5px 0;border-radius:6px;border:1px solid var(--accent);background:var(--accent);color:#fff;font-size:11px;font-weight:600;cursor:pointer;transition:opacity 0.15s;" onmouseover="this.style.opacity=&quot;0.85&quot;" onmouseout="this.style.opacity=&quot;1&quot;">\u63A5\u53D7</button>';
    h += '<button onclick="confirmRejectInvite(&quot;' + inv.room_id + '&quot;,&quot;' + esc(inv.room_name).replace(/"/g, '&quot;') + '&quot;)" style="flex:1;padding:5px 0;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;font-weight:600;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;#DC2626&quot;;this.style.color=&quot;#DC2626&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;;this.style.color=&quot;var(--tx2)&quot;">\u5A49\u62D2</button>';
    h += '</div></div>';
  });
  h += '</div>';
  el.innerHTML = h;
}

async function showAcceptInviteModal(roomId, roomName) {
  if (!state.companies || !state.companies.length) { try { var d = await api('/dashboard'); state.companies = d.companies || []; } catch(e) {} }
  var companies = state.companies || [];
  var h = '<div class="modal-header"><h3>\u63A5\u53D7\u9080\u8BF7</h3><button class="modal-close" onclick="closeModal()">\u2715</button></div>';
  h += '<div class="modal-body">';
  h += '<div style="font-size:14px;color:var(--tx2);margin-bottom:12px;">\u4F60\u5373\u5C06\u52A0\u5165\u5BF9\u8BDD <b>' + esc(roomName) + '</b>\uFF0C\u8BF7\u9009\u62E9\u4F60\u7684\u5173\u8054\u516C\u53F8\uFF1A</div>';
  h += '<select id="accept-invite-company" style="width:100%;padding:9px 10px;border:1px solid var(--bd);border-radius:10px;font-size:14px;background:var(--bg-soft);color:var(--tx);outline:none;box-sizing:border-box;">';
  if (companies.length === 0) {
    h += '<option value="">(\u8BF7\u5148\u521B\u5EFA\u516C\u53F8)</option>';
  } else {
    companies.forEach(function(c) { h += '<option value="' + c.id + '">' + esc(c.name) + '</option>'; });
  }
  h += '</select>';
  h += '<div style="font-size:11px;color:var(--tx2);margin-top:4px;">\ud83d\udca1 Agent \u5C06\u4EE5\u52A9\u7406\u89D2\u8272\u4EE3\u8868\u4F60\u7684\u516C\u53F8\u53C2\u4E0E\u5BF9\u8BDD</div>';
  h += '</div>';
  h += '<div class="modal-footer">';
  h += '<button class="btn btn-secondary" onclick="closeModal()" style="padding:10px 24px;">\u53D6\u6D88</button>';
  h += '<button class="btn btn-primary" onclick="doAcceptInvite(&quot;' + roomId + '&quot;)" style="padding:10px 24px;">\u786E\u8BA4\u52A0\u5165</button>';
  h += '</div>';
  showModal(h);
}

async function doAcceptInvite(roomId) {
  var companyId = document.getElementById('accept-invite-company')?.value || '';
  try {
    await apiPost('/agent-rooms/' + roomId + '/accept', { company_id: companyId, agent_role: 'assistant' });
    closeModal();
    toast('\u5DF2\u52A0\u5165\u5BF9\u8BDD', 'success');
    var data = await api('/agent-rooms');
    _agentRoomListCache = data.rooms || [];
    try { var invData = await api('/agent-rooms/invites'); _agentInvitesCache = invData.invites || []; } catch(e) { _agentInvitesCache = []; }
    renderAgentInviteCards(_agentInvitesCache);
    renderAgentRoomList(_agentRoomListCache);
    selectAgentRoom(roomId);
  } catch(e) { toast(e.message, 'error'); }
}

function confirmRejectInvite(roomId, roomName) {
  var h = '<div class="modal-header"><h3>\u5A49\u62D2\u9080\u8BF7</h3><button class="modal-close" onclick="closeModal()">\u2715</button></div>';
  h += '<div class="modal-body">';
  h += '<div style="color:var(--tx2);font-size:14px;">\u786E\u5B9A\u8981\u5A69\u62D2\u5BF9\u8BDD <b>' + esc(roomName) + '</b> \u7684\u9080\u8BF7\u5417\uFF1F</div>';
  h += '</div>';
  h += '<div class="modal-footer">';
  h += '<button class="btn btn-secondary" onclick="closeModal()" style="padding:10px 24px;">\u53D6\u6D88</button>';
  h += '<button class="btn" onclick="doRejectInvite(&quot;' + roomId + '&quot;)" style="padding:10px 24px;background:#DC2626;color:#fff;border-color:#DC2626;">\u5A29\u62D2</button>';
  h += '</div>';
  showModal(h);
}

async function doRejectInvite(roomId) {
  try {
    await apiPost('/agent-rooms/' + roomId + '/reject', {});
    closeModal();
    toast('\u5DF2\u5A69\u62D2', 'success');
    _agentInvitesCache = _agentInvitesCache.filter(function(inv) { return inv.room_id !== roomId; });
    renderAgentInviteCards(_agentInvitesCache);
  } catch(e) { toast(e.message, 'error'); }
}

async function selectAgentRoom(roomId) {
  _agentActiveRoomId = roomId;
  renderAgentRoomList(_agentRoomListCache);
  await loadAgentRoomDetail(roomId);
}

async function showCreateRoomModal() {
  if (!state.companies || !state.companies.length) { try { var d = await api('/dashboard'); state.companies = d.companies || []; } catch(e) {} }
  var friendsData = await api('/friends');
  var friends = friendsData.friends || [];
  if (friends.length === 0) { toast('\u8BF7\u5148\u6DFB\u52A0\u597D\u53CB', 'error'); return; }
  var companies = state.companies || [];
  var colors = ['#F97316','#8B5CF6','#3B82F6','#EC4899','#10B981','#F59E0B'];

  var h = '<div style="padding:24px;max-height:80vh;overflow-y:auto;">';
  h += '<div style="display:flex;align-items:center;gap:12px;margin-bottom:24px;"><div style="width:44px;height:44px;border-radius:12px;background:linear-gradient(135deg,#3B82F6,#2563EB);display:flex;align-items:center;justify-content:center;font-size:20px;color:#fff;">💬</div><div><div style="font-weight:700;font-size:18px;">\u65B0\u5EFA Agent \u5BF9\u8BDD</div><div style="font-size:13px;color:var(--tx2);margin-top:2px;">\u9009\u62E9\u597D\u53CB\u5F00\u59CB\u5546\u52A1\u5BF9\u63A5</div></div></div>';

  h += '<div style="background:var(--bg-soft);border:1px solid var(--bd);border-radius:12px;padding:16px;margin-bottom:20px;">';
  h += '<div style="font-weight:700;font-size:14px;margin-bottom:12px;display:flex;align-items:center;gap:6px;">🤖 \u5173\u8054\u516C\u53F8</div>';
  h += '<select id="create-room-company" style="width:100%;padding:8px 10px;border:1px solid var(--bd);border-radius:8px;font-size:13px;background:var(--bg-soft);color:var(--tx);outline:none;">';
  if (companies.length === 0) {
    h += '<option value="">(\u8BF7\u5148\u521B\u5EFA\u516C\u53F8)</option>';
  } else {
    companies.forEach(function(c) { h += '<option value="' + c.id + '">' + esc(c.name) + '</option>'; });
  }
  h += '</select>';
  h += '<div style="font-size:11px;color:var(--tx2);margin-top:8px;">💡 Agent \u5C06\u4EE5\u52A9\u7406\u89D2\u8272\u4EE3\u8868\u4F60\u7684\u516C\u53F8\u53C2\u4E0E\u5BF9\u8BDD</div>';
  h += '</div>';

  h += '<label style="font-weight:600;font-size:13px;margin-bottom:6px;display:block;">\u5BF9\u8BDD\u540D\u79F0 <span style="font-weight:400;font-size:11px;color:var(--tx2);">(\u53EF\u9009)</span></label>';
  h += '<input type="text" id="room-name-input" placeholder="\u7559\u7A7A\u5219\u81EA\u52A8\u547D\u540D" style="width:100%;padding:9px 14px;border:1px solid var(--bd);border-radius:10px;font-size:14px;background:var(--bg-soft);color:var(--tx);outline:none;box-sizing:border-box;margin-bottom:18px;" onfocus="this.style.borderColor=&quot;var(--accent)&quot;" onblur="this.style.borderColor=&quot;var(--bd)&quot;" />';
  var sortedFriends = friends.slice().sort(function(a, b) { return (a.name || '').localeCompare(b.name || '', 'zh-CN'); });
  h += '<label style="font-weight:600;font-size:13px;margin-bottom:6px;display:block;">\u9009\u62E9\u597D\u53CB</label>';
  h += '<select id="create-room-friend" style="width:100%;padding:9px 10px;border:1px solid var(--bd);border-radius:10px;font-size:14px;background:var(--bg-soft);color:var(--tx);outline:none;box-sizing:border-box;">';
  sortedFriends.forEach(function(f) { h += '<option value="' + f.friend_id + '">' + esc(f.name) + ' (' + esc(f.email) + ')</option>'; });
  h += '</select>';
  h += '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:20px;padding-top:16px;border-top:1px solid var(--bd);">';
  h += '<button class="btn btn-secondary" onclick="closeModal()" style="padding:10px 20px;border-radius:10px;">\u53D6\u6D88</button>';
  h += '<button class="btn btn-primary" onclick="doCreateGroupRoom()" style="padding:10px 24px;border-radius:10px;">\u521B\u5EFA\u5BF9\u8BDD</button></div>';
  h += '</div>';
  showModal(h);
}

async function doCreateGroupRoom() {
  var name = document.getElementById('room-name-input')?.value?.trim();
  var companyId = document.getElementById('create-room-company')?.value || '';
  var agentRole = 'assistant';
  var friendSelect = document.getElementById('create-room-friend');
  var friendId = friendSelect?.value || '';
  if (!friendId) { toast('\u8BF7\u9009\u62E9\u597D\u53CB', 'error'); return; }
  var friendName = friendSelect?.options?.[friendSelect.selectedIndex]?.text?.split(' (')[0] || '';
  if (!name) name = friendName || '\u79C1\u804A';
  var type = 'dm';
  try {
    var data = await apiPost('/agent-rooms', { type: type, name: name, company_id: companyId, agent_role: agentRole, invite_friend_id: friendId });
    closeModal();
    toast('\u5BF9\u8BDD\u5DF2\u521B\u5EFA\uFF0C\u7B49\u5F85\u5BF9\u65B9\u63A5\u53D7\u9080\u8BF7', 'success');
    var refreshData = await api('/agent-rooms');
    _agentRoomListCache = refreshData.rooms || [];
    renderAgentRoomList(_agentRoomListCache);
    selectAgentRoom(data.room_id);
  } catch(e) { toast(e.message, 'error'); }
}

// ─── Agent 房间详情（右侧面板）─────────────────────────────────────────
var _dialogueAbort = null;

async function loadAgentRoom(roomId) {
  _agentActiveRoomId = roomId;
  if (!state.companies || !state.companies.length) { try { var d = await api('/dashboard'); state.companies = d.companies || []; } catch(e) {} }
  var mc = document.getElementById('mc'); if (!mc) return;
  var data = await api('/agent-rooms');
  _agentRoomListCache = data.rooms || [];
  try { var invData = await api('/agent-rooms/invites'); _agentInvitesCache = invData.invites || []; } catch(e) { _agentInvitesCache = []; }
  mc.innerHTML = renderAgentSplitLayout();
  renderAgentInviteCards(_agentInvitesCache);
  renderAgentRoomList(_agentRoomListCache);
  await loadAgentRoomDetail(roomId);
  startAgentPoll();
}

async function loadAgentRoomDetail(roomId) {
  var panel = document.getElementById('agent-room-detail'); if (!panel) return;
  var roomData = await api('/agent-rooms/' + roomId);
  var msgData = await api('/agent-rooms/' + roomId + '/messages');
  var room = roomData.room;
  var members = roomData.members || [];
  var pendingMembers = roomData.pending_members || [];
  _agentPendingSnapshot = pendingMembers.map(function(m){return m.name}).join(',');
  var messages = msgData.messages || [];
  var colors = ['#F97316','#8B5CF6','#3B82F6','#EC4899','#10B981','#F59E0B'];
  var myMember = members.find(function(m) { return m.user_id === state.user?.id; });
  var myConfigured = myMember && myMember.company_id && myMember.agent_role;
  var unconfiguredOthers = members.filter(function(m) { return m.user_id !== state.user?.id && (!m.company_id || !m.agent_role); });

  var h = '<div style="display:flex;flex-direction:column;height:100%;overflow:hidden;">';

  // Header
  h += '<div style="display:flex;align-items:center;gap:12px;padding:12px 20px;border-bottom:1px solid var(--bd);background:var(--card);flex-shrink:0;">';
  h += '<div style="flex:1;"><div style="font-weight:700;font-size:15px;">' + esc(room.name) + '</div>';
  h += '<div style="font-size:11px;color:var(--tx2);display:flex;align-items:center;gap:4px;margin-top:2px;"><span style="width:5px;height:5px;border-radius:50%;background:#10B981;"></span> ' + members.length + ' \u4E2A Agent</div></div>';
  h += '<div style="display:flex;gap:4px;margin-right:4px;">';
  members.forEach(function(m, idx) {
    var c = colors[idx % colors.length];
    var cfg = m.company_id && m.agent_role;
    h += '<div style="width:28px;height:28px;border-radius:50%;background:linear-gradient(135deg,' + c + ',' + c + 'aa);color:#fff;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;border:2px solid ' + (cfg ? 'var(--card)' : '#FCD34D') + ';" title="' + esc(m.name) + (cfg ? '' : ' (\u672A\u914D\u7F6E)') + '">' + esc((m.name || '?')[0]) + '</div>';
  });
  h += '</div>';
  h += '<button onclick="showRoomSettings(&quot;' + roomId + '&quot;)" style="width:30px;height:30px;border-radius:8px;border:1px solid var(--bd);background:transparent;display:flex;align-items:center;justify-content:center;cursor:pointer;color:var(--tx2);font-size:13px;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">\u2699</button>';
  h += '</div>';

  // Warnings
  if (!myConfigured) {
    h += '<div style="display:flex;align-items:center;gap:8px;padding:8px 20px;background:#FEF3C7;font-size:12px;color:#92400E;flex-shrink:0;">';
    h += '⚠️ <span>\u4F60\u7684 Agent \u672A\u914D\u7F6E</span>';
    h += '<button onclick="showRoomSettings(&quot;' + roomId + '&quot;)" style="margin-left:auto;background:#F59E0B;color:#fff;border:none;border-radius:6px;padding:3px 10px;font-size:11px;cursor:pointer;">\u8BBE\u7F6E</button></div>';
  }
  if (unconfiguredOthers.length > 0) {
    h += '<div style="padding:6px 20px;background:var(--bg-soft);font-size:11px;color:var(--tx2);flex-shrink:0;border-bottom:1px solid var(--bd);">\uD83D\uDCA4 ' + esc(unconfiguredOthers.map(function(m) { return m.name; }).join('\u3001')) + ' \u7684 Agent \u672A\u914D\u7F6E</div>';
  }
  if (pendingMembers.length > 0) {
    h += '<div style="padding:6px 20px;background:rgba(59,130,246,0.06);font-size:11px;color:#3B82F6;flex-shrink:0;border-bottom:1px solid var(--bd);">\u2709\uFE0F \u7B49\u5F85 ' + esc(pendingMembers.map(function(m) { return m.name; }).join('\u3001')) + ' \u63A5\u53D7\u9080\u8BF7</div>';
  }

  // Progress bar
  h += '<div id="dialogue-progress" style="display:none;padding:8px 20px;background:var(--card);border-bottom:1px solid var(--bd);flex-shrink:0;">';
  h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;"><div style="display:flex;align-items:center;gap:6px;"><span style="font-size:13px;">🤖</span><span id="dialogue-status" style="font-weight:600;font-size:12px;">Agent \u5BF9\u8BDD\u4E2D</span></div>';
  h += '<div style="display:flex;align-items:center;gap:6px;"><span id="dialogue-turn-text" style="font-size:11px;color:var(--tx2);">0/10</span>';
  h += '<button id="dialogue-stop-btn" onclick="stopDialogue(&quot;' + roomId + '&quot;)" style="padding:3px 10px;border-radius:6px;border:1px solid #DC2626;background:transparent;color:#DC2626;font-size:10px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.background=&quot;#DC2626&quot;;this.style.color=&quot;#fff&quot;" onmouseout="this.style.background=&quot;transparent&quot;;this.style.color=&quot;#DC2626&quot;">\u25A0 \u7ED3\u675F</button></div></div>';
  h += '<div style="height:3px;background:var(--bg-soft);border-radius:3px;overflow:hidden;"><div id="dialogue-progress-bar" style="height:100%;width:0%;background:linear-gradient(90deg,#F97316,#3B82F6);border-radius:3px;transition:width 0.5s ease;"></div></div></div>';

  // Messages area
  h += '<div id="agent-room-messages" class="scroll-area" style="flex:1;overflow-y:auto;padding:16px 20px;">';

  if (messages.length === 0) {
    h += '<div style="text-align:center;padding:60px 20px;">';
    h += '<div style="font-size:48px;margin-bottom:16px;opacity:0.6;">🤖💬🤖</div>';
    h += '<div style="font-size:15px;font-weight:700;margin-bottom:6px;">\u6307\u4EE4\u5F0F Agent \u5BF9\u8BDD</div>';
    h += '<div style="font-size:13px;color:var(--tx2);max-width:400px;margin:0 auto;line-height:1.7;">\u8F93\u5165\u8BAE\u9898\uFF0CAgent \u5C06\u81EA\u52A8\u591A\u8F6E\u5BF9\u8BDD\uFF0C\u8FBE\u6210\u5171\u8BC6\u540E\u751F\u6210\u603B\u7ED3</div>';
    h += '<div style="display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin-top:16px;">';
    var examples = ['\u4E92\u76F8\u4ECB\u7ECD\u516C\u53F8\u4E1A\u52A1','\u63A2\u8BA8\u9879\u76EE\u5408\u4F5C','\u5BF9\u9F50\u670D\u52A1\u80FD\u529B\u548C\u4EF7\u683C','\u8BA8\u8BBA\u8D44\u6E90\u4E92\u6362'];
    examples.forEach(function(ex) {
      h += '<button onclick="document.getElementById(&quot;agent-room-input&quot;).value=&quot;' + ex + '&quot;;document.getElementById(&quot;agent-room-input&quot;).focus();" style="padding:6px 14px;border-radius:20px;border:1px solid var(--bd);background:var(--card);color:var(--tx);font-size:12px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">' + ex + '</button>';
    });
    h += '</div></div>';
  }

  messages.forEach(function(m, idx) {
    h += renderRoomMsg(m, members, colors, idx);
  });
  h += '</div>';

  // Input area
  h += '<div style="display:flex;gap:8px;align-items:center;padding:10px 20px;border-top:1px solid var(--bd);background:var(--card);flex-shrink:0;">';
  h += '<input type="text" id="agent-room-input" placeholder="\u8F93\u5165\u8BAE\u9898\uFF0CAgent \u5C06\u81EA\u52A8\u591A\u8F6E\u5BF9\u8BDD..." style="flex:1;padding:9px 14px;border:1px solid var(--bd);border-radius:10px;font-size:14px;background:var(--bg-soft);color:var(--tx);outline:none;transition:border 0.2s;" onfocus="this.style.borderColor=&quot;var(--accent)&quot;" onblur="this.style.borderColor=&quot;var(--bd)&quot;" />';
  h += '<select id="agent-room-turns" style="padding:9px 6px;border:1px solid var(--bd);border-radius:10px;font-size:12px;background:var(--bg-soft);color:var(--tx);outline:none;width:70px;">';
  [6,8,10,15,20].forEach(function(n) { h += '<option value="' + n + '"' + (n === 10 ? ' selected' : '') + '>' + n + ' \u8F6E</option>'; });
  h += '</select>';
  h += '<button class="btn btn-primary" id="agent-room-send-btn" onclick="startAgentDialogue(&quot;' + roomId + '&quot;)" style="border-radius:10px;padding:9px 18px;display:flex;align-items:center;gap:4px;white-space:nowrap;font-size:13px;">🚀 \u53D1\u8D77\u5BF9\u8BDD</button>';
  h += '</div></div>';
  panel.innerHTML = h;

  var msgContainer = document.getElementById('agent-room-messages');
  if (msgContainer) msgContainer.scrollTop = msgContainer.scrollHeight;
  var roomInput = document.getElementById('agent-room-input');
  roomInput?.addEventListener('keydown', function(e) { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); startAgentDialogue(roomId); } });
  roomInput?.focus();
}

function renderMd(text) {
  if (typeof marked !== 'undefined' && marked.parse) {
    try { return marked.parse(text); } catch(e) {}
  }
  return safeFormatMd(text);
}

function renderRoomMsg(m, members, colors, idx) {
  var isSystem = m.msg_type === 'system';
  var isMe = m.sender_user_id === state.user?.id;
  if (isSystem) {
    var isSummary = m.content.indexOf('\u5BF9\u8BDD\u603B\u7ED3') >= 0 || m.content.indexOf('##') >= 0 || m.content.indexOf('**') >= 0;
    if (isSummary) {
      var summaryId = 'summary-' + idx + '-' + Date.now();
      return '<div style="margin:16px 0;padding:16px 18px;background:linear-gradient(135deg,rgba(59,130,246,0.06),rgba(139,92,246,0.06));border:1px solid rgba(59,130,246,0.15);border-radius:14px;">' +
        '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;"><div style="display:flex;align-items:center;gap:8px;"><span style="font-size:16px;">📊</span><span style="font-weight:700;font-size:14px;">\u5BF9\u8BDD\u603B\u7ED3</span></div>' +
        '<div style="display:flex;gap:4px;"><button onclick="exportSummary(&quot;md&quot;,this)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">📄 MD</button>' +
        '<button onclick="exportSummary(&quot;docx&quot;,this)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;transition:all 0.15s;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">📝 Word</button></div></div>' +
        '<div class="md-content" style="font-size:13px;color:var(--tx);line-height:1.8;">' + renderMd(m.content) + '</div></div>';
    }
    return '<div style="text-align:center;padding:8px;"><span style="font-size:11px;color:var(--tx2);background:var(--bg);padding:4px 12px;border-radius:10px;">' + esc(m.content) + '</span></div>';
  }
  var memberIdx = members.findIndex(function(mb) { return mb.user_id === m.sender_user_id; });
  var avatarColor = colors[(memberIdx >= 0 ? memberIdx : idx) % colors.length];
  var h = '<div style="display:flex;gap:10px;margin-bottom:14px;' + (isMe ? 'flex-direction:row-reverse;' : '') + '">';
  h += '<div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,' + avatarColor + ',' + avatarColor + 'aa);color:#fff;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;flex-shrink:0;box-shadow:0 2px 8px ' + avatarColor + '30;">' + esc((m.sender_name || '?')[0]) + '</div>';
  h += '<div style="max-width:68%;">';
  h += '<div style="font-size:11px;color:var(--tx2);margin-bottom:3px;' + (isMe ? 'text-align:right;' : '') + '">' + esc(m.sender_name || '') + (m.sender_agent_role && m.sender_agent_role !== 'system' ? ' <span style="opacity:0.5;">(' + esc(m.sender_agent_role) + ')</span>' : '') + '</div>';
  if (isMe) {
    h += '<div style="padding:10px 14px;background:linear-gradient(135deg,var(--accent),#EA580C);color:#fff;border-radius:14px 4px 14px 14px;font-size:14px;line-height:1.6;">' + esc(m.content) + '</div>';
  } else {
    h += '<div style="padding:10px 14px;background:var(--card);border:1px solid var(--bd);color:var(--tx);border-radius:4px 14px 14px 14px;font-size:14px;line-height:1.6;">' + esc(m.content) + '</div>';
  }
  h += '</div></div>';
  return h;
}

async function startAgentDialogue(roomId) {
  var input = document.getElementById('agent-room-input');
  var topic = input?.value?.trim();
  if (!topic) { toast('\u8BF7\u8F93\u5165\u5BF9\u8BDD\u8BAE\u9898', 'error'); return; }
  input.value = '';
  var turnsSelect = document.getElementById('agent-room-turns');
  var maxTurns = Number(turnsSelect?.value) || 10;

  var sendBtn = document.getElementById('agent-room-send-btn');
  if (sendBtn) { sendBtn.disabled = true; sendBtn.innerHTML = '🔄 \u5BF9\u8BDD\u4E2D...'; }
  input.disabled = true;
  stopAgentPoll();

  var container = document.getElementById('agent-room-messages');
  var progress = document.getElementById('dialogue-progress');
  if (progress) progress.style.display = 'block';

  var token = state.token || '';
  var colors = ['#F97316','#8B5CF6','#3B82F6','#EC4899','#10B981','#F59E0B'];

  try {
    var resp = await fetch('/api/agent-rooms/' + roomId + '/dialogue', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
      body: JSON.stringify({ topic: topic, max_turns: maxTurns }),
    });

    if (!resp.ok) {
      var errData = await resp.json().catch(function() { return { error: 'unknown' }; });
      toast(errData.error || '\u53D1\u8D77\u5BF9\u8BDD\u5931\u8D25', 'error');
      if (sendBtn) { sendBtn.disabled = false; sendBtn.innerHTML = '🚀 \u53D1\u8D77\u5BF9\u8BDD'; }
      input.disabled = false;
      if (progress) progress.style.display = 'none';
      return;
    }

    var reader = resp.body.getReader();
    var decoder = new TextDecoder();
    var buffer = '';

    while (true) {
      var readResult = await reader.read();
      if (readResult.done) break;
      buffer += decoder.decode(readResult.value, { stream: true });

      var lines = buffer.split(String.fromCharCode(10));
      buffer = lines.pop() || '';

      var currentEvent = '';
      for (var i = 0; i < lines.length; i++) {
        var line = lines[i];
        if (line.startsWith('event: ')) { currentEvent = line.slice(7).trim(); continue; }
        if (line.startsWith('data: ') && currentEvent) {
          try {
            var payload = JSON.parse(line.slice(6));
            handleDialogueEvent(currentEvent, payload, container, colors, maxTurns);
          } catch(e) {}
          currentEvent = '';
        }
      }
    }
  } catch(e) {
    toast(e.message || '\u5BF9\u8BDD\u8FDE\u63A5\u5931\u8D25', 'error');
  }

  if (sendBtn) { sendBtn.disabled = false; sendBtn.innerHTML = '🚀 \u53D1\u8D77\u5BF9\u8BDD'; }
  input.disabled = false;
  if (progress) progress.style.display = 'none';
  startAgentPoll();
}

function handleDialogueEvent(event, data, container, colors, maxTurns) {
  var statusEl = document.getElementById('dialogue-status');
  var turnText = document.getElementById('dialogue-turn-text');
  var progressBar = document.getElementById('dialogue-progress-bar');

  if (event === 'session_start') {
    container.innerHTML += '<div style="text-align:center;padding:12px;"><div style="display:inline-flex;align-items:center;gap:8px;padding:8px 18px;background:linear-gradient(135deg,rgba(249,115,22,0.08),rgba(59,130,246,0.08));border:1px solid rgba(249,115,22,0.2);border-radius:20px;font-size:13px;font-weight:600;color:var(--tx);">📋 ' + esc(data.topic) + ' <span style="font-size:11px;color:var(--tx2);font-weight:400;">\u00B7 \u6700\u591A ' + data.max_turns + ' \u8F6E</span></div></div>';
    container.scrollTop = container.scrollHeight;
  }

  if (event === 'turn_start') {
    var pct = Math.round(((data.turn - 1) / maxTurns) * 100);
    if (progressBar) progressBar.style.width = pct + '%';
    if (turnText) turnText.textContent = data.turn + '/' + maxTurns;
    if (statusEl) statusEl.textContent = data.speaker.name + ' \u7684 Agent \u6B63\u5728\u8BF4...';

    var isMyAgent = data.speaker.user_id === (state.user ? state.user.id : '');
    var color = colors[(data.turn - 1) % colors.length];
    var el = document.createElement('div');
    el.id = 'turn-bubble-' + data.turn;
    el.style.cssText = 'display:flex;gap:10px;margin-bottom:14px;' + (isMyAgent ? 'flex-direction:row-reverse;' : '');
    var bubbleBg = isMyAgent ? 'background:linear-gradient(135deg,var(--accent),#EA580C);color:#fff;border-radius:14px 4px 14px 14px;' : 'background:var(--card);border:1px solid var(--bd);color:var(--tx);border-radius:4px 14px 14px 14px;';
    el.innerHTML = '<div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,' + color + ',' + color + 'aa);color:#fff;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;flex-shrink:0;box-shadow:0 2px 8px ' + color + '30;">' + esc(data.speaker.name[0]) + '</div><div style="max-width:68%;"><div style="font-size:11px;color:var(--tx2);margin-bottom:3px;' + (isMyAgent ? 'text-align:right;' : '') + '">' + esc(data.speaker.name) + ' <span style="opacity:0.5;">(' + esc(data.speaker.role) + ')</span> <span style="opacity:0.4;">\u00B7 \u7B2C ' + data.turn + ' \u8F6E</span></div><div id="turn-text-' + data.turn + '" style="padding:10px 14px;' + bubbleBg + 'font-size:14px;line-height:1.6;min-height:20px;"><span style="display:inline-flex;gap:2px;"><span style="width:5px;height:5px;border-radius:50%;background:currentColor;opacity:0.5;animation:pulse 1s infinite;"></span><span style="width:5px;height:5px;border-radius:50%;background:currentColor;opacity:0.5;animation:pulse 1s 0.15s infinite;"></span><span style="width:5px;height:5px;border-radius:50%;background:currentColor;opacity:0.5;animation:pulse 1s 0.3s infinite;"></span></span></div></div>';
    container.appendChild(el);
    container.scrollTop = container.scrollHeight;
  }

  if (event === 'turn_chunk') {
    var textEl = document.getElementById('turn-text-' + data.turn);
    if (textEl) {
      var dots = textEl.querySelector('span[style*="inline-flex"]');
      if (dots) dots.remove();
      textEl.textContent = (textEl.textContent || '') + data.chunk;
      container.scrollTop = container.scrollHeight;
    }
  }

  if (event === 'turn_done') {
    var pct2 = Math.round((data.turn / maxTurns) * 100);
    if (progressBar) progressBar.style.width = pct2 + '%';
    if (turnText) turnText.textContent = data.turn + '/' + maxTurns;
    if (statusEl) statusEl.textContent = 'Agent \u5BF9\u8BDD\u4E2D \u00B7 \u7B2C ' + data.turn + '/' + maxTurns + ' \u8F6E';
    container.scrollTop = container.scrollHeight;
  }

  if (event === 'summarizing') {
    if (statusEl) statusEl.textContent = '\u2728 \u6B63\u5728\u751F\u6210\u603B\u7ED3...';
    if (progressBar) progressBar.style.width = '100%';
  }

  if (event === 'summary') {
    window._lastSummaryMd = data.summary || '';
    container.innerHTML += '<div style="margin:16px 0;padding:16px 18px;background:linear-gradient(135deg,rgba(59,130,246,0.06),rgba(139,92,246,0.06));border:1px solid rgba(59,130,246,0.15);border-radius:14px;">' +
      '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;"><div style="display:flex;align-items:center;gap:8px;"><span style="font-size:16px;">📊</span><span style="font-weight:700;font-size:14px;">\u5BF9\u8BDD\u603B\u7ED3</span></div>' +
      '<div style="display:flex;gap:4px;"><button onclick="exportSummary(&quot;md&quot;,this)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">📄 MD</button>' +
      '<button onclick="exportSummary(&quot;docx&quot;,this)" style="padding:3px 10px;border-radius:6px;border:1px solid var(--bd);background:transparent;color:var(--tx2);font-size:11px;cursor:pointer;" onmouseover="this.style.borderColor=&quot;var(--accent)&quot;" onmouseout="this.style.borderColor=&quot;var(--bd)&quot;">📝 Word</button></div></div>' +
      '<div class="md-content" style="font-size:13px;color:var(--tx);line-height:1.8;">' + renderMd(data.summary) + '</div></div>';
    container.scrollTop = container.scrollHeight;
  }

  if (event === 'session_end') {
    var reasonMap = { consensus: '\u2705 \u53CC\u65B9\u8FBE\u6210\u5171\u8BC6', stopped: '\u25A0 \u624B\u52A8\u7ED3\u675F', max_turns: '\u2705 \u5DF2\u5B8C\u6210\u5168\u90E8\u8F6E\u6B21' };
    container.innerHTML += '<div style="text-align:center;padding:12px;"><span style="font-size:12px;padding:6px 16px;border-radius:20px;background:var(--bg);color:var(--tx2);border:1px solid var(--bd);">' + (reasonMap[data.reason] || data.reason) + ' \u00B7 \u5171 ' + data.total_turns + ' \u8F6E</span></div>';
    container.scrollTop = container.scrollHeight;
  }

  if (event === 'error') {
    container.innerHTML += '<div style="text-align:center;padding:10px;"><span style="font-size:12px;color:#DC2626;background:#FEE2E2;padding:6px 14px;border-radius:10px;">❌ ' + esc(data.message) + '</span></div>';
    container.scrollTop = container.scrollHeight;
  }
}

async function stopDialogue(roomId) {
  try {
    await apiPost('/agent-rooms/' + roomId + '/dialogue/stop');
    toast('\u5BF9\u8BDD\u5C06\u5728\u5F53\u524D\u8F6E\u7ED3\u675F\u540E\u505C\u6B62');
  } catch(e) { toast(e.message, 'error'); }
}

async function sendAgentRoomMsg(roomId) {
  startAgentDialogue(roomId);
}

function confirmDeleteRoom(roomId, roomName) {
  var h = '<div class="modal-header"><h3>\u5220\u9664\u5BF9\u8BDD</h3><button class="modal-close" onclick="closeModal()">\u2715</button></div>';
  h += '<div class="modal-body" style="align-items:center;text-align:center;padding:32px 22px 28px;">';
  h += '<div style="width:64px;height:64px;border-radius:18px;background:rgba(220,38,38,0.1);display:flex;align-items:center;justify-content:center;font-size:30px;margin-bottom:12px;">🗑️</div>';
  h += '<div style="font-size:17px;font-weight:700;margin-bottom:8px;">\u786E\u5B9A\u5220\u9664\u8FD9\u4E2A\u5BF9\u8BDD\uFF1F</div>';
  h += '<div style="font-size:15px;color:var(--tx2);line-height:1.7;">\u300C<span style="color:var(--accent);font-weight:600;">' + esc(roomName) + '</span>\u300D\u7684\u6240\u6709\u804A\u5929\u8BB0\u5F55\u5C06\u88AB\u6C38\u4E45\u5220\u9664\u3002</div>';
  h += '</div>';
  h += '<div class="modal-footer">';
  h += '<button class="btn btn-secondary" onclick="closeModal()" style="padding:10px 28px;">\u53D6\u6D88</button>';
  h += '<button class="btn" onclick="deleteRoom(&quot;' + roomId + '&quot;)" style="padding:10px 28px;background:#DC2626;color:#fff;border-color:#DC2626;transition:all 0.15s;" onmouseover="this.style.background=&quot;#B91C1C&quot;;this.style.transform=&quot;translateY(-1px)&quot;;this.style.boxShadow=&quot;0 8px 20px rgba(220,38,38,0.3)&quot;" onmouseout="this.style.background=&quot;#DC2626&quot;;this.style.transform=&quot;&quot;;this.style.boxShadow=&quot;&quot;">\u5220\u9664</button>';
  h += '</div>';
  showModal(h);
}

async function deleteRoom(roomId) {
  try {
    await apiDel('/agent-rooms/' + roomId);
    closeModal();
    toast('\u5BF9\u8BDD\u5DF2\u5220\u9664', 'success');
    _agentRoomListCache = _agentRoomListCache.filter(function(r) { return r.id !== roomId; });
    renderAgentRoomList(_agentRoomListCache);
    if (_agentActiveRoomId === roomId) {
      _agentActiveRoomId = null;
      var panel = document.getElementById('agent-room-detail');
      if (panel) panel.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--tx2);font-size:14px;">\u9009\u62E9\u4E00\u4E2A\u5BF9\u8BDD</div>';
      if (_agentRoomListCache.length > 0) selectAgentRoom(_agentRoomListCache[0].id);
    }
  } catch(e) { toast(e.message, 'error'); }
}

function exportSummary(format, btnEl) {
  var mdContent = window._lastSummaryMd || '';
  if (!mdContent && btnEl) {
    var card = btnEl.closest('.md-content') ? btnEl.closest('div[style*="margin"]') : btnEl.parentElement?.parentElement?.parentElement;
    var mdEl = card ? card.querySelector('.md-content') : null;
    if (mdEl) mdContent = mdEl.innerText || mdEl.textContent || '';
  }
  if (!mdContent) { toast('\u6CA1\u6709\u53EF\u5BFC\u51FA\u7684\u5185\u5BB9', 'error'); return; }

  var summaryTitle = '';
  var lines = mdContent.trim().split(String.fromCharCode(10));
  for (var li = 0; li < lines.length; li++) {
    var line = lines[li].trim();
    if (line) { summaryTitle = line; break; }
  }
  var filename = buildExportFilename(summaryTitle, '\u5BF9\u8BDD\u603B\u7ED3_' + new Date().toISOString().slice(0,10));
  if (format === 'md') {
    var blob = new Blob([mdContent], { type: 'text/markdown;charset=utf-8' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a'); a.href = url; a.download = filename + '.md'; a.click();
    URL.revokeObjectURL(url);
    toast('\u5DF2\u5BFC\u51FA MD \u6587\u4EF6', 'success');
  } else if (format === 'docx') {
    var summaryCard = btnEl ? btnEl.closest('div[style*="margin"]') : null;
    var summaryHtmlEl = summaryCard ? summaryCard.querySelector('.md-content') : null;
    var htmlContent = summaryHtmlEl ? summaryHtmlEl.innerHTML : renderMd(mdContent);
    var docHtml = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8"><style>body{font-family:"Microsoft YaHei",sans-serif;font-size:14px;line-height:1.8;color:#333;}h1,h2,h3{color:#1a1a1a;}ul,ol{padding-left:20px;}</style></head><body>' + htmlContent + '</body></html>';
    var blob2 = new Blob([docHtml], { type: 'application/msword;charset=utf-8' });
    var url2 = URL.createObjectURL(blob2);
    var a2 = document.createElement('a'); a2.href = url2; a2.download = filename + '.doc'; a2.click();
    URL.revokeObjectURL(url2);
    toast('\u5DF2\u5BFC\u51FA Word \u6587\u4EF6', 'success');
  }
}

async function showRoomSettings(roomId) {
  if (!state.companies || !state.companies.length) { try { var d = await api('/dashboard'); state.companies = d.companies || []; } catch(e) {} }
  var data = await api('/agent-rooms/' + roomId);
  var members = data.members || [];
  var companies = state.companies || [];
  var myMember = members.find(function(m) { return m.user_id === state.user?.id; });
  var mColors = ['#F97316','#8B5CF6','#3B82F6','#EC4899','#10B981','#F59E0B'];

  var h = '<div style="padding:24px;">';
  h += '<div style="display:flex;align-items:center;gap:12px;margin-bottom:24px;"><div style="width:44px;height:44px;border-radius:12px;background:linear-gradient(135deg,#6366F1,#4F46E5);display:flex;align-items:center;justify-content:center;font-size:20px;color:#fff;">\u2699</div><div><div style="font-weight:700;font-size:18px;">\u623F\u95F4\u8BBE\u7F6E</div><div style="font-size:13px;color:var(--tx2);margin-top:2px;">\u914D\u7F6E Agent \u89D2\u8272\u3001\u5173\u8054\u516C\u53F8\u548C\u4FE1\u606F\u5171\u4EAB\u8303\u56F4</div></div></div>';

  // Members
  h += '<div style="margin-bottom:20px;"><div style="font-weight:600;font-size:14px;margin-bottom:10px;display:flex;align-items:center;gap:6px;">\u6210\u5458\u5217\u8868 <span style="font-size:11px;padding:2px 8px;border-radius:10px;background:var(--bg-soft);color:var(--tx2);">' + members.length + ' \u4EBA</span></div>';
  members.forEach(function(m, idx) {
    var c = mColors[idx % mColors.length];
    h += '<div style="display:flex;align-items:center;gap:12px;padding:10px 12px;background:var(--bg-soft);border-radius:10px;margin-bottom:6px;">';
    h += '<div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,' + c + ',' + c + 'aa);color:#fff;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:13px;flex-shrink:0;">' + esc((m.name || '?')[0]) + '</div>';
    h += '<div style="flex:1;"><div style="font-weight:600;font-size:13px;">' + esc(m.name) + (m.user_id === state.user?.id ? ' <span style="font-size:10px;padding:1px 6px;border-radius:8px;background:var(--accent);color:#fff;">\u6211</span>' : '') + '</div>';
    h += '<div style="font-size:11px;color:var(--tx2);margin-top:1px;">' + esc(m.company_name || '\u672A\u9009\u62E9\u516C\u53F8') + ' \u00B7 ' + esc(m.agent_role || '\u672A\u8BBE\u7F6E') + '</div></div></div>';
  });
  h += '</div>';

  if (myMember) {
    h += '<div style="border-top:1px solid var(--bd);padding-top:18px;">';
    h += '<div style="font-weight:700;font-size:15px;margin-bottom:14px;display:flex;align-items:center;gap:6px;">🤖 \u6211\u7684 Agent \u8BBE\u7F6E</div>';

    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px;">';
    h += '<div><label style="font-weight:600;font-size:12px;color:var(--tx2);margin-bottom:6px;display:block;">\u5173\u8054\u516C\u53F8</label>';
    h += '<select id="room-my-company" style="width:100%;padding:9px 12px;border:1px solid var(--bd);border-radius:10px;font-size:13px;background:var(--bg-soft);color:var(--tx);outline:none;">';
    companies.forEach(function(c) { h += '<option value="' + c.id + '"' + (c.id === myMember.company_id ? ' selected' : '') + '>' + esc(c.name) + '</option>'; });
    h += '</select></div>';

    h += '<div><label style="font-weight:600;font-size:12px;color:var(--tx2);margin-bottom:6px;display:block;">Agent \u89D2\u8272</label>';
    h += '<select id="room-my-role" style="width:100%;padding:9px 12px;border:1px solid var(--bd);border-radius:10px;font-size:13px;background:var(--bg-soft);color:var(--tx);outline:none;">';
    var roleLabels = { assistant: '\u52A9\u7406', cfo: 'CFO \u8D22\u52A1', legal: '\u6CD5\u52A1', hr: 'HR \u4EBA\u4E8B', cmo: 'CMO \u8425\u9500', cto: 'CTO \u6280\u672F', product: '\u4EA7\u54C1', operation: '\u8FD0\u8425' };
    ['assistant','cfo','legal','hr','cmo','cto','product','operation'].forEach(function(r) { h += '<option value="' + r + '"' + (r === myMember.agent_role ? ' selected' : '') + '>' + (roleLabels[r] || r) + '</option>'; });
    h += '</select></div></div>';

    h += '<div><label style="font-weight:600;font-size:12px;color:var(--tx2);margin-bottom:8px;display:flex;align-items:center;gap:6px;">🔒 \u4FE1\u606F\u5171\u4EAB\u8303\u56F4 <span style="font-size:10px;color:var(--tx2);font-weight:400;">\u63A7\u5236 Agent \u53EF\u4EE5\u5411\u5BF9\u65B9\u900F\u9732\u7684\u4FE1\u606F</span></label>';
    var scopes = ['basic_info','finance_summary','projects','contacts','capabilities','employees','schedule'];
    var scopeLabels = { basic_info: '\u516C\u53F8\u57FA\u672C\u4FE1\u606F', finance_summary: '\u8D22\u52A1\u6982\u51B5\uFF08\u8131\u654F\uFF09', projects: '\u9879\u76EE\u6982\u51B5', contacts: '\u5BA2\u6237\u6982\u51B5', capabilities: '\u80FD\u529B/\u670D\u52A1\u6E05\u5355', employees: '\u56E2\u961F\u6982\u51B5', schedule: '\u65E5\u7A0B\u5B89\u6392' };
    var scopeIcons = { basic_info: '🏢', finance_summary: '💰', projects: '📋', contacts: '📇', capabilities: '⚡', employees: '👤', schedule: '📅' };
    var currentScope = Array.isArray(myMember.share_scope) ? myMember.share_scope : ['basic_info'];
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">';
    scopes.forEach(function(s) {
      var checked = currentScope.includes(s);
      h += '<label style="display:flex;align-items:center;gap:8px;padding:8px 10px;border-radius:8px;cursor:pointer;border:1px solid ' + (checked ? 'var(--accent)' : 'var(--bd)') + ';background:' + (checked ? 'rgba(249,115,22,0.04)' : 'transparent') + ';transition:all 0.15s;">';
      h += '<input type="checkbox" class="room-scope-cb" value="' + s + '"' + (checked ? ' checked' : '') + ' style="width:16px;height:16px;accent-color:var(--accent);flex-shrink:0;" onchange="this.parentElement.style.borderColor=this.checked?&quot;var(--accent)&quot;:&quot;var(--bd)&quot;;this.parentElement.style.background=this.checked?&quot;rgba(249,115,22,0.04)&quot;:&quot;transparent&quot;" />';
      h += '<span style="font-size:14px;">' + scopeIcons[s] + '</span>';
      h += '<span style="font-size:12px;font-weight:500;">' + scopeLabels[s] + '</span></label>';
    });
    h += '</div></div></div>';
  }

  h += '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:20px;padding-top:16px;border-top:1px solid var(--bd);">';
  h += '<button class="btn" onclick="closeModal()" style="padding:10px 20px;border-radius:10px;">\u53D6\u6D88</button>';
  h += '<button class="btn btn-primary" onclick="saveRoomSettings(&quot;' + roomId + '&quot;)" style="padding:10px 24px;border-radius:10px;">\u4FDD\u5B58\u8BBE\u7F6E</button></div>';
  h += '</div>';
  showModal(h);
}

async function saveRoomSettings(roomId) {
  var companyId = document.getElementById('room-my-company')?.value || '';
  var agentRole = document.getElementById('room-my-role')?.value || '';
  var scopeCbs = document.querySelectorAll('.room-scope-cb:checked');
  var scope = []; scopeCbs.forEach(function(cb) { scope.push(cb.value); });
  if (scope.length === 0) scope = ['basic_info'];
  try {
    await apiPut('/agent-rooms/' + roomId + '/sharing-rules', { company_id: companyId, agent_role: agentRole, share_scope: scope });
    toast('设置已保存', 'success');
    closeModal();
    loadAgentRoom(roomId);
  } catch(e) { toast(e.message, 'error'); }
}

function quickChat(msg) {
  const input = document.getElementById('chat-input');
  if (input) { input.value = msg; input.focus(); sendChatMessage(); }
}

function triggerCompanyButlerPrompt(msg) {
  quickChat(msg);
}
window.triggerCompanyButlerPrompt = triggerCompanyButlerPrompt;

function openCompanyButlerTab(tab) {
  var companyId = state.chatCompanyId || '';
  if (!companyId) return;
  if (!state.currentCompany || state.currentCompany.id !== companyId) {
    loadCompanyDetail(companyId).then(function() {
      _detailTab = tab || 'overview';
      navigate('company_detail');
    });
    return;
  }
  _detailTab = tab || 'overview';
  navigate('company_detail');
}
window.openCompanyButlerTab = openCompanyButlerTab;

function selectChatCompany(id) {
  state.chatCompanyId = id || '';
  state.chatCompanySnapshot = (state.currentCompany && state.currentCompany.id === state.chatCompanyId && state.companyDetail)
    ? { company: state.currentCompany, dashboard: state.companyDetail.dashboard, stats: state.companyDetail.stats }
    : null;
  state.currentConvId = '';
  state.messages = [];
  sessionStorage.removeItem('opc-conv-id');
  const hidden = document.getElementById('chat-company-select');
  if (hidden) hidden.value = id || '';
  document.querySelectorAll('.chat-company-pill').forEach(function(el) {
    el.classList.toggle('active', el.dataset.id === id);
  });
  renderPage();
}
window.selectChatCompany = selectChatCompany;

// ─── 工具函数 ──────────────────────────────────────────────────────────

function esc(s) { if (!s) return ''; const d = document.createElement('div'); d.textContent = s; return d.innerHTML; }
// 用于 HTML 属性值（额外转义双引号和换行）
function escAttr(s) { if (!s) return ''; return esc(s).replace(/"/g, '&quot;').replace(new RegExp('\\n', 'g'), '&#10;').replace(new RegExp('\\r', 'g'), ''); }
function formatMoney(n) { if (n === undefined || n === null) return '0'; var num = Number(n); if (isNaN(num)) return String(n); if (Math.abs(num) >= 10000) return (num/10000).toFixed(1) + '\u4e07'; return num.toLocaleString('zh-CN', { minimumFractionDigits: 0, maximumFractionDigits: 2 }); }
function statusText(s) { return { active: '运营中', pending: '筹备中', inactive: '已停业', registered: '已注册' }[s] || s; }
function closeModal(id) { if (id) { document.getElementById(id)?.remove(); } else { var m = document.querySelector('.modal-overlay.generic-modal'); if (m) m.remove(); } }
function showModal(titleOrHtml, bodyHtml, footerHtml) {
  closeModal();
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay generic-modal';
  var content = '';
  if (bodyHtml !== undefined) {
    content = '<div class="modal" style="max-width:560px;width:100%;padding:24px 28px;">' +
      '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px"><h2 style="font-size:18px;font-weight:700">' + titleOrHtml + '</h2><button onclick="closeModal()" style="background:none;border:none;font-size:18px;cursor:pointer;color:var(--tx3);padding:4px 8px">&times;</button></div>' +
      '<div style="margin-bottom:20px">' + bodyHtml + '</div>' +
      (footerHtml ? '<div style="display:flex;justify-content:flex-end;gap:8px;margin-top:16px">' + footerHtml + '</div>' : '') +
    '</div>';
  } else {
    content = '<div class="modal" style="max-width:560px;width:100%;padding:24px 28px;">' + titleOrHtml + '</div>';
  }
  overlay.innerHTML = content;
  overlay.addEventListener('click', function(e) { if (e.target === overlay) closeModal(); });
  document.body.appendChild(overlay);
}

function confirmModal(msg, opts) {
  opts = opts || {};
  return new Promise(function(resolve) {
    var title = opts.title || '操作确认';
    var confirmText = opts.confirmText || '确定';
    var cancelText = opts.cancelText || '取消';
    var danger = opts.danger !== false;
    var id = 'confirm-modal-' + Date.now();
    var overlay = document.createElement('div');
    overlay.className = 'modal-overlay generic-modal';
    overlay.id = id;
    overlay.innerHTML = '<div class="modal" style="max-width:420px;width:100%;padding:24px">' +
      '<h3 style="font-size:16px;font-weight:700;margin-bottom:12px">' + esc(title) + '</h3>' +
      '<p style="font-size:14px;color:var(--tx2);line-height:1.7;margin-bottom:20px">' + esc(msg) + '</p>' +
      '<div style="display:flex;justify-content:flex-end;gap:8px">' +
        '<button class="btn btn-secondary" id="' + id + '-cancel">' + esc(cancelText) + '</button>' +
        '<button class="btn ' + (danger ? 'btn-primary' : 'btn-primary') + '" id="' + id + '-ok" style="' + (danger ? 'background:var(--red,#EF4444);border-color:var(--red,#EF4444)' : '') + '">' + esc(confirmText) + '</button>' +
      '</div></div>';
    overlay.addEventListener('click', function(e) { if (e.target === overlay) { overlay.remove(); resolve(false); } });
    document.body.appendChild(overlay);
    document.getElementById(id + '-cancel').onclick = function() { overlay.remove(); resolve(false); };
    document.getElementById(id + '-ok').onclick = function() { overlay.remove(); resolve(true); };
  });
}

var _modalResolve = null;
function modalAlert(msg, type) {
  var icon = type === 'error' ? '<svg viewBox="0 0 24 24" width="28" height="28" fill="none" stroke="var(--red)" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>'
    : type === 'success' ? '<svg viewBox="0 0 24 24" width="28" height="28" fill="none" stroke="var(--green)" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="9 12 12 15 16 10"/></svg>'
    : '<svg viewBox="0 0 24 24" width="28" height="28" fill="none" stroke="var(--accent)" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>';
  showModal(
    '<div class="modal-body" style="text-align:center;padding:30px 24px 10px;">' +
      '<div style="margin-bottom:12px;">' + icon + '</div>' +
      '<div style="font-size:15px;color:var(--tx);line-height:1.6;word-break:break-word;">' + esc(msg) + '</div>' +
    '</div>' +
    '<div class="modal-footer" style="justify-content:center;">' +
      '<button class="btn btn-primary" onclick="_modalOk()">\u786e\u5b9a</button>' +
    '</div>'
  );
  return new Promise(function(resolve) { _modalResolve = resolve; });
}
function _modalOk() { closeModal(); if (_modalResolve) { _modalResolve(true); _modalResolve = null; } }
function _modalCancel() { closeModal(); if (_modalResolve) { _modalResolve(false); _modalResolve = null; } }

function modalConfirm(msg) {
  showModal(
    '<div class="modal-body" style="text-align:center;padding:30px 24px 10px;">' +
      '<div style="margin-bottom:12px;"><svg viewBox="0 0 24 24" width="28" height="28" fill="none" stroke="var(--accent)" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg></div>' +
      '<div style="font-size:15px;color:var(--tx);line-height:1.6;">' + esc(msg) + '</div>' +
    '</div>' +
    '<div class="modal-footer" style="justify-content:center;">' +
      '<button class="btn btn-secondary" onclick="_modalCancel()">\u53d6\u6d88</button>' +
      '<button class="btn btn-primary" onclick="_modalOk()">\u786e\u8ba4</button>' +
    '</div>'
  );
  return new Promise(function(resolve) { _modalResolve = resolve; });
}
window._modalOk = _modalOk;
window._modalCancel = _modalCancel;

