function confirmModal(opts) {
  return new Promise(function(resolve) {
    var title = (opts && opts.title) || '请确认';
    var message = (opts && opts.message) || '确定继续此操作吗？';
    var confirmText = (opts && opts.confirmText) || '确定';
    var cancelText = (opts && opts.cancelText) || '取消';
    var confirmType = (opts && opts.confirmType) || 'primary';
    var dangerStyle = 'background:#ef4444;color:#fff;border:none;';
    var primaryStyle = '';

    var id = 'confirm-modal-' + Date.now() + '-' + Math.floor(Math.random() * 1000);
    var overlay = document.createElement('div');
    overlay.className = 'modal-overlay';
    overlay.id = id;
    overlay.innerHTML =
      '<div class="modal" style="max-width:420px;">' +
        '<div class="modal-header">' +
          '<h3 style="font-size:18px;">' + esc(title) + '</h3>' +
          '<button class="modal-close" data-action="cancel">&times;</button>' +
        '</div>' +
        '<div class="modal-body">' +
          '<p style="color:var(--tx2);line-height:1.7;">' + esc(message) + '</p>' +
        '</div>' +
        '<div class="modal-footer">' +
          '<button class="btn btn-secondary" data-action="cancel">' + esc(cancelText) + '</button>' +
          '<button class="btn ' + (confirmType === 'danger' ? '' : 'btn-primary') + '" style="' + (confirmType === 'danger' ? dangerStyle : primaryStyle) + '" data-action="confirm">' + esc(confirmText) + '</button>' +
        '</div>' +
      '</div>';

    var done = function(v) {
      overlay.remove();
      resolve(v);
    };
    overlay.addEventListener('click', function(e) {
      if (e.target === overlay) done(false);
    });
    overlay.querySelectorAll('[data-action=\"cancel\"]').forEach(function(btn) {
      btn.addEventListener('click', function() { done(false); });
    });
    var confirmBtn = overlay.querySelector('[data-action=\"confirm\"]');
    if (confirmBtn) confirmBtn.addEventListener('click', function() { done(true); });

    document.body.appendChild(overlay);
  });
}

// ─── 反馈论坛 ─────────────────────────────────────────────────────────

async function loadFeedbackForum() {
  var filterStatus = '';
  var filterType = '';

  async function render() {
    var qs = '';
    if (filterStatus) qs += '&status=' + filterStatus;
    if (filterType) qs += '&type=' + filterType;
    var r = await fetch('/api/feedback?_=1' + qs, { headers: authH() });
    var d = await r.json();
    var list = d.feedbacks || [];

    var typeLabels = { bug: 'Bug', feature: '新功能', improvement: '改进建议', other: '其他' };
    var statusLabels = { open: '待处理', in_progress: '处理中', accepted: '已采纳', rejected: '已拒绝', closed: '已关闭' };
    var statusColors = { open: '#f97316', in_progress: '#3b82f6', accepted: '#22c55e', rejected: '#6b7280', closed: '#6b7280' };

    var isAdmin = state.user && state.user.role === 'admin';

    var h = '<div class="page-inner"><div class="page-header"><div><h1>反馈论坛</h1><p>提交 Bug、功能建议，被采纳可获得 500 积分奖励</p></div>' +
      '<button class="btn btn-primary btn-sm" onclick="showNewFeedbackModal()">提交反馈</button></div>';

    h += '<div style="display:flex;gap:6px;margin-bottom:20px;flex-wrap:wrap;align-items:center;">';
    h += '<div style="display:flex;background:var(--bg-soft);border-radius:10px;padding:3px;gap:2px;">';
    var statuses = [['', '\u5168\u90e8'], ['open', '\u5f85\u5904\u7406'], ['in_progress', '\u5904\u7406\u4e2d'], ['accepted', '\u5df2\u91c7\u7eb3']];
    statuses.forEach(function(s) {
      var active = filterStatus === s[0];
      h += '<button style="padding:5px 14px;border-radius:8px;font-size:12px;font-weight:' + (active ? '700' : '500') + ';border:none;cursor:pointer;transition:all .15s;background:' + (active ? 'var(--accent)' : 'transparent') + ';color:' + (active ? '#fff' : 'var(--tx2)') + ';" onclick="filterFeedback(&quot;' + s[0] + '&quot;,&quot;' + filterType + '&quot;)">' + s[1] + '</button>';
    });
    h += '</div>';
    h += '<div style="width:1px;height:20px;background:var(--bd);margin:0 6px;"></div>';
    h += '<div style="display:flex;background:var(--bg-soft);border-radius:10px;padding:3px;gap:2px;">';
    var types = [['', '\u5168\u90e8'], ['bug', 'Bug'], ['feature', '\u65b0\u529f\u80fd'], ['improvement', '\u6539\u8fdb']];
    types.forEach(function(t) {
      var active = filterType === t[0];
      h += '<button style="padding:5px 14px;border-radius:8px;font-size:12px;font-weight:' + (active ? '700' : '500') + ';border:none;cursor:pointer;transition:all .15s;background:' + (active ? 'var(--accent)' : 'transparent') + ';color:' + (active ? '#fff' : 'var(--tx2)') + ';" onclick="filterFeedback(&quot;' + filterStatus + '&quot;,&quot;' + t[0] + '&quot;)">' + t[1] + '</button>';
    });
    h += '</div></div>';

    if (list.length === 0) {
      h += '<div style="text-align:center;padding:60px 20px;">';
      h += '<div style="width:64px;height:64px;margin:0 auto 16px;border-radius:20px;background:rgba(249,115,22,0.08);display:flex;align-items:center;justify-content:center;"><svg viewBox="0 0 24 24" width="28" height="28" fill="none" stroke="var(--accent)" stroke-width="1.5"><path d="M21 11.5a8.38 8.38 0 01-.9 3.8 8.5 8.5 0 01-7.6 4.7 8.38 8.38 0 01-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 01-.9-3.8 8.5 8.5 0 014.7-7.6 8.38 8.38 0 013.8-.9h.5a8.48 8.48 0 018 8v.5z"/></svg></div>';
      h += '<div style="font-size:16px;font-weight:700;color:var(--tx);margin-bottom:6px;">\u6682\u65e0\u53cd\u9988</div>';
      h += '<div style="font-size:13px;color:var(--tx3);">\u6210\u4e3a\u7b2c\u4e00\u4e2a\u63d0\u4ea4\u53cd\u9988\u7684\u7528\u6237\u5427</div></div>';
    } else {
      h += '<div style="display:flex;flex-direction:column;gap:14px;">';
      list.forEach(function(fb) {
        var sc = statusColors[fb.status] || '#6b7280';
        var sl = statusLabels[fb.status] || fb.status;
        var tl = typeLabels[fb.type] || fb.type;
        var typeIcons = { bug: '\u26a0', feature: '\u2728', improvement: '\u2699', other: '\u2709' };
        var ti = typeIcons[fb.type] || '\u2709';

        h += '<div style="background:var(--card-strong);border:1px solid var(--bd);border-radius:16px;padding:0;overflow:hidden;transition:box-shadow .2s,border-color .2s;" onmouseenter="this.style.boxShadow=&quot;0 4px 24px rgba(0,0,0,.08)&quot;;this.style.borderColor=&quot;rgba(249,115,22,.25)&quot;" onmouseleave="this.style.boxShadow=&quot;none&quot;;this.style.borderColor=&quot;var(--bd)&quot;">';

        h += '<div style="padding:18px 22px 0;">';
        h += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">';
        h += '<div style="width:36px;height:36px;border-radius:10px;background:' + sc + '14;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0;">' + ti + '</div>';
        h += '<div style="flex:1;min-width:0;">';
        h += '<div style="font-size:15px;font-weight:700;color:var(--tx);line-height:1.3;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + esc(fb.title) + '</div>';
        h += '<div style="display:flex;align-items:center;gap:6px;margin-top:3px;">';
        h += '<span style="padding:1px 8px;border-radius:6px;font-size:11px;font-weight:600;background:' + sc + '18;color:' + sc + ';">' + sl + '</span>';
        h += '<span style="padding:1px 8px;border-radius:6px;font-size:11px;background:rgba(99,102,241,0.08);color:#818cf8;">' + tl + '</span>';
        h += '</div></div>';
        h += '<div style="text-align:right;flex-shrink:0;">';
        h += '<div style="font-size:11px;color:var(--tx3);">' + (fb.user_name || '\u533f\u540d') + '</div>';
        h += '<div style="font-size:11px;color:var(--tx3);margin-top:1px;">' + new Date(fb.created_at).toLocaleDateString() + '</div>';
        h += '</div></div>';

        if (fb.content) {
          h += '<div style="font-size:13px;color:var(--tx2);line-height:1.6;margin-bottom:4px;white-space:pre-wrap;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden;">' + esc(fb.content) + '</div>';
        }
        h += '</div>';

        if (fb.admin_reply) {
          h += '<div style="margin:0 22px 0;padding:10px 14px;background:rgba(34,197,94,0.05);border-radius:10px;border-left:3px solid #22c55e;">';
          h += '<div style="font-size:11px;font-weight:700;color:#22c55e;margin-bottom:3px;text-transform:uppercase;letter-spacing:.5px;">\u7ba1\u7406\u5458\u56de\u590d</div>';
          h += '<div style="font-size:13px;color:var(--tx2);line-height:1.5;">' + esc(fb.admin_reply) + '</div></div>';
        }

        h += '<div style="padding:12px 22px;display:flex;align-items:center;gap:10px;border-top:1px solid var(--bd);margin-top:14px;">';
        h += '<button class="btn btn-sm" onclick="voteFeedback(&quot;' + fb.id + '&quot;)" style="font-size:12px;display:flex;align-items:center;gap:4px;border-radius:8px;"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2"><path d="M14 9V5a3 3 0 00-3-3l-4 9v11h11.28a2 2 0 002-1.7l1.38-9a2 2 0 00-2-2.3H14z"/><path d="M7 22H4a2 2 0 01-2-2v-7a2 2 0 012-2h3"/></svg> ' + fb.upvotes + '</button>';
        if (isAdmin && fb.status !== 'accepted') {
          h += '<button class="btn btn-sm btn-primary" style="font-size:12px;border-radius:8px;" onclick="adoptFeedback(&quot;' + fb.id + '&quot;)">\u91c7\u7eb3 +500</button>';
          h += '<button class="btn btn-sm" style="font-size:12px;border-radius:8px;" onclick="replyFeedbackModal(&quot;' + fb.id + '&quot;)">\u56de\u590d</button>';
        }
        if (fb.reward_given) h += '<span style="margin-left:auto;font-size:11px;color:#22c55e;font-weight:600;display:flex;align-items:center;gap:3px;"><svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> +500 \u5df2\u53d1\u653e</span>';
        h += '</div></div>';
      });
      h += '</div>';
    }
    h += '</div>';
    var el = document.getElementById('mc');
    if (el) el.innerHTML = h;
  }

  window.filterFeedback = function(s, t) { filterStatus = s; filterType = t; render(); };
  window.showNewFeedbackModal = function() {
    showModal(
      '<div class="modal-header"><h3>\u63d0\u4ea4\u53cd\u9988</h3><button class="modal-close" onclick="closeModal()">\u2715</button></div>' +
      '<div class="modal-body">' +
        '<div class="input-group"><label>\u53cd\u9988\u7c7b\u578b</label><select id="fb-type" class="input-field" style="background:var(--card-strong);color:var(--tx);"><option value="bug">Bug</option><option value="feature">\u65b0\u529f\u80fd</option><option value="improvement">\u6539\u8fdb\u5efa\u8bae</option><option value="other">\u5176\u4ed6</option></select></div>' +
        '<div class="input-group"><label>\u6807\u9898</label><input id="fb-title" class="input-field" placeholder="\u7b80\u660e\u626e\u8981\u63cf\u8ff0\u95ee\u9898"></div>' +
        '<div class="input-group"><label>\u8be6\u7ec6\u63cf\u8ff0</label><textarea id="fb-content" class="input-field" rows="5" placeholder="\u8bf7\u8be6\u7ec6\u63cf\u8ff0\u95ee\u9898\u6216\u5efa\u8bae\u2026"></textarea></div>' +
      '</div>' +
      '<div class="modal-footer">' +
        '<button class="btn btn-secondary" onclick="closeModal()">\u53d6\u6d88</button>' +
        '<button class="btn btn-primary" onclick="submitFeedback()">\u63d0\u4ea4</button>' +
      '</div>'
    );
  };
  window.submitFeedback = async function() {
    var t = document.getElementById('fb-type'); var ti = document.getElementById('fb-title'); var c = document.getElementById('fb-content');
    if (!ti || !ti.value.trim()) { toast('\u6807\u9898\u4e0d\u80fd\u4e3a\u7a7a', 'error'); return; }
    await fetch('/api/feedback', { method: 'POST', headers: { ...authH(), 'Content-Type': 'application/json' }, body: JSON.stringify({ type: t.value, title: ti.value.trim(), content: c.value.trim() }) });
    closeModal(); render();
  };
  window.voteFeedback = async function(id) {
    var r = await fetch('/api/feedback/' + id + '/vote', { method: 'POST', headers: authH() });
    var d = await r.json();
    if (d.error) toast(d.error, 'error'); else render();
  };
  window.adoptFeedback = async function(id) {
    var ok = await modalConfirm('\u786e\u8ba4\u91c7\u7eb3\uff1f\u7528\u6237\u5c06\u83b7\u5f97 500 \u79ef\u5206\u5956\u52b1');
    if (!ok) return;
    await fetch('/api/feedback/' + id + '/adopt', { method: 'POST', headers: authH() });
    render();
  };
  window.replyFeedbackModal = function(id) {
    showModal(
      '<div class="modal-header"><h3>\u7ba1\u7406\u5458\u56de\u590d</h3><button class="modal-close" onclick="closeModal()">\u2715</button></div>' +
      '<div class="modal-body">' +
        '<div class="input-group"><label>\u56de\u590d\u5185\u5bb9</label><textarea id="fb-reply" class="input-field" rows="4" placeholder="\u8bf7\u8f93\u5165\u56de\u590d\u5185\u5bb9\u2026"></textarea></div>' +
        '<div class="input-group"><label>\u66f4\u65b0\u72b6\u6001</label><select id="fb-reply-status" class="input-field" style="background:var(--card-strong);color:var(--tx);"><option value="">\u4e0d\u6539\u53d8\u72b6\u6001</option><option value="in_progress">\u5904\u7406\u4e2d</option><option value="accepted">\u5df2\u91c7\u7eb3</option><option value="rejected">\u5df2\u62d2\u7edd</option><option value="closed">\u5df2\u5173\u95ed</option></select></div>' +
      '</div>' +
      '<div class="modal-footer">' +
        '<button class="btn btn-secondary" onclick="closeModal()">\u53d6\u6d88</button>' +
        '<button class="btn btn-primary" onclick="doReplyFeedback(&quot;' + id + '&quot;)">\u53d1\u9001</button>' +
      '</div>'
    );
  };
  window.doReplyFeedback = async function(id) {
    var r = document.getElementById('fb-reply'); var s = document.getElementById('fb-reply-status');
    if (!r || !r.value.trim()) { toast('\u56de\u590d\u4e0d\u80fd\u4e3a\u7a7a', 'error'); return; }
    await fetch('/api/feedback/' + id + '/reply', { method: 'POST', headers: { ...authH(), 'Content-Type': 'application/json' }, body: JSON.stringify({ reply: r.value.trim(), status: s.value }) });
    closeModal(); render();
  };

  await render();
}

// ─── 邀请推广 ─────────────────────────────────────────────────────────

async function loadInvitePage() {
  var r1 = await fetch('/api/growth/invite-code', { headers: authH() });
  var invite = await r1.json();
  var r2 = await fetch('/api/growth/points-log', { headers: authH() });
  var pts = await r2.json();

  var reasonLabels = { signup: '注册奖励', invited: '受邀奖励', referral: '邀请奖励', join_group: '加群奖励', feedback_accepted: '反馈被采纳' };

  var h = '<div class="page-inner"><div class="page-header"><div><h1>邀请推广</h1><p>邀请好友使用星环 OPC，双方各得 500 积分</p></div></div>';

  // 积分总览卡片
  h += '<div class="invite-stats-grid" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:28px;">';
  h += '<div style="background:linear-gradient(135deg,#f97316,#fb923c);border-radius:14px;padding:20px;color:#fff;">';
  h += '<div style="font-size:13px;opacity:0.8;">可用积分</div><div style="font-size:36px;font-weight:900;">' + pts.bonus_points + '</div></div>';
  h += '<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:14px;padding:20px;">';
  h += '<div style="font-size:13px;color:var(--text-muted);">已邀请用户</div><div style="font-size:36px;font-weight:900;color:var(--text-primary);">' + invite.invited_count + '</div></div>';
  h += '<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:14px;padding:20px;">';
  h += '<div style="font-size:13px;color:var(--text-muted);">月度配额</div><div style="font-size:24px;font-weight:700;color:var(--text-primary);">' + pts.quota_used + ' / ' + pts.quota_total + '</div></div>';
  h += '</div>';

  // 邀请码
  h += '<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:14px;padding:24px;margin-bottom:20px;">';
  h += '<h3 style="margin-bottom:14px;">我的邀请码</h3>';
  h += '<div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap;">';
  h += '<div style="font-size:28px;font-weight:900;letter-spacing:4px;color:#f97316;font-family:monospace;word-break:break-all;">' + esc(invite.invite_code) + '</div>';
  h += '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
  h += '<button class="btn btn-primary btn-sm" onclick="copyInviteCode()">复制邀请码</button>';
  h += '<button class="btn btn-sm" onclick="copyInviteLink()">复制邀请链接</button>';
  h += '</div></div>';
  h += '<p style="font-size:13px;color:var(--text-muted);margin-top:10px;">分享给朋友，对方注册时填入此邀请码，双方各得 500 积分</p>';
  h += '</div>';

  // 推广三步骤
  h += '<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:14px;padding:24px;margin-bottom:20px;">';
  h += '<h3 style="margin-bottom:16px;">推广三步走</h3>';
  h += '<div class="invite-steps-grid" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;">';

  h += '<div style="border:1px solid rgba(249,115,22,0.2);border-radius:12px;padding:18px;background:rgba(249,115,22,0.03);">';
  h += '<div style="font-size:24px;font-weight:900;color:#f97316;margin-bottom:6px;">Step 1</div>';
  h += '<div style="font-size:15px;font-weight:600;margin-bottom:4px;">注册即送 500 积分</div>';
  h += '<div style="font-size:13px;color:var(--text-muted);">新用户注册自动获得 500 积分，立即体验所有功能</div></div>';

  h += '<div style="border:1px solid rgba(59,130,246,0.2);border-radius:12px;padding:18px;background:rgba(59,130,246,0.03);">';
  h += '<div style="font-size:24px;font-weight:900;color:#3b82f6;margin-bottom:6px;">Step 2</div>';
  h += '<div style="font-size:15px;font-weight:600;margin-bottom:4px;">\u52a0\u5165\u5185\u6d4b\u7fa4\uff0c\u83b7\u53d6\u5bc6\u94a5</div>';
  h += '<div style="font-size:13px;color:var(--text-muted);margin-bottom:8px;">\u52a0\u5165\u300c\u661f\u73afOPC\u5185\u6d4b\u7fa4\u300d\u540e\u8054\u7cfb\u7fa4\u4e3b\u83b7\u53d6\u5151\u6362\u5bc6\u94a5\uff0c\u8f93\u5165\u5bc6\u94a5\u5373\u53ef\u83b7\u5f97\u5bf9\u5e94\u79ef\u5206</div>';
  h += '<div style="display:flex;gap:8px;align-items:center;margin-top:6px;">';
  h += '<input id="redeem-key-input" class="input-field" placeholder="\u8bf7\u8f93\u5165\u5151\u6362\u5bc6\u94a5" style="flex:1;font-size:13px;padding:8px 12px;font-family:monospace;text-transform:uppercase;">';
  h += '<button class="btn btn-primary btn-sm" onclick="redeemGroupKey()">\u5151\u6362</button>';
  h += '</div>';
  h += '</div>';

  h += '<div style="border:1px solid rgba(139,92,246,0.2);border-radius:12px;padding:18px;background:rgba(139,92,246,0.03);">';
  h += '<div style="font-size:24px;font-weight:900;color:#8b5cf6;margin-bottom:6px;">Step 3</div>';
  h += '<div style="font-size:15px;font-weight:600;margin-bottom:4px;">邀请好友，双方 +500</div>';
  h += '<div style="font-size:13px;color:var(--text-muted);">分享邀请码给朋友，对方注册后双方各得 500 积分，无限累积</div></div>';

  h += '</div></div>';

  // 积分明细
  h += '<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:14px;padding:24px;">';
  h += '<h3 style="margin-bottom:14px;">积分明细</h3>';
  var logs = pts.logs || [];
  if (logs.length === 0) {
    h += '<div style="text-align:center;color:var(--text-muted);padding:20px;">暂无积分记录</div>';
  } else {
    h += '<div style="display:flex;flex-direction:column;gap:8px;">';
    logs.forEach(function(log) {
      var label = reasonLabels[log.reason] || log.reason;
      var color = log.amount > 0 ? '#22c55e' : '#ef4444';
      h += '<div style="display:flex;align-items:center;padding:10px 14px;border-radius:8px;background:rgba(255,255,255,0.02);border:1px solid var(--border);">';
      h += '<div style="flex:1;"><div style="font-size:14px;font-weight:600;">' + esc(label) + '</div>';
      if (log.detail) h += '<div style="font-size:12px;color:var(--text-muted);">' + esc(log.detail) + '</div>';
      h += '</div>';
      h += '<div style="font-size:16px;font-weight:700;color:' + color + ';">' + (log.amount > 0 ? '+' : '') + log.amount + '</div>';
      h += '<div style="font-size:12px;color:var(--text-muted);margin-left:12px;min-width:80px;text-align:right;">' + new Date(log.created_at).toLocaleDateString() + '</div>';
      h += '</div>';
    });
    h += '</div>';
  }
  h += '</div>';
  h += '</div>';

  var el = document.getElementById('mc');
  if (el) el.innerHTML = h;
}

window.copyInviteCode = function() {
  var code = document.querySelector('[style*="letter-spacing:4px"]');
  if (code) { navigator.clipboard.writeText(code.textContent); toast('\u9080\u8bf7\u7801\u5df2\u590d\u5236', 'success'); }
};
window.copyInviteLink = function() {
  var code = document.querySelector('[style*="letter-spacing:4px"]');
  var link = location.origin + '/#login?invite=' + (code ? code.textContent : '');
  navigator.clipboard.writeText(link); toast('\u9080\u8bf7\u94fe\u63a5\u5df2\u590d\u5236', 'success');
};
window.redeemGroupKey = async function() {
  var input = document.getElementById('redeem-key-input');
  var key = input ? input.value.trim() : '';
  if (!key) { toast('\u8bf7\u8f93\u5165\u5151\u6362\u5bc6\u94a5', 'error'); return; }
  try {
    var r = await fetch('/api/growth/claim-group-bonus', {
      method: 'POST',
      headers: { ...authH(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ redeem_key: key }),
    });
    var d = await r.json();
    if (d.error) { toast(d.error, 'error'); return; }
    toast(d.message || '\u5151\u6362\u6210\u529f', 'success');
    loadSidebarQuota();
    loadInvitePage();
  } catch(e) { toast('\u5151\u6362\u5931\u8d25', 'error'); }
};

function showAdminUserModal(userId, userName, used, total, bonus, plan, swarmUsed) {
  showModal(
    '<div class="modal-header"><h3>\u7BA1\u7406\u7528\u6237: ' + esc(userName) + '</h3><button class="modal-close" onclick="closeModal()">\u2715</button></div>' +
    '<div class="modal-body">' +
      '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;">' +
        '<div style="background:var(--bg-soft);border-radius:10px;padding:14px;text-align:center;">' +
          '<div style="font-size:12px;color:var(--tx3);">\u5DF2\u7528/\u603B\u989D</div>' +
          '<div style="font-size:20px;font-weight:800;color:var(--tx);">' + used + ' / ' + total + '</div>' +
        '</div>' +
        '<div style="background:var(--bg-soft);border-radius:10px;padding:14px;text-align:center;">' +
          '<div style="font-size:12px;color:var(--tx3);">\u5956\u52B1\u79EF\u5206</div>' +
          '<div style="font-size:20px;font-weight:800;color:#f97316;">' + bonus + '</div>' +
        '</div>' +
        '<div style="background:var(--bg-soft);border-radius:10px;padding:14px;text-align:center;">' +
          '<div style="font-size:12px;color:var(--tx3);">\u9F99\u5BAB\u5DF2\u7528\u6B21\u6570</div>' +
          '<div style="font-size:20px;font-weight:800;color:var(--tx);">' + (swarmUsed || 0) + ' / 3</div>' +
        '</div>' +
      '</div>' +
      '<div class="input-group"><label>\u5957\u9910</label>' +
        '<select id="adm-plan" class="input-field" style="background:var(--card-strong);color:var(--tx);"><option value="free"' + (plan==='free'?' selected':'') + '>Free</option><option value="pro"' + (plan==='pro'?' selected':'') + '>Pro</option><option value="ultra"' + (plan==='ultra'?' selected':'') + '>Ultra</option></select></div>' +
      '<div class="input-group"><label>\u6708\u5EA6\u603B\u989D</label><input id="adm-total" class="input-field" type="number" value="' + total + '" style="background:var(--card-strong);color:var(--tx);" /></div>' +
      '<div class="input-group"><label>\u5956\u52B1\u79EF\u5206</label><input id="adm-bonus" class="input-field" type="number" value="' + bonus + '" style="background:var(--card-strong);color:var(--tx);" /></div>' +
    '</div>' +
    '<div class="modal-footer">' +
      '<button class="btn btn-sm" style="color:var(--red);margin-right:auto;" onclick="adminResetQuota(&quot;' + userId + '&quot;)">\u91CD\u7F6E\u5DF2\u7528\u989D\u5EA6</button>' +
      '<button class="btn btn-sm" style="color:#f97316;" onclick="adminResetSwarm(&quot;' + userId + '&quot;)">\u91CD\u7F6E\u9F99\u5BAB\u989D\u5EA6</button>' +
      '<button class="btn btn-secondary" onclick="closeModal()">\u53D6\u6D88</button>' +
      '<button class="btn btn-primary" onclick="adminSaveUser(&quot;' + userId + '&quot;)">\u4FDD\u5B58</button>' +
    '</div>'
  );
}

async function adminResetQuota(userId) {
  var ok = await modalConfirm('\u786e\u8ba4\u5c06\u8be5\u7528\u6237\u5df2\u7528\u989d\u5ea6\u91cd\u7f6e\u4e3a 0\uff1f');
  if (!ok) return;
  try {
    await api('/admin/users/' + userId, { method: 'PUT', body: { reset_quota: true } });
    toast('额度已重置', 'success');
    closeModal(); loadAdminStats();
  } catch(e) { toast(e.message || '操作失败', 'error'); }
}

async function adminResetSwarm(userId) {
  var ok = await modalConfirm('\u786E\u8BA4\u91CD\u7F6E\u8BE5\u7528\u6237\u7684\u9F99\u5BAB\u4F7F\u7528\u989D\u5EA6\u5417\uFF1F\u5386\u53F2\u8BB0\u5F55\u4F1A\u4FDD\u7559\u3002');
  if (!ok) return;
  try {
    await api('/admin/users/' + userId, { method: 'PUT', body: { reset_swarm: true } });
    toast('\u9F99\u5BAB\u989D\u5EA6\u5DF2\u91CD\u7F6E', 'success');
    closeModal(); loadAdminStats();
  } catch(e) { toast(e.message || '操作失败', 'error'); }
}

async function adminSaveUser(userId) {
  var planEl = document.getElementById('adm-plan');
  var totalEl = document.getElementById('adm-total');
  var bonusEl = document.getElementById('adm-bonus');
  var body = {};
  if (planEl) body.plan = planEl.value;
  if (totalEl) body.quota_total = parseInt(totalEl.value) || 0;
  if (bonusEl) body.bonus_points = parseInt(bonusEl.value) || 0;
  try {
    await api('/admin/users/' + userId, { method: 'PUT', body: body });
    toast('已保存', 'success');
    closeModal(); loadAdminStats();
  } catch(e) { toast(e.message || '保存失败', 'error'); }
}

async function exportDocFromChat(exportUrl, docTitle) {
  try {
    var res = await fetch(exportUrl, {
      method: 'POST',
      headers: { ...authH(), 'Content-Type': 'application/json' },
      body: JSON.stringify({}),
    });
    if (!res.ok) { var d = await res.json(); throw new Error(d.error || '导出失败'); }
    var blob = await res.blob();
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = (docTitle || '文档') + '.docx';
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast('文档已下载', 'success');
  } catch(e) { toast(e.message || '导出失败', 'error'); }
}

// ─── 通知系统 ─────────────────────────────────────────────────────────

var _notifs = [];
var _notifTaskMap = {};
var _pendingCompanyInviteCount = 0;
var _pendingParkApprovalCount = 0;
var _latestPendingParkApprovalItems = [];
var _pendingToolApprovalCount = 0;
var _latestPendingToolApprovalItems = [];
var _latestMyApplicationItems = [];
var _myApplicationAlertCount = 0;

function _getUnreadCount() {
  return _notifs.filter(function(n) { return !n.read; }).length;
}

function getApplicationStatusMeta(status) {
  if (status === 'approved') return { label: '\u5DF2\u901A\u8FC7', color: '#16a34a', bg: '#dcfce7', border: '#bbf7d0', icon: '\u2705' };
  if (status === 'rejected') return { label: '\u672A\u901A\u8FC7', color: '#dc2626', bg: '#fef2f2', border: '#fecaca', icon: '\u274C' };
  return { label: '\u5BA1\u6279\u4E2D', color: '#d97706', bg: '#fffbeb', border: '#fed7aa', icon: '\u2709\uFE0F' };
}

function normalizeAddressText(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/\s+/g, '')
    .replace(/[，,。．·•_()（）]/g, '')
    .replace(/-/g, '')
    .replace(/—/g, '')
    .replace(/四川省|云南省|成都市|巴中市|曲靖市|双流区|巴州区|麒麟区|怡心街道/g, '');
}

function resolveFeaturedCenterAlias(app) {
  var appName = String(app && app.park_name || '').trim();
  var appAddress = normalizeAddressText(app && app.address);
  var appCity = String(app && app.city_name || '').trim();
  if (appName === '星环OPC总部') {
    return getFeaturedOpcCenters().find(function(center) { return center.id === 'featured-chengdu-opc-center'; }) || null;
  }
  var centers = getFeaturedOpcCenters();
  for (var i = 0; i < centers.length; i += 1) {
    var center = centers[i];
    var centerAddress = normalizeAddressText(center.address || '');
    var sameAddress = !!appAddress && !!centerAddress && (appAddress.indexOf(centerAddress) >= 0 || centerAddress.indexOf(appAddress) >= 0);
    var sameCity = appCity && center.city_name && appCity === center.city_name;
    var sameName = appName && (appName === center.name || appName.replace(/总部/g, '中心') === center.name);
    if (sameAddress || (sameCity && sameName) || (sameCity && appName === '星环OPC总部' && center.id === 'featured-chengdu-opc-center')) {
      return center;
    }
  }
  return null;
}

function canonicalizeMyApplication(app) {
  var next = Object.assign({}, app || {});
  var alias = resolveFeaturedCenterAlias(next);
  if (!alias) return next;
  next.park_id = alias.id;
  next.park_name = alias.name;
  next.city_name = alias.city_name || next.city_name;
  next.address = alias.address || next.address;
  return next;
}

function dedupeMyApplications(items) {
  var map = {};
  (items || []).forEach(function(app) {
    if (!app) return;
    app = canonicalizeMyApplication(app);
    var addressKey = normalizeAddressText(app.address || '');
    var cityKey = String(app.city_name || '').trim().toLowerCase();
    var nameKey = String(app.park_name || '').replace(/总部/g, '中心').trim().toLowerCase();
    var key = addressKey ? (cityKey + '|' + addressKey) : nameKey;
    var prev = map[key];
    var prevTs = prev ? Date.parse(prev.reviewed_at || prev.created_at || '') || 0 : 0;
    var nextTs = Date.parse(app.reviewed_at || app.created_at || '') || 0;
    if (!prev || nextTs >= prevTs) map[key] = app;
  });
  return Object.keys(map).map(function(key) { return map[key]; }).filter(function(app) {
    return String(app.park_name || '').trim() !== '星环OPC总部';
  }).sort(function(a, b) {
    return (Date.parse(b.reviewed_at || b.created_at || '') || 0) - (Date.parse(a.reviewed_at || a.created_at || '') || 0);
  });
}

function getMyApplicationByParkId(parkId) {
  return (_latestMyApplicationItems || []).find(function(app) { return app.park_id === parkId; }) || null;
}

function _updateNotifBadge() {
  var badge = document.getElementById('notif-badge');
  if (!badge) return;
  var count = _getUnreadCount();
  if (count > 0) {
    badge.textContent = count > 99 ? '99+' : String(count);
    badge.style.display = '';
  } else {
    badge.style.display = 'none';
  }
}

function _addNotif(notif) {
  _notifs.unshift(notif);
  if (_notifs.length > 50) _notifs = _notifs.slice(0, 50);
  _updateNotifBadge();
  _showTaskExecCard(notif);
}

function _showTaskExecCard(notif) {
  document.querySelectorAll('.task-exec-card').forEach(function(el) { el.remove(); });
  var isSuccess = notif.type === 'success';
  var card = document.createElement('div');
  card.className = 'task-exec-card';
  var barId = 'exec-bar-' + Date.now();
  card.innerHTML =
    '<div class="task-exec-card-body">' +
      '<div style="display:flex;align-items:flex-start;gap:10px;">' +
        '<div style="font-size:24px;line-height:1.2;">' + (isSuccess ? '\u2705' : '\u274C') + '</div>' +
        '<div style="flex:1;min-width:0;">' +
          '<div style="font-size:13px;font-weight:700;margin-bottom:3px;">' + esc(notif.title) + '</div>' +
          '<div style="font-size:12px;color:var(--tx2);word-break:break-all;">' + esc(notif.message) + '</div>' +
        '</div>' +
        '<button onclick="this.closest(&quot;.task-exec-card&quot;).remove()" style="background:none;border:none;cursor:pointer;color:var(--tx3);font-size:18px;line-height:1;padding:0;flex-shrink:0;">\xd7</button>' +
      '</div>' +
    '</div>' +
    '<div class="task-exec-progress"><div class="task-exec-bar" id="' + barId + '" style="width:100%;background:' + (isSuccess ? 'var(--green)' : 'var(--red)') + ';"></div></div>';
  document.body.appendChild(card);

  var bar = document.getElementById(barId);
  var start = Date.now();
  var dur = 10000;
  var timer = setInterval(function() {
    var pct = Math.max(0, 100 - (Date.now() - start) / dur * 100);
    if (bar) bar.style.width = pct + '%';
    if (pct <= 0) { clearInterval(timer); if (card.parentElement) card.remove(); }
  }, 200);
  setTimeout(function() { clearInterval(timer); if (card.parentElement) card.remove(); }, dur + 600);
}

function toggleNotifPanel() {
  var existing = document.getElementById('notif-panel');
  if (existing) { existing.remove(); return; }

  _notifs.forEach(function(n) { n.read = true; });
  _updateNotifBadge();

  var panel = document.createElement('div');
  panel.id = 'notif-panel';
  panel.className = 'notif-panel';

  var listHtml = '';

  listHtml += '<div id="tool-approval-section"></div>';
  listHtml += '<div id="park-approval-section"></div>';
  listHtml += '<div id="my-application-section"></div>';
  listHtml += '<div id="company-invite-section"></div>';

  var hasSystemSections = _pendingToolApprovalCount > 0 || _pendingParkApprovalCount > 0 || _pendingCompanyInviteCount > 0 || (_latestMyApplicationItems || []).length > 0;
  if (_notifs.length === 0 && !hasSystemSections) {
    listHtml += '<div style="text-align:center;padding:36px 16px;color:var(--tx2);font-size:13px;">\u6682\u65E0\u901A\u77E5</div>';
  } else {
    _notifs.slice(0, 20).forEach(function(n) {
      var icon = n.type === 'success' ? '\u2705' : '\u274C';
      var iconBg = n.type === 'success' ? 'rgba(34,197,94,0.1)' : 'rgba(239,68,68,0.1)';
      var timeStr = new Date(n.ts).toLocaleString('zh-CN', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' });
      listHtml += '<div class="notif-item" onclick="navigate(&quot;scheduler&quot;)">' +
        '<div class="notif-item-icon" style="background:' + iconBg + ';">' + icon + '</div>' +
        '<div style="flex:1;min-width:0;">' +
          '<div style="font-weight:600;margin-bottom:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(n.title) + '</div>' +
          '<div style="color:var(--tx2);word-break:break-all;">' + esc(n.message) + '</div>' +
        '</div>' +
        '<div style="color:var(--tx3);white-space:nowrap;margin-left:8px;font-size:11px;">' + timeStr + '</div>' +
      '</div>';
    });
  }

  panel.innerHTML =
    '<div class="notif-panel-header">' +
      '<span>\u6D88\u606F\u901A\u77E5</span>' +
      '<button onclick="document.getElementById(&quot;notif-panel&quot;).remove()" style="background:none;border:none;cursor:pointer;color:var(--tx2);font-size:20px;line-height:1;padding:0;">\xd7</button>' +
    '</div>' +
    '<div class="notif-panel-list">' + listHtml + '</div>' +
    (_notifs.length > 0 ? '<div class="notif-panel-footer"><button class="btn btn-sm btn-secondary" onclick="clearNotifs()">\u6E05\u7A7A\u901A\u77E5</button></div>' : '');

  document.body.appendChild(panel);

  _loadToolApprovalsIntoPanel();
  _loadParkApprovalsIntoPanel();
  _loadMyApplicationsIntoPanel();
  _loadCompanyInvitesIntoPanel();

  setTimeout(function() {
    document.addEventListener('click', function handler(e) {
      var panelEl = document.getElementById('notif-panel');
      var btnWrap = document.getElementById('notif-btn-wrap');
      if (panelEl && !panelEl.contains(e.target) && (!btnWrap || !btnWrap.contains(e.target))) {
        panelEl.remove();
        document.removeEventListener('click', handler);
      }
    });
  }, 10);
}

function clearNotifs() {
  _notifs = [];
  _myApplicationAlertCount = 0;
  var p = document.getElementById('notif-panel');
  if (p) p.remove();
  _updateNotifBadge();
}

async function _loadCompanyInvitesIntoPanel() {
  var section = document.getElementById('company-invite-section');
  if (!section) return;
  try {
    var data = await api('/company-invites/pending');
    var invites = data.invites || [];
    if (!invites.length) { section.innerHTML = ''; return; }

    var ih = '<div style="padding:0 0 8px;border-bottom:1px solid var(--bd);margin-bottom:8px;">';
    ih += '<div style="font-size:12px;font-weight:700;color:var(--accent);padding:0 16px 6px;">公司协作邀请</div>';
    invites.forEach(function(inv) {
      ih += '<div style="padding:10px 16px;display:flex;align-items:center;gap:10px;">';
      ih += '<div style="width:36px;height:36px;border-radius:50%;background:linear-gradient(135deg,#f97316,#f59e0b);color:#fff;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;flex-shrink:0;">🏢</div>';
      ih += '<div style="flex:1;min-width:0;">';
      ih += '<div style="font-weight:600;font-size:13px;">' + esc(inv.company_name) + '</div>';
      ih += '<div style="font-size:11px;color:var(--tx3);">' + esc(inv.inviter_name) + ' 邀请你加入 · ' + teamRoleLabel(inv.role) + '</div>';
      ih += '</div>';
      ih += '<div style="display:flex;gap:4px;flex-shrink:0;">';
      ih += '<button class="btn btn-primary btn-sm" onclick="acceptCompanyInvite(&quot;' + inv.id + '&quot;)" style="font-size:11px;padding:3px 10px;">接受</button>';
      ih += '<button class="btn btn-sm" onclick="rejectCompanyInvite(&quot;' + inv.id + '&quot;)" style="font-size:11px;padding:3px 10px;">拒绝</button>';
      ih += '</div></div>';
    });
    ih += '</div>';
    section.innerHTML = ih;

  } catch (e) { /* ignore */ }
}

