    html += '<div style="flex:1;min-width:0;">';
    html += '<div style="font-weight:600;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(item.tool || '高风险工具') + '</div>';
    html += '<div style="font-size:11px;color:var(--tx3);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(item.userId || '未知用户') + ' · ' + esc(createdAt) + '</div>';
