// ─── 本地操作面板（LOCAL_MODE only）──────────────────────────────

async function loadLocalTasks() {
  if (!window.LOCAL_MODE) { navigate('dashboard'); return; }
  var mc = document.getElementById('mc'); if (!mc) return;
  mc.innerHTML = renderLoading();

  var sysInfo = {};
  try { sysInfo = await api('/local/system-info'); } catch(e) {}
  var data = {};
  try { data = await api('/local/tasks'); } catch(e) {}
  var tasks = data.tasks || [];

  var h = '<div class="page-inner"><div class="page-header"><div><h1>任务面板</h1><p>本地操作任务管理 — AI 拆解复杂指令并逐步执行</p></div>';
  h += '<button class="btn btn-primary btn-sm" onclick="showNewLocalTaskModal()">+ 新建任务</button></div>';

  if (sysInfo.platform) {
    h += '<div class="card" style="margin-bottom:16px;padding:14px 18px;display:flex;gap:16px;flex-wrap:wrap;font-size:12px;color:var(--tx2);">';
    h += '<span><strong>系统:</strong> ' + esc(sysInfo.platform) + ' ' + esc(sysInfo.arch) + '</span>';
    h += '<span><strong>主机:</strong> ' + esc(sysInfo.hostname) + '</span>';
    h += '<span><strong>CPU:</strong> ' + sysInfo.cpus + ' 核</span>';
    h += '<span><strong>内存:</strong> ' + esc(sysInfo.memory?.free) + ' 可用 / ' + esc(sysInfo.memory?.total) + '</span>';
    h += '<span><strong>运行:</strong> ' + esc(sysInfo.uptime) + '</span>';
    h += '</div>';
  }

  if (tasks.length === 0) {
    h += '<div style="text-align:center;padding:60px 20px;color:var(--tx3);"><div style="font-size:48px;margin-bottom:16px;">🖥️</div>';
    h += '<div style="font-size:16px;font-weight:600;margin-bottom:8px;">暂无任务</div>';
    h += '<div style="font-size:13px;">在 AI 对话中下达复杂指令，或点击"新建任务"来创建</div></div>';
  } else {
    h += '<div style="display:flex;flex-direction:column;gap:10px;">';
    tasks.forEach(function(t) {
      var statusIcon = t.status === 'done' ? '<span style="color:#22c55e;">✓</span>' :
        t.status === 'running' ? '<span class="loading-spinner" style="width:14px;height:14px;display:inline-block;"></span>' :
        t.status === 'failed' ? '<span style="color:#ef4444;">✗</span>' :
        t.status === 'cancelled' ? '<span style="color:var(--tx3);">⊘</span>' :
        '<span style="color:var(--tx3);">○</span>';
      var doneSteps = (t.steps || []).filter(function(s) { return s.status === 'done'; }).length;
      var totalSteps = (t.steps || []).length;
      h += '<div class="card" style="padding:14px 18px;cursor:pointer;" onclick="showLocalTaskDetail(&quot;' + t.id + '&quot;)">';
      h += '<div style="display:flex;align-items:center;gap:10px;">';
      h += '<div style="flex-shrink:0;font-size:16px;">' + statusIcon + '</div>';
      h += '<div style="flex:1;min-width:0;">';
      h += '<div style="font-size:14px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + esc(t.title) + '</div>';
      h += '<div style="font-size:12px;color:var(--tx3);margin-top:2px;">' + doneSteps + '/' + totalSteps + ' 步完成 · ' + new Date(t.created_at || t.createdAt).toLocaleString() + '</div>';
      h += '</div>';
      if (t.status === 'running') h += '<button class="btn btn-sm" onclick="event.stopPropagation();cancelLocalTask(&quot;' + t.id + '&quot;)" style="color:var(--red);font-size:11px;">取消</button>';
      h += '</div>';
      if (t.summary) h += '<div style="font-size:12px;color:var(--tx2);margin-top:8px;line-height:1.5;">' + esc(t.summary) + '</div>';
      h += '</div>';
    });
    h += '</div>';
  }
  h += '</div>';
  mc.innerHTML = h;
}

async function showLocalTaskDetail(taskId) {
  var data = await api('/local/tasks/' + taskId);
  var t = data.task;
  if (!t) { toast('任务不存在', 'error'); return; }
  var h = '<div class="modal-header"><h3>' + esc(t.title) + '</h3></div>';
  h += '<div class="modal-body" style="max-height:60vh;overflow-y:auto;">';
  (t.steps || []).forEach(function(s, i) {
    var color = s.status === 'done' ? '#22c55e' : s.status === 'running' ? 'var(--accent)' : s.status === 'failed' ? '#ef4444' : 'var(--tx3)';
    var icon = s.status === 'done' ? '✓' : s.status === 'running' ? '⏳' : s.status === 'failed' ? '✗' : '○';
    h += '<div style="display:flex;gap:10px;padding:10px 0;border-bottom:1px solid var(--bd);">';
    h += '<div style="width:24px;height:24px;border-radius:50%;background:' + color + '18;color:' + color + ';display:flex;align-items:center;justify-content:center;font-size:12px;flex-shrink:0;">' + icon + '</div>';
    h += '<div style="flex:1;min-width:0;">';
    h += '<div style="font-size:13px;font-weight:600;">' + esc(s.description) + '</div>';
    if (s.tool) h += '<div style="font-size:11px;color:var(--tx3);margin-top:2px;">工具: ' + esc(s.tool) + '</div>';
    if (s.error) h += '<div style="font-size:11px;color:#ef4444;margin-top:4px;">' + esc(s.error) + '</div>';
    if (s.result) {
      var parsed = ''; try { var r = JSON.parse(s.result); parsed = JSON.stringify(r, null, 2); } catch(e) { parsed = s.result; }
      h += '<details style="margin-top:4px;"><summary style="font-size:11px;color:var(--tx3);cursor:pointer;">查看结果</summary>';
      h += '<pre style="font-size:11px;background:var(--bg-soft);padding:8px;border-radius:6px;overflow-x:auto;margin-top:4px;max-height:150px;overflow-y:auto;">' + esc(parsed.slice(0, 2000)) + '</pre></details>';
    }
    h += '</div></div>';
  });
  if (t.summary) {
    h += '<div style="margin-top:14px;padding:12px;background:rgba(34,197,94,0.06);border-radius:10px;border:1px solid rgba(34,197,94,0.15);">';
    h += '<div style="font-size:12px;font-weight:700;color:#22c55e;margin-bottom:4px;">任务总结</div>';
    h += '<div style="font-size:13px;color:var(--tx);line-height:1.5;">' + esc(t.summary) + '</div></div>';
  }
  h += '</div><div class="modal-footer"><button class="btn" onclick="this.closest(&quot;.modal-overlay&quot;).remove()">关闭</button></div>';
  showModalRaw(h);
}

function showNewLocalTaskModal() {
  var h = '<div class="modal-header"><h3>新建本地任务</h3></div>';
  h += '<div class="modal-body">';
  h += '<div class="input-group"><label>任务指令</label>';
  h += '<textarea id="local-task-input" class="input-field" rows="4" placeholder="描述你需要 AI 帮你完成的任务，例如：\\n- 整理桌面，把所有PDF放到Documents/PDF文件夹\\n- 查看系统磁盘使用情况\\n- 搜索最近一周修改过的Excel文件" style="resize:vertical;"></textarea>';
  h += '</div></div>';
  h += '<div class="modal-footer"><button class="btn" onclick="this.closest(&quot;.modal-overlay&quot;).remove()">取消</button>';
  h += '<button class="btn btn-primary" onclick="submitLocalTask()">创建并执行</button></div>';
  showModalRaw(h);
}

async function submitLocalTask() {
  var el = document.getElementById('local-task-input');
  var instruction = el ? el.value.trim() : '';
  if (!instruction) { toast('请输入任务指令', 'error'); return; }
  var overlay = el.closest('.modal-overlay');
  if (overlay) overlay.remove();
  toast('任务已创建，正在规划执行...', 'success');
  try {
    await api('/local/tasks', { method: 'POST', body: { instruction: instruction } });
    setTimeout(function() { loadLocalTasks(); }, 1000);
  } catch(e) { toast(e.message, 'error'); }
}

async function cancelLocalTask(taskId) {
  try {
    await api('/local/tasks/' + taskId + '/cancel', { method: 'POST' });
    toast('任务已取消', 'success');
    loadLocalTasks();
  } catch(e) { toast(e.message, 'error'); }
}

function showModalRaw(innerHtml) {
  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.innerHTML = '<div class="modal" style="max-width:600px;">' + innerHtml + '</div>';
  overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
  document.body.appendChild(overlay);
}

// ─── 操作审计日志 ──────────────────────────────

async function loadLocalAuditLog() {
  if (state.user?.role !== 'admin') { navigate('dashboard'); return; }
  var mc = document.getElementById('mc'); if (!mc) return;
  mc.innerHTML = renderLoading();
  var data = {};
  var approvalsData = {};
  try { data = await api('/admin/tool-audit'); } catch(e) {}
  try { approvalsData = await api('/admin/tool-approvals'); } catch(e) {}
  var logs = data.logs || [];
  var approvals = approvalsData.approvals || [];

  var h = '<div class="page-inner"><div class="page-header"><h1>工具审计</h1><p>仅管理员可见，查看全系统 AI/工具执行留痕、风险等级与结果摘要</p></div>';
  if (approvals.length) {
    h += '<div class="card" style="margin-bottom:16px;border:1px solid #fed7aa;background:linear-gradient(135deg,#fff7ed,#fffbeb);">';
    h += '<div style="padding:16px 18px;border-bottom:1px solid #fdba74;display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;">';
    h += '<div><div style="font-size:16px;font-weight:800;color:#9a3412;">待审批高风险工具</div><div style="font-size:12px;color:#c2410c;margin-top:4px;">这些操作已被系统挂起，审批通过后才会继续执行。</div></div>';
    h += '<div style="font-size:12px;font-weight:700;color:#ea580c;">' + approvals.length + ' 条待处理</div>';
    h += '</div>';
    h += '<div style="padding:16px;display:grid;gap:12px;">';
    approvals.forEach(function(app) {
      var when = new Date(app.createdAt || Date.now()).toLocaleString();
      h += '<div style="padding:14px;border:1px solid #fdba74;border-radius:12px;background:#fff;">';
      h += '<div style="display:flex;justify-content:space-between;gap:10px;align-items:flex-start;flex-wrap:wrap;margin-bottom:8px;">';
      h += '<div><div style="font-size:14px;font-weight:700;color:var(--tx);">' + esc(app.tool || '-') + '</div><div style="font-size:12px;color:var(--tx3);margin-top:4px;">申请用户：' + esc(app.userId || '-') + ' · ' + esc(when) + '</div></div>';
      h += '<span style="padding:4px 8px;border-radius:999px;background:#fef2f2;color:#dc2626;font-size:11px;font-weight:700;">高风险</span>';
      h += '</div>';
      h += '<div style="font-size:12px;color:var(--tx2);line-height:1.7;background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:10px;">' + esc(app.description || '-') + '</div>';
      h += '<div style="font-size:11px;color:var(--tx3);margin-top:8px;white-space:pre-wrap;word-break:break-word;">' + esc(JSON.stringify(app.args || {}, null, 2).slice(0, 600)) + '</div>';
      h += '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:12px;flex-wrap:wrap;">';
      h += '<button class="btn btn-sm" style="background:#fff;border-color:#fecaca;color:#dc2626;" onclick="resolveToolApproval(&quot;' + esc(app.id) + '&quot;, false)">拒绝</button>';
      h += '<button class="btn btn-primary btn-sm" onclick="resolveToolApproval(&quot;' + esc(app.id) + '&quot;, true)">批准执行</button>';
      h += '</div>';
      h += '</div>';
    });
    h += '</div></div>';
  }
  if (logs.length === 0) {
    h += '<div style="text-align:center;padding:40px;color:var(--tx3);">暂无工具执行记录</div>';
  } else {
    h += '<div class="card"><div class="table-wrap"><table><thead><tr>';
    h += '<th>时间</th><th>用户</th><th>工具</th><th>风险</th><th>状态</th><th>参数摘要</th><th>结果摘要</th>';
    h += '</tr></thead><tbody>';
    logs.forEach(function(log) {
      var riskColor = log.risk_level === 'high' ? '#ef4444' : log.risk_level === 'medium' ? '#f97316' : '#22c55e';
      var riskLabel = log.risk_level === 'high' ? '高' : log.risk_level === 'medium' ? '中' : '低';
      var userLabel = log.user_name || log.user_phone || log.user_email || log.user_id || '-';
      var ok = true;
      try {
        var parsed = typeof log.result === 'string' ? JSON.parse(log.result) : log.result;
        ok = !(parsed && parsed.ok === false);
      } catch(e) {}
      h += '<tr>';
      h += '<td style="font-size:11px;white-space:nowrap;">' + new Date(log.created_at).toLocaleString() + '</td>';
      h += '<td style="font-size:12px;max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + esc(userLabel) + '</td>';
      h += '<td style="font-family:monospace;font-size:12px;">' + esc(log.tool) + '</td>';
      h += '<td><span style="color:' + riskColor + ';font-size:11px;font-weight:600;">' + riskLabel + '</span></td>';
      h += '<td>' + (log.approved ? (ok ? '<span style="color:#22c55e;">成功</span>' : '<span style="color:#ef4444;">失败</span>') : '<span style="color:#ef4444;">✗ 拒绝</span>') + '</td>';
      h += '<td style="max-width:260px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:11px;">' + esc(typeof log.args === 'string' ? log.args.slice(0, 180) : JSON.stringify(log.args || {}).slice(0, 180)) + '</td>';
      h += '<td style="max-width:320px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:11px;">' + esc(typeof log.result === 'string' ? log.result.slice(0, 220) : JSON.stringify(log.result || {}).slice(0, 220)) + '</td>';
      h += '</tr>';
    });
    h += '</tbody></table></div></div>';
  }
  h += '</div>';
  mc.innerHTML = h;
}

async function resolveToolApproval(id, approved) {
  try {
    await api('/admin/tool-approvals/' + id, { method: 'POST', body: { approved: !!approved } });
    toast(approved ? '已批准执行' : '已拒绝执行', approved ? 'success' : 'info');
    await loadLocalAuditLog();
  } catch(e) {
    toast(e.message || '审批失败', 'error');
  }
}

// ─── 审批弹窗轮询（LOCAL_MODE 专用）──────────

var _approvalPollTimer = null;
function startApprovalPolling() {
  if (!window.LOCAL_MODE || _approvalPollTimer) return;
  _approvalPollTimer = setInterval(async function() {
    if (!state.token) { clearInterval(_approvalPollTimer); _approvalPollTimer = null; return; }
    try {
      var res = await fetch('/api/local/approvals', { headers: { 'Authorization': 'Bearer ' + state.token } });
      if (!res.ok) return;
      var data = await res.json();
      var approvals = data.approvals || [];
      approvals.forEach(function(a) {
        if (document.getElementById('approval-' + a.id)) return;
        showApprovalPopup(a);
      });
    } catch(e) {}
  }, 3000);
}

function showApprovalPopup(approval) {
  var riskColor = approval.riskLevel === 'high' ? '#ef4444' : '#f97316';
  var riskLabel = approval.riskLevel === 'high' ? '高风险' : '中风险';
  var card = document.createElement('div');
  card.id = 'approval-' + approval.id;
  card.style.cssText = 'position:fixed;bottom:80px;right:18px;width:360px;background:var(--card-strong);border:2px solid ' + riskColor + ';border-radius:16px;box-shadow:0 8px 32px rgba(0,0,0,.2);z-index:9999;overflow:hidden;animation:notifPanelIn .2s ease;';
  card.innerHTML =
    '<div style="padding:14px 16px;border-bottom:1px solid var(--bd);display:flex;align-items:center;gap:8px;">' +
      '<div style="width:10px;height:10px;border-radius:50%;background:' + riskColor + ';animation:pulse 1.5s infinite;"></div>' +
      '<span style="font-size:13px;font-weight:700;color:' + riskColor + ';">' + riskLabel + ' 操作确认</span>' +
    '</div>' +
    '<div style="padding:14px 16px;">' +
      '<div style="font-size:13px;color:var(--tx);line-height:1.5;margin-bottom:12px;">' + esc(approval.description) + '</div>' +
      '<div style="font-size:11px;color:var(--tx3);margin-bottom:12px;">工具: ' + esc(approval.tool) + '</div>' +
      '<div style="display:flex;gap:8px;">' +
        '<button class="btn btn-sm" style="flex:1;background:' + riskColor + ';color:#fff;border-color:' + riskColor + ';" onclick="resolveLocalApproval(&quot;' + approval.id + '&quot;,true)">允许执行</button>' +
        '<button class="btn btn-sm" style="flex:1;background:var(--accent);color:#fff;border-color:var(--accent);" onclick="resolveAllApprovals(true)">全部允许</button>' +
        '<button class="btn btn-sm" style="flex:1;background:var(--bg-soft);color:var(--tx);border-color:var(--bd);" onclick="resolveLocalApproval(&quot;' + approval.id + '&quot;,false)">拒绝</button>' +
      '</div>' +
    '</div>';
  document.body.appendChild(card);
}

async function resolveAllApprovals(approved) {
  var cards = document.querySelectorAll('[id^="approval-"]');
  for (var i = 0; i < cards.length; i++) {
    var aid = cards[i].id.replace('approval-', '');
    try { await api('/local/approvals/' + aid, { method: 'POST', body: { approved: approved } }); } catch(e) {}
    cards[i].remove();
  }
  if (approved) {
    try { await api('/local/auto-approve', { method: 'POST', body: { enabled: true } }); } catch(e) {}
    toast('已全部允许，本次会话后续操作将自动放行');
  } else {
    toast('已全部拒绝');
  }
}

async function resolveLocalApproval(id, approved) {
  try {
    await api('/local/approvals/' + id, { method: 'POST', body: { approved: approved } });
  } catch(e) {}
  var el = document.getElementById('approval-' + id);
  if (el) el.remove();
}

if (window.LOCAL_MODE && state.token) startApprovalPolling();

window.loadLocalTasks = loadLocalTasks;
window.showLocalTaskDetail = showLocalTaskDetail;
window.showNewLocalTaskModal = showNewLocalTaskModal;
window.submitLocalTask = submitLocalTask;
window.cancelLocalTask = cancelLocalTask;
window.loadLocalAuditLog = loadLocalAuditLog;
window.resolveLocalApproval = resolveLocalApproval;
window.resolveAllApprovals = resolveAllApprovals;

// ─── 今日焦点面板（LOCAL_MODE only）──────────────────────────────

async function loadFocusPanel() {
  if (!window.LOCAL_MODE) { navigate('dashboard'); return; }
  var mc = document.getElementById('mc'); if (!mc) return;
  mc.innerHTML = renderLoading();
  var data = {};
  try { data = await api('/local/focus'); } catch(e) { toast('加载失败: ' + e.message, 'error'); }
  var items = data.items || [];
  var summary = data.summary || '暂无焦点';
  var todayStr = data.date || new Date().toISOString().slice(0, 10);

  var catIcons = { follow_up: '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/></svg>', contract_expiring: '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>', finance_alert: '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>', todo_due: '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M9 12l2 2 4-4"/></svg>', email_unread: '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg>' };
  var catColors = { follow_up: '#3b82f6', contract_expiring: '#f97316', finance_alert: '#ef4444', todo_due: '#8b5cf6', email_unread: '#06b6d4' };
  var catLabels = { follow_up: '客户跟进', contract_expiring: '合同到期', finance_alert: '财务预警', todo_due: '待办到期', email_unread: '未读邮件' };

  var h = '<div class="page-inner">';
  h += '<div class="page-header"><div><h1>今日焦点</h1><p>' + todayStr + '</p></div>';
  h += '<div style="display:flex;gap:8px;">';
  h += '<button class="btn btn-sm" onclick="generateReport(&quot;daily&quot;)">生成日报</button>';
  h += '<button class="btn btn-sm" onclick="generateReport(&quot;weekly&quot;)">生成周报</button>';
  h += '</div></div>';

  // summary card
  var urgentCount = items.filter(function(i) { return i.priority >= 8; }).length;
  var summaryBg = urgentCount > 0 ? 'linear-gradient(135deg, #fef2f2, #fff1f2)' : 'linear-gradient(135deg, #f0fdf4, #ecfdf5)';
  var summaryBorder = urgentCount > 0 ? '#fecaca' : '#bbf7d0';
  h += '<div style="background:' + summaryBg + ';border:1px solid ' + summaryBorder + ';border-radius:14px;padding:18px 20px;margin-bottom:20px;">';
  h += '<div style="font-size:14px;line-height:1.6;color:var(--tx);">' + esc(summary) + '</div></div>';

  // stats row
  var cats = {};
  items.forEach(function(i) { cats[i.category] = (cats[i.category] || 0) + 1; });
  h += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px;margin-bottom:20px;">';
  ['follow_up','contract_expiring','finance_alert','todo_due','email_unread'].forEach(function(cat) {
    var cnt = cats[cat] || 0;
    h += '<div style="background:var(--card);border:1px solid var(--bd);border-radius:12px;padding:14px 16px;text-align:center;">';
    h += '<div style="color:' + (catColors[cat] || '#888') + ';margin-bottom:6px;">' + (catIcons[cat] || '') + '</div>';
    h += '<div style="font-size:22px;font-weight:700;color:var(--tx);">' + cnt + '</div>';
    h += '<div style="font-size:11px;color:var(--tx3);margin-top:2px;">' + (catLabels[cat] || cat) + '</div>';
    h += '</div>';
  });
  h += '</div>';

  if (items.length === 0) {
    h += '<div style="text-align:center;padding:60px 20px;">';
    h += '<div style="font-size:48px;margin-bottom:12px;">&#127919;</div>';
    h += '<div style="font-size:16px;color:var(--tx);font-weight:600;margin-bottom:6px;">今天没有待办焦点</div>';
    h += '<div style="font-size:13px;color:var(--tx3);">所有事项都已处理完毕，继续保持！</div>';
    h += '</div>';
  } else {
    items.forEach(function(item, idx) {
      var color = catColors[item.category] || '#888';
      var isUrgent = item.priority >= 8;
      h += '<div class="card" style="margin-bottom:10px;border-left:3px solid ' + color + ';' + (isUrgent ? 'background:rgba(239,68,68,0.03);' : '') + '">';
      h += '<div style="display:flex;align-items:flex-start;gap:12px;padding:14px 16px;">';
      h += '<div style="color:' + color + ';flex-shrink:0;margin-top:2px;">' + (catIcons[item.category] || '') + '</div>';
      h += '<div style="flex:1;min-width:0;">';
      h += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">';
      if (isUrgent) h += '<span style="font-size:10px;font-weight:700;color:#fff;background:#ef4444;padding:1px 6px;border-radius:4px;">紧急</span>';
      h += '<span style="font-size:10px;color:' + color + ';font-weight:600;">' + (catLabels[item.category] || item.category) + '</span>';
      h += '</div>';
      h += '<div style="font-size:13px;font-weight:600;color:var(--tx);margin-bottom:3px;">' + esc(item.title) + '</div>';
      h += '<div style="font-size:12px;color:var(--tx3);line-height:1.4;">' + esc(item.detail) + '</div>';
      if (item.actionHint) h += '<div style="font-size:11px;color:' + color + ';margin-top:4px;font-weight:500;">' + esc(item.actionHint) + '</div>';
      h += '</div></div></div>';
    });
  }
  h += '</div>';
  mc.innerHTML = h;
}

async function generateReport(reportType) {
  toast('正在生成' + (reportType === 'weekly' ? '周报' : '日报') + '...', 'success');
  try {
    var data = await api('/local/report', { method: 'POST', body: { type: reportType } });
    var h = '<div class="modal-header"><h3>' + (reportType === 'weekly' ? '智能周报' : '智能日报') + '</h3></div>';
    h += '<div class="modal-body"><div style="font-size:13px;line-height:1.7;color:var(--tx);white-space:pre-wrap;">' + esc(data.report) + '</div></div>';
    h += '<div class="modal-footer"><button class="btn" onclick="this.closest(&quot;.modal-overlay&quot;).remove()">关闭</button>';
    h += '<button class="btn btn-primary" onclick="copyReportToClipboard(this)">复制到剪贴板</button></div>';
    showModalRaw(h);
    window._lastReport = data.report;
  } catch(e) { toast('生成失败: ' + e.message, 'error'); }
}

function copyReportToClipboard(btn) {
  if (window._lastReport && navigator.clipboard) {
    navigator.clipboard.writeText(window._lastReport);
    toast('已复制到剪贴板', 'success');
  }
}

window.loadFocusPanel = loadFocusPanel;
window.generateReport = generateReport;
window.copyReportToClipboard = copyReportToClipboard;

// ─── 智能工作流管理（LOCAL_MODE only）──────────────────────────────

async function loadWorkflows() {
  if (!window.LOCAL_MODE) { navigate('dashboard'); return; }
  var mc = document.getElementById('mc'); if (!mc) return;
  mc.innerHTML = renderLoading();
  var data = {};
  try { data = await api('/local/workflows'); } catch(e) {}
  var workflows = data.workflows || [];

  var h = '<div class="page-inner">';
  h += '<div class="page-header"><div><h1>自动化</h1><p>把提醒、抓取、生成、通知这些重复动作编成自动化流程，减少人工操作</p></div>';
  h += '<div style="display:flex;gap:8px;flex-wrap:wrap;"><button class="btn btn-sm" onclick="navigate(&quot;chat&quot;)">AI 设计流程</button><button class="btn btn-primary btn-sm" onclick="showNewWorkflowModal()">+ 新建自动化</button></div></div>';
  h += '<div class="card" style="margin-bottom:18px;padding:14px 16px;background:linear-gradient(135deg,rgba(249,115,22,.08),transparent);"><div style="font-size:13px;font-weight:700;color:var(--tx);margin-bottom:6px;">自动化适合做什么</div><div style="font-size:12px;color:var(--tx2);line-height:1.8;">适合定时收集线索、批量生成报告、到点提醒跟进、触发邮件发送、将项目动作串成 SOP。重点不是“技术炫技”，而是减少人工重复劳动。</div></div>';
  var workflowPresets = [
    { key: 'weekly-briefing', title: '商机周报', desc: '每周五生成一份商机简报，并推送到邮箱。', color: '#2563eb', trigger: '每周五 17:00', steps: 'AI 生成 + 邮件发送' },
    { key: 'lead-alert', title: '新线索提醒', desc: '出现新线索后，自动生成待办并发站内提醒。', color: '#f97316', trigger: '事件触发', steps: '创建待办 + 站内通知' },
    { key: 'contract-renewal', title: '合同到期提醒', desc: '合同快到期时，提醒续约并给出跟进建议。', color: '#10b981', trigger: '事件触发', steps: 'AI 生成 + 站内通知' },
    { key: 'followup-pack', title: '跟进任务包', desc: '每天早上生成当日跟进清单，避免遗漏客户推进。', color: '#8b5cf6', trigger: '每天 09:00', steps: 'AI 生成 + 创建待办' }
  ];
  h += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin-bottom:18px;">';
  workflowPresets.forEach(function(p) {
    h += '<div class="card" style="padding:16px;border-top:3px solid ' + p.color + ';background:linear-gradient(180deg,' + p.color + '0d,transparent 45%,transparent);">';
    h += '<div style="display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:8px;"><div style="font-size:14px;font-weight:700;color:var(--tx);">' + p.title + '</div><span style="font-size:10px;color:' + p.color + ';background:' + p.color + '18;padding:2px 8px;border-radius:999px;">' + p.trigger + '</span></div>';
    h += '<div style="font-size:12px;color:var(--tx2);line-height:1.8;min-height:44px;margin-bottom:10px;">' + p.desc + '</div>';
    h += '<div style="font-size:11px;color:var(--tx3);margin-bottom:12px;">默认步骤：' + p.steps + '</div>';
    h += '<button class="btn btn-sm" style="width:100%;border-color:' + p.color + ';color:' + p.color + ';" onclick="createWorkflowPreset(&quot;' + p.key + '&quot;)">使用这个模板</button>';
    h += '</div>';
  });
  h += '</div>';

  if (workflows.length === 0) {
    h += '<div style="text-align:center;padding:60px 20px;">';
    h += '<div style="font-size:48px;margin-bottom:12px;">&#9889;</div>';
    h += '<div style="font-size:16px;color:var(--tx);font-weight:600;margin-bottom:6px;">还没有自动化流程</div>';
    h += '<div style="font-size:13px;color:var(--tx3);max-width:460px;margin:0 auto;line-height:1.7;">用自然语言描述你想自动化的事情，比如：<br>"每周五下午5点生成本周商机周报发到我邮箱"<br>"抓到新招标后自动生成跟进清单并提醒我"</div>';
    h += '</div>';
  } else {
    h += '<div style="display:grid;gap:12px;">';
    workflows.forEach(function(wf) {
      var triggerLabel = { cron: '定时触发', event: '事件触发', manual: '手动触发' }[wf.triggerType] || wf.triggerType;
      var triggerColor = { cron: '#3b82f6', event: '#f97316', manual: '#8b5cf6' }[wf.triggerType] || '#888';
      h += '<div class="card" style="cursor:pointer;" onclick="showWorkflowDetail(&quot;' + wf.id + '&quot;)">';
      h += '<div style="padding:16px 18px;">';
      h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">';
      h += '<div style="display:flex;align-items:center;gap:8px;">';
      h += '<span style="font-size:10px;font-weight:700;color:#fff;background:' + triggerColor + ';padding:2px 8px;border-radius:4px;">' + esc(triggerLabel) + '</span>';
      h += '<span style="font-size:14px;font-weight:600;color:var(--tx);">' + esc(wf.name) + '</span>';
      h += '</div>';
      h += '<div style="display:flex;align-items:center;gap:8px;">';
      h += '<span style="font-size:11px;color:var(--tx3);">执行 ' + (wf.runCount || 0) + ' 次</span>';
      h += '<button class="btn btn-sm" style="font-size:11px;padding:3px 8px;" onclick="event.stopPropagation();toggleWf(&quot;' + wf.id + '&quot;,' + (!wf.enabled) + ')">' + (wf.enabled ? '已启用' : '已禁用') + '</button>';
      h += '</div></div>';
      if (wf.description) h += '<div style="font-size:12px;color:var(--tx3);margin-bottom:8px;">' + esc(wf.description) + '</div>';
      h += '<div style="display:flex;gap:6px;flex-wrap:wrap;">';
      (wf.actions || []).forEach(function(a, i) {
        var actionColor = { send_email: '#06b6d4', create_todo: '#8b5cf6', ai_generate: '#f59e0b', notify: '#22c55e', opc_tool: '#3b82f6', local_tool: '#ec4899', fetch_webpage: '#0ea5e9', render_html: '#8b5cf6', render_video: '#ec4899' }[a.type] || '#888';
        h += '<span style="font-size:10px;background:' + actionColor + '18;color:' + actionColor + ';padding:2px 8px;border-radius:4px;">' + (i + 1) + '. ' + esc(a.label || a.type) + '</span>';
      });
      h += '</div>';
      if (wf.lastRunAt) h += '<div style="font-size:10px;color:var(--tx3);margin-top:6px;">上次执行: ' + new Date(wf.lastRunAt).toLocaleString() + '</div>';
      h += '</div></div>';
    });
    h += '</div>';
  }
  h += '</div>';
  mc.innerHTML = h;
}

// 渲染工作流步骤结果，视频/图片路径显示为可点击链接
function openVideoFolder() {
  api('/video/open-folder', { method: 'POST' })
    .then(function(r) { toast('已打开文件夹：' + (r.path || ''), 'success'); })
    .catch(function(e) { toast('打开失败: ' + e.message, 'error'); });
}

function renderStepResult(result) {
  var s = String(result || '');
  var mp4Match = s.match(new RegExp('\\/public\\/videos\\/[\\w.-]+\\.mp4'));
  if (mp4Match) {
    var url = mp4Match[0];
    return '<div style="margin-top:4px;">'
      + '<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-bottom:6px;">'
      + '<a href="' + url + '" target="_blank" style="display:inline-flex;align-items:center;gap:4px;background:#1e1b4b;color:#818cf8;padding:5px 10px;border-radius:6px;font-size:12px;text-decoration:none;font-weight:500;">▶ 播放</a>'
      + '<a href="' + url + '" download style="display:inline-flex;align-items:center;gap:4px;background:rgba(0,0,0,0.06);color:var(--tx2);padding:5px 10px;border-radius:6px;font-size:12px;text-decoration:none;">⬇ 下载</a>'
      + '<button onclick="openVideoFolder()" style="display:inline-flex;align-items:center;gap:4px;background:rgba(0,0,0,0.06);color:var(--tx2);padding:5px 10px;border-radius:6px;font-size:12px;border:none;cursor:pointer;">📂 打开文件夹</button>'
      + '</div>'
      + '<div style="font-size:10px;color:var(--tx3);font-family:monospace;">' + esc(url) + '</div>'
      + '</div>';
  }
  return '<div style="font-size:11px;color:var(--tx2);background:rgba(0,0,0,0.04);border-radius:5px;padding:6px 8px;margin-top:4px;max-height:120px;overflow-y:auto;white-space:pre-wrap;word-break:break-all;font-family:monospace;line-height:1.5;">'
    + esc(s.slice(0, 800)) + (s.length > 800 ? '...' : '') + '</div>';
}

function buildWfLogHtml(logs) {
  var h = '';
  if (!logs || logs.length === 0) return h;
  h += '<div style="font-size:12px;font-weight:700;color:var(--tx);margin:16px 0 8px;">最近执行记录</div>';
  // 只自动展开第一条 running 的记录，其余折叠
  var firstRunningIdx = -1;
  logs.slice(0, 10).forEach(function(log, li) { if (firstRunningIdx < 0 && log.status === 'running') firstRunningIdx = li; });
  // 没有 running 就展开第一条
  var autoExpandIdx = firstRunningIdx >= 0 ? firstRunningIdx : 0;
  logs.slice(0, 10).forEach(function(log, li) {
    var statusColor = log.status === 'done' ? '#22c55e' : log.status === 'failed' ? '#ef4444' : '#f97316';
    var statusIcon = log.status === 'done' ? '✅' : log.status === 'failed' ? '❌' : '⏳';
    var steps = [];
    try {
      if (Array.isArray(log.steps)) steps = log.steps;
      else if (typeof log.steps === 'string' && log.steps) steps = JSON.parse(log.steps);
    } catch(e) {}
    var logId = 'wf-log-' + li;
    var isRunning = log.status === 'running';
    var isExpanded = li === autoExpandIdx;
    h += '<div style="border:1px solid var(--bd);border-radius:8px;margin-bottom:8px;overflow:hidden;">';
    h += '<div onclick="wfToggleLog(&quot;' + logId + '&quot;)" style="display:flex;align-items:center;justify-content:space-between;padding:8px 12px;cursor:pointer;background:var(--bg-soft);user-select:none;">';
    h += '<span style="font-size:12px;color:var(--tx3);">' + new Date(log.started_at).toLocaleString() + '</span>';
    h += '<div style="display:flex;align-items:center;gap:8px;">';
    if (steps.length > 0) h += '<span style="font-size:10px;color:var(--tx3);">' + steps.length + ' 步骤</span>';
    if (isRunning) h += '<span style="font-size:10px;color:#f97316;">● 执行中...</span>';
    h += '<span style="font-size:12px;font-weight:600;color:' + statusColor + ';">' + statusIcon + ' ' + esc(log.status) + '</span>';
    h += '<span style="font-size:11px;color:var(--tx3);" id="' + logId + '-arrow">' + (isExpanded ? '▼' : '▶') + '</span>';
    h += '</div></div>';
    h += '<div id="' + logId + '" style="display:' + (isExpanded ? 'block' : 'none') + ';">';
    if (steps.length > 0) {
      steps.forEach(function(step, si) {
        var sc = step.status === 'done' ? '#22c55e' : step.status === 'failed' ? '#ef4444' : '#f97316';
        var si_icon = step.status === 'done' ? '✅' : step.status === 'failed' ? '❌' : '⏭';
        h += '<div style="padding:8px 12px;border-top:1px solid var(--bd);background:' + (si % 2 === 0 ? 'var(--bg)' : 'var(--bg-soft)') + ';">';
        h += '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;">';
        h += '<span style="width:18px;height:18px;border-radius:50%;background:' + sc + ';color:#fff;font-size:9px;font-weight:700;display:flex;align-items:center;justify-content:center;flex-shrink:0;">' + (si + 1) + '</span>';
        h += '<span style="font-size:12px;font-weight:500;color:var(--tx);">' + esc(step.action || '') + '</span>';
        h += '<span style="font-size:10px;color:' + sc + ';margin-left:auto;">' + si_icon + ' ' + esc(step.status || '') + '</span>';
        h += '</div>';
        if (step.result) h += renderStepResult(step.result);
        if (step.error) h += '<div style="font-size:11px;color:#ef4444;background:#fef2f2;border-radius:5px;padding:5px 8px;margin-top:4px;">⚠ ' + esc(step.error) + '</div>';
        h += '</div>';
      });
    } else if (isRunning) {
      h += '<div style="padding:10px 12px;font-size:12px;color:#f97316;">⏳ 正在执行，请稍候...</div>';
    } else if (log.error) {
      h += '<div style="padding:10px 12px;font-size:12px;color:#ef4444;">⚠ ' + esc(log.error) + '</div>';
    } else {
      h += '<div style="padding:10px 12px;font-size:12px;color:var(--tx3);">暂无步骤详情</div>';
    }
    h += '</div></div>';
  });
  return h;
}

var _wfDetailTimer = null;

async function showWorkflowDetail(wfId) {
  var data = {};
  try { data = await api('/local/workflows/' + wfId); } catch(e) { toast(e.message, 'error'); return; }
  var wf = data.workflow;
  var logs = data.logs || [];
  if (!wf) return;

  var triggerLabel = { cron: '定时触发', event: '事件触发', manual: '手动触发' }[wf.triggerType] || wf.triggerType;

  var h = '<div class="modal-header" style="display:flex;align-items:center;justify-content:space-between;">';
  h += '<h3>' + esc(wf.name) + '</h3>';
  h += '<span id="wf-detail-refresh-badge" style="font-size:11px;color:var(--tx3);"></span>';
  h += '</div>';
  h += '<div class="modal-body">';
  h += '<div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:16px;">';
  h += '<div style="background:var(--bg-soft);padding:8px 14px;border-radius:8px;font-size:12px;"><b>触发:</b> ' + esc(triggerLabel) + '</div>';
  if (wf.triggerConfig && wf.triggerConfig.expression) h += '<div style="background:var(--bg-soft);padding:8px 14px;border-radius:8px;font-size:12px;font-family:monospace;"><b>Cron:</b> ' + esc(wf.triggerConfig.expression) + '</div>';
  h += '<div style="background:var(--bg-soft);padding:8px 14px;border-radius:8px;font-size:12px;"><b>执行次数:</b> <span id="wf-detail-runcount">' + (wf.runCount || 0) + '</span></div>';
  h += '<div style="background:var(--bg-soft);padding:8px 14px;border-radius:8px;font-size:12px;"><b>状态:</b> ' + (wf.enabled ? '<span style="color:#22c55e;">启用</span>' : '<span style="color:#ef4444;">禁用</span>') + '</div>';
  h += '</div>';
  if (wf.description) h += '<div style="font-size:13px;color:var(--tx3);margin-bottom:16px;">' + esc(wf.description) + '</div>';
  h += '<div style="font-size:12px;font-weight:700;color:var(--tx);margin-bottom:8px;">动作链</div>';
  (wf.actions || []).forEach(function(a, i) {
    var actionColor = { send_email: '#06b6d4', create_todo: '#8b5cf6', ai_generate: '#f59e0b', notify: '#22c55e', opc_tool: '#3b82f6', local_tool: '#ec4899', fetch_webpage: '#0ea5e9', render_html: '#8b5cf6', render_video: '#ec4899' }[a.type] || '#888';
    h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px;">';
    h += '<div style="width:24px;height:24px;border-radius:50%;background:' + actionColor + ';color:#fff;font-size:11px;font-weight:700;display:flex;align-items:center;justify-content:center;">' + (i + 1) + '</div>';
    h += '<div><div style="font-size:13px;font-weight:500;color:var(--tx);">' + esc(a.label || a.type) + '</div><div style="font-size:11px;color:var(--tx3);">' + esc(a.type) + '</div></div>';
    h += '</div>';
    if (i < (wf.actions || []).length - 1) h += '<div style="width:1px;height:12px;background:var(--bd);margin-left:12px;"></div>';
  });
  h += '<div id="wf-detail-logs">' + buildWfLogHtml(logs) + '</div>';
  h += '</div>';
  h += '<div class="modal-footer">';
  h += '<button class="btn" onclick="wfDetailClose()">关闭</button>';
  h += '<button class="btn btn-sm" style="background:#ef4444;color:#fff;border-color:#ef4444;" onclick="deleteWf(&quot;' + wf.id + '&quot;)">删除</button>';
  h += '<button class="btn btn-primary btn-sm" onclick="runWf(&quot;' + wf.id + '&quot;)">立即执行</button>';
  h += '</div>';
  showModalRaw(h);

  // 启动轮询刷新（有 running 状态的记录每 3 秒刷一次，否则 8 秒刷一次）
  if (_wfDetailTimer) { clearTimeout(_wfDetailTimer); _wfDetailTimer = null; }
  var scheduleWfRefresh = function(ms) {
    _wfDetailTimer = setTimeout(async function() {
      var overlay = document.querySelector('.modal-overlay');
      if (!overlay) { _wfDetailTimer = null; return; }
      try {
        var fresh = await api('/local/workflows/' + wfId);
        var freshLogs = (fresh && fresh.logs) || [];
        var logsEl = document.getElementById('wf-detail-logs');
        var badge = document.getElementById('wf-detail-refresh-badge');
        var rcEl = document.getElementById('wf-detail-runcount');
        if (logsEl) logsEl.innerHTML = buildWfLogHtml(freshLogs);
        if (badge) badge.textContent = '已更新 ' + new Date().toLocaleTimeString();
        if (rcEl && fresh && fresh.workflow) rcEl.textContent = fresh.workflow.runCount || 0;
        var stillRunning = freshLogs.some(function(l) { return l.status === 'running'; });
        scheduleWfRefresh(stillRunning ? 3000 : 8000);
      } catch(_) { scheduleWfRefresh(8000); }
    }, ms);
  };
  var hasRunning = logs.some(function(l) { return l.status === 'running'; });
  scheduleWfRefresh(hasRunning ? 3000 : 8000);
}

function wfDetailClose() {
  if (_wfDetailTimer) { clearTimeout(_wfDetailTimer); _wfDetailTimer = null; }
  var overlay = document.querySelector('.modal-overlay');
  if (overlay) overlay.remove();
}

