  h += '<div style="font-size:12px;color:var(--tx);margin-bottom:8px;">示例：</div>';
  h += '<div style="display:flex;flex-direction:column;gap:6px;margin-bottom:14px;">';
  var examples = [
    '每天早上9点抓取新华网科技频道内容，AI 整理成简报，发到我邮箱',
    '每周五17点抓取政策网站新闻，制作成视频，发邮件通知我',
    '每天8点检查财联社要闻，AI 总结，截图并发邮件',
  ];
  examples.forEach(function(ex) {
    h += '<div style="font-size:11px;padding:6px 10px;background:var(--bg-soft);border-radius:6px;cursor:pointer;color:var(--tx3);line-height:1.5;" onclick="document.getElementById(&quot;wf-nl-input&quot;).value=&quot;' + ex + '&quot;">' + ex + '</div>';
  });
  h += '</div>';
  h += '<textarea id="wf-nl-input" class="input-field" rows="4" placeholder="例如：每天早上9点抓取新华网内容，AI整理成简报发邮件..." style="resize:vertical;"></textarea>';
  h += '</div>';
  h += '<div class="modal-footer"><button class="btn" onclick="this.closest(&quot;.modal-overlay&quot;).remove()">取消</button>';
